# ===== FILE: ambiguity_detector.py  (101 lines) =====
# ==============================================================================================================

"""
v29 STAGE 29 — ambiguity detector + reasonable completion (the DEFAULT policy: almost never asks).
====================================================================================================
When a prompt admits several readings we do NOT silently pick one and we do NOT reflexively ask. The
default is to COMPLETE reasonably and STATE the assumption. Only a genuine high-stakes fork (a choice that
is irreversible/costly AND left open) is escalated to S30 — and even there S30 usually proceeds.

  • CLEAR              — no vague markers → proceed.
  • MINOR_AMBIGUITY    — vague terms but a concrete goal → reasonable completion + "assumed X" (does NOT ask).
  • HIGH_STAKES_FORK   — a costly/irreversible dimension left genuinely open → hand to S30 (VoI-gated).

★ HONEST (§0.4, §1.4, §1.13, §5.2) ★: ambiguity detection is imperfect (precision 34-97%, ClariQ
ask-need F1 ~0.37), so this is CONSERVATIVE toward CLEAR/MINOR (not asking). The cheap path is a
deterministic LEXICON; the semantic-entropy probe and ClarifyGPT-style multi-sample code-consistency need
an LLM and are [BLOCKED: key/egress]. Fail-safe: uncertain → reasonable completion + stated assumption.
"""
from __future__ import annotations

import re
from dataclasses import dataclass, field
from typing import Dict, List, Optional

# vague / open-ended terms → a sensible default to assume (and state)
_VAGUE_DEFAULT: Dict[str, str] = {
    "fast": "target the standard optimal complexity for the task (e.g. O(n log n) sort)",
    "efficient": "target the standard optimal complexity; avoid quadratic blowups",
    "large": "design for inputs up to ~1e6 elements; stream/iterate, don't hold needless copies",
    "small": "assume inputs fit comfortably in memory",
    "robust": "validate inputs and raise clear typed errors",
    "scalable": "keep per-item work near-linear; no global quadratic structures",
    "user-friendly": "clear error messages + sensible defaults",
    "appropriate": "a sensible default consistent with the stated goal",
    "reasonable": "a sensible default consistent with the stated goal",
    "some": "a small representative set",
    "several": "about 3-5",
    "etc": "the remaining cases follow the same pattern",
    "and so on": "the remaining cases follow the same pattern",
    "as needed": "only when the stated condition holds",
    "handle it": "validate and handle the error path explicitly",
}
_OPEN_RANGE = ("up to", "around", "approximately", "roughly", "or so", "ish")
# dimensions where the WRONG choice is costly/irreversible
_HIGH_STAKES = ("delete", "remove", "drop", "overwrite", "truncate", "wipe", "destroy", "purge",
                "payment", "charge", "refund", "production", "migrate", "irreversible", "format")
# markers that a choice is left genuinely OPEN
_FORK = ("either", " or ", "your call", "you decide", "whichever", "up to you", "if you want",
         "one of", "some way", "a or b")


@dataclass
class AmbiguityReport:
    status: str                 # CLEAR | MINOR_AMBIGUITY | HIGH_STAKES_FORK
    score: float = 0.0
    vague_terms: List[str] = field(default_factory=list)
    completions: Dict[str, str] = field(default_factory=dict)   # vague term -> assumed default
    fork: Optional[str] = None
    detail: str = ""

    @property
    def asks(self) -> bool:
        return False             # ★ S29 itself NEVER asks — only S30 may, and only on HIGH_STAKES_FORK ★

    def assumptions(self) -> List[str]:
        return [f"assumed '{t}' = {d}" for t, d in self.completions.items()]

    def __str__(self):
        if self.status == "CLEAR":
            return "CLEAR — no vague markers (proceed, no question)"
        if self.status == "MINOR_AMBIGUITY":
            return f"MINOR_AMBIGUITY {self.vague_terms} → reasonable completion (no question): {self.assumptions()}"
        return f"HIGH_STAKES_FORK ({self.fork}) → S30 (VoI-gated)"


def _high_stakes_fork(text: str) -> Optional[str]:
    """A fork is high-stakes only when a costly/irreversible dimension is ALSO left genuinely open."""
    t = " " + text.lower() + " "
    stake = next((k for k in _HIGH_STAKES if k in t), None)
    forked = next((k for k in _FORK if k in t), None)
    if stake and forked:
        return f"'{stake}' with an open choice ('{forked.strip()}') — wrong pick is costly/irreversible"
    return None


def detect_ambiguity(prompt: str, goal_present: Optional[bool] = None) -> AmbiguityReport:
    """Classify ambiguity. DEFAULT = reasonable completion (no ask); only a genuine high-stakes fork → S30."""
    text = prompt.lower()
    words = re.findall(r"[a-zA-Z]+", text)
    n = max(len(words), 1)
    vague = [t for t in _VAGUE_DEFAULT if re.search(rf"\b{re.escape(t)}\b", text)]
    vague += [t for t in _OPEN_RANGE if t in text]
    score = len(vague) / n
    fork = _high_stakes_fork(prompt)
    if fork:
        return AmbiguityReport("HIGH_STAKES_FORK", score, vague, fork=fork,
                               detail="costly/irreversible choice left open → escalate to S30 (VoI-gated)")
    if not vague:
        return AmbiguityReport("CLEAR", score, detail="no vague markers — proceed")
    completions = {t: _VAGUE_DEFAULT[t] for t in vague if t in _VAGUE_DEFAULT}
    return AmbiguityReport("MINOR_AMBIGUITY", score, vague, completions,
                           detail="vague but intent clear → reasonable completion + stated assumption (no ask)")


# ==============================================================================================================
# ===== FILE: approx_cert.py  (144 lines) =====
# ==============================================================================================================

"""
v33 STAGE 3 — certified-approximate folding (Direction D): recover defers with a STATED error certificate.
============================================================================================================
When EXACT folding fails, breadth is recovered by APPROXIMATION — but only with a machine-checkable error
certificate (rule: no approximation emitted without an error bound). Three honest, never-mixed certificate
kinds here:
  • asymptotic-with-error : a closed form + an explicit truncation bound (Euler-Maclaurin). e.g. the harmonic
                            sum Σ1/k = ln n + γ + 1/2n − 1/12n² + R, |R| ≤ 1/(120 n⁴). EXACT-defers, yet folds
                            APPROXIMATELY with a proven bound — a genuine recovery from defer.
  • epsilon-delta (δ)     : a Monte-Carlo estimate within ε w.p. ≥ 1−δ, via Hoeffding: n ≥ (b−a)²/(2ε²)·ln(2/δ).
                            The CHECK (the bound) is O(1); evidence collection is BOUNDED. Hoeffding FLOOR
                            stated honestly: ε cannot be pushed arbitrarily low (n explodes) — approximation
                            is never exact.
  • precision-on-demand   : pick arithmetic precision from the required ε (decimal digits = ⌈−log10 ε⌉+guard),
                            so we are exactly as precise as the context needs — no waste, with the residual
                            bounded by the chosen precision.

Clock C (the approximate closed form runs fast) + Clock B (the bound is a cheap check). Distinct label
"APPROX_FOLD" — never reported as exact (rule R3.5).
"""
from __future__ import annotations

import decimal
import math
import random
from dataclasses import dataclass
from typing import Callable, Optional


@dataclass
class ApproxCert:
    kind: str                   # asymptotic-with-error | epsilon-delta | precision-on-demand
    closed_form: str
    error_bound: str            # the STATED error (ε term / δ / residual)
    eps: float = 0.0
    delta: float = 0.0
    detail: str = ""


# ── asymptotic-with-error: harmonic sum (a real recovery of an exact-defer) ─────────────────────────
_EULER_GAMMA = 0.5772156649015328606

def harmonic_approx_value(n: int) -> float:
    """H_n ≈ ln n + γ + 1/(2n) − 1/(12 n²)  (Euler–Maclaurin), truncation |R| ≤ 1/(120 n⁴)."""
    return math.log(n) + _EULER_GAMMA + 1.0 / (2 * n) - 1.0 / (12 * n * n)


def harmonic_error_bound(n: int) -> float:
    return 1.0 / (120 * n**4)


def certify_harmonic() -> ApproxCert:
    """Certified-approximate fold of Σ_{k=1}^n 1/k (which EXACT-defers). The bound is CHECKED below."""
    return ApproxCert("asymptotic-with-error", "log(n) + gamma + 1/(2*n) - 1/(12*n**2)",
                      "|R| <= 1/(120*n**4)", detail="Euler–Maclaurin; recovers an exact-defer (harmonic)")


def check_harmonic_within_bound(n: int) -> bool:
    """Independent CHECK (Clock B): the approximation is within its stated bound of the TRUE partial sum."""
    true_h = sum(1.0 / k for k in range(1, n + 1))
    return abs(harmonic_approx_value(n) - true_h) <= harmonic_error_bound(n) + 1e-12


# ── epsilon-delta: Hoeffding-bounded Monte-Carlo estimate ───────────────────────────────────────────
def hoeffding_n(eps: float, delta: float, a: float = 0.0, b: float = 1.0) -> int:
    """Samples needed for a mean estimate within ε w.p. ≥ 1−δ: n ≥ (b−a)²/(2ε²)·ln(2/δ)."""
    return math.ceil((b - a) ** 2 / (2 * eps * eps) * math.log(2.0 / delta))


def certify_monte_carlo(sample: Callable[[], float], eps: float, delta: float,
                        a: float = 0.0, b: float = 1.0, cap: int = 2_000_000, seed: int = 0) -> ApproxCert:
    """Estimate E[sample] within ε w.p. ≥ 1−δ (Hoeffding). Evidence collection is BOUNDED by `cap`; if the
    required n exceeds the cap we state that (honest floor) and widen ε to what the cap supports."""
    need = hoeffding_n(eps, delta, a, b)
    rng = random.Random(seed)
    if need > cap:                                  # Hoeffding floor: can't reach this ε within the cap
        n = cap
        eps = math.sqrt((b - a) ** 2 / (2 * n) * math.log(2.0 / delta))   # the ε the cap actually supports
        note = f"requested ε needed {need}>{cap} samples (Hoeffding floor) — widened to ε={eps:.2e}"
    else:
        n = need
        note = f"n={n} samples for ε={eps:.2e}, δ={delta:.2e}"
    s = sum(sample() for _ in range(min(n, cap)))
    mean = s / min(n, cap)
    return ApproxCert("epsilon-delta", f"E≈{mean:.6f}", f"|Ê−E|≤ε w.p.≥1−δ", eps=eps, delta=delta, detail=note)


# ── precision-on-demand (revolution-axis: dynamic precision) ────────────────────────────────────────
def precision_digits(required_eps: float, guard: int = 4) -> int:
    return max(1, math.ceil(-math.log10(required_eps)) + guard)


def evaluate_on_demand(expr_fn: Callable[[decimal.Decimal], decimal.Decimal], x: float,
                       required_eps: float) -> ApproxCert:
    """Evaluate at exactly the precision the context needs (no waste). residual bounded by the chosen prec."""
    digits = precision_digits(required_eps)
    ctx = decimal.Context(prec=digits)
    val = expr_fn(ctx.create_decimal(repr(x)))
    return ApproxCert("precision-on-demand", f"{val}", f"residual ≤ 10^-{digits-1}",
                      eps=required_eps, detail=f"precision={digits} digits chosen from ε={required_eps:.1e}")


# ── disposition hook for STAGE 6 ────────────────────────────────────────────────────────────────────
def approx_dispose(summand_str: str):
    """Return a STAGE-6 Disposition (APPROX_FOLD) if a certified approximation recovers this summand, else
    None. Currently: the harmonic family (Σ1/k) → asymptotic-with-error (a real recovery of an exact-defer)."""
    import disposition as D
    s = summand_str.replace(" ", "")
    if s in ("1/k", "1/(k)"):
        cert = certify_harmonic()
        if check_harmonic_within_bound(1000):       # independent check at a witness n
            return D.Disposition("APPROX_FOLD", "approx-asymptotic", "C", cert.closed_form,
                                 "asymptotic-with-error", "approx (Euler–Maclaurin)", summand_str,
                                 f"recovered from exact-defer; {cert.error_bound}")
    return None


def metamorphic_check(fn: Callable[[int], float], n: int = 1000, tol: float = 1e-2) -> bool:
    """A metamorphic relation for the harmonic family: H(2n) − H(n) → ln 2 as n→∞. Cheap independent
    sanity that the approximation respects a known invariant (not a proof — a corroborating check)."""
    return abs((fn(2 * n) - fn(n)) - math.log(2.0)) < tol


def bayesian_aggregate(deltas) -> dict:
    """Aggregate INDEPENDENT evidence: if k checks each fail w.p. ≤ δᵢ, all-pass confidence ≥ 1−∏δᵢ.
    Honest: assumes independence (stated). Returns combined δ and confidence."""
    prod = 1.0
    for d in deltas:
        prod *= d
    return {"combined_delta": prod, "confidence": 1.0 - prod, "assumes": "independence (stated)"}


def measure_recovery(defer_summands) -> dict:
    """How many EXACT-defers does certified-approximation recover? (the 'built from defer %', MEASURED)."""
    recovered = 0
    rows = []
    for s in defer_summands:
        d = approx_dispose(s)
        ok = d is not None
        recovered += int(ok)
        rows.append((s, "APPROX_FOLD" if ok else "still-DEFER"))
    n = len(defer_summands)
    return {"n": n, "recovered": recovered, "rate": round(recovered / n, 3) if n else 0.0, "rows": rows}


# ==============================================================================================================
# ===== FILE: artifact_store.py  (88 lines) =====
# ==============================================================================================================

"""
v33 STAGE 0 — content-addressed offline artifact store (the "soup pantry").
============================================================================
Slow work (proved fold families, compiled decision functions, discovered algorithms, absence certificates)
is brewed ONCE at build-time and persisted here. Runtime only LOOKS UP by content address — never re-derives
(first principle). Addresses are blake2b digests of a canonical serialization (blake3 is unavailable in this
environment → blake2b, honestly labeled; both are collision-resistant for this use).

Layout:  .fold_soup/<aa>/<digest>.json   (sharded by first byte). An in-memory L1 dict fronts the L2 disk.
A manifest records counts. Everything is JSON (auditable, no pickling of code — artifacts are DATA: closed
forms, certificates, decision-function parameters — executed by a fixed interpreter, never eval of stored code).
"""
from __future__ import annotations

import hashlib
import json
import os
from dataclasses import dataclass
from typing import Any, Dict, Optional

HASH_NAME = "blake2b"              # blake3 unavailable here → blake2b (labeled, not faked as blake3)
_ROOT = os.path.join(os.path.dirname(os.path.abspath(__file__)), ".fold_soup")


def digest(obj: Any) -> str:
    """Content address = blake2b of the canonical JSON (sorted keys, compact)."""
    blob = json.dumps(obj, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return hashlib.blake2b(blob, digest_size=16).hexdigest()


@dataclass
class ArtifactStore:
    root: str = _ROOT
    _l1: Dict[str, Any] = None      # in-memory hot cache (L1) over the on-disk L2

    def __post_init__(self):
        self._l1 = {}
        os.makedirs(self.root, exist_ok=True)

    def _path(self, dg: str) -> str:
        sub = os.path.join(self.root, dg[:2])
        os.makedirs(sub, exist_ok=True)
        return os.path.join(sub, dg + ".json")

    def put(self, obj: Any) -> str:
        """Store an artifact (DATA only — closed forms / certificates / decider params). Returns its address."""
        dg = digest(obj)
        self._l1[dg] = obj
        p = self._path(dg)
        if not os.path.exists(p):
            with open(p, "w") as f:
                json.dump(obj, f, sort_keys=True, separators=(",", ":"), ensure_ascii=False)
        return dg

    def get(self, dg: str) -> Optional[Any]:
        """O(1) lookup: L1 memory → L2 disk. None if absent."""
        if dg in self._l1:
            return self._l1[dg]
        p = self._path(dg)
        if os.path.exists(p):
            with open(p) as f:
                obj = json.load(f)
            self._l1[dg] = obj
            return obj
        return None

    def has(self, dg: str) -> bool:
        return dg in self._l1 or os.path.exists(self._path(dg))

    def count(self) -> int:
        n = 0
        for sub in os.listdir(self.root) if os.path.isdir(self.root) else []:
            d = os.path.join(self.root, sub)
            if os.path.isdir(d):
                n += sum(1 for f in os.listdir(d) if f.endswith(".json"))
        return n

    def clear(self) -> None:
        import shutil
        if os.path.isdir(self.root):
            shutil.rmtree(self.root)
        os.makedirs(self.root, exist_ok=True)
        self._l1 = {}


# a process-wide default store
STORE = ArtifactStore()


# ==============================================================================================================
# ===== FILE: assume_guarantee.py  (217 lines) =====
# ==============================================================================================================

"""
v26 STAGE 5 — assume-guarantee orchestrator + bi-abduction + opaque-boundary runtime contracts.
================================================================================================
The divide-and-conquer engine for LARGE + OPAQUE systems. A "system" is a set of modules (each a HARAN
function with `requires`/`ensures`/body). Each module is verified **modularly** (Z3): assuming its own
`requires` and the *contracts* (`ensures`) of the modules it calls, does its body satisfy its `ensures`?

  • assume-guarantee : verify M assuming callees' contracts; discharge each callee's `requires` at the call.
  • bi-abduction     : if a callee's `requires` is NOT implied by M's `requires`, ABDUCE it — add it to M's
                       inferred precondition (the anti-frame) and proceed. Reported in the ledger.
  • opaque boundary  : a call to a module NOT in the system (closed binary / network / DB) has no contract
                       → its result is unconstrained, and we record a RUNTIME-MONITOR boundary with BLAME
                       on the opaque component (Findler-Felleisen/Wadler: blame the less-precise party).
                       If the user supplies an assumed contract for it, that contract is *assumed but
                       runtime-monitored* (not statically proven).

Output = a CERTIFICATE (assumption ledger): {proven modules + (pre,post), assumed callee contracts,
runtime-monitored opaque boundaries + blame, residual TCB}. This is the product — independently checkable.

★ HONEST LIMITS (§1.9) ★: this is **conditional / compositional**, NEVER a whole-system proof. Every
opaque boundary and every abduced/assumed contract is listed in the ledger as part of the residual TCB.
Bounded to arithmetic contracts Z3 can decide; an unencodable spec → MODULE_UNMODELED (not a false proof).
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Dict, List, Optional

import haran_ast as A
import z3_adapter as Z
from haran_parser import parse


@dataclass
class ModuleResult:
    name: str
    status: str                          # MODULE_PROVEN | MODULE_REFUTED | MODULE_UNMODELED
    abduced_pre: List[str] = field(default_factory=list)   # bi-abduced extra preconditions
    assumed_contracts: List[str] = field(default_factory=list)
    opaque_boundaries: List[str] = field(default_factory=list)   # runtime-monitored (blame=these)
    counterexample: Optional[dict] = None
    detail: str = ""


@dataclass
class SystemCertificate:
    modules: List[ModuleResult]
    def proven(self) -> List[str]:
        return [m.name for m in self.modules if m.status == "MODULE_PROVEN"]
    def residual_tcb(self) -> dict:
        opaque, assumed, abduced = set(), set(), set()
        for m in self.modules:
            opaque.update(m.opaque_boundaries); assumed.update(m.assumed_contracts)
            for a in m.abduced_pre:
                abduced.add(f"{m.name}: {a}")
        return {"opaque_boundaries": sorted(opaque), "assumed_contracts": sorted(assumed),
                "abduced_preconditions": sorted(abduced)}
    def __str__(self):
        lines = ["ASSUME-GUARANTEE CERTIFICATE (conditional / compositional — NOT a whole-system proof):"]
        for m in self.modules:
            extra = []
            if m.abduced_pre: extra.append(f"abduced-pre={m.abduced_pre}")
            if m.opaque_boundaries: extra.append(f"opaque(monitored,blame)={m.opaque_boundaries}")
            lines.append(f"  · {m.name}: {m.status} {' '.join(extra)}")
        tcb = self.residual_tcb()
        lines.append(f"  residual TCB: opaque={tcb['opaque_boundaries']} "
                     f"assumed={tcb['assumed_contracts']} abduced={tcb['abduced_preconditions']}")
        return "\n".join(lines)


class _Acc:
    def __init__(self):
        self.obligations = []      # [(callee_name, z3 requires-at-call)]
        self.assumptions = []      # [z3 ensures-at-call]  (things we get to assume)
        self.opaque = []           # [callee_name] opaque boundaries hit
        self.assumed_contracts = []


def _var_types(fn):
    vt = {}
    for p in fn.params:
        if isinstance(p.ty, A.TyName) and p.ty.name in ("Float", "Real", "rat"):
            vt[p.name] = "Real"
        else:
            vt[p.name] = "Int"
    return vt


def _enc(e, zenv, real, table, opaque_contracts, acc):
    """Encode a body expression to a Z3 term; module calls become fresh vars + contract obligations/
    assumptions; unknown calls become opaque boundaries. Mirrors z3_adapter._to_z3 for arithmetic."""
    import z3
    if isinstance(e, A.Num):
        return (z3.RealVal(e.value) if (real or e.is_float) else z3.IntVal(int(e.value)))
    if isinstance(e, A.Var):
        if e.name not in zenv:
            raise Z._Unsupported(f"free var {e.name}")
        return zenv[e.name]
    if isinstance(e, A.Un) and e.op == "-":
        return -_enc(e.operand, zenv, real, table, opaque_contracts, acc)
    if isinstance(e, A.Bin):
        l = _enc(e.lhs, zenv, real, table, opaque_contracts, acc)
        r = _enc(e.rhs, zenv, real, table, opaque_contracts, acc)
        if e.op == "+": return l + r
        if e.op == "-": return l - r
        if e.op == "*": return l * r
        raise Z._Unsupported(f"operator {e.op}")
    if isinstance(e, A.Call) and isinstance(e.func, A.Var):
        g = e.func.name
        args = [_enc(a, zenv, real, table, opaque_contracts, acc) for a in e.args]
        ret = z3.FreshReal(g) if real else z3.FreshInt(g)
        if g in table:                                   # known module → assume-guarantee
            callee = table[g]
            env_g = {p.name: at for p, at in zip(callee.params, args)}
            env_g["result"] = ret
            if callee.requires is not None:
                try:
                    acc.obligations.append((g, Z._to_z3(callee.requires, env_g, real)))
                except Z._Unsupported:
                    pass
            if callee.ensures is not None:
                try:
                    ens = Z._to_z3(callee.ensures, env_g, real)
                    acc.assumptions.append(ens)
                    acc.assumed_contracts.append(f"{g}.ensures")
                except Z._Unsupported:
                    pass
            return ret
        # opaque boundary (not in the system)
        acc.opaque.append(g)
        if opaque_contracts and g in opaque_contracts:   # assumed contract → runtime-monitored, blame=g
            try:
                spec = parse(f"fn _c() -> Int\n  ensures {opaque_contracts[g]}\n{{ 0 }}").items[0].ensures
                env_g = {"result": ret}
                for i, at in enumerate(args):
                    env_g[f"arg{i}"] = at
                acc.assumptions.append(Z._to_z3(spec, env_g, real))
                acc.assumed_contracts.append(f"{g}.ensures (runtime-monitored)")
            except Exception:   # noqa: BLE001
                pass
        return ret
    raise Z._Unsupported(type(e).__name__)


def _raise(op):
    raise Z._Unsupported(f"operator {op}")


def _block_return(b):
    if isinstance(b, A.Block) and b.stmts and isinstance(b.stmts[-1], A.ExprStmt):
        return b.stmts[-1].value
    return b


def verify_module(fn, table, opaque_contracts=None) -> ModuleResult:
    import z3
    real = any(t == "Real" for t in _var_types(fn).values())
    zenv = {n: (z3.Real(n) if t == "Real" else z3.Int(n)) for n, t in _var_types(fn).items()}
    try:
        pre = Z._to_z3(fn.requires, zenv, real) if fn.requires is not None else z3.BoolVal(True)
    except Z._Unsupported:
        return ModuleResult(fn.name, "MODULE_UNMODELED", detail="requires not Z3-encodable")
    if fn.ensures is None:
        return ModuleResult(fn.name, "MODULE_UNMODELED", detail="no ensures to verify")
    acc = _Acc()
    try:
        body_term = _enc(_block_return(fn.body), zenv, real, table, opaque_contracts or {}, acc)
        env_post = dict(zenv); env_post["result"] = body_term
        post = Z._to_z3(fn.ensures, env_post, real)
    except Z._Unsupported as e:
        return ModuleResult(fn.name, "MODULE_UNMODELED", detail=f"body/ensures not encodable: {e}")

    # bi-abduction: discharge each callee requires from pre+assumptions; if not, abduce it.
    abduced = []
    for (g, req) in acc.obligations:
        s = z3.Solver(); s.set("timeout", 4000)
        s.add(pre)
        for a in acc.assumptions:
            s.add(a)
        s.add(z3.Not(req))
        if s.check() != z3.unsat:          # cannot prove the callee's precondition from pre → abduce it
            abduced.append((g, req))

    # prove the module's post under pre + abduced-pres + callee assumptions
    s = z3.Solver(); s.set("timeout", 5000)
    s.add(pre)
    for (_, req) in abduced:
        s.add(req)                          # assume the abduced preconditions
    for a in acc.assumptions:
        s.add(a)
    s.add(z3.Not(post))
    r = s.check()
    abduced_names = sorted({f"{g}.requires" for (g, _) in abduced})
    if r == z3.unsat:
        return ModuleResult(fn.name, "MODULE_PROVEN", abduced_pre=abduced_names,
                            assumed_contracts=sorted(set(acc.assumed_contracts)),
                            opaque_boundaries=sorted(set(acc.opaque)))
    if r == z3.sat:
        m = s.model()
        cx = {n: str(m.eval(zenv[n], model_completion=True)) for n in zenv}
        return ModuleResult(fn.name, "MODULE_REFUTED", counterexample=cx,
                            opaque_boundaries=sorted(set(acc.opaque)),
                            detail="ensures not implied by pre + contracts")
    return ModuleResult(fn.name, "MODULE_UNMODELED", detail="Z3 unknown")


def verify_system(sources: List[str], opaque_contracts: Optional[Dict[str, str]] = None) -> SystemCertificate:
    """Verify a system of modules (each a HARAN function source). Returns the assumption-ledger cert."""
    table = {}
    fns = []
    for src in sources:
        prog = parse(src)
        for fn in prog.fns():
            table[fn.name] = fn
            fns.append(fn)
    return SystemCertificate([verify_module(fn, table, opaque_contracts) for fn in fns])


