"""
§3 (STREAM EVERY STEP) — the live CODE process trace: ordered, human-readable phase records.
============================================================================================
The UI must show EVERY step of what CODE is doing, live — not just the final result. This module produces the
ORDERED phase records (the "process") the frontend renders progressively, mirroring MATH mode's
ROUTE / RECOGNIZE / KERNEL / 증명서 transparency. `iter_code_trace` is a GENERATOR: it yields each PhaseEvent as
the REAL work completes (parse → recognize → apply fold/decision → certify → verify → result), so the SSE endpoint
streams them incrementally rather than blocking on the whole run.

★ HONEST (§X) ★: every record reflects the REAL tier, the REAL structure/fold/decision, the REAL proof step, the
REAL budget elapsed, and the REAL grade + certificate — NEVER fabricated progress. The grade shown in the RESULT
record is the engine's actual grade (re-read from its verdict), not a guess; a step that is honestly undecided
says so ("아직 닫히지 않음"), it does not invent progress. extend's budget line shows the BOUNDED ~8 min ("/ 8:00").
"""
from __future__ import annotations

from dataclasses import asdict, dataclass
from typing import Iterator, List, Optional

import mode_budget as MB
from pillar3.mode import Mode

# phase tags (the live process spine — mirrors MATH's ROUTE/RECOGNIZE/KERNEL/증명서)
ANALYZE = "ANALYZE"
RECOGNIZE = "RECOGNIZE"
APPLY = "APPLY"
CERTIFY = "CERTIFY"
VERIFY = "VERIFY"
RESULT = "RESULT"


@dataclass
class PhaseEvent:
    phase: str                       # ANALYZE | RECOGNIZE | APPLY | CERTIFY | VERIFY | RESULT
    message: str                     # human-readable Korean live status
    tier: str                        # fast | normal | extend
    budget: str                      # the live tier+budget line, e.g. 'extend · 0:03 / 8:00'
    detail: str = ""
    grade: Optional[str] = None      # EXACT | PROBABILISTIC | DECLINE — the REAL grade where one exists
    certificate: str = ""            # the REAL certificate text where one exists

    def to_dict(self) -> dict:
        return asdict(self)


def _mode(mode: str) -> Mode:
    return Mode(mode) if mode in (x.value for x in Mode) else Mode.NORMAL


def iter_code_trace(code: str, mode: str = "normal") -> Iterator[PhaseEvent]:
    """Yield the live CODE process records one at a time AS each real step completes (for SSE streaming). Every
    record is derived from real engine/verdict data — no fabricated progress."""
    from webapi import engine_bridge as EB                    # lazy: keep import light
    import structure_recognizer as SR
    import loop_decision as LD

    m = _mode(mode)
    budget = MB.start_budget(m)                               # the live deadline (elapsed/remaining for the UI)

    def ev(phase: str, message: str, **kw) -> PhaseEvent:
        return PhaseEvent(phase, message, m.value, budget.display(), **kw)

    # 1) ANALYZE — parsing, under the chosen tier + its enforced budget
    yield ev(ANALYZE, "분석 중… (코드 파싱)", detail=MB.tier_label(m))

    # 2) RECOGNIZE — real AST waste/structure detection
    detected = EB.detect_in_source(code)
    kinds = ", ".join(sorted({d["waste_type"] for d in detected})) or "없음"
    yield ev(RECOGNIZE, f"구조 인식 중… (낭비/구조 패턴 {len(detected)}건 탐지)", detail=kinds)

    # 3+4) APPLY + CERTIFY — the absorbed MATH decision procedure on a Σ-accumulation loop (§2), surfaced live
    dec = SR.decide_loop(code)
    rc = None
    mc = None
    sd = None                                                # a code-shape dispatch collapse (while/comp/recursion/…)
    if dec is not None:
        if dec.status == "CLOSED_FORM":
            yield ev(APPLY, f"fold 적용 중: 결정 절차로 멱합/누적 루프 접는 중… Σ {dec.summand}",
                     detail=f"닫힌형 = {dec.closed_form} ({dec.complexity})")
            yield ev(CERTIFY, "증명서 생성 중… (차분 등가성 게이트로 닫힌형 검증)",
                     grade=dec.verdict.status, certificate=dec.certificate)
            # §4: MEASURE the O(n) loop → O(1) collapse and stream the Amdahl-honest result (real timing)
            sp_meas = LD.measure_collapse_speedup(dec.summand, dec.var, dec.lo, n=20000, trials=3)
            if sp_meas.status == "MEASURED":
                yield ev(VERIFY, f"속도향상 실측 중… O(n) 루프 → O(1) 닫힌형 (n={sp_meas.n})",
                         detail=f"측정 {sp_meas.ratio:.0f}× · f=1 · Amdahl 천장 이하 · domain-conditional · n에 따라 O(n) 증가",
                         grade=sp_meas.verdict.status, certificate=sp_meas.verdict.certificate.detail)
        elif dec.status == "NO_CLOSED_FORM":
            yield ev(APPLY, f"결정 절차 적용 중: Σ {dec.summand} 의 닫힌형 존재 여부 판정 중…")
            yield ev(CERTIFY, "증명서 생성 중… (Gosper 결정 — 닫힌형 없음 증명; 루프는 기약)",
                     grade=dec.verdict.status, certificate=dec.certificate)
        else:                                                # UNDECIDED — honest, no fabricated progress
            yield ev(APPLY, f"결정 절차: Σ {dec.summand} — 이 클래스 밖이라 판정 보류(정직, 아직 닫히지 않음)",
                     detail=dec.certificate)
    else:
        # §3 (other code-shapes): a nested Σ_iΣ_j, or a counter-while / comprehension / recursion / reduce /
        # filtered fold → an O(1) closed form. Tried BEFORE the recurrence detector (consistent with the optimize
        # RESULT in engine_bridge._loop_collapse), so a polynomial sum surfaces as O(1) — not the O(log n) companion.
        is_nested = False
        try:
            sd = SR.dispatch(code)                            # handles nested + all fold shapes (bounded gate, no hang)
            fn2 = SR._first_fn(code, None)
            is_nested = fn2 is not None and SR._nested_acc(fn2) is not None
        except Exception:                                    # noqa: BLE001 — analysis must never crash the stream
            sd = None
        if sd is not None and sd.status == "OFFLOADED" and sd.closed_form:
            yield ev(APPLY, "코드형태 인식 중: O(n)+ 루프 → O(1) 닫힌형 접는 중… (for/while/comprehension/recursion/reduce/filtered/nested)",
                     detail=f"닫힌형 = {sd.closed_form} ({sd.complexity})")
            yield ev(CERTIFY, "증명서 생성 중… (차분 등가성 게이트로 닫힌형 검증; CAS 제안·실행 게이트가 권위)",
                     grade="EXACT", certificate=sd.certificate)
        elif not is_nested:
            # §4 ceiling-breaker: a C-finite state-update loop (Fibonacci-like) → O(log n) companion collapse. (A
            # recognized nested that did NOT collapse is SKIPPED here — the recurrence detector samples by executing
            # the loop, which could hang on an explosive inner bound; sound + no-hang, matching _loop_collapse.)
            try:
                import loop_recurrence as LR2
                rc = LR2.decide_recurrence_collapse(code, n=20000, trials=2)
                if rc is None or rc.status != "COLLAPSED":     # exact declined → try the genuine-win modular case
                    mc = LR2.decide_modular_recurrence_collapse(code, n=20000, trials=2)
            except Exception:                                # noqa: BLE001 — analysis must never crash the stream
                rc = None
            if rc is not None and rc.status == "COLLAPSED":
                yield ev(APPLY, f"선형 점화식 인식 중: O(n) 상태-갱신 루프 → O(log n) 동반행렬 (order={rc.order}, c={rc.c})")
                _win = "측정 win" if rc.measured_win else "검증됨 (이 n에선 측정 win 아님 — 정직)"
                yield ev(CERTIFY, f"증명서 생성 중… (동반형 ≡ 루프, held-out n 검증) · {rc.ratio:.1f}× {_win}",
                         grade=rc.verdict.status, certificate=rc.verdict.certificate.detail)
            elif mc is not None and mc.status == "COLLAPSED":
                yield ev(APPLY, f"모듈러 선형 점화식 인식 중: O(n) 루프 → O(log n) 동반행렬 mod M (order={mc.order}, c={mc.c})")
                yield ev(CERTIFY, f"증명서 생성 중… (동반형-mod ≡ 루프, wrap된 held-out n 검증) · {mc.ratio:.1f}× 측정 win "
                         f"[경계 정수 ⇒ 진짜 O(log n)]", grade=mc.verdict.status, certificate=mc.verdict.certificate.detail)

    # 5) VERIFY — run the REAL engine UNDER the mode's enforced budget (§1)
    res = EB.run_optimize(code, m.value)
    bd = res.get("budget", {})
    yield ev(VERIFY, "검증 중… (in-house SMT / 차분 등가성으로 원본≡최적화 확인)",
             detail=f"z3_calls={res.get('z3_calls', 0)} · {bd.get('display', budget.display())}")

    # 6) RESULT — the REAL outcome + grade + certificate (never fabricated)
    shipped, declined = res.get("shipped", []), res.get("declined", [])
    if shipped:
        s0 = shipped[0]
        yield ev(RESULT, f"결과: 검증된 수정 {len(shipped)}건 출하 (grade={s0['grade'].upper()})",
                 grade=s0["grade"].upper(),
                 certificate=f"ratio={s0['ratio']} · ceiling={s0.get('ceiling')} (whole-program; Amdahl 천장 이하)")
    elif dec is not None and dec.status == "CLOSED_FORM":
        yield ev(RESULT, f"결과: O(n) 루프 → O(1) 닫힌형 {dec.closed_form} — 증명된 붕괴 (차분 등가성 검증)",
                 grade=dec.verdict.status, certificate=dec.certificate)
    elif sd is not None and sd.status == "OFFLOADED" and sd.closed_form:
        yield ev(RESULT, f"결과: 루프 → O(1) 닫힌형 {sd.closed_form} — 증명된 붕괴 ({sd.complexity}; 차분 등가성 검증)",
                 grade="EXACT", certificate=sd.certificate)
    elif rc is not None and rc.status == "COLLAPSED":
        yield ev(RESULT, f"결과: O(n) 점화식 루프 → O(log n) 동반형 — 증명된 붕괴 (held-out n 검증, {rc.ratio:.1f}×)",
                 grade=rc.verdict.status, certificate=rc.verdict.certificate.detail)
    elif mc is not None and mc.status == "COLLAPSED":
        yield ev(RESULT, f"결과: O(n) 모듈러 점화식 루프 → O(log n) 동반형 mod M — 증명된 붕괴 (wrap된 held-out 검증, "
                 f"{mc.ratio:.1f}×)", grade=mc.verdict.status, certificate=mc.verdict.certificate.detail)
    elif dec is not None and dec.status == "NO_CLOSED_FORM":
        yield ev(RESULT, "결과: 이 루프는 닫힌형이 없음 — PROVEN DECLINE (루프를 그대로 유지)",
                 grade=dec.verdict.status, certificate=dec.certificate)
    elif declined:
        yield ev(RESULT, f"결과: {len(declined)}건 정직한 DECLINE (안전하게 출하할 게 없음)",
                 grade="DECLINE", detail=declined[0]["reason"])
    else:
        yield ev(RESULT, "결과: 검증된 수정 없음 — 정직한 빈 결과", grade="DECLINE")

    # final budget line (so the UI shows the elapsed/bounded budget at completion)
    yield ev(RESULT, f"완료 · {bd.get('display', budget.display())}", detail=f"status={bd.get('status', '')}")


def build_code_trace(code: str, mode: str = "normal") -> List[PhaseEvent]:
    """Materialize the whole ordered trace (for tests / non-streaming callers)."""
    return list(iter_code_trace(code, mode))


def to_sse(events) -> List[str]:
    """Format phase events as SSE `data:` frames (the frontend's existing event channel renders them live)."""
    import json
    return [f"data: {json.dumps(e.to_dict(), ensure_ascii=False)}\n\n" for e in events]


# ==============================================================================================================
# ===== FILE: compressed_sensing.py  (95 lines) =====
# ==============================================================================================================

"""
v37 STAGE 1.3 — compressed sensing + Fuchs DUAL CERTIFICATE (the flagship per-instance witness).
=================================================================================================
Recover a k-sparse N-vector x from m=O(k log(N/k)) linear measurements y=Ax. The recovery SOLVER is
UNTRUSTED (here: numpy OMP — cvxpy basis-pursuit is [BLOCKED]); what makes the result EXACT is a per-instance
DUAL CERTIFICATE, not a uniform property.

★ NEVER verify RIP (§1.7) — it is NP-hard. ★ Instead the Fuchs/KKT optimality witness on the recovered support
S: x is the UNIQUE ℓ1-minimizer ⟺ the dual v = Aᵀ A_S (A_Sᵀ A_S)⁻¹ sign(x_S) satisfies
  (i)  v_S = sign(x_S)              (by construction; verified)
  (ii) ‖v_{Sᶜ}‖_∞ < 1               (STRICT, with margin)
  (iii) A_S has full column rank
All strict ⇒ EXACT (unique exact recovery certified for THIS instance, by ℓ1 strong duality). Any failure /
no margin ⇒ DECLINE. The check is O(mN) ≪ the combinatorial search; it is a per-instance optimality witness.
"""
from __future__ import annotations

import numpy as np

import sublinear_layer as SL


def _omp(A: np.ndarray, y: np.ndarray, k: int, tol: float = 1e-10):
    """Orthogonal matching pursuit: greedy support recovery (the UNTRUSTED solver). Returns (support, x_S)."""
    m, N = A.shape
    residual = y.astype(float).copy()
    support: list = []
    xs = np.zeros(0)
    for _ in range(min(k, m)):
        corr = np.abs(A.T @ residual)
        corr[support] = -1.0
        j = int(np.argmax(corr))
        support.append(j)
        As = A[:, support]
        xs, *_ = np.linalg.lstsq(As, y, rcond=None)
        residual = y - As @ xs
        if np.linalg.norm(residual) < tol:
            break
    return support, xs


def recover(data, k: int = None, margin: float = 1e-6) -> SL.SublinearVerdict:
    """`data` = (A, y) with y = A x for some k-sparse x. OMP recovers the support; the Fuchs dual certificate
    certifies (or refutes) UNIQUE exact recovery for this instance → EXACT or DECLINE."""
    A, y = np.asarray(data[0], dtype=float), np.asarray(data[1], dtype=float)
    m, N = A.shape
    k = k or max(1, m // 4)
    support, xs = _omp(A, y, k)
    if not support:
        return SL.decline("OMP recovered empty support", "compressed_sensing")
    # reconstruct + measurement residual (the recovered x must explain y)
    As = A[:, support]
    resid = float(np.linalg.norm(y - As @ xs))
    if resid > 1e-6 * (np.linalg.norm(y) + 1e-30):
        return SL.decline(f"recovery does not explain the measurements (residual {resid:.2e}) ⇒ DECLINE", "compressed_sensing")
    # (iii) A_S full column rank
    sv = np.linalg.svd(As, compute_uv=False)
    if sv.min() <= 1e-9:
        return SL.decline("A_S rank-deficient — no unique-recovery certificate", "compressed_sensing")
    # ★ build the Fuchs dual certificate v = Aᵀ A_S (A_Sᵀ A_S)⁻¹ sign(x_S) ★
    sgn = np.sign(xs)
    G = As.T @ As
    v = A.T @ (As @ np.linalg.solve(G, sgn))
    # (i) v_S = sign(x_S) by construction (verify it holds numerically)
    i_ok = np.allclose(v[support], sgn, atol=1e-7)
    # (ii) STRICT ‖v_{Sᶜ}‖_∞ < 1 (with margin)
    mask = np.ones(N, dtype=bool); mask[support] = False
    off_max = float(np.max(np.abs(v[mask]))) if mask.any() else 0.0
    if not i_ok:
        return SL.decline("dual v_S != sign(x_S) — no Fuchs certificate", "compressed_sensing")
    if off_max >= 1.0 - margin:
        return SL.decline(f"‖v_Sᶜ‖_∞={off_max:.4f} not strictly < 1 (no margin) — NOT certified unique ⇒ DECLINE",
                          "compressed_sensing")
    x = np.zeros(N); x[support] = xs
    cert = SL.Certificate(grade=SL.EXACT, kind="dual_cert", passed=True,
                          check_cost=f"O(m·N)=O({m}·{N}) — per-instance Fuchs witness (NOT RIP)",
                          bound=off_max,
                          detail=f"Fuchs: v_S=sign(x_S) ✓, ‖v_Sᶜ‖∞={off_max:.4f}<1 (margin {1-off_max:.4f}), "
                                 f"A_S full-rank ✓ ⇒ x is the UNIQUE ℓ1 minimizer (exact recovery certified)")
    return SL.SublinearVerdict(SL.EXACT, {"x": x, "support": support, "k": len(support)}, "compressed_sensing",
                              f"m=O(k log(N/k)), m={m}, N={N}, k={len(support)}", cert)


SL.register("sparse_recovery", recover)


def make_instance(N: int, k: int, m: int, seed: int = 0):
    """A random k-sparse instance: x (k-sparse), Gaussian A (m×N), y=Ax."""
    rng = np.random.default_rng(seed)
    x = np.zeros(N)
    supp = rng.choice(N, size=k, replace=False)
    x[supp] = rng.choice([-1.0, 1.0], size=k) * rng.uniform(1, 5, size=k)
    A = rng.standard_normal((m, N)) / np.sqrt(m)
    return A, A @ x, x


# ==============================================================================================================
# ===== FILE: concretization_gate.py  (119 lines) =====
# ==============================================================================================================

"""
v28 STAGE 24 — spurious-counterexample concretization gate (CEGAR).  ★protects working code★
============================================================================================
The most DANGEROUS failure mode: an over-approximate abstraction reports a "counterexample" that does not
actually occur at runtime, and a fix loop then MANGLES correct code to chase a bug that was never real.
This gate stops that: BEFORE any edit, the abstract counterexample is RUN ON THE REAL RUNTIME.

  • reproduced on the real runtime  → REAL_BUG  (enter the fix loop)
  • NOT reproduced                  → SPURIOUS  (refine the abstraction to exclude it; ★DO NOT edit the code★)
  • refinement budget exhausted     → DEFER     (honest — never loops forever)

Plus a regression guard: any proposed fix that breaks a previously-passing test is ROLLED BACK — a
hallucinated fix can never silently destroy working behavior.

★ HONEST (§1.4, §5.6) ★: CEGAR FILTERS spurious counterexamples; it does not make abstraction free —
precision ↔ speed is a real trade-off (a more precise domain is slower), and each concretization costs a
real execution. We never claim to decide the undecidable — on budget exhaustion we DEFER.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Callable, Dict, List, Optional, Tuple

CounterExample = Dict[str, object]                 # concrete input, e.g. {"a": 1, "b": 0}
ProposeFn = Callable[[set], Optional[CounterExample]]   # abstract analyzer: next cex not in `excluded`
ViolationFn = Callable[[CounterExample, object, Optional[BaseException]], bool]   # is this a real violation?


def _freeze(cex: CounterExample):
    return frozenset(cex.items())


@dataclass
class ConcResult:
    reproduced: bool
    observed: object = None
    exc: Optional[str] = None


def concretize(fn: Callable, cex: CounterExample, is_violation: ViolationFn) -> ConcResult:
    """Run `fn` on the concrete counterexample and decide whether the violation ACTUALLY occurs."""
    try:
        out = fn(**cex)
        return ConcResult(is_violation(cex, out, None), out, None)
    except BaseException as e:  # noqa: BLE001 — a runtime crash IS an observable failure to judge
        return ConcResult(is_violation(cex, None, e), None, type(e).__name__)


@dataclass
class CegarVerdict:
    status: str                 # REAL_BUG | NO_BUG | DEFER
    counterexample: Optional[CounterExample] = None
    observed: object = None
    spurious: List[CounterExample] = field(default_factory=list)
    refinements: int = 0
    detail: str = ""

    def __str__(self):
        if self.status == "REAL_BUG":
            return f"REAL_BUG at {self.counterexample} (reproduced on the real runtime) → fix"
        if self.status == "NO_BUG":
            return f"NO_BUG ({len(self.spurious)} spurious counterexample(s) filtered — code NOT edited)"
        return f"DEFER — {self.detail}"


def cegar(propose: ProposeFn, fn: Callable, is_violation: ViolationFn, max_refine: int = 12) -> CegarVerdict:
    """The CEGAR loop: get an abstract counterexample, CONCRETIZE it; real → REAL_BUG; spurious → refine
    (exclude) and retry; no more counterexamples → NO_BUG; budget exhausted → DEFER (never loops forever)."""
    excluded: set = set()
    spurious: List[CounterExample] = []
    for i in range(max_refine + 1):
        cex = propose(excluded)
        if cex is None:
            return CegarVerdict("NO_BUG", spurious=spurious, refinements=i,
                                detail="abstraction reports no (further) counterexample")
        c = concretize(fn, cex, is_violation)
        if c.reproduced:
            return CegarVerdict("REAL_BUG", cex, c.observed, spurious, i, "reproduced on the real runtime")
        spurious.append(cex)            # ★ SPURIOUS: refine, DO NOT edit the code ★
        excluded.add(_freeze(cex))
    return CegarVerdict("DEFER", spurious=spurious, refinements=max_refine,
                        detail=f"refinement budget ({max_refine}) exhausted — deferred (no hang, no edit)")


# ── regression guard: a fix that breaks a passing test is ROLLED BACK ───────────────────────────────
@dataclass
class FixOutcome:
    status: str                 # APPLIED | ROLLBACK
    fn: Callable = None
    broke: List = field(default_factory=list)
    detail: str = ""


def _passes(fn: Callable, inp: CounterExample, expected) -> bool:
    try:
        return fn(**inp) == expected
    except BaseException:  # noqa: BLE001
        return False


def apply_fix_guarded(orig_fn: Callable, fixed_fn: Callable,
                      tests: List[Tuple[CounterExample, object]]) -> FixOutcome:
    """Apply `fixed_fn` only if it breaks NO test that `orig_fn` passed; otherwise ROLL BACK to orig."""
    broke = [inp for inp, exp in tests if _passes(orig_fn, inp, exp) and not _passes(fixed_fn, inp, exp)]
    if broke:
        return FixOutcome("ROLLBACK", orig_fn, broke,
                          "fix broke previously-passing test(s) — rolled back (no hallucinated regression)")
    return FixOutcome("APPLIED", fixed_fn, [], "fix preserves all previously-passing tests")


def from_candidates(candidates: List[CounterExample]) -> ProposeFn:
    """Build an abstract analyzer that proposes each candidate counterexample once (skipping excluded)."""
    def propose(excluded: set) -> Optional[CounterExample]:
        for c in candidates:
            if _freeze(c) not in excluded:
                return c
        return None
    return propose


