# ===== FILE: cost_control.py  (97 lines) =====
# ==============================================================================================================

"""
PHASE 3.S3 — LLM cost control: cacheable static prefix + best-of-N with verifier early-exit.
=============================================================================================
Two structural levers that cut LLM cost WITHOUT touching soundness (the verifier is still the gate):
  • prompt-cache prefix: the STATIC context (system prompt, spec, broth rules) is placed FIRST as a stable,
    cacheable prefix; only the volatile tail (this code + its counterexample) changes per call. A cache HIT
    bills the prefix at ~0.1×. effective = tail + 0.1·prefix.
  • best-of-N + early-exit: generate candidates in parallel but STOP at the first one the SOUND verifier
    accepts (the rest are cancelled). The exact verifier is the cost ceiling — no reward-model, no waste.

★ ENV HONESTY: live LLM token cost/latency needs an API key + egress → [BLOCKED]. We therefore measure the
STRUCTURAL savings from token counts (a word-count PROXY — no live tokenizer), not a live bill. Stated. ★
"""
from __future__ import annotations

from dataclasses import dataclass
from typing import Callable, List, Optional, Tuple


def approx_tokens(text: str) -> int:
    """A coarse token PROXY (≈ words + punctuation/4). NOT a real tokenizer (none here) — labeled as a proxy."""
    return max(1, len(text.split()) + len(text) // 4)


@dataclass
class CachePlan:
    prefix_tokens: int
    tail_tokens: int
    cold_tokens: int
    warm_tokens: float          # with a prefix cache hit (~0.1× prefix)
    savings: float              # 1 - warm/cold

    def __str__(self):
        return f"cache prefix {self.prefix_tokens}t + tail {self.tail_tokens}t: cold {self.cold_tokens} → warm "\
               f"{self.warm_tokens:.0f} ({self.savings:.0%} saved on a cache hit)"


def plan_with_cache_prefix(static_ctx: str, volatile_tail: str, hit_factor: float = 0.1) -> CachePlan:
    """Place the static context as a cacheable prefix; the volatile tail changes per call. Returns the
    cold vs warm (cache-hit) token cost. hit_factor is the provider's cached-prefix discount (~0.1×)."""
    p, t = approx_tokens(static_ctx), approx_tokens(volatile_tail)
    cold = p + t
    warm = hit_factor * p + t
    return CachePlan(p, t, cold, warm, round(1 - warm / cold, 3) if cold else 0.0)


@dataclass
class BestOfNCost:
    n: int
    p_pass: float
    expected_candidates: float  # expected #generations until the first verifier-PASS (early-exit)
    tokens_per_cand: int
    expected_tokens: float
    naive_tokens: int           # if we generated all N
    savings: float

    def __str__(self):
        return f"best-of-{self.n} @p={self.p_pass}: E[cands]={self.expected_candidates:.2f} → "\
               f"{self.expected_tokens:.0f}t vs {self.naive_tokens}t ({self.savings:.0%} saved by early-exit)"


def best_of_n_cost(n: int, p_pass: float, tokens_per_cand: int) -> BestOfNCost:
    """Expected generation cost with verifier EARLY-EXIT: stop at the first PASS. E[#generated until first
    success in N tries] under independent pass-prob p (capped at N). The SOUND verifier bounds the cost."""
    # E[min(geom(p), N)] = Σ_{i=1..N} P(no pass in first i-1) = Σ_{i=0..N-1} (1-p)^i
    q = 1 - p_pass
    exp_cands = sum(q ** i for i in range(n)) if p_pass > 0 else n
    expected_tokens = exp_cands * tokens_per_cand
    naive = n * tokens_per_cand
    return BestOfNCost(n, p_pass, round(exp_cands, 3), tokens_per_cand, round(expected_tokens, 1), naive,
                       round(1 - expected_tokens / naive, 3) if naive else 0.0)


@dataclass
class CostReport:
    cache: CachePlan
    best_of_n: BestOfNCost
    live_llm: str

    def combined_factor(self) -> float:
        """Illustrative combined cost factor (cache warm × best-of-N early-exit), per the proxy model."""
        return round((self.cache.warm_tokens / self.cache.cold_tokens) *
                     (self.best_of_n.expected_tokens / self.best_of_n.naive_tokens), 3)


def measure_cost(static_ctx: Optional[str] = None, tail: Optional[str] = None,
                 n: int = 6, p_pass: float = 0.5) -> CostReport:
    """Structural LLM-cost measurement (proxy tokens). Live billing is [BLOCKED: key/egress]."""
    static_ctx = static_ctx or ("SYSTEM: verify code against spec. SPEC: ensures result = sum 1..n. "
                                 "BROTH RULES: faulhaber, c-finite, gosper, telescoping. " * 20)
    tail = tail or "USER: fn f(n: Nat){ fold k in 1..n { k } }  COUNTEREXAMPLE: n=1 -> 2 != 1"
    cache = plan_with_cache_prefix(static_ctx, tail)
    bon = best_of_n_cost(n, p_pass, tokens_per_cand=approx_tokens(tail) + 40)
    return CostReport(cache, bon,
                      "[BLOCKED: live LLM token cost needs an API key + egress; structural savings measured "
                      "from a token PROXY, not a live bill]")


# ==============================================================================================================
# ===== FILE: cp_decompose.py  (76 lines) =====
# ==============================================================================================================

"""
HARAN #25 (Group B) — exact CP (CANDECOMP/PARAFAC) tensor decomposition for the EXACT-DECIDABLE case.
=====================================================================================================
A CP decomposition writes a tensor as a sum of rank-1 terms. General CP rank is NP-hard, so the HONEST exact
scope is the rank-1 (and rank-0) case over ℚ, which IS exactly decidable and certifiable: a 3-way tensor T is
rank-1 iff T[i][j][k] = a_i·b_j·c_k for some vectors a,b,c — recovered from one nonzero "pivot" fibre and then
RE-COMPOSED and checked entry-by-entry exactly. Higher CP rank ⇒ honest DECLINE (we never fake an exact
decomposition where deciding the rank is NP-hard; that is certified-numeric territory, not EXACT). The certificate
is re-composition equality: Σ (rank-1 terms) ≡ T over ℚ.
"""
from __future__ import annotations

from fractions import Fraction as Fr
from typing import List

import kernel_verdict as KV


def _f3(T):
    return [[[x if isinstance(x, Fr) else Fr(x) for x in row] for row in mat] for mat in T]


def _outer(a, b, c):
    return [[[a[i] * b[j] * c[k] for k in range(len(c))] for j in range(len(b))] for i in range(len(a))]


def cp_rank1(T):
    """If the 3-way tensor T is rank-1 over ℚ, return (a,b,c) with T = a⊗b⊗c; else None. Recover from a nonzero
    pivot (i0,j0,k0): a_i=T[i,j0,k0], b_j=T[i0,j,k0], c_k=T[i0,j0,k]/p² (p=T[i0,j0,k0]); then VERIFY exactly."""
    T = _f3(T)
    I, J, K = len(T), len(T[0]), len(T[0][0])
    piv = None
    for i in range(I):
        for j in range(J):
            for k in range(K):
                if T[i][j][k] != 0:
                    piv = (i, j, k)
                    break
            if piv:
                break
        if piv:
            break
    if piv is None:
        return ([Fr(0)] * I, [Fr(0)] * J, [Fr(0)] * K)       # the zero tensor (rank 0)
    i0, j0, k0 = piv
    p = T[i0][j0][k0]
    a = [T[i][j0][k0] for i in range(I)]
    b = [T[i0][j][k0] for j in range(J)]
    c = [T[i0][j0][k] / (p * p) for k in range(K)]           # normalization so a⊗b⊗c reproduces T at the pivot
    return (a, b, c) if _outer(a, b, c) == T else None


def cp_decompose_grade(T) -> KV.Verdict:
    """Exact CP decomposition of a 3-way tensor over ℚ. EXACT iff T is rank ≤ 1 (recovered factors RE-COMPOSE to T
    exactly — a re-checkable certificate). Higher CP rank ⇒ honest DECLINE (exact CP rank is NP-hard; that case is
    certified-numeric, never a faked EXACT). Malformed (non-rectangular) input ⇒ DECLINE."""
    try:
        T = _f3(T)
        I, J, K = len(T), len(T[0]), len(T[0][0])
        if any(len(m) != J for m in T) or any(len(r) != K for m in T for r in m):
            return KV.decline("cp_decompose: non-rectangular tensor ⇒ DECLINE", "cp_decompose")
    except (TypeError, IndexError, ValueError):
        return KV.decline("cp_decompose: malformed 3-way tensor ⇒ DECLINE", "cp_decompose")
    fac = cp_rank1(T)
    if fac is None:
        return KV.decline("cp_decompose: tensor is not rank ≤ 1 ⇒ DECLINE (general CP rank is NP-hard — exact "
                          "decomposition beyond rank-1 is certified-numeric, not EXACT)", "cp_decompose")
    a, b, c = fac
    rank = 0 if all(x == 0 for x in a) else 1
    if _outer(a, b, c) != T:                                  # ★ re-composition certificate, re-checked ★
        return KV.decline("cp_decompose: re-composition ≠ T ⇒ DECLINE (bug guard)", "cp_decompose")
    cert = KV.Cert(KV.EXACT, "cp_recomposition", passed=True, check_cost="O(IJK) re-composition equality",
                   detail=f"rank-{rank} CP over ℚ: T = a⊗b⊗c with a={a}, b={b}, c={c} — Σ rank-1 terms ≡ T "
                          f"(verified entry-by-entry)")
    return KV.exact({"rank": rank, "factors": (a, b, c)}, "cp_decompose", "exact CP (rank ≤ 1)", cert)


# ==============================================================================================================
# ===== FILE: ct_certifier.py  (219 lines) =====
# ==============================================================================================================

"""
v26 STAGE 1 — constant-time / secret-taint certifier (HARAN-IR level, 2-safety taint). ★FLAGSHIP★
=================================================================================================
The differentiated capability: an LLM can only *guess* that code is secret-independent; it cannot
*prove* it. This emits a machine certificate — CT_PROVEN — or a concrete leak counterexample. General,
domain-agnostic: a value labeled `secret` (a key, token, password — anything) must not influence

  (a) a BRANCH condition         (match on secret → control-flow timing leak)
  (b) a MEMORY access index      (table/array indexed by secret → cache-timing leak)
  (c) a VARIABLE-TIME operation  (`/` or `%` with a secret operand — the KyberSlash *class* of bug:
                                  secret-dependent division leaks via timing; this is NOT a claim
                                  that this project implements Kyber — it's the canonical example)
  (d) a LOOP TRIP COUNT          (fold over a secret-dependent range → secret iteration count)

Labels: mark secrets via `requires secret(x)` in the HARAN spec, or pass `secrets={"x", ...}`.

★ HONEST LEVEL LABELING (non-negotiable) ★: this proves constant-timeness at the **HARAN-IR level**.
It does NOT cover binary-level leaks a COMPILER may introduce (Binsec/Rel showed gcc/clang passes inject
CT violations into source-safe code). The certificate says exactly this; never claim binary CT here.

Soundness stance: CT_PROVEN is emitted ONLY when the whole function was modeled and no secret reaches a
leak site. Any unmodeled construct → UNMODELED (we do NOT claim proven). A leak → CT_VIOLATION with the
exact construct + line (a concrete counterexample the write→verify→fix loop feeds back to the model).
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import List, Optional, Set

import haran_ast as A
from haran_parser import parse

# operations whose latency is classically data-dependent (constant-time code must avoid these on secrets)
_VARTIME_OPS = {"/", "%"}
# memory-access style calls: a secret in an INDEX position (any arg after the collection) is a leak.
# (HARAN has no subscript node; table/array access is modeled via these configurable function names.)
_INDEX_FNS = {"get", "at", "nth", "index", "lookup", "table", "select", "load", "fetch"}


@dataclass
class CTVerdict:
    status: str                       # CT_PROVEN | CT_VIOLATION | UNMODELED | NO_SECRETS | PARSE_ERROR | NONE
    secrets: List[str] = field(default_factory=list)
    leaks: List[dict] = field(default_factory=list)     # [{kind, line, detail}]
    unmodeled: List[str] = field(default_factory=list)
    level: str = "HARAN-IR"
    detail: str = ""

    def proven(self) -> bool:
        return self.status == "CT_PROVEN"

    def certificate(self) -> str:
        if self.status == "CT_PROVEN":
            return (f"CT-CERT: constant-time PROVEN at {self.level} level for secrets {self.secrets} — "
                    f"no secret-dependent branch / memory index / variable-time op / loop bound. "
                    f"★ binary-level NOT covered (a compiler may introduce leaks — Binsec/Rel).")
        if self.status == "CT_VIOLATION":
            first = self.leaks[0]
            return (f"CT-VIOLATION ({len(self.leaks)} leak(s)) at {self.level} level; first: line "
                    f"{first['line']}: {first['detail']}")
        return f"{self.status} — {self.detail}"

    def __str__(self):
        return self.certificate()


def _pattern_vars(pat) -> Set[str]:
    """Variable names a pattern binds (these inherit the scrutinee's taint)."""
    out: Set[str] = set()
    if isinstance(pat, A.PVar):
        out.add(pat.name)
    elif isinstance(pat, A.PCons):
        out |= _pattern_vars(pat.head) | _pattern_vars(pat.tail)
    elif isinstance(pat, A.PList):
        for e in pat.elems:
            out |= _pattern_vars(e)
    elif isinstance(pat, A.PCtor):
        for a in pat.args:
            out |= _pattern_vars(a)
    return out


class _Analyzer:
    def __init__(self):
        self.leaks: List[dict] = []
        self.unmodeled: List[str] = []

    def _leak(self, kind: str, node, detail: str):
        self.leaks.append({"kind": kind, "line": getattr(getattr(node, "span", None), "line", 0),
                           "detail": detail})

    def visit(self, n, env: Set[str]) -> bool:
        """Walk node `n`; record any leaks; return True iff the node's VALUE is secret-tainted.
        `env` is the set of secret-tainted variable names in scope (mutated by Let within a Block)."""
        if n is None:
            return False
        if isinstance(n, (A.Num, A.BoolLit)):
            return False
        if isinstance(n, A.Var):
            return n.name in env
        if isinstance(n, A.Un):
            return self.visit(n.operand, env)
        if isinstance(n, A.Bin):
            ls = self.visit(n.lhs, env)
            rs = self.visit(n.rhs, env)
            if n.op in _VARTIME_OPS and (ls or rs):
                self._leak("var_time_op", n, f"variable-time op '{n.op}' on a secret-dependent operand "
                           f"(data-dependent timing — the KyberSlash *class* of leak)")
            return ls or rs
        if isinstance(n, A.Call):
            fname = n.func.name if isinstance(n.func, A.Var) else None
            arg_secret = [self.visit(a, env) for a in n.args]
            if fname in _INDEX_FNS and len(arg_secret) >= 2 and any(arg_secret[1:]):
                self._leak("mem_index", n, f"memory access '{fname}(...)' indexed by a secret-dependent "
                           f"value (table/cache-timing leak — use a constant-time scan)")
            return any(arg_secret)
        if isinstance(n, A.Match):
            sc = self.visit(n.scrut, env)
            if sc:
                self._leak("branch", n, "secret-dependent branch — `match` on a secret-tainted value "
                           "(control-flow timing leak; use arithmetic select / masking)")
            any_arm = False
            for arm in n.arms:
                child = set(env)
                if sc:
                    child |= _pattern_vars(arm.pattern)   # vars from a secret scrutinee are secret
                any_arm = self.visit(arm.body, child) or any_arm
            return sc or any_arm
        if isinstance(n, A.Fold):
            if isinstance(n.domain, A.Range):
                if self.visit(n.domain.lo, env) or self.visit(n.domain.hi, env):
                    self._leak("secret_loop_bound", n, "fold over a secret-dependent range — secret "
                               "iteration count (timing leak; iterate a fixed public range)")
            else:
                self.visit(n.domain, env)
            return self.visit(n.body, set(env))           # binder ranges over a public domain
        if isinstance(n, A.Block):
            child = set(env)
            last = False
            for st in n.stmts:
                last = self.visit(st, child)
            return last
        if isinstance(n, A.Let):
            if self.visit(n.value, env):
                env.add(n.name)                            # block-scoped taint binding
            return False
        if isinstance(n, A.ExprStmt):
            return self.visit(n.value, env)
        if isinstance(n, A.Range):
            return self.visit(n.lo, env) or self.visit(n.hi, env)
        if isinstance(n, A.ListLit):
            return any(self.visit(e, env) for e in n.elems)
        if isinstance(n, A.Quant):
            return self.visit(n.body, env)
        if isinstance(n, A.Lambda):
            return self.visit(n.body, env)
        # a construct we don't model — record it so we never claim CT_PROVEN over unknown control/data flow
        self.unmodeled.append(type(n).__name__)
        return False


def _collect_secrets(fn, secrets: Optional[Set[str]]) -> Set[str]:
    """Secrets = explicit `secrets` arg ∪ every `secret(param)` marker in the `requires` clause."""
    out: Set[str] = set(secrets or ())
    def walk(e):
        if isinstance(e, A.Call) and isinstance(e.func, A.Var) and e.func.name == "secret":
            for a in e.args:
                if isinstance(a, A.Var):
                    out.add(a.name)
        if isinstance(e, A.Bin):
            walk(e.lhs); walk(e.rhs)
        elif isinstance(e, A.Un):
            walk(e.operand)
    if fn.requires is not None:
        walk(fn.requires)
    return out


def certify_ct(code: str, secrets: Optional[Set[str]] = None) -> CTVerdict:
    """Certify constant-timeness of one HARAN function (HARAN-IR level). See module docstring."""
    prog = parse(code)
    if prog.errors:
        return CTVerdict("PARSE_ERROR", detail=str(prog.errors[0]))
    fns = prog.fns()
    if not fns:
        return CTVerdict("NONE", detail="no function found")
    fn = fns[0]
    sec = _collect_secrets(fn, secrets)
    if not sec:
        return CTVerdict("NO_SECRETS", detail="no secret-labeled inputs — mark with `requires secret(x)` "
                         "or pass secrets={...}; nothing to certify")
    an = _Analyzer()
    an.visit(fn.body, set(sec))
    secs = sorted(sec)
    if an.leaks:
        return CTVerdict("CT_VIOLATION", secrets=secs, leaks=an.leaks, unmodeled=an.unmodeled)
    if an.unmodeled:
        return CTVerdict("UNMODELED", secrets=secs, unmodeled=sorted(set(an.unmodeled)),
                         detail=f"unmodeled constructs {sorted(set(an.unmodeled))} — not claiming CT_PROVEN")
    return CTVerdict("CT_PROVEN", secrets=secs)


def ct_feedback(v: CTVerdict) -> str:
    """Concrete counterexample → fix instruction for the write→verify→fix loop (precise, not vague)."""
    if v.status != "CT_VIOLATION" or not v.leaks:
        return ""
    f = v.leaks[0]
    hints = {
        "branch": "replace the secret-dependent `match` with a constant-time arithmetic select/mask "
                  "(compute both arms, select with a 0/1 secret mask).",
        "var_time_op": "remove the secret-dependent `/`/`%` — use Montgomery/Barrett reduction or a "
                       "constant-time routine instead of hardware division.",
        "mem_index": "replace the secret-indexed lookup with a constant-time linear scan over the table.",
        "secret_loop_bound": "iterate a FIXED public range; do not let a secret determine the trip count.",
    }
    return (f"CONSTANT-TIME VIOLATION at line {f['line']}: {f['detail']}. "
            f"Fix: {hints.get(f['kind'], 'make the secret-dependent operation constant-time')} "
            f"Return the corrected constant-time HARAN function only.")


# ==============================================================================================================
# ===== FILE: dangerous_instruction_detector.py  (160 lines) =====
# ==============================================================================================================

"""
v29 STAGE 28 — dangerous / contradictory / infeasible instruction detector.  ★safety; breaks GIGO★
====================================================================================================
Most systems faithfully implement a bad instruction. We don't: a dangerous, self-contradictory, or
infeasible instruction is FLAGGED with a safe alternative instead of being silently obeyed — the heart of
breaking garbage-in-garbage-out.

Two bases, clearly labeled:
  • danger lexicon (HEURISTIC) — a small CWE-mapped pattern catalog (TLS-verify-off, rm -rf /, plaintext
    passwords, eval/exec, pickle.loads, shell=True, AES-ECB, hardcoded secrets…). Each hit → FLAG + a safe
    alternative + the CWE. ★Never a heuristic-only HARD BLOCK — flag + alternative; the user decides.★
  • contradiction / infeasibility (SOUND) — numeric/ordering constraints are formalized and checked with
    Z3; UNSAT ⇒ a real contradiction (a proof, not a guess).

★ HONEST (§1.4, §1.5, §5.5) ★: "dangerous" is undecidable in general — we cover an ENUMERATED catalog
(measured coverage), everything else degrades gracefully (SAFE-by-default, not a false alarm). Only the
FORMALIZED contradiction is sound (Z3 UNSAT); lexicon flags are heuristic and never block.
"""
from __future__ import annotations

import re
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple

import z3

# ── danger lexicon → (CWE, kind, safe alternative). Heuristic: FLAG + alternative, never hard-block. ──
_DANGER: List[Tuple[str, str, str, str]] = [
    (r"verify\s*=\s*false|insecure_?skip_?verify|ssl[_ ]?verify\s*=\s*false|disable[^\n]{0,15}(tls|ssl|cert)",
     "CWE-295", "TLS/certificate verification disabled",
     "keep certificate verification ON; pin a cert or use a trusted CA bundle"),
    (r"rm\s+-rf\s+/(?:\s|$)|shutil\.rmtree\(\s*['\"]?/",
     "destructive", "unbounded filesystem deletion",
     "scope deletion to a specific subdirectory; never the filesystem root"),
    (r"plain\s*text\s*password|store[^\n]{0,20}password[^\n]{0,20}(plain|clear)|password[^\n]{0,10}in\s+clear",
     "CWE-256/319", "passwords stored in plaintext",
     "hash passwords with a slow KDF (Argon2/bcrypt/scrypt), never store plaintext"),
    (r"(md5|sha1)[^\n]{0,20}password|password[^\n]{0,20}(md5|sha1)",
     "CWE-327/916", "fast/broken hash for passwords",
     "use Argon2/bcrypt for passwords (SHA-256+ is for integrity, not password storage)"),
    (r"\beval\s*\(|\bexec\s*\(",
     "CWE-95", "eval/exec of (possibly untrusted) input",
     "parse explicitly or use ast.literal_eval; never eval/exec untrusted input"),
    (r"pickle\.loads|yaml\.load\s*\((?![^)]*Loader)",
     "CWE-502", "deserializing untrusted data",
     "use json or yaml.safe_load; never unpickle/yaml.load untrusted bytes"),
    (r"shell\s*=\s*true",
     "CWE-78", "shell=True (command-injection risk)",
     "pass an argument list with shell=False; never interpolate user input into a shell string"),
    (r"\becb\b|ecb[_ ]?mode|mode\s*=\s*['\"]?ecb",
     "CWE-327", "AES-ECB (leaks plaintext structure)",
     "use an authenticated mode (AES-GCM); never ECB"),
    (r"(api[_-]?key|secret|password|token)\s*=\s*['\"][A-Za-z0-9_\-]{8,}['\"]",
     "CWE-798", "hardcoded secret/credential",
     "load secrets from env/secret-manager; never hardcode credentials in source"),
]
_DANGER_RE = [(re.compile(p, re.IGNORECASE), cwe, kind, alt) for (p, cwe, kind, alt) in _DANGER]

# known-infeasible combinations (HEURISTIC catalog → flag, not block)
_INFEASIBLE = [
    (("o(1)", "sort"), "O(1)-time sort of arbitrary data is impossible (Ω(n log n) comparison lower bound)",
     "target O(n log n); use O(n) counting/radix only when the key domain is bounded"),
    (("o(1)", "search") , "O(1) search of UNSORTED data is impossible (must inspect Ω(n))",
     "index/sort first (amortize), or accept O(n) for a single unsorted scan"),
]


@dataclass
class Flag:
    kind: str                   # danger | contradiction | infeasible
    basis: str                  # heuristic-lexicon | heuristic-catalog | sound-UNSAT
    evidence: str
    alternative: str
    cwe: str = ""


@dataclass
class DangerReport:
    status: str                 # SAFE | FLAGGED
    flags: List[Flag] = field(default_factory=list)

    @property
    def hard_block(self) -> bool:
        return False             # ★ this detector NEVER hard-blocks — it flags + proposes ★

    def __str__(self):
        if self.status == "SAFE":
            return "SAFE — no dangerous/contradictory/infeasible instruction detected (catalog-bounded)"
        return "FLAGGED:\n  " + "\n  ".join(f"[{f.basis}] {f.kind} ({f.cwe or '-'}): {f.evidence} → {f.alternative}"
                                            for f in self.flags)


# ── contradiction / infeasibility (SOUND, via Z3) ──────────────────────────────────────────────────
_OP = {"<": "<", ">": ">", "<=": "<=", ">=": ">=", "less than": "<", "greater than": ">",
       "at most": "<=", "at least": ">=", "under": "<", "over": ">", "below": "<", "above": ">",
       "no more than": "<=", "no less than": ">="}
_STOP = {"the", "a", "an", "must", "be", "should", "is", "of", "its", "it", "this", "value"}
_BOUND = re.compile(
    r"([a-zA-Z][a-zA-Z ]{0,24}?)\s*(?:must be|should be|be|is)?\s*"
    r"(<=|>=|<|>|less than|greater than|at most|at least|no more than|no less than|under|over|below|above)\s*(\d+)",
    re.IGNORECASE)


def _subject(phrase: str) -> str:
    words = [w for w in re.findall(r"[a-zA-Z]+", phrase.lower()) if w not in _STOP]
    return words[-1] if words else "_"


def extract_bounds(text: str) -> Dict[str, List[Tuple[str, int]]]:
    out: Dict[str, List[Tuple[str, int]]] = {}
    for m in _BOUND.finditer(text):
        subj = _subject(m.group(1))
        op = _OP[m.group(2).lower()]
        out.setdefault(subj, []).append((op, int(m.group(3))))
    return out


def _unsat(bounds: List[Tuple[str, int]]) -> bool:
    s = z3.Solver()
    x = z3.Int("x")
    for op, n in bounds:
        s.add({"<": x < n, ">": x > n, "<=": x <= n, ">=": x >= n}[op])
    return s.check() == z3.unsat


def check_contradiction(text: str) -> List[Flag]:
    """SOUND: per subject, formalize its numeric bounds and report a Z3-UNSAT conjunction as a contradiction."""
    flags: List[Flag] = []
    for subj, bounds in extract_bounds(text).items():
        if len(bounds) >= 2 and _unsat(bounds):
            flags.append(Flag("contradiction", "sound-UNSAT",
                              f"the constraints on '{subj}' are jointly unsatisfiable: {bounds}",
                              f"relax one bound on '{subj}' — there is no value satisfying all of them"))
    return flags


def _check_infeasible(text: str) -> List[Flag]:
    t = text.lower()
    flags: List[Flag] = []
    for keys, why, alt in _INFEASIBLE:
        if all(k in t for k in keys):
            flags.append(Flag("infeasible", "heuristic-catalog", why, alt))
    return flags


def scan_danger(text: str) -> List[Flag]:
    flags: List[Flag] = []
    for rx, cwe, kind, alt in _DANGER_RE:
        m = rx.search(text)
        if m:
            flags.append(Flag("danger", "heuristic-lexicon", f"matched: '{m.group(0).strip()}'", alt, cwe))
    return flags


def detect(prompt: str) -> DangerReport:
    """Flag dangerous (lexicon), contradictory (Z3 UNSAT — sound), or infeasible (catalog) instructions with
    a safe alternative. NEVER silently complies; NEVER heuristic-only hard-blocks."""
    flags = scan_danger(prompt) + check_contradiction(prompt) + _check_infeasible(prompt)
    return DangerReport("FLAGGED" if flags else "SAFE", flags)


# ==============================================================================================================
# ===== FILE: decline_recovery.py  (182 lines) =====
# ==============================================================================================================

"""
v39 PHASE B — DECLINE-pile recovery: separate fake-Ω(N) (hidden structure) from real-Ω(N) (genuine noise).
==========================================================================================================
v38's coverage work only refined ALREADY-folded cases (O(log n)→O(1)); it never RECOVERED declined ones. This
module wakes the sleeping v37 sublinear cluster (hidden_closed / prony / sparse_fft / compressed_sensing /
randomized_svd / planted_detect) and points it AT the DECLINE pile. Each recovery passes a SOUND, per-instance,
HELD-OUT certificate or it does not happen.

★ THE LINE WE NEVER CROSS ★ real-Ω(N) (genuine random/independent data) must NEVER be "recovered" — that would
  be a false structure / a wrong answer. The hard guarantee measured here is false_structure == 0 on the
  real-random cases. fake-Ω(N) (a polynomial / exponential-sum / k-sparse / low-rank hiding behind an opaque
  presentation that the current engine declines) IS recovered, with its grade (EXACT or PROBABILISTIC(ε,δ)).

★ GRADES ★ never mixed: polynomial / exact exp-sum / k-sparse → EXACT; low-rank / spiked → PROBABILISTIC(ε,δ);
  no certificate → DECLINE (byte-identical to before — lossless defer).
"""
from __future__ import annotations

from dataclasses import dataclass
from typing import List, Optional

import numpy as np

import sublinear_layer as SL
import hidden_closed as HC
import prony
import sparse_fft
import compressed_sensing as CS
import randomized_svd as RS
import planted_detect as PD


@dataclass
class RecoveryCase:
    cid: str
    category: str                       # numeric-sequence | signal | matrix | statistical
    truth: str                          # ground truth: hidden_poly|hidden_expsum|hidden_sparse|hidden_lowrank|
                                        #                hidden_spiked | real_random
    shape: str                          # "sequence" | "signal" | "matrix"
    data: object
    split: str = "measure"              # "tune" | "measure" (held-out)


@dataclass
class RecoveryVerdict:
    cid: str
    grade: str                          # EXACT | PROBABILISTIC | DECLINE
    kind: str                           # which detector certified it (or "—")
    bound: Optional[float] = None
    detail: str = ""


def recover(case: RecoveryCase) -> RecoveryVerdict:
    """Try the SHAPE-appropriate sound-gated detectors; return the first that CERTIFIES, else DECLINE.
    Every non-DECLINE carries the underlying v37 per-instance certificate (held-out / residual / dual / gap)."""
    if case.shape == "sequence":
        samples = list(case.data)
        # 1) hidden polynomial (finite differences + held-out) → EXACT O(1)
        if all(float(x).is_integer() for x in samples):
            rec = HC.classify(lambda n: int(samples[n]), m=len(samples) - 1)
            if rec.status == HC.CLOSED_O1 and rec.grade == "EXACT":
                return RecoveryVerdict(case.cid, SL.EXACT, "hidden_closed:poly", float(rec.degree),
                                       f"degree-{rec.degree} polynomial, held-out×{rec.checked_holdout}")
        # 2) hidden exponential sum (Prony/ESPRIT, residual < machine-ε, cfinite cross-checked) → EXACT
        #    ★ soundness guard: an INTEGER sequence may earn EXACT only if its values are within float64's
        #    exact-integer range (<2^53); beyond that a small RELATIVE residual could mask float error → a
        #    false EXACT. Outside the exact range we DECLINE (float arithmetic cannot certify bit-exactness). ★
        exact_ok = (not all(float(x).is_integer() for x in samples)) or max(abs(x) for x in samples) < 2 ** 53
        v = prony.recover(np.asarray(samples, dtype=float))
        if v.status == SL.EXACT and exact_ok:
            return RecoveryVerdict(case.cid, SL.EXACT, "prony:exp_sum", v.certificate.bound,
                                   "exponential sum recovered, held-out residual < machine-ε (values < 2^53)")
        return RecoveryVerdict(case.cid, SL.DECLINE, "—", None, "no polynomial / exp-sum structure (held-out)")

    if case.shape == "signal":
        v = sparse_fft.recover(np.asarray(case.data, dtype=float))   # k-sparse spectrum (Prony on O(k) samples)
        if v.status == SL.EXACT:
            return RecoveryVerdict(case.cid, SL.EXACT, "sparse_fft", v.certificate.bound, "k-sparse spectrum")
        return RecoveryVerdict(case.cid, SL.DECLINE, "—", None, "spectrum not k-sparse")

    if case.shape == "matrix":
        M = np.asarray(case.data, dtype=float)
        # low-rank (rSVD posterior residual, δ stated) → PROBABILISTIC
        v = RS.approximate(M)
        if v.status == SL.PROBABILISTIC:
            return RecoveryVerdict(case.cid, SL.PROBABILISTIC, "randomized_svd", v.certificate.bound,
                                   f"low-rank, ε={v.certificate.epsilon:.1e} δ={v.certificate.delta:.0e}")
        # spiked/planted (BBP spectral gap) → PROBABILISTIC (detectability, never an absence proof)
        if M.shape[0] == M.shape[1]:
            v2 = PD.detect(M)
            if v2.status == SL.PROBABILISTIC:
                return RecoveryVerdict(case.cid, SL.PROBABILISTIC, "planted_detect", v2.certificate.bound,
                                       "spectral gap above BBP edge")
        return RecoveryVerdict(case.cid, SL.DECLINE, "—", None, "no low-rank / spectral structure")

    return RecoveryVerdict(case.cid, SL.DECLINE, "—", None, "unknown shape")


# ───────────────────────────────────── B0: a GROUND-TRUTH-labelled corpus (fake-Ω(N) + real-Ω(N))
def make_corpus(seed: int = 0) -> List[RecoveryCase]:
    """Each case has a KNOWN truth so recovery can be scored honestly and false-structure caught. The current
    engine DECLINES all of these (raw sequences/signals/matrices — outside the HARAN-fold front-end), so the
    baseline recovery is 0%. tune/measure = train/held-out split (we report on held-out)."""
    rng = np.random.default_rng(seed)
    C: List[RecoveryCase] = []

    # fake-Ω(N): hidden POLYNOMIAL (current engine sees an opaque sequence → DECLINE; hidden_closed recovers)
    for cid, poly in [("poly_cubic", lambda n: 3 * n**3 - 2 * n + 5), ("poly_sq", lambda n: n * n),
                      ("poly_sumk", lambda n: n * (n + 1) // 2), ("poly_quartic", lambda n: n**4 - n + 1)]:
        C.append(RecoveryCase(cid, "numeric-sequence", "hidden_poly", "sequence",
                              [poly(n) for n in range(40)], "tune" if cid.endswith("sq") else "measure"))

    # fake-Ω(N): hidden EXPONENTIAL SUM (Prony recovers; not polynomial). Ranges kept within float64's exact
    # range (<2^53) so the EXACT grade is GENUINELY exact (not a float-masked relative residual).
    for cid, f, m in [("exp_2_5", lambda n: 3 * 2**n + 2 * 5**n, 18), ("exp_fib", None, 0),
                      ("exp_mix", lambda n: 2**n + 3**n + 1, 24)]:
        if cid == "exp_fib":
            fib = [0, 1]
            for _ in range(28):
                fib.append(fib[-1] + fib[-2])
            data = fib
        else:
            data = [f(n) for n in range(m)]
        C.append(RecoveryCase(cid, "numeric-sequence", "hidden_expsum", "sequence", data,
                              "tune" if cid == "exp_fib" else "measure"))

    # fake-Ω(N): hidden k-SPARSE signal (a few tones in noise-free spectrum) → sparse_fft EXACT
    for cid, tones in [("sparse_3", [5, 40, 100]), ("sparse_2", [7, 64])]:
        N = 256
        sig = np.zeros(N)
        for t in tones:
            sig += np.cos(2 * np.pi * t * np.arange(N) / N)
        C.append(RecoveryCase(cid, "signal", "hidden_sparse", "signal", sig, "measure"))

    # fake-Ω(N): hidden LOW-RANK / SPIKED matrix → rSVD / planted PROBABILISTIC
    A = rng.standard_normal((120, 5)) @ rng.standard_normal((5, 120))
    C.append(RecoveryCase("lowrank_r5", "matrix", "hidden_lowrank", "matrix", A, "measure"))
    spiked, _ = PD.make_spiked(160, snr=3.0, seed=seed)
    C.append(RecoveryCase("spiked_snr3", "statistical", "hidden_spiked", "matrix", spiked, "measure"))

    # ★ real-Ω(N): GENUINE noise — every detector MUST DECLINE (recovery here = false structure = wrong) ★
    C.append(RecoveryCase("rand_seq", "numeric-sequence", "real_random", "sequence",
                          [int(x) for x in rng.integers(0, 1_000_000, 40)], "measure"))
    C.append(RecoveryCase("hash_seq", "numeric-sequence", "real_random", "sequence",
                          [(n * 2654435761) % 1_000_003 for n in range(40)], "tune"))
    C.append(RecoveryCase("rand_signal", "signal", "real_random", "signal", rng.standard_normal(256), "measure"))
    C.append(RecoveryCase("rand_matrix", "matrix", "real_random", "matrix", rng.standard_normal((120, 120)), "measure"))
    return C


# ───────────────────────────────────── B2: recovery measurement (held-out, by category) + the hard guarantee
def measure_recovery(split: Optional[str] = "measure", seed: int = 0) -> dict:
    """Recovery rate over the labelled corpus (held-out by default). Reports recovered_exact / recovered_prob /
    still_decline, the per-instance grades, and — the hard soundness number — false_structure (a real_random
    case wrongly graded non-DECLINE), which MUST be 0."""
    cases = [c for c in make_corpus(seed) if (split is None or c.split == split)]
    fake = [c for c in cases if c.truth != "real_random"]
    real = [c for c in cases if c.truth == "real_random"]
    rec_exact = rec_prob = missed = 0
    false_structure = 0
    rows = []
    for c in cases:
        v = recover(c)
        rows.append((c.cid, c.truth, v.grade, v.kind))
        if c.truth == "real_random":
            if v.grade != SL.DECLINE:
                false_structure += 1                       # ★ must stay 0 ★
        else:
            if v.grade == SL.EXACT:
                rec_exact += 1
            elif v.grade == SL.PROBABILISTIC:
                rec_prob += 1
            else:
                missed += 1
    nf = len(fake)
    return {"split": split or "all", "n_fake": nf, "n_real": len(real),
            "recovered_exact": rec_exact, "recovered_probabilistic": rec_prob, "still_decline_fake": missed,
            "recovery_rate": round((rec_exact + rec_prob) / nf, 3) if nf else 0.0,
            "false_structure": false_structure,                       # real-Ω(N) wrongly recovered — MUST be 0
            "real_correctly_declined": sum(1 for c in real if recover(c).grade == SL.DECLINE),
            "rows": rows}


