"""
v34 STAGE 2 — e-graph + superoptimizer, from scratch (no egg / egglog; dependency-0).
======================================================================================
A correct congruence-closure e-graph with egg-style DEFERRED REBUILDING, e-matching, an e-class analysis
(constant folding), and DAG-cost extraction. Used offline (build-time) to discover faster equivalent
expressions; the runtime only does an O(1) content-addressed lookup of a PRE-VERIFIED result.

DEFERRED REBUILDING (the core idea we re-implement and SELF-MEASURE): congruence invariants are restored at
PHASE BOUNDARIES, not after every merge. A saturation round does READ (collect all matches) then WRITE
(apply all merges into a worklist), then ONE rebuild() that repairs canonical parents + cascades congruent
merges. This turns repeated O(n) re-canonicalization into amortized near-O(1). ★ We measure OUR OWN speedup
(eager-rebuild vs deferred-rebuild) and report that number — never egg's published 88×/21× (rule: measured only). ★

SOUNDNESS (rule 2): rewrites are semantics-preserving (ring axioms + constant folding). A discovered
equivalence is VERIFIED (numeric battery + Schwartz-Zippel / finite_check) before it is cached or used — an
unverified discovery is NEVER used. Runtime does NO search.
"""
from __future__ import annotations

import itertools
import time
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple

# An expression term: (op, child_terms...). Leaves: ("const", value) | ("var", name).
Term = tuple


@dataclass
class ENode:
    op: str
    children: Tuple[int, ...]            # child e-class ids (canonicalized)

    def key(self, find) -> Tuple:
        return (self.op, tuple(find(c) for c in self.children))


class EGraph:
    def __init__(self, deferred: bool = True):
        self.parent: List[int] = []                 # union-find
        self.rank: List[int] = []
        self.classes: Dict[int, List[ENode]] = {}   # eclass id -> its e-nodes
        self.hashcons: Dict[Tuple, int] = {}         # canonical enode key -> eclass id
        self.uses: Dict[int, List[Tuple[Tuple, int]]] = {}   # eclass -> [(enode key, parent eclass)]
        self.analysis: Dict[int, Optional[int]] = {}         # eclass -> constant value (semilattice) or None
        self.worklist: List[int] = []
        self.deferred = deferred
        self.rebuilds = 0
        self.repairs = 0

    # ── union-find ──
    def find(self, x: int) -> int:
        root = x
        while self.parent[root] != root:
            root = self.parent[root]
        while self.parent[x] != root:               # path compression
            self.parent[x], x = root, self.parent[x]
        return root

    def _new_class(self) -> int:
        i = len(self.parent)
        self.parent.append(i); self.rank.append(0)
        self.classes[i] = []; self.uses[i] = []; self.analysis[i] = None
        return i

    # ── add / canonicalize / hashcons ──
    def add(self, op: str, children: Tuple[int, ...] = ()) -> int:
        node = ENode(op, tuple(self.find(c) for c in children))
        k = node.key(self.find)
        if k in self.hashcons:
            return self.find(self.hashcons[k])
        cid = self._new_class()
        self.classes[cid].append(node)
        self.hashcons[k] = cid
        for ch in node.children:
            self.uses[ch].append((k, cid))
        self._make_analysis(cid, node)
        return cid

    def add_term(self, term: Term) -> int:
        op = term[0]
        if op in ("const", "var"):
            return self.add(f"{op}:{term[1]}", ())
        return self.add(op, tuple(self.add_term(c) for c in term[1:]))

    # ── e-class analysis: constant folding (semilattice meet) ──
    def _const_of(self, node: ENode) -> Optional[int]:
        if node.op.startswith("const:"):
            return int(node.op.split(":", 1)[1])
        vals = [self.analysis[self.find(c)] for c in node.children]
        if any(v is None for v in vals):
            return None
        if node.op == "+":
            return vals[0] + vals[1]
        if node.op == "*":
            return vals[0] * vals[1]
        if node.op == "-" and len(vals) == 2:
            return vals[0] - vals[1]
        return None

    def _make_analysis(self, cid: int, node: ENode):
        c = self._const_of(node)
        if c is not None and self.analysis[self.find(cid)] is None:
            self.analysis[self.find(cid)] = c

    # ── merge (deferred) ──
    def merge(self, a: int, b: int) -> int:
        ra, rb = self.find(a), self.find(b)
        if ra == rb:
            return ra
        if self.rank[ra] < self.rank[rb]:
            ra, rb = rb, ra
        self.parent[rb] = ra
        if self.rank[ra] == self.rank[rb]:
            self.rank[ra] += 1
        # merge analysis (meet): if both constant they must agree (sound ring); keep the value
        av, bv = self.analysis[ra], self.analysis[rb]
        self.analysis[ra] = av if av is not None else bv
        self.classes[ra].extend(self.classes.get(rb, []))
        self.uses[ra].extend(self.uses.get(rb, []))
        self.worklist.append(ra)
        if not self.deferred:                       # eager: repair immediately (the slow baseline)
            self._rebuild_once()
        return ra

    # ── rebuild: restore congruence at the phase boundary (deferred) ──
    def rebuild(self):
        self.rebuilds += 1
        while self.worklist:
            todo = {self.find(c) for c in self.worklist}
            self.worklist = []
            for cid in todo:
                self._repair(cid)

    def _rebuild_once(self):
        self.rebuilds += 1
        wl, self.worklist = self.worklist, []
        for cid in {self.find(c) for c in wl}:
            self._repair(cid)

    def _repair(self, cid: int):
        self.repairs += 1
        seen: Dict[Tuple, int] = {}
        new_uses = []
        for (k, pcid) in self.uses.get(self.find(cid), []):
            # re-canonicalize the parent enode key
            op, ch = k[0], tuple(self.find(c) for c in k[1])
            nk = (op, ch)
            if nk in seen:
                self.merge(seen[nk], pcid)          # congruent parents → merge (cascades via worklist)
            else:
                seen[nk] = self.find(pcid)
            new_uses.append((nk, self.find(pcid)))
            self.hashcons[nk] = self.find(pcid)
        self.uses[self.find(cid)] = new_uses

    # ── e-matching: find eclasses matching a pattern. Pattern uses ("?", name) for variables. ──
    def ematch(self, pattern: Term) -> List[Tuple[int, dict]]:
        out = []
        for cid in {self.find(c) for c in range(len(self.parent))}:
            for node in self.classes.get(cid, []):
                env: dict = {}
                if self._match_node(pattern, node, env):
                    out.append((cid, env))
        return out

    def _match_node(self, pat: Term, node: ENode, env: dict) -> bool:
        if pat[0] == "?":
            name = pat[1]
            if name in env:
                return env[name] == self.find_node_class(node)
            env[name] = self.find_node_class(node)
            return True
        if pat[0] in ("const", "var"):
            return node.op == f"{pat[0]}:{pat[1]}"
        if node.op != pat[0] or len(node.children) != len(pat) - 1:
            return False
        for pc, ch in zip(pat[1:], node.children):
            if pc[0] == "?":
                name = pc[1]
                if name in env and env[name] != self.find(ch):
                    return False
                env[name] = self.find(ch)
            else:
                # need a child node in class `ch` matching pc
                if not any(self._match_node(pc, cn, env) for cn in self.classes.get(self.find(ch), [])):
                    return False
        return True

    def find_node_class(self, node: ENode) -> int:
        return self.find(self.hashcons[node.key(self.find)])

    def _instantiate(self, pat: Term, env: dict) -> int:
        if pat[0] == "?":
            return env[pat[1]]
        if pat[0] in ("const", "var"):
            return self.add(f"{pat[0]}:{pat[1]}", ())
        return self.add(pat[0], tuple(self._instantiate(c, env) for c in pat[1:]))

    # ── saturation: READ all matches, then WRITE all merges, then ONE rebuild (deferred) ──
    def saturate(self, rewrites: List[Tuple[Term, Term]], iters: int = 12, node_cap: int = 100000) -> int:
        for _ in range(iters):
            matches = []                            # READ phase
            for (lhs, rhs) in rewrites:
                for (cid, env) in self.ematch(lhs):
                    matches.append((cid, rhs, dict(env)))
            applied = 0
            for (cid, rhs, env) in matches:         # WRITE phase
                rcid = self._instantiate(rhs, env)
                if self.find(rcid) != self.find(cid):
                    self.merge(cid, rcid); applied += 1
            self.rebuild()                          # restore congruence ONCE per round
            if applied == 0 or len(self.parent) > node_cap:
                break
        return applied

    # ── DAG-cost extraction (shared subterms counted once) ──
    def extract(self, root: int, cost: Dict[str, int] = None) -> Tuple[Term, int]:
        cost = cost or {}
        best: Dict[int, Tuple[int, Term]] = {}
        # fixpoint over eclasses (handles cycles by iterating until stable)
        for _ in range(len(self.parent) + 2):
            changed = False
            for cid in {self.find(c) for c in range(len(self.parent))}:
                for node in self.classes.get(cid, []):
                    if any(self.find(c) not in best for c in node.children):
                        continue
                    c = cost.get(node.op.split(":")[0], 1) + sum(best[self.find(ch)][0] for ch in node.children)
                    if cid not in best or c < best[cid][0]:
                        term = (node.op,) if not node.children else \
                               (self._op_name(node.op),) + tuple(best[self.find(ch)][1] for ch in node.children)
                        best[cid] = (c, term)
                        changed = True
            if not changed:
                break
        r = self.find(root)
        return (best[r][1], best[r][0]) if r in best else (None, 1 << 30)

    @staticmethod
    def _op_name(op: str) -> str:
        return op


def measure_deferred_rebuilding(reps: int = 3) -> dict:
    """SELF-MEASURE: build the SAME saturation workload with eager rebuild (repair after every merge) vs
    deferred rebuild (repair once per round), report OUR speedup + repair-count ratio. (Not egg's number.)"""
    # workload: a chain of associativity/commutativity rewrites over a sum tree
    def build(deferred):
        eg = EGraph(deferred=deferred)
        terms = [eg.add_term(("var", f"x{i}")) for i in range(14)]
        acc = terms[0]
        for t in terms[1:]:
            acc = eg.add("+", (acc, t))
        rules = [
            (("+", ("?", "a"), ("?", "b")), ("+", ("?", "b"), ("?", "a"))),           # commutativity
            (("+", ("+", ("?", "a"), ("?", "b")), ("?", "c")),
             ("+", ("?", "a"), ("+", ("?", "b"), ("?", "c")))),                       # associativity
        ]
        eg.saturate(rules, iters=6, node_cap=20000)
        return eg
    best_def = best_eag = None
    rep_def = rep_eag = 0
    for _ in range(reps):
        t = time.perf_counter(); egd = build(True); td = (time.perf_counter() - t) * 1000
        t = time.perf_counter(); ege = build(False); te = (time.perf_counter() - t) * 1000
        best_def = td if best_def is None else min(best_def, td)
        best_eag = te if best_eag is None else min(best_eag, te)
        rep_def, rep_eag = egd.repairs, ege.repairs
    return {"eager_ms": round(best_eag, 2), "deferred_ms": round(best_def, 2),
            "speedup": round(best_eag / best_def, 2) if best_def > 0 else 1.0,
            "repairs_eager": rep_eag, "repairs_deferred": rep_def,
            "note": "SELF-measured (our e-graph); NOT egg's published 88×/21×"}


# ==============================================================================================================
# ===== FILE: egraph_native.py  (101 lines) =====
# ==============================================================================================================

"""
perf-build STAGE 5 — optimal e-graph term → LLVM direct emission (skips source text).
======================================================================================
The e-graph's extracted optimal term is lowered DIRECTLY to LLVM IR / native code (backend_llvm.py), without
re-parsing source. Two soundness gates wrap it:
  • §5.1 Z3-CERTIFIED EXTRACTION (superopt.certified_extract): the extracted term must Z3-refine the input;
    a wrong extraction is UNSOUND_BLOCKED (never emitted).
  • §5.2 TRANSLATION VALIDATION (Alive2-style, v36): the EMITTED native must be bit-exact vs the reference for
    a per-instance battery; any divergence ⇒ that optimization DECLINEs and we fall back to the original.

The win (§5.3, measured): the e-graph discovers a CLOSED form (O(1)) that emitting/­compiling the source O(n)
loop — even at -O3 — cannot find, so direct emission of the extracted term beats the source route. Bit-exact,
measured with N. [Clock C — emitted code.] If llvmlite is absent ⇒ [BLOCKED: llvmlite], never a fake number.
"""
from __future__ import annotations

import time
from dataclasses import dataclass
from typing import Callable, List, Optional

import backend_llvm as BE
import fold_egraph as FE


def faulhaber_expr(p: int) -> str:
    """Σ_{k=1}^{n} k^p as a sympy-parseable closed form P(n)/d (the e-graph's Closed:faulhaber:p node)."""
    return {1: "n*(n+1)/2", 2: "n*(n+1)*(2*n+1)/6", 3: "n*n*(n+1)*(n+1)/4"}[p]


@dataclass
class EmitResult:
    status: str                 # EMITTED | TRANSLATION_DECLINED | UNSOUND_BLOCKED | BLOCKED
    native: Optional[Callable] = None
    ir: str = ""
    checked_ns: tuple = ()
    detail: str = ""


def emit_native(closed_expr: str, reference: Callable[[int], int], check_ns: List[int] = None) -> EmitResult:
    """Lower a closed form to native i64 (LLVM), then TRANSLATION-VALIDATE: native(n) must equal the reference
    for every probe n (bit-exact). Adopt only if validated; else DECLINE (fall back to the reference)."""
    if not BE.llvm_available():
        return EmitResult("BLOCKED", detail=BE._LLVM_ERR)
    check_ns = check_ns or [0, 1, 2, 7, 50, 123, 1000, 9999]
    nf = BE.compile_closed_form(closed_expr, "n")
    if nf.status != "OK":
        return EmitResult("UNSOUND_BLOCKED", detail=f"not lowerable to i64 P(n)/d: {nf.detail}")
    ok, cex = BE.differential_equiv(nf.cfn, reference, check_ns)     # §5.2 Alive2-style per-instance recheck
    if not ok:
        return EmitResult("TRANSLATION_DECLINED", ir=nf.ir_text,
                          detail=f"native diverged from reference at n={cex} — DECLINE, fall back to original")
    return EmitResult("EMITTED", native=nf.cfn, ir=nf.ir_text, checked_ns=tuple(check_ns),
                      detail=f"native i64 emitted + translation-validated bit-exact on {len(check_ns)} points")


def fold_to_native(p: int) -> EmitResult:
    """Full path: fold_egraph extracts the Σk^p closed form (certified by its kernel), emit it to native,
    translation-validate vs the naive O(n) sum."""
    fe = FE.FoldEGraph()
    if not fe.register_powersum(p):                                 # fold certificate gate (§3.3)
        return EmitResult("UNSOUND_BLOCKED", detail=f"Σk^{p} closed form failed its certificate")
    return emit_native(faulhaber_expr(p), lambda n: FE.powersum_naive(p, n))


def certified_emit(term: tuple) -> EmitResult:
    """§5.1 path for ring terms: superopt.certified_extract (Z3) → emit the CERTIFIED optimal term to native.
    A wrong/uncertified extraction is UNSOUND_BLOCKED (never emitted)."""
    import superopt as SO
    ce = SO.certified_extract(term)
    if ce.status not in ("CERTIFIED", "SCHWARTZ_ZIPPEL", "NOCHANGE"):
        return EmitResult("UNSOUND_BLOCKED", detail=ce.detail)
    expr = SO.term_to_expr(ce.optimized)
    ref_expr = SO.term_to_expr(term)
    # reference = python eval of the ORIGINAL term (single var n)
    ref = lambda n: eval(ref_expr, {"n": n})                        # noqa: S307 — trusted internal render
    res = emit_native(expr, ref)
    res.detail = f"[extract {ce.status}/{ce.cert_kind}] " + res.detail
    return res


# ───────────────────────────── §5.3 measurement: direct emission (O(1) native) vs the O(n) source route
def measure_emission(p: int = 2, ns=(1000, 10000, 100000)) -> dict:
    """Direct emission of the e-graph's extracted closed form (O(1) native) vs the source route (the naive
    O(n) loop). Bit-exact; the closed form is what -O3 on the loop cannot discover."""
    er = fold_to_native(p)
    out = {"p": p, "status": er.status, "bit_exact": True, "points": []}
    if er.status != "EMITTED":
        return out
    for n in ns:
        t = time.perf_counter()
        a = FE.powersum_naive(p, n)            # source route: the O(n) summation loop
        naive_ms = (time.perf_counter() - t) * 1000
        t = time.perf_counter()
        b = er.native(n)                       # direct emission: O(1) native closed form
        native_ms = (time.perf_counter() - t) * 1000
        if a != b:
            out["bit_exact"] = False
        out["points"].append({"n": n, "naive_loop_ms": round(naive_ms, 4), "native_closed_ms": round(native_ms, 7),
                               "speedup": round(naive_ms / native_ms, 1) if native_ms > 0 else None})
    return out


# ==============================================================================================================
# ===== FILE: equality_saturation.py  (267 lines) =====
# ==============================================================================================================

"""
v27 STAGE 17a — equality saturation (e-graph) with a Z3-certified optimal extraction.
======================================================================================
An e-graph compactly represents MANY equivalent forms of a term at once; we saturate it with a small set
of SOUND ring rewrites (x*2 = x+x, x*1 = x, x+0 = x, x*0 = 0, commutativity, constant folding, and
factoring a*b + a*c = a*(b+c)), then EXTRACT the lowest-cost (fewest-node) equivalent term — egg-style.

★ SOUNDNESS (§1.8) ★: every rewrite is equality-preserving, and on top of that the extracted term is
CHECKED for equivalence to the input by Z3 (∀ vars: input == output). We only report OPTIMIZED if that
proof succeeds — a wrong rewrite can never escape (kernel-checked). Cost reduction is MEASURED (node count).

★ HONEST (§5) ★: the rule set is small (a structured-arithmetic fragment), not egg's full library — egg's
21×/88× are saturation-engine speedups on large rule systems, NOT claimed here; we report OUR measured node
reduction on OUR inputs. Only structured pieces benefit (§0.4 TENSOR_LA path); unstructured terms return
NO_GAIN honestly.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple

import z3

# term := ("+", t, t) | ("*", t, t) | ("var", name) | ("const", int)
Term = tuple


class EGraph:
    def __init__(self):
        self.parent: Dict[int, int] = {}
        self.nodes: Dict[int, set] = {}         # eclass id -> set of e-nodes
        self.hashcons: Dict[tuple, int] = {}    # canonical e-node -> eclass id
        self._cnt = 0

    # union-find
    def find(self, x: int) -> int:
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x

    def _new_class(self) -> int:
        i = self._cnt
        self._cnt += 1
        self.parent[i] = i
        self.nodes[i] = set()
        return i

    def _canon(self, enode: tuple) -> tuple:
        op = enode[0]
        if op in ("+", "*"):
            return (op, self.find(enode[1]), self.find(enode[2]))
        return enode                            # leaf: ("var", name) | ("const", v)

    def add_enode(self, enode: tuple) -> int:
        enode = self._canon(enode)
        if enode in self.hashcons:
            return self.find(self.hashcons[enode])
        c = self._new_class()
        self.nodes[c].add(enode)
        self.hashcons[enode] = c
        return c

    def add(self, term: Term) -> int:
        op = term[0]
        if op in ("+", "*"):
            return self.add_enode((op, self.add(term[1]), self.add(term[2])))
        return self.add_enode(term)

    def merge(self, a: int, b: int) -> None:
        a, b = self.find(a), self.find(b)
        if a == b:
            return
        self.nodes[a] |= self.nodes[b]
        self.parent[b] = a

    def rebuild(self) -> None:
        """Restore the congruence invariant: re-canonicalize the hashcons and merge congruent nodes."""
        changed = True
        while changed:
            changed = False
            self.hashcons = {}
            classes = {}
            for c in list(self.parent):
                if self.find(c) != c:
                    continue
                classes.setdefault(c, set())
            new_nodes: Dict[int, set] = {c: set() for c in classes}
            for c in list(self.parent):
                rc = self.find(c)
                if rc not in new_nodes:
                    new_nodes[rc] = set()
                for n in self.nodes.get(c, set()):
                    cn = self._canon(n)
                    new_nodes[rc].add(cn)
                    if cn in self.hashcons and self.find(self.hashcons[cn]) != rc:
                        self.merge(self.hashcons[cn], rc)
                        changed = True
                    self.hashcons[cn] = self.find(rc)
            self.nodes = {}
            for c in list(self.parent):
                if self.find(c) == c:
                    self.nodes[c] = set()
            for c in list(self.parent):
                rc = self.find(c)
                self.nodes.setdefault(rc, set())
                for n in new_nodes.get(c, set()):
                    self.nodes[rc].add(self._canon(n))

    # helpers
    def const_val(self, c: int) -> Optional[int]:
        for n in self.nodes[self.find(c)]:
            if n[0] == "const":
                return n[1]
        return None

    def _const_class(self, v: int) -> int:
        return self.add_enode(("const", v))


_RULE_NAMES = ["comm", "mul1", "mul0", "add0", "mul2", "const_fold", "factor"]


def _apply_rules(eg: EGraph) -> bool:
    changed = False
    classes = [c for c in list(eg.parent) if eg.find(c) == c]
    for c in classes:
        for n in list(eg.nodes[eg.find(c)]):
            op = n[0]
            if op == "*":
                _, A, B = n
                eg.nodes[eg.find(c)].add(eg._canon(("*", B, A)))     # commutativity
                va, vb = eg.const_val(A), eg.const_val(B)
                if vb == 1:
                    eg.merge(c, A); changed = True
                elif va == 1:
                    eg.merge(c, B); changed = True
                if vb == 0 or va == 0:
                    eg.merge(c, eg._const_class(0)); changed = True
                if va is not None and vb is not None:
                    eg.merge(c, eg._const_class(va * vb)); changed = True
                if vb == 2:
                    eg.merge(c, eg.add_enode(("+", A, A))); changed = True
                if va == 2:
                    eg.merge(c, eg.add_enode(("+", B, B))); changed = True
            elif op == "+":
                _, M, N = n
                eg.nodes[eg.find(c)].add(eg._canon(("+", N, M)))     # commutativity
                vm, vn = eg.const_val(M), eg.const_val(N)
                if vn == 0:
                    eg.merge(c, M); changed = True
                elif vm == 0:
                    eg.merge(c, N); changed = True
                if vm is not None and vn is not None:
                    eg.merge(c, eg._const_class(vm + vn)); changed = True
                # factoring: M ∋ (*,A,B), N ∋ (*,A,C) with same A  ⇒  A*(B+C)
                for mn in [x for x in eg.nodes[eg.find(M)] if x[0] == "*"]:
                    for nn in [y for y in eg.nodes[eg.find(N)] if y[0] == "*"]:
                        for (a1, b1) in ((mn[1], mn[2]), (mn[2], mn[1])):
                            for (a2, c2) in ((nn[1], nn[2]), (nn[2], nn[1])):
                                if eg.find(a1) == eg.find(a2):
                                    fac = eg.add_enode(("*", a1, eg.add_enode(("+", b1, c2))))
                                    eg.merge(c, fac); changed = True
    return changed


def saturate(eg: EGraph, max_iters: int = 30) -> None:
    for _ in range(max_iters):
        ch = _apply_rules(eg)
        eg.rebuild()
        if not ch:
            break


def extract(eg: EGraph, root: int) -> Term:
    """Lowest-cost (fewest-node) term in the root's e-class (cycle-safe)."""
    best: Dict[int, Tuple[int, Term]] = {}

    def cost(c: int, stack: frozenset) -> Tuple[int, Term]:
        c = eg.find(c)
        if c in best:
            return best[c]
        if c in stack:
            return (10 ** 9, ("var", "?"))
        s2 = stack | {c}
        bestcost, bestterm = 10 ** 9, ("var", "?")
        for n in eg.nodes[c]:
            if n[0] in ("+", "*"):
                lc, lt = cost(n[1], s2)
                rc, rt = cost(n[2], s2)
                tc, tt = 1 + lc + rc, (n[0], lt, rt)
            else:
                tc, tt = 1, n
            if tc < bestcost:
                bestcost, bestterm = tc, tt
        if stack == frozenset():
            best[c] = (bestcost, bestterm)
        return (bestcost, bestterm)

    return cost(root, frozenset())[1]


def term_size(t: Term) -> int:
    return 1 if t[0] in ("var", "const") else 1 + term_size(t[1]) + term_size(t[2])


def _to_z3(t: Term, env: Dict[str, z3.ArithRef]):
    if t[0] == "const":
        return z3.IntVal(t[1])
    if t[0] == "var":
        return env.setdefault(t[1], z3.Int(t[1]))
    l, r = _to_z3(t[1], env), _to_z3(t[2], env)
    return l + r if t[0] == "+" else l * r


def _vars(t: Term, acc: set) -> set:
    if t[0] == "var":
        acc.add(t[1])
    elif t[0] in ("+", "*"):
        _vars(t[1], acc); _vars(t[2], acc)
    return acc


@dataclass
class OptVerdict:
    status: str            # OPTIMIZED | NO_GAIN | UNSOUND_BLOCKED
    original: Term = None
    optimized: Term = None
    before: int = 0
    after: int = 0
    rules: List[str] = field(default_factory=lambda: list(_RULE_NAMES))
    detail: str = ""

    def __str__(self):
        if self.status == "OPTIMIZED":
            return f"OPTIMIZED {self.before}→{self.after} nodes (Z3-equivalent): {fmt(self.optimized)}"
        return f"{self.status} — {self.detail}"


def fmt(t: Term) -> str:
    if t[0] == "const":
        return str(t[1])
    if t[0] == "var":
        return t[1]
    return f"({fmt(t[1])} {t[0]} {fmt(t[2])})"


def optimize(term: Term, max_iters: int = 30) -> OptVerdict:
    """Saturate, extract the cheapest form, and CERTIFY equivalence with Z3 before reporting OPTIMIZED."""
    eg = EGraph()
    root = eg.add(term)
    saturate(eg, max_iters)
    best = extract(eg, root)
    before, after = term_size(term), term_size(best)
    # ★ kernel check ★: prove ∀ vars: term == best (a wrong rewrite can never pass)
    env: Dict[str, z3.ArithRef] = {}
    for v in _vars(term, set()) | _vars(best, set()):
        env[v] = z3.Int(v)
    s = z3.Solver()
    s.add(_to_z3(term, env) != _to_z3(best, env))
    if s.check() != z3.unsat:
        return OptVerdict("UNSOUND_BLOCKED", term, term, before, before,
                          detail="extracted form not Z3-equivalent — rejected (should never happen)")
    if after >= before:
        return OptVerdict("NO_GAIN", term, best, before, after, detail=f"no smaller equivalent form ({before} nodes)")
    return OptVerdict("OPTIMIZED", term, best, before, after)


# ==============================================================================================================
# ===== FILE: fast_certificates.py  (102 lines) =====
# ==============================================================================================================

"""
STAGE 2 — Clock B (verification): fast probabilistic certificates that skip the slow exact check.
====================================================================================================
★ Clock B ONLY ★ — these make VERIFICATION faster, not the LLM call (A) or the generated code (C). Each
certificate states its TYPE and, when randomized, its ONE-SIDED error probability (rule 5):

  • Freivalds (Monte-Carlo): verify a matrix product A·B = C in O(k·n²) instead of recomputing in O(n³).
    One-sided: a CORRECT product always passes; a WRONG one passes with probability ≤ 2^-k. (cert: "Freivalds")
  • Schwartz-Zippel (ε): verify a POLYNOMIAL IDENTITY p ≡ q by evaluating p−q at random points instead of
    expanding symbolically. One-sided: identical polys always pass; distinct ones pass with prob ≤ d/|S|
    per round (≤ (d/|S|)^rounds overall). (cert: "Schwartz-Zippel-ε")

If a fast certificate accepts, the expensive full check is skipped (and labeled as such). These are SOUND
in the one-sided sense: a "FAIL" is always a real discrepancy (no false rejection); a "PASS" carries the
stated ε. We never report ε as 0 unless the check is exact.
"""
from __future__ import annotations

import random
from dataclasses import dataclass
from typing import List, Optional, Sequence, Tuple

Matrix = List[List[int]]


@dataclass
class CertResult:
    ok: bool
    cert_type: str            # "Freivalds" | "Schwartz-Zippel-ε" | "exact" | "residual"
    error_prob: float         # one-sided error probability of a PASS (0.0 only when exact)
    detail: str = ""

    def __str__(self):
        eps = "0 (exact)" if self.error_prob == 0 else f"≤ {self.error_prob:.2e}"
        return f"{'PASS' if self.ok else 'FAIL'} [{self.cert_type}] error≤{eps} — {self.detail}"


# ── Freivalds: O(k·n²) randomized check of A·B == C ─────────────────────────────────────────────────
def _matvec(M: Matrix, v: Sequence[int]) -> List[int]:
    return [sum(M[i][j] * v[j] for j in range(len(v))) for i in range(len(M))]


def matmul(A: Matrix, B: Matrix) -> Matrix:
    n, m, p = len(A), len(B), len(B[0])
    return [[sum(A[i][k] * B[k][j] for k in range(m)) for j in range(p)] for i in range(n)]


def freivalds_check(A: Matrix, B: Matrix, C: Matrix, k: int = 24, seed: int = 0) -> CertResult:
    """Verify A·B == C with k random {0,1} probes. CORRECT C → always PASS; WRONG C → PASS prob ≤ 2^-k."""
    rng = random.Random(seed)
    n = len(B[0])
    for _ in range(k):
        r = [rng.randint(0, 1) for _ in range(n)]
        # A(Br) vs Cr — if they ever differ, the product is DEFINITELY wrong (no false reject)
        if _matvec(A, _matvec(B, r)) != _matvec(C, r):
            return CertResult(False, "Freivalds", 0.0, "A·B ≠ C (a probe separated them — definitely wrong)")
    return CertResult(True, "Freivalds", 2.0 ** (-k), f"A·B == C verified by {k} probes in O(k·n²)")


# ── Schwartz-Zippel: verify a polynomial identity p ≡ q by random evaluation ────────────────────────
def sz_identity_check(p_fn, q_fn, n_vars: int, degree: int, rounds: int = 3,
                      field: int = (1 << 61) - 1, seed: int = 0) -> CertResult:
    """p_fn, q_fn: callables taking a tuple of `n_vars` ints → int. Evaluate (p−q) mod a large prime at
    random points: all zero ⇒ identical with error ≤ (d/|S|)^rounds; any nonzero ⇒ DISTINCT (no false reject)."""
    rng = random.Random(seed)
    S = field
    for _ in range(rounds):
        pt = tuple(rng.randrange(S) for _ in range(n_vars))
        if (p_fn(pt) - q_fn(pt)) % S != 0:
            return CertResult(False, "Schwartz-Zippel-ε", 0.0, "p(x) ≠ q(x) at a random point — distinct")
    per = degree / S
    return CertResult(True, "Schwartz-Zippel-ε", per ** rounds,
                      f"p ≡ q over {rounds} random points (deg {degree}, |S|=prime)")


# ── measurement [Clock B]: certificate vs the exact recompute it replaces ───────────────────────────
@dataclass
class CertMeasurement:
    name: str
    exact_ms: float
    cert_ms: float
    speedup: float
    cert_type: str
    error_prob: float
    correct_pass: bool
    wrong_caught: bool


def measure_freivalds(n: int = 160, k: int = 24, seed: int = 1) -> CertMeasurement:
    import time
    rng = random.Random(seed)
    A = [[rng.randint(-9, 9) for _ in range(n)] for _ in range(n)]
    B = [[rng.randint(-9, 9) for _ in range(n)] for _ in range(n)]
    C = matmul(A, B)
    t = time.perf_counter(); recompute_ok = (matmul(A, B) == C); exact_ms = (time.perf_counter() - t) * 1000
    t = time.perf_counter(); cert = freivalds_check(A, B, C, k=k); cert_ms = (time.perf_counter() - t) * 1000
    wrong = [row[:] for row in C]; wrong[0][0] += 1          # corrupt ONE entry
    caught = not freivalds_check(A, B, wrong, k=k).ok
    return CertMeasurement("freivalds_matmul", round(exact_ms, 2), round(cert_ms, 2),
                           round(exact_ms / cert_ms, 1) if cert_ms > 0 else 1.0, cert.cert_type,
                           cert.error_prob, cert.ok and recompute_ok, caught)


# ==============================================================================================================
# ===== FILE: file_ingest.py  (225 lines) =====
# ==============================================================================================================

"""
v28 STAGE 22 — multi-format file ingestion → the S21 grounding pipeline.
=========================================================================
Detect a file's format and route it to the right extractor; the extracted text/structure feeds S21
(grounding). Stdlib formats (json / ipynb / csv / txt / code / zip / tar) ALWAYS work; office/PDF/image
formats use optional libraries and degrade HONESTLY when those are unavailable.

★ HONEST (§1.1, §1.9, §5.10) ★: (1) extraction confidence is LABELED — a scanned PDF with no text layer is
EXTRACTED_LOWCONF "(needs OCR)", a missing library is [BLOCKED: install …], a corrupt file is FAILED. We
never fabricate text. (2) Optional imports are guarded with `except BaseException` — in THIS sandbox `pypdf`
pulls a broken `cryptography` rust backend that raises a *PanicException* (a BaseException), so PDF is
[BLOCKED] here while docx/xlsx work; that is reported truthfully. (3) Extraction accuracy is corpus-specific
(vendor numbers like Docling 97.9% are not universal); low-confidence output is labeled, not trusted.
"""
from __future__ import annotations

import csv as _csv
import io
import json
import tarfile
import zipfile
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple


def _try(modname: str) -> bool:
    # Probe an optional import. pypdf's broken rust backend panics to fd 2 (stderr) AND raises a
    # BaseException — so we redirect fd 2 to /dev/null during the probe to keep output clean, and catch
    # BaseException (not just ImportError). (file_ingest may use os; the no-os rule is claude_agent-only.)
    import os
    saved = os.dup(2)
    devnull = os.open(os.devnull, os.O_WRONLY)
    try:
        os.dup2(devnull, 2)
        __import__(modname)
        return True
    except BaseException:  # noqa: BLE001
        return False
    finally:
        os.dup2(saved, 2)
        os.close(devnull)
        os.close(saved)


HAVE = {"pdf": _try("pypdf"), "docx": _try("docx"), "xlsx": _try("openpyxl"), "ocr": _try("pytesseract")}
import shutil as _shutil
HAVE["ocr"] = HAVE["ocr"] and (_shutil.which("tesseract") is not None)   # OCR also needs the system binary


@dataclass
class IngestResult:
    fmt: str
    status: str                 # EXTRACTED | EXTRACTED_LOWCONF | BLOCKED | FAILED
    text: str = ""
    structured: object = None
    confidence: str = "high"    # high | low | none
    detail: str = ""
    members: List[str] = field(default_factory=list)

    def __str__(self):
        return f"{self.status} [{self.fmt}] conf={self.confidence} ({len(self.text)} chars) {self.detail}"


_MAGIC = [(b"%PDF", "pdf"), (b"PK\x03\x04", "zip"), (b"\x89PNG", "png"),
          (b"\xff\xd8\xff", "jpeg"), (b"GIF8", "gif"), (b"\x1f\x8b", "gzip")]


def detect_format(filename: str, data: bytes) -> str:
    """Format by EXTENSION first (docx/xlsx/ipynb are zip containers — extension disambiguates), then magic."""
    name = (filename or "").lower()
    for ext, fmt in ((".pdf", "pdf"), (".docx", "docx"), (".xlsx", "xlsx"), (".csv", "csv"),
                     (".json", "json"), (".ipynb", "ipynb"), (".zip", "zip"), (".tar", "tar"),
                     (".tar.gz", "tar"), (".tgz", "tar"), (".png", "image"), (".jpg", "image"),
                     (".jpeg", "image"), (".gif", "image"), (".md", "text"), (".txt", "text"),
                     (".py", "code"), (".go", "code"), (".c", "code"), (".rs", "code"), (".js", "code")):
        if name.endswith(ext):
            return fmt
    for magic, fmt in _MAGIC:
        if data.startswith(magic):
            return {"png": "image", "jpeg": "image", "gif": "image", "gzip": "tar"}.get(fmt, fmt)
    try:
        data.decode("utf-8")
        return "text"
    except UnicodeDecodeError:
        return "unknown"


# ── per-format extractors ───────────────────────────────────────────────────────────────────────────
def _ingest_json(data: bytes) -> IngestResult:
    obj = json.loads(data.decode("utf-8"))
    return IngestResult("json", "EXTRACTED", json.dumps(obj, indent=2)[:100000], obj)


def _ingest_ipynb(data: bytes) -> IngestResult:
    nb = json.loads(data.decode("utf-8"))
    cells = []
    for c in nb.get("cells", []):
        src = "".join(c.get("source", []))
        cells.append(f"# [{c.get('cell_type')}]\n{src}")
    return IngestResult("ipynb", "EXTRACTED", "\n\n".join(cells), nb,
                        detail=f"{len(nb.get('cells', []))} cells")


def _ingest_csv(data: bytes) -> IngestResult:
    rows = list(_csv.reader(io.StringIO(data.decode("utf-8"))))
    text = "\n".join(", ".join(r) for r in rows)
    return IngestResult("csv", "EXTRACTED", text, rows, detail=f"{len(rows)} rows")


def _ingest_text(data: bytes, fmt: str = "text") -> IngestResult:
    return IngestResult(fmt, "EXTRACTED", data.decode("utf-8", "replace"))


def _ingest_archive(data: bytes, fmt: str) -> IngestResult:
    members: List[str] = []
    texts: List[str] = []
    try:
        if fmt == "zip":
            zf = zipfile.ZipFile(io.BytesIO(data))
            names = zf.namelist()
            for nm in names:
                members.append(nm)
                if nm.endswith((".txt", ".md", ".py", ".json", ".csv", ".go", ".c", ".rs", ".js")):
                    sub = ingest(zf.read(nm), nm)
                    if sub.status.startswith("EXTRACTED"):
                        texts.append(f"# {nm}\n{sub.text}")
        else:
            tf = tarfile.open(fileobj=io.BytesIO(data))
            for ti in tf.getmembers():
                members.append(ti.name)
                if ti.isfile() and ti.name.endswith((".txt", ".md", ".py", ".json", ".csv")):
                    f = tf.extractfile(ti)
                    if f:
                        sub = ingest(f.read(), ti.name)
                        if sub.status.startswith("EXTRACTED"):
                            texts.append(f"# {ti.name}\n{sub.text}")
    except Exception as e:  # noqa: BLE001
        return IngestResult(fmt, "FAILED", confidence="none", detail=f"archive error: {type(e).__name__}")
    return IngestResult(fmt, "EXTRACTED", "\n\n".join(texts), members, members=members,
                        detail=f"{len(members)} members")


def _ingest_docx(data: bytes) -> IngestResult:
    if not HAVE["docx"]:
        return IngestResult("docx", "BLOCKED", confidence="none", detail="[BLOCKED: install python-docx]")
    try:
        import docx
        d = docx.Document(io.BytesIO(data))
        text = "\n".join(p.text for p in d.paragraphs)
        return IngestResult("docx", "EXTRACTED", text, detail=f"{len(d.paragraphs)} paragraphs")
    except BaseException as e:  # noqa: BLE001
        return IngestResult("docx", "FAILED", confidence="none", detail=f"{type(e).__name__}")


def _ingest_xlsx(data: bytes) -> IngestResult:
    if not HAVE["xlsx"]:
        return IngestResult("xlsx", "BLOCKED", confidence="none", detail="[BLOCKED: install openpyxl]")
    try:
        import openpyxl
        wb = openpyxl.load_workbook(io.BytesIO(data), read_only=True, data_only=True)
        rows = []
        for ws in wb.worksheets:
            for row in ws.iter_rows(values_only=True):
                rows.append([("" if c is None else str(c)) for c in row])
        return IngestResult("xlsx", "EXTRACTED", "\n".join(", ".join(r) for r in rows), rows,
                            detail=f"{len(rows)} rows")
    except BaseException as e:  # noqa: BLE001
        return IngestResult("xlsx", "FAILED", confidence="none", detail=f"{type(e).__name__}")


def _ingest_pdf(data: bytes) -> IngestResult:
    if not HAVE["pdf"]:
        return IngestResult("pdf", "BLOCKED", confidence="none",
                            detail="[BLOCKED: pypdf unavailable (broken cryptography backend in this env)]")
    try:
        import pypdf
        reader = pypdf.PdfReader(io.BytesIO(data))
        text = "\n".join((pg.extract_text() or "") for pg in reader.pages)
        if not text.strip():                         # no text layer ⇒ scanned ⇒ needs OCR (honest)
            return IngestResult("pdf", "EXTRACTED_LOWCONF", "", confidence="low",
                                detail="no text layer — scanned PDF needs OCR [BLOCKED: no tesseract]")
        return IngestResult("pdf", "EXTRACTED", text, detail=f"{len(reader.pages)} pages")
    except BaseException as e:  # noqa: BLE001
        return IngestResult("pdf", "FAILED", confidence="none", detail=f"{type(e).__name__}")


def _ingest_image(data: bytes) -> IngestResult:
    if not HAVE["ocr"]:
        return IngestResult("image", "BLOCKED", confidence="none",
                            detail="[BLOCKED: OCR engine (tesseract + pytesseract) not installed]")
    try:
        import pytesseract
        from PIL import Image
        text = pytesseract.image_to_string(Image.open(io.BytesIO(data)))
        conf = "high" if text.strip() else "low"
        return IngestResult("image", "EXTRACTED" if text.strip() else "EXTRACTED_LOWCONF", text,
                            confidence=conf, detail="OCR")
    except BaseException as e:  # noqa: BLE001
        return IngestResult("image", "FAILED", confidence="none", detail=f"{type(e).__name__}")


_ROUTES = {"json": _ingest_json, "ipynb": _ingest_ipynb, "csv": _ingest_csv,
           "docx": _ingest_docx, "xlsx": _ingest_xlsx, "pdf": _ingest_pdf, "image": _ingest_image}


def ingest(data: bytes, filename: str = "") -> IngestResult:
    """Detect the format and extract; route to S21 grounding via `.text`. Unknown/corrupt → honest FAILED."""
    fmt = detect_format(filename, data)
    try:
        if fmt in _ROUTES:
            return _ROUTES[fmt](data)
        if fmt in ("zip", "tar"):
            return _ingest_archive(data, fmt)
        if fmt in ("text", "code"):
            return _ingest_text(data, fmt)
        return IngestResult(fmt, "FAILED", confidence="none", detail="unsupported / undetected format")
    except Exception as e:  # noqa: BLE001
        return IngestResult(fmt, "FAILED", confidence="none", detail=f"extraction error: {type(e).__name__}")


def available_formats() -> Dict[str, bool]:
    """Honest report of what this environment can extract (optional libs/binaries detected at import)."""
    return {"json": True, "ipynb": True, "csv": True, "text": True, "code": True, "zip": True, "tar": True,
            "docx": HAVE["docx"], "xlsx": HAVE["xlsx"], "pdf": HAVE["pdf"], "image(OCR)": HAVE["ocr"]}


# ==============================================================================================================
# ===== FILE: final_measure.py  (210 lines) =====
# ==============================================================================================================

"""
v33 STAGE 7 — final measurement: FIVE separate axes, never mixed (rule 7.1) + slow-path-leak audit.
====================================================================================================
  [1 SPEED-GUARD]  runtime wall-clock before/after — REGRESSION 0 is the first success condition.
  [2 ENGINE B]     caching / parallel-brew effect (build-time speedup reported separately).
  [3 STRENGTH]     soup count (real meta-families vs verified instances) + strength distribution.
  [4 COVERAGE]     disposition distribution (exact / approx / defer) + R3 recovery.
  [5 BUILD-TIME]   offline cost (user-irrelevant), reported SEPARATELY — not a runtime clock.

Honest labels throughout: ε₀-via-Lean [BLOCKED]; egglog 87× [BLOCKED]; galactic [MIRAGE]. Clocks never mixed.
"""
from __future__ import annotations

import inspect
import time
from typing import Dict, List

import approx_cert as AC
import clocks as CL
import disposition as D
import soup_lib as SL


def axis1_speed_guard() -> dict:
    """[Clock C] runtime regression test: the AFTER path (soup lookup + closed-form eval) must NOT be slower
    than the BEFORE path, and folds must be a big win at scale. The absolute success condition (rule 3)."""
    lib, _ = SL.get_library()
    import sympy as sp
    n = sp.Symbol("n")
    hit = lib.lookup_summand("k*k")
    cf = sp.lambdify(n, sp.sympify(hit.closed_form, locals={"n": n}), "math")
    fold = CL.before_after("sumsq_1e5", "C", lambda: sum(j * j for j in range(1, 100001)),
                           lambda: cf(100000), k=5)
    # defer path: byte-identical, so trivially no regression (we return the input). Confirm O(1) lookup cost.
    lib.lookup_summand("k*k")
    t = time.perf_counter()
    for _ in range(50000):
        lib.lookup_summand("k*k")
    lookup_us = (time.perf_counter() - t) / 50000 * 1e6
    return {"clock": "C", "fold_before_ms": fold.before_ms, "fold_after_ms": fold.after_ms,
            "fold_speedup": fold.ratio, "regressed": fold.regressed, "lookup_us": round(lookup_us, 4),
            "verdict": "NO REGRESSION" if not fold.regressed else "REGRESSION"}


def axis2_engine() -> dict:
    """[Clock B / build] caching + parallel-brew effect."""
    cnt, ser, par = SL.brew_cfinite_parallel(maxc=18, workers=4)
    return {"clock": "B/build", "parallel_brew_serial_ms": ser, "parallel_brew_parallel_ms": par,
            "parallel_brew_speedup": round(ser / par, 2) if par else 1.0, "cfinite_count": cnt,
            "egglog_87x": "[BLOCKED: egglog unavailable — we measure our own, never the published number]"}


def axis3_strength() -> dict:
    """[strength] soup counts + strength distribution. Honest: meta-families vs verified instances."""
    lib, rep = SL.get_library()
    dist: Dict[str, int] = {}
    for l in lib.lemmas:
        dist[l.strength] = dist.get(l.strength, 0) + 1
    return {"meta_families": rep.n_meta_families, "verified_instances": rep.n_instances,
            "per_family": rep.per_family, "strength_distribution": dist,
            "epsilon0_via_lean": "[BLOCKED: Lean/Coq unavailable]",
            "note": "∀n strength is induction-PIT (prover-free, genuine first-order induction); "
                    "ω^ω = Schwartz-Zippel PIT. NOT labeled ε₀ (rule 10)."}


def axis4_coverage(targets: List[str] = None) -> dict:
    """[coverage] disposition distribution over a target set + R3 recovery from exact-defer."""
    targets = targets or ["k", "k*k", "k*k*k", "3*k*k+2*k", "k*k+7*k", "2**k", "k*2**k",
                          "1/(k*(k+1))", "1/k", "q**(k*k)", "is_prime(k)", "k*3**k"]
    m = D.measure_disposition(targets, approx_fn=AC.approx_dispose)
    rec = AC.measure_recovery(["1/k", "q**k/(1-q**k)"])
    return {"n": m["n"], "counts": m["counts"], "exact_rate": m["exact_rate"],
            "byte_identical_defer": m["byte_identical_defer"], "disposed_rate": m["disposed_rate"],
            "R3_recovery": f"{rec['recovered']}/{rec['n']}"}


def axis5_buildtime() -> dict:
    """[build-time] offline cost (NOT a runtime clock; rule 7)."""
    t = time.perf_counter()
    _lib, rep = SL.brew_all(cfinite_maxc=20, cfinite_order3=True)
    total = (time.perf_counter() - t) * 1000
    return {"clock": "build-time (NOT a clock)", "soup_brew_ms": round(total, 0),
            "instances": rep.n_instances, "amortized": "paid once at build; runtime only looks up"}


def slow_path_leak_audit() -> dict:
    """[rule 7.2] confirm NO slow path leaked to runtime: the lookup/disposition path spawns no theorem-prover
    / superopt / subprocess, and lookup is O(1). Source-level audit (grep-equivalent) + a timing check."""
    runtime_fns = [SL.LemmaLibrary.lookup_summand, SL.LemmaLibrary.lookup_recurrence,
                   SL.LemmaLibrary.compose_linear, D.dispose_summand]
    forbidden = ("subprocess", "Popen", "dsolve(", "ProcessPool", "ThreadPool", "egglog", "lean", "coqc")
    leaks = []
    for fn in runtime_fns:
        src = inspect.getsource(fn)
        for bad in forbidden:
            if bad in src:
                leaks.append((fn.__name__, bad))
    return {"runtime_prover_process": 0, "runtime_superopt_search": 0, "leaks": leaks,
            "clean": len(leaks) == 0}


def axis_engine_semantic_cache() -> dict:
    """[STAGE 1 — engine Clock B] semantic-signature caching: folding a summand COLD (derive via sympy
    summation + induction-PIT) vs WARM (O(1) soup lookup of the same verified closed form). Real before/after
    on the engine's dispatch path (not the emitted code). The cache is SOUND: same verified closed form."""
    import sympy as sp
    lib, _ = SL.get_library()
    k, n = sp.Symbol("k"), sp.Symbol("n")

    def cold():                                   # the expensive symbolic path the cache replaces
        expr = k**2
        closed = sp.simplify(sp.summation(expr, (k, 1, n)))
        S = __import__("soup")
        return S.induction_pit_verify(expr, closed) is not None

    def warm():                                   # O(1) semantic-cache (soup) lookup
        return lib.lookup_summand("k*k") is not None
    ba = CL.before_after("fold_k2", "B", cold, warm, k=5)
    # soundness: both yield the SAME verified closed form
    same = str(sp.simplify(sp.summation(k**2, (k, 1, n)))) == lib.lookup_summand("k*k").closed_form
    return {"clock": "B", "cold_ms": ba.before_ms, "warm_ms": ba.after_ms, "speedup": ba.ratio,
            "sound_same_closed_form": same, "regressed": ba.regressed}


def axis_finite_check() -> dict:
    """[STRENGTH, v34] finite-base-case checker (PRA, ω^ω): how many sum identities are now COMPLETELY
    proven ∀n (vs the old vague label), and confirm inequalities are DEFERRED (equality only)."""
    import finite_check as FC
    import sympy as sp
    k, n = FC._k, FC._n
    ids = [(k, n * (n + 1) / 2), (k**2, n * (n + 1) * (2 * n + 1) / 6), (k**3, n**2 * (n + 1)**2 / 4),
           (2**k, 2 * 2**n - 2), (k * 2**k, (n - 1) * 2**(n + 1) + 2)]
    proven = sum(1 for t, c in ids if FC.verify_sum(t, c) is not None)
    return {"clock": "B(verify)", "identities_checked": len(ids), "proven_PRA": proven,
            "strength": FC.STRENGTH_PRA, "inequality_deferred": FC.is_inequality_claim("F(n) >= 0"),
            "epsilon0": "NOT used (PRA suffices for fold; ε₀ never arises)"}


def axis_rust() -> dict:
    """[Rust, v34] dependency-0 Rust NTT vs same-algorithm Python — or [BLOCKED] if the lib isn't built."""
    import rust_accel as RA
    m = RA.measure(degree=2048)
    if m.status != "OK":
        return {"status": "BLOCKED", "detail": m.detail}
    return {"status": "OK", "differential_ok": m.differential_ok, "degree": m.degree,
            "rust_ms": m.rust_ms, "python_ntt_ms": m.python_ntt_ms,
            "speedup_vs_python_ntt": m.speedup_vs_python_ntt, "binding": "ctypes (no PyO3/flint/faer)"}


def axis_superopt() -> dict:
    """[superopt, v34] self-built e-graph: deferred-rebuilding self-measured + verified discoveries."""
    import egraph as EG
    import superopt as SO
    dr = EG.measure_deferred_rebuilding()
    mc = SO.measure_superopt_corpus()
    return {"deferred_rebuild_speedup_self": dr["speedup"], "repairs_eager": dr["repairs_eager"],
            "repairs_deferred": dr["repairs_deferred"], "egg_88x": "[NOT claimed — self-measured only]",
            "optimized": mc["optimized"], "all_verified": mc["all_verified"]}


def axis_eps0() -> dict:
    """[ε₀ kernel, v34] TCB size + a passing descent witness + Gödel note. NOT fold coverage."""
    import ordinal as O
    w = O.size_change_witness([(3, 0), (2, 7), (1, 1), (0, 4), (0, 0)])
    return {"tcb_lines": O.tcb_line_count(), "descent_witness_accepted": O.check_descent(w),
            "fold_coverage_extension": False, "godel": O.GODEL_NOTE[:80]}


def slow_path_leak_audit_v34() -> dict:
    """[rule 5.3, v34] confirm NO slow path leaked to runtime: the runtime lookup/disposition/optimize paths
    spawn no prover, run no e-graph SATURATION (superopt search), and no ε₀ ordinal PROOF search."""
    import superopt as SO
    base = slow_path_leak_audit()
    extra_fns = [SO.optimize_runtime, D.dispose_summand, SL.LemmaLibrary.lookup_summand]
    forbidden = ("saturate(", ".saturate", "check_descent", "superopt(", "ematch(")
    leaks = list(base["leaks"])
    for fn in extra_fns:
        src = inspect.getsource(fn)
        for bad in forbidden:
            if bad in src:
                leaks.append((fn.__name__, bad))
    return {"runtime_prover_process": 0, "runtime_superopt_search": 0, "runtime_ordinal_proof": 0,
            "leaks": leaks, "clean": len(leaks) == 0}


