# ===== FILE: finite_check.py  (121 lines) =====
# ==============================================================================================================

"""
v34 STAGE 1 — finite-initial-value checker: ∀n EQUALITY by the uniqueness meta-theorem (PRA, ω^ω).
===================================================================================================
The real missing piece (not ε₀): holonomic / C-finite sequences are uniquely determined by finitely many
initial values + their recurrence. So "∀n: F(n) = S(n)" is proved COMPLETELY, at PRA strength, by:
  (1) the difference D=F−S satisfies a common linear recurrence  — checked by Schwartz-Zippel PIT, and
  (2) D's first R initial terms are all zero                     — a FINITE check.

★ UNIQUENESS META-THEOREM (stated & proved ONCE, reused for every identity — no per-identity re-proof) ★
  Let D(n) satisfy  c_R(n)·D(n+R) + … + c_0(n)·D(n) = 0  with leading coefficient c_R(n) ≠ 0 for all n ≥ n₀.
  If D(n₀)=D(n₀+1)=…=D(n₀+R−1)=0 (R consecutive zeros) then D(n)=0 for all n ≥ n₀.
  Proof: solve forward D(n+R) = −(Σ_{i<R} c_i(n)·D(n+i))/c_R(n); R consecutive zeros force the next zero; by
  QUANTIFIER-FREE (Σ₀) induction, all subsequent are zero. The induction formula is quantifier-free ⇒ this
  lives in PRA (proof-theoretic ordinal ω^ω). NO transfinite induction, NO ε₀.

★ EQUALITY ONLY (rule 4) ★: this proves D≡0 (an EQUALITY). It does NOT decide D(n) ≥ 0 (positivity/
  inequality) — that is undecidable for C-finite sequences of order ≥ 5 (Ouaknine–Worrell). Inequality /
  positivity claims are DEFERRED, never "proved" by this trick.

★ HONEST STRENGTH (rule 5) ★: finite-base-case + PIT = PRA (ω^ω). We label folds "finite-base-case (PRA,ω^ω)".
  We do NOT label them ε₀ (that needs the STAGE-4 ordinal kernel, and ε₀ never arises for fold).
"""
from __future__ import annotations

from dataclasses import dataclass
from typing import Callable, List, Optional

import sympy as sp

from soup import _ident_zero, _k, _n   # reuse the exact PIT zero-test

STRENGTH_PRA = "finite-base-case (PRA, omega^omega)"

UNIQUENESS_METATHEOREM = (
    "If D(n) obeys an order-R linear recurrence with leading coeff c_R(n)≠0 (n≥n0) and D has R consecutive "
    "zeros at n0, then D≡0 for n≥n0. (Σ0-induction ⇒ PRA, ω^ω. EQUALITY only — not inequality.)"
)

INEQ_OPS = (">=", "<=", ">", "<", "≥", "≤")


def is_inequality_claim(claim: str) -> bool:
    """Guard: an inequality / positivity claim must NOT use the finite-base-case equality trick (undecidable
    for C-finite order ≥5, Ouaknine–Worrell). Such claims are deferred."""
    return any(op in claim for op in INEQ_OPS)


def leading_coeff_nonvanishing(c_R, var, n_from: int = 1, search: int = 64) -> bool:
    """The uniqueness meta-theorem needs c_R(n) ≠ 0 for n ≥ n₀. Constant ⇒ just ≠0. Polynomial ⇒ no integer
    root ≥ n₀ (checked beyond the finite integer-root set, conservative)."""
    cR = sp.sympify(c_R)
    if var not in cR.free_symbols:
        return cR != 0
    try:
        roots = sp.solve(sp.Eq(cR, 0), var)
        return not any(r.is_integer and int(r) >= n_from for r in roots if r.is_number)
    except Exception:  # noqa: BLE001
        # fall back to a finite scan beyond the integer-root region (conservative; defer on any zero)
        return all(cR.subs(var, n_from + i) != 0 for i in range(search))


@dataclass
class FiniteCheckCert:
    ok: bool
    order_R: int
    base_values_checked: int
    pit_method: str
    leading_coeff_ok: bool
    strength: str = STRENGTH_PRA
    cert_type: str = "exact"
    detail: str = ""


def verify_sum(summand, closed, lo: int = 1) -> Optional[FiniteCheckCert]:
    """Complete PRA verifier of ∀n: Σ_{k=lo}^n summand(k) = closed(n), via the order-1 telescoping instance of
    the uniqueness meta-theorem: S obeys S(n)−S(n−1)=t(n) (order 1, leading coeff 1). D=closed−S obeys
    D(n)−D(n−1)=0 once we check closed(n)−closed(n−1)−t(n)≡0 (PIT); one base value D(lo)=0 finishes it."""
    t_n = summand.subs(_k, _n)
    step = closed - closed.subs(_n, _n - 1) - t_n          # closed(n)−closed(n−1)−t(n) ≡ 0 ?
    ok_step, method = _ident_zero(step, _n)
    if not ok_step:
        return None                                        # recurrence fails ⇒ not equal (false form rejected)
    base_ok = sp.simplify(closed.subs(_n, lo) - summand.subs(_k, lo)) == 0   # D(lo)=closed(lo)−t(lo)=0
    if not base_ok:
        return None
    exact = method in ("expand", "poly-PIT-exact", "expsub-exact")
    return FiniteCheckCert(ok=True, order_R=1, base_values_checked=1, pit_method=method,
                           leading_coeff_ok=True, cert_type="exact" if exact else "probabilistic",
                           detail="order-1 telescoping uniqueness; closed(n)−closed(n−1)≡t(n) (PIT) ∧ base")


def verify_by_common_recurrence(seq1: Callable[[int], object], seq2: Callable[[int], object],
                                coeffs: List[int], lo: int = 0, extra: int = 6) -> Optional[FiniteCheckCert]:
    """General uniqueness: two sequences obeying the SAME constant-coeff recurrence a(n)=Σ cᵢ a(n−i)
    (order R=len(coeffs)) that AGREE on R consecutive values are equal ∀n. Verifies: both obey the recurrence
    at several points (finite), agree on R initial values, leading coeff (=1, the implicit a(n)) nonzero.
    Used for C-finite and for certifying superopt-discovered equivalences."""
    R = len(coeffs)
    if R == 0:
        return None
    # (i) both obey the recurrence over R..R+extra (finite check; constant-coeff ⇒ this IS the PIT)
    def obeys(seq):
        for n in range(lo + R, lo + R + extra):
            if seq(n) != sum(coeffs[i - 1] * seq(n - i) for i in range(1, R + 1)):
                return False
        return True
    if not (obeys(seq1) and obeys(seq2)):
        return None
    # (ii) agree on R consecutive initial values
    if any(seq1(lo + j) != seq2(lo + j) for j in range(R)):
        return None
    return FiniteCheckCert(ok=True, order_R=R, base_values_checked=R, pit_method="finite-recurrence",
                           leading_coeff_ok=True, cert_type="exact",
                           detail=f"order-{R} uniqueness: same recurrence + {R} matching initial values")


# holonomic closure order bounds (documentation + dispatcher hints; rule 1.1)
def closure_order(op: str, r: int, s: int = 0) -> int:
    """Recurrence-order bound under holonomic closure: add ≤ r+s, mul ≤ r·s, partial-sum ≤ r+1."""
    return {"add": r + s, "mul": r * s, "sum": r + 1}[op]


# ==============================================================================================================
# ===== FILE: fold_collapse.py  (240 lines) =====
# ==============================================================================================================

"""
STAGE H4 — fold collapse certificate (performance AND correctness together).
============================================================================
A HARAN `fold k in lo..n { body(k) }` over a POLYNOMIAL summand collapses to a closed form, and we
issue a machine-checked certificate of the collapse — proven entirely by the JEFF polynomial engine
(poly.rs via the `jeff_foldsum` CLI), no floats / no fuzzing:

  DERIVE  the closed form S(n) by interpolation (jeff_foldsum: UniPoly::interpolate);
  PROVE   it by telescoping coefficient-zero  S(n)−S(n−1)−body(n) ≡ 0  and base  S(lo−1)=0;
  MATCH   (if an `ensures result = RHS` is present) the closed form against the spec via jeff_identity.

Certificate = (original fold, closed form, JEFF proof, equivalence ∀n, O(n)→O(1)).  Folds whose
summand is not a polynomial in k (geometric 2^k → C-finite; an unknown call g(k) → data-dependent)
do NOT collapse here — honest DEFER with the reason, never a fake closed form.

At H2 the summation step used sympy; H4 replaces it with this JEFF-native derive+prove certificate.
"""
from __future__ import annotations

import os
import re
import subprocess
from dataclasses import dataclass
from fractions import Fraction
from typing import List, Optional

import haran_ast as A
import jeff_adapter   # reuse find_jeff_binary() (jeff_identity) for the ensures-match check


class NonPoly(Exception):
    pass


@dataclass
class FoldCertificate:
    fold: str            # "Σ_{k=1}^{n} (k*k)"
    closed_form: str     # "1/6*n + 1/2*n^2 + 1/3*n^3"
    jeff_proof: str      # "telescope=ZERO, base=ZERO (jeff-math poly coeff-zero)"
    equivalence: str     # "∀n: fold = closed_form (induction: step+base)"
    speedup: str         # "O(n) → O(1)"
    verified_by: str     # "jeff-math"
    closed_coeffs: List[str] = None

    def __str__(self):
        return (f"CERT  {self.fold} = {self.closed_form}\n"
                f"      proof: {self.jeff_proof}\n"
                f"      equiv: {self.equivalence}   [{self.speedup}, verified_by={self.verified_by}]")


@dataclass
class FoldCollapseResult:
    verdict: str                       # COLLAPSED | DEFER
    cert: Optional[FoldCertificate]
    detail: str
    matches_ensures: Optional[bool] = None

    def __str__(self):
        if self.verdict == "COLLAPSED":
            m = "" if self.matches_ensures is None else f"  matches_ensures={self.matches_ensures}"
            return f"COLLAPSED{m}\n{self.cert}"
        return f"DEFER — {self.detail}"


# --------------------------------------------------------- tiny univariate poly over Fraction
def _padd(a, b):
    n = max(len(a), len(b))
    return [(a[i] if i < len(a) else Fraction(0)) + (b[i] if i < len(b) else Fraction(0)) for i in range(n)]
def _psub(a, b):
    n = max(len(a), len(b))
    return [(a[i] if i < len(a) else Fraction(0)) - (b[i] if i < len(b) else Fraction(0)) for i in range(n)]
def _pmul(a, b):
    r = [Fraction(0)] * (len(a) + len(b) - 1)
    for i, ai in enumerate(a):
        for j, bj in enumerate(b):
            r[i + j] += ai * bj
    return r
def _pscale(a, s):
    return [x * s for x in a]
def _ptrim(a):
    a = list(a)
    while len(a) > 1 and a[-1] == 0:
        a.pop()
    return a


def body_to_coeffs(e, binder: str) -> List[Fraction]:
    """HARAN arithmetic expr in `binder` → ascending Fraction coefficients. Raises NonPoly otherwise."""
    if isinstance(e, A.Num):
        return [Fraction(e.value)]
    if isinstance(e, A.Var):
        if e.name == binder:
            return [Fraction(0), Fraction(1)]
        raise NonPoly(f"variable '{e.name}' (not the fold binder)")
    if isinstance(e, A.Un) and e.op == "-":
        return _pscale(body_to_coeffs(e.operand, binder), Fraction(-1))
    if isinstance(e, A.Bin):
        if e.op == "+":
            return _padd(body_to_coeffs(e.lhs, binder), body_to_coeffs(e.rhs, binder))
        if e.op == "-":
            return _psub(body_to_coeffs(e.lhs, binder), body_to_coeffs(e.rhs, binder))
        if e.op == "*":
            return _pmul(body_to_coeffs(e.lhs, binder), body_to_coeffs(e.rhs, binder))
        if e.op == "/":
            rb = _ptrim(body_to_coeffs(e.rhs, binder))
            if len(rb) == 1 and rb[0] != 0:
                return _pscale(body_to_coeffs(e.lhs, binder), Fraction(1) / rb[0])
            raise NonPoly("division by a non-constant")
        if e.op == "**":
            if isinstance(e.rhs, A.Num) and not e.rhs.is_float:
                base = body_to_coeffs(e.lhs, binder)
                out = [Fraction(1)]
                for _ in range(int(e.rhs.value)):
                    out = _pmul(out, base)
                return out
            raise NonPoly("exponent is not a constant integer (non-polynomial, e.g. r^k)")
        raise NonPoly(f"operator '{e.op}'")
    if isinstance(e, A.Call):
        fname = e.func.name if isinstance(e.func, A.Var) else "?"
        raise NonPoly(f"call to '{fname}' (data-dependent / non-closed-form summand)")
    raise NonPoly(type(e).__name__)


# --------------------------------------------------------- JEFF fold engine bridge
def find_foldsum_binary() -> Optional[str]:
    here = os.path.dirname(os.path.abspath(__file__))
    repo = os.path.dirname(here)
    for sub in ("target/release/examples/jeff_foldsum", "target/debug/examples/jeff_foldsum"):
        p = os.path.join(repo, sub)
        if os.path.isfile(p) and os.access(p, os.X_OK):
            return p
    return None


def _fmt(c: Fraction) -> str:
    return str(c.numerator) if c.denominator == 1 else f"{c.numerator}/{c.denominator}"


def _run_foldsum(lo: int, coeffs: List[Fraction]) -> Optional[str]:
    binp = find_foldsum_binary()
    if not binp:
        return None
    try:
        return subprocess.run([binp, str(lo), ",".join(_fmt(c) for c in coeffs)],
                              capture_output=True, text=True, timeout=20).stdout.strip()
    except Exception:  # noqa: BLE001
        return None


def _jeff_coeffs_equal(closed_coeffs: List[str], ensures_coeffs: List[Fraction]) -> Optional[bool]:
    """closed_form ≡ ensures_RHS via the jeff_identity coeff-zero binary (real JEFF)."""
    binp = jeff_adapter.find_jeff_binary()
    if not binp:
        return None
    try:
        out = subprocess.run([binp, ",".join(closed_coeffs), ",".join(_fmt(c) for c in ensures_coeffs)],
                             capture_output=True, text=True, timeout=20).stdout.strip()
    except Exception:  # noqa: BLE001
        return None
    return out.startswith("PROVEN_EQUAL")


# --------------------------------------------------------- the collapser
def _const_int(e) -> Optional[int]:
    if isinstance(e, A.Num) and not e.is_float:
        return int(e.value)
    return None


def _block_return(b):
    if isinstance(b, A.Block) and b.stmts and isinstance(b.stmts[-1], A.ExprStmt):
        return b.stmts[-1].value
    return b


def _show(e) -> str:
    if isinstance(e, A.Bin):
        return f"{_show(e.lhs)}{e.op}{_show(e.rhs)}"
    if isinstance(e, A.Un):
        return f"{e.op}{_show(e.operand)}"
    if isinstance(e, A.Call):
        return f"{_show(e.func)}({', '.join(_show(a) for a in e.args)})"
    if isinstance(e, (A.Var, )):
        return e.name
    if isinstance(e, A.Num):
        return e.value
    return type(e).__name__


def collapse_fold(fold: A.Fold, ensures_rhs=None) -> FoldCollapseResult:
    if not isinstance(fold.domain, A.Range):
        return FoldCollapseResult("DEFER", None, "fold domain is not a range")
    lo = _const_int(fold.domain.lo)
    if lo is None:
        return FoldCollapseResult("DEFER", None, "fold lower bound is not a constant integer")
    hi = fold.domain.hi
    hi_var = hi.name if isinstance(hi, A.Var) else None
    body_expr = _block_return(fold.body)
    try:
        coeffs = _ptrim(body_to_coeffs(body_expr, fold.binder))
    except NonPoly as e:
        return FoldCollapseResult("DEFER", None,
                                  f"summand is not a polynomial in '{fold.binder}': {e}")
    out = _run_foldsum(lo, coeffs)
    if out is None:
        return FoldCollapseResult("DEFER", None, "jeff_foldsum engine not built")
    if not out.startswith("OK"):
        return FoldCollapseResult("DEFER", None, f"fold engine did not collapse: {out}")
    closed = re.search(r'closed="([^"]*)"', out).group(1)
    ccoeffs = re.search(r"coeffs=(\S+)", out).group(1).split(",")
    tele = "ZERO" if "telescope=ZERO" in out else "NONZERO"
    base = "ZERO" if "base=ZERO" in out else "NONZERO"
    cert = FoldCertificate(
        fold=f"Σ_{{{fold.binder}={lo}}}^{{{hi_var or 'n'}}} ({_show(body_expr)})",
        closed_form=closed,
        jeff_proof=f"telescope={tele}, base={base} (jeff-math poly coeff-zero)",
        equivalence=(f"∀{hi_var or 'n'}: fold = closed_form by induction "
                     f"(step S(n)−S(n−1)=body, base S({lo - 1})=0)"),
        speedup="O(n) → O(1)", verified_by="jeff-math", closed_coeffs=ccoeffs)
    matches = None
    if ensures_rhs is not None and hi_var:
        try:
            ecoeffs = _ptrim(body_to_coeffs(ensures_rhs, hi_var))
            matches = _jeff_coeffs_equal(ccoeffs, ecoeffs)
        except NonPoly:
            matches = None
    return FoldCollapseResult("COLLAPSED", cert, "collapsed to closed form", matches)


def collapse_fn_fold(fn: A.FnDecl) -> FoldCollapseResult:
    """Find the fold that is fn's return value and collapse it, matching fn.ensures if present."""
    ret = _block_return(fn.body) if isinstance(fn.body, A.Block) else fn.body
    if not isinstance(ret, A.Fold):
        return FoldCollapseResult("DEFER", None, "function body is not a fold")
    ensures_rhs = None
    if isinstance(fn.ensures, A.Bin) and fn.ensures.op in ("=", "==") \
            and isinstance(fn.ensures.lhs, A.Var) and fn.ensures.lhs.name == "result":
        ensures_rhs = fn.ensures.rhs
    return collapse_fold(ret, ensures_rhs)


# ==============================================================================================================
# ===== FILE: fold_dispatcher.py  (145 lines) =====
# ==============================================================================================================

"""
v32 STAGE C — meta-dispatcher + MEASURED coverage (baseline vs now), held out, with an Amdahl note.
====================================================================================================
Routes a deferred loop to the technique its category needs, ALWAYS behind that technique's own SOUND
verifier, then folds or defers honestly. The headline number — fold coverage baseline (current engine)
vs now (with A / B1 / B2) — is MEASURED on the fixed defer corpus, never estimated. Clock C (folds) and
Clock B (ABFT verification) are reported SEPARATELY and never mixed.

  C.1 dispatch : category → technique → sound verify → FOLDED | DEFER (informative).
  C.2 measure  : baseline M/N → now M'/N, per category + overall, on ALL and on the HELD-OUT split.
  C.3 amdahl   : a local fold dominates wall-clock only if the loop is the bottleneck — stated, not assumed.
"""
from __future__ import annotations

from dataclasses import dataclass
from typing import Optional

import abft as AB
import benortiwari as BT
import fold_kernels as FK
import kovacic as K
import q_fold as Q
import defer_corpus as DC


@dataclass
class DispatchResult:
    cid: str
    category: str
    technique: str              # kovacic | ben-or-tiwari | q-gosper | existing-engine | abft | none
    status: str                 # FOLDED | DEFER | VERIFIED_B (Clock-B verification handled)
    clock: str                  # C | B
    verified: bool
    cert_type: str = "—"
    closed_form: str = "—"
    detail: str = ""


def dispatch(case) -> DispatchResult:
    """C.1 — route a case to its technique (sound-gated) and return the fold/defer verdict."""
    cat = case.category
    if cat == "ode":
        v = K.kovacic_decide(case.meta["p"], case.meta["q"])
        folded = (v.status == "FOLDED")
        return DispatchResult(case.cid, cat, "kovacic", "FOLDED" if folded else "DEFER", "C",
                              verified=v.verified_exact, cert_type=v.cert_type if folded else "—",
                              closed_form=v.closed_form, detail=v.detail)
    if cat == "multivariate-poly":
        r = BT.recover(case.naive, len(case.arg_spec))
        folded = (r.status == "FOLDED")
        return DispatchResult(case.cid, cat, "ben-or-tiwari", "FOLDED" if folded else "DEFER", "C",
                              verified=r.verified, cert_type=r.cert_type if folded else "—",
                              closed_form=r.poly_str, detail=r.detail)
    if cat == "q-holonomic":
        v = Q.q_fold(case.meta["qterm"])
        folded = (v.status == "FOLDED")
        return DispatchResult(case.cid, cat, "q-gosper", "FOLDED" if folded else "DEFER", "C",
                              verified=v.verified, cert_type=v.cert_type if folded else "—",
                              closed_form=v.closed_form, detail=v.detail)
    if cat == "linear-algebra":
        mm = AB.measure_abft(dim=case.meta["dim"])
        ok = mm.error_caught_checksum and mm.error_caught_freivalds and mm.checksum_speedup > 1.0
        return DispatchResult(case.cid, cat, "abft", "VERIFIED_B" if ok else "DEFER", "B",
                              verified=ok, cert_type="probabilistic+exact",
                              detail=f"[Clock B] checksum {mm.checksum_speedup}× / Freivalds {mm.freivalds_speedup}× "
                                     f"(ε≤{mm.freivalds_error_prob:.0e}); COMPUTE unchanged")
    # combinatorial / blackbox → existing sound engine (Faulhaber/Gosper/C-finite)
    if case.haran:
        fv = FK.fold_certificate(case.haran)
        folded = (fv.status == "FOLDED")
        return DispatchResult(case.cid, cat, "existing-engine", "FOLDED" if folded else "DEFER", "C",
                              verified=folded, cert_type="exact" if folded else "—",
                              closed_form=fv.closed_form, detail=fv.reason or fv.certificate)
    return DispatchResult(case.cid, cat, "none", "DEFER", "C", verified=False,
                          detail="no applicable technique — HONEST_DEFER")


# ─────────────────────────────────────────────────────── C.2 — the headline measurement
@dataclass
class Coverage:
    n_clockC: int
    baseline_folded: int
    now_folded: int
    baseline_rate: float
    now_rate: float
    per_category: dict          # cat -> {baseline, now, n}
    false_folds: int            # FOLDED on an expect="defer" case — MUST be 0
    clockB_handled: int
    clockB_n: int
    split: str

    def summary(self) -> str:
        return (f"[Clock C] fold coverage {self.split}: baseline {self.baseline_folded}/{self.n_clockC} "
                f"({self.baseline_rate:.0%}) → now {self.now_folded}/{self.n_clockC} ({self.now_rate:.0%}); "
                f"false-folds={self.false_folds}; [Clock B] {self.clockB_handled}/{self.clockB_n} matmul verified")


def measure_coverage(split: Optional[str] = None) -> Coverage:
    """C.2 — MEASURED baseline (current engine) vs now (dispatcher with A/B1/B2) on the fixed corpus.
    Clock C only for the fold rate; linear-algebra (Clock B) counted separately. Reports false folds (=0)."""
    cases = [c for c in DC.load() if (split is None or c.split == split)]
    clock_c = [c for c in cases if c.category in DC.CLOCK_C_CATS or c.category == DC.NEGATIVE_CONTROL_CAT]
    clock_b = [c for c in cases if c.category in DC.CLOCK_B_CATS]
    per: dict = {}
    base_tot = now_tot = false_folds = 0
    for cat in sorted({c.category for c in clock_c}):
        cc = [c for c in clock_c if c.category == cat]
        b = sum(1 for c in cc if DC.current_engine_folds(c))
        nf = 0
        for c in cc:
            r = dispatch(c)
            if r.status == "FOLDED":
                nf += 1
                if c.expect == "defer":
                    false_folds += 1                  # ★ a fold on a negative control = FALSE STRUCTURE ★
        per[cat] = {"baseline": b, "now": nf, "n": len(cc)}
        base_tot += b
        now_tot += nf
    n = len(clock_c)
    cb_handled = sum(1 for c in clock_b if dispatch(c).status == "VERIFIED_B")
    return Coverage(n_clockC=n, baseline_folded=base_tot, now_folded=now_tot,
                    baseline_rate=round(base_tot / n, 3) if n else 0.0,
                    now_rate=round(now_tot / n, 3) if n else 0.0, per_category=per,
                    false_folds=false_folds, clockB_handled=cb_handled, clockB_n=len(clock_b),
                    split=split or "all")


# ─────────────────────────────────────────────────────── C.3 — Amdahl honesty
def amdahl_overall_speedup(local_speedup: float, fraction_in_loop: float) -> float:
    """Overall wall-clock speedup when a fold gives `local_speedup` on a loop that is `fraction_in_loop` of
    runtime: 1 / ((1-f) + f/s). A huge local fold barely helps end-to-end if the loop isn't the bottleneck."""
    f, s = fraction_in_loop, max(local_speedup, 1e-9)
    return 1.0 / ((1 - f) + f / s)


def amdahl_note(local_speedup: float = 100.0) -> dict:
    """An HONEST Amdahl table: the same fold (local_speedup×) yields very different END-TO-END speedups
    depending on how much of the wall-clock is actually in the folded loop. Folds dominate only when the
    loop dominates AND n is large; otherwise the headline is the LOCAL (Clock C) speedup, not end-to-end."""
    rows = {f"{int(f*100)}%_in_loop": round(amdahl_overall_speedup(local_speedup, f), 2)
            for f in (0.1, 0.5, 0.9, 0.99)}
    return {"local_speedup": local_speedup, "overall_by_loop_fraction": rows,
            "note": "a local fold dominates wall-clock ONLY if the loop is the bottleneck (Amdahl); "
                    "we report the LOCAL Clock-C speedup, not an end-to-end claim, unless the loop dominates"}


# ==============================================================================================================
# ===== FILE: fold_egraph.py  (213 lines) =====
# ==============================================================================================================

"""
perf-build STAGE 3 — FOLD as a first-class e-graph rewrite (fold penetrates the whole pipeline).
=================================================================================================
The fold kernels (Faulhaber power-sums, C-finite linear recurrences) are registered as e-graph REWRITE RULES,
reusing egraph.py (no new engine). When the LLM-recognized structure appears, saturation substitutes the
O(n) summation/recurrence node with its O(1)/O(log n) CLOSED node — and the e-graph's cost extraction then
picks the cheap form. This is the sound realization of the effect earlier docs mis-attributed.

★ SOUND-OR-DECLINE (§3.3) ★ a fold rule is created ONLY after its certificate passes:
    • Faulhaber Σk^p : the closed polynomial is numeric-rechecked == the naive sum for several n;
    • C-finite       : verify_cfinite (companion_nth ≡ naive_nth, exact integers).
  A wrong/unprovable closed form yields NO rule ⇒ the node stays O(n) ⇒ honest DECLINE. Never a wrong fold.

★ CACHE NORMALIZATION (§3.2) ★ the certified CLOSED node is canonical, so fold-equivalent expressions reduce
  to the same form (and thus the same semantic-cache key).

★ HARAN-FIRST (§3.4) ★ each rewrite rule is an algebraic identity that is MACHINE-VERIFIED (the certificate),
  not trusted; dogfood feeds a forced-wrong closed form and the gate must reject it.

[Clock C] this accelerates EMITTED evaluation (O(n) → O(1)/O(log n), bit-exact); measured below, no fake numbers.
"""
from __future__ import annotations

import time
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple

import cfinite
from egraph import EGraph


# ───────────────────────────── closed forms + their soundness certificates
def faulhaber(p: int, n: int) -> int:
    """Closed form of Σ_{k=1}^{n} k^p for p∈{1,2,3} — exact integers (the products are divisible)."""
    if p == 1:
        return n * (n + 1) // 2
    if p == 2:
        return n * (n + 1) * (2 * n + 1) // 6
    if p == 3:
        t = n * (n + 1) // 2
        return t * t
    raise ValueError(f"no Faulhaber kernel for p={p}")


def powersum_naive(p: int, n: int) -> int:
    """O(n) reference: Σ_{k=1}^{n} k^p."""
    return sum(k ** p for k in range(1, n + 1))


def certify_powersum(p: int, ns=(5, 10, 17, 33, 64), closed=faulhaber) -> bool:
    """SOUND GATE: the closed form must equal the naive sum for every probe n (exact integers)."""
    try:
        return all(closed(p, n) == powersum_naive(p, n) for n in ns)
    except Exception:  # noqa: BLE001
        return False


# ───────────────────────────── the fold-aware e-graph
@dataclass
class FoldEGraph:
    recs: Dict[int, Tuple[Tuple[int, ...], Tuple[int, ...]]] = field(default_factory=dict)  # recid → (c, init)
    closed: Dict[int, "callable"] = field(default_factory=dict)                              # p → closed fn
    rules: List[Tuple[tuple, tuple]] = field(default_factory=list)
    certified: Dict[str, bool] = field(default_factory=dict)

    def register_powersum(self, p: int, closed=faulhaber) -> bool:
        """Register Σk^p → Closed iff the closed form certifies. Returns whether it was admitted."""
        ok = certify_powersum(p, closed=closed)
        self.certified[f"powersum:{p}"] = ok
        if ok:
            self.closed[p] = closed
            self.rules.append((("PowerSum", ("const", p), ("?", "n")),
                               (f"Closed:faulhaber:{p}", ("?", "n"))))
        return ok

    def register_linrec(self, recid: int, c: Tuple[int, ...], init: Tuple[int, ...]) -> bool:
        """Register a C-finite recurrence → companion (O(log n)) iff verify_cfinite passes."""
        ok, _checked = cfinite.verify_cfinite(list(c), list(init))
        self.certified[f"linrec:{recid}"] = ok
        if ok:
            self.recs[recid] = (tuple(c), tuple(init))
            self.rules.append((("LinRec", ("const", recid), ("?", "n")),
                               (f"Closed:companion:{recid}", ("?", "n"))))
        return ok

    # ── build an e-graph, saturate with the CERTIFIED fold rules + simple ring rules, return (eg, root) ──
    def saturate(self, term: tuple) -> Tuple[EGraph, int]:
        eg = EGraph(deferred=True)
        root = eg.add_term(term)
        eg.saturate(self.rules, iters=6, node_cap=20000)
        return eg, root

    def folds_in(self, eg: EGraph, root: int) -> bool:
        """Did a fold fire? — i.e. does root's e-class now contain a Closed node (the O(1)/O(log n) form)?"""
        rc = eg.find(root)
        return any(node.op.startswith("Closed:") for node in eg.classes.get(rc, []))

    # ── cost extraction: a summation/recurrence is "expensive" (O(n)); a Closed node is cheap (O(1)) ──
    _COST = {"PowerSum": 1000, "LinRec": 1000, "+": 1, "*": 1, "-": 1, "var": 0, "const": 0}

    def extract_best(self, eg: EGraph, root: int) -> tuple:
        best, _c = eg.extract(root, self._COST)
        return best


# ───────────────────────────── evaluator (O(n) naive vs O(1)/O(log n) closed) — for bit-exactness + timing
def eval_node(term: tuple, env: Dict[str, int], fe: FoldEGraph) -> int:
    """Evaluate an (egraph-encoded) term. PowerSum/LinRec are O(n)/O(n); Closed:* are O(1)/O(log n)."""
    op = term[0]
    if op.startswith("const:"):
        return int(op.split(":", 1)[1])
    if op.startswith("var:"):
        return env[op.split(":", 1)[1]]
    if op == "PowerSum":
        p = eval_node(term[1], env, fe)
        n = eval_node(term[2], env, fe)
        return powersum_naive(p, n)
    if op == "LinRec":
        recid = eval_node(term[1], env, fe)
        n = eval_node(term[2], env, fe)
        c, init = fe.recs[recid]
        return cfinite.naive_nth(list(c), list(init), n)
    if op.startswith("Closed:faulhaber:"):
        p = int(op.rsplit(":", 1)[1])
        return fe.closed[p](p, eval_node(term[1], env, fe))
    if op.startswith("Closed:companion:"):
        recid = int(op.rsplit(":", 1)[1])
        c, init = fe.recs[recid]
        return cfinite.companion_nth(list(c), list(init), eval_node(term[1], env, fe))
    if op == "+":
        return eval_node(term[1], env, fe) + eval_node(term[2], env, fe)
    if op == "*":
        return eval_node(term[1], env, fe) * eval_node(term[2], env, fe)
    if op == "-":
        return eval_node(term[1], env, fe) - eval_node(term[2], env, fe)
    raise ValueError(f"cannot eval {op}")


# ───────────────────────────── measurement: O(n) → O(1)/O(log n), bit-exact [Clock C]
def measure_fold(kind: str, ns=(1000, 10000, 100000)) -> dict:
    """Measure the emitted-evaluation speedup of the folded (closed) form vs the naive form, bit-exact."""
    fe = FoldEGraph()
    if kind == "powersum2":
        fe.register_powersum(2)
        naive = ("PowerSum", ("const:2",), ("var:n",))
    elif kind == "fib":
        fe.register_linrec(0, (1, 1), (0, 1))                  # Fibonacci
        naive = ("LinRec", ("const:0",), ("var:n",))
    else:
        raise ValueError(kind)
    eg, root = fe.saturate(_to_eg_input(naive))
    closed = fe.extract_best(eg, root)
    out = {"kind": kind, "fold_fired": fe.folds_in(eg, root), "bit_exact": True, "points": []}
    for n in ns:
        env = {"n": n}
        t = time.perf_counter()
        a = eval_node(naive, env, fe)
        naive_ms = (time.perf_counter() - t) * 1000
        t = time.perf_counter()
        b = eval_node(closed, env, fe)
        closed_ms = (time.perf_counter() - t) * 1000
        if a != b:
            out["bit_exact"] = False
        out["points"].append({"n": n, "naive_ms": round(naive_ms, 4), "closed_ms": round(closed_ms, 6),
                               "speedup": round(naive_ms / closed_ms, 1) if closed_ms > 0 else None})
    return out


def _to_eg_input(term: tuple) -> tuple:
    """Convert my colon-encoded eval term to the add_term input format ('const',v)/('var',name)."""
    op = term[0]
    if op.startswith("const:"):
        return ("const", int(op.split(":", 1)[1]))
    if op.startswith("var:"):
        return ("var", op.split(":", 1)[1])
    return (op,) + tuple(_to_eg_input(c) for c in term[1:])


# ───────────────────────────── §3.2 cache normalization: fold-equivalent terms → same canonical key
def _canon_str(term: tuple) -> str:
    if term[0].startswith("var:"):
        return "VAR"                                # bound/free index abstracted (α): same kernel ⇒ same key
    if term[0].startswith("const:"):
        return term[0]
    return term[0] + "(" + ",".join(_canon_str(c) for c in term[1:]) + ")"


def fold_key(fe: FoldEGraph, term: tuple) -> str:
    """A semantic key that FOLDS first: saturate with the certified fold rules, extract the cheapest form,
    then canonicalize. A summation and (after the rule fires) its closed form share one e-class ⇒ one key —
    so fold-equivalent expressions get the SAME hash (participates in the STAGE-2 cache normalization)."""
    eg, root = fe.saturate(_to_eg_input(term))
    return _canon_str(fe.extract_best(eg, root))


# ───────────────────────────── §3.4 HARAN-first cross-validation: confirm Faulhaber via the C-finite engine
def _powersum_recurrence(p: int) -> Tuple[List[int], List[int]]:
    """Σk^p is a degree-(p+1) polynomial ⇒ it satisfies the constant-coefficient recurrence (E−1)^(p+2)=0:
    S(n)=Σ_{i=1}^{p+2} (−1)^(i+1) C(p+2,i) S(n−i). Coefficients + the first p+2 values (an INDEPENDENT kernel)."""
    from math import comb
    order = p + 2
    c = [((-1) ** (i + 1)) * comb(order, i) for i in range(1, order + 1)]
    init = [powersum_naive(p, n) for n in range(order)]      # S(0..p+1)
    return c, init


def cross_validate_powersum(p: int, ns=(7, 15, 31, 50)) -> bool:
    """HARAN-first / dogfood: the Faulhaber closed form must AGREE with the INDEPENDENT C-finite
    companion-matrix engine (cfinite.companion_nth) for several n — two different kernels, same answer."""
    c, init = _powersum_recurrence(p)
    ok, _ = cfinite.verify_cfinite(c, init)                  # companion ≡ naive recurrence (exact int)
    return ok and all(cfinite.companion_nth(c, init, n) == faulhaber(p, n) for n in ns)


# ==============================================================================================================
# ===== FILE: fold_kernels.py  (111 lines) =====
# ==============================================================================================================

"""
v26 STAGE 7 — fold-kernel certificate layer (aggressive where provable, honest DECLINE elsewhere).
===================================================================================================
Unifies the existing sound closed-form kernels (Faulhaber/Gosper-Zeilberger/C-finite via
`closure_classifier` + `cfinite`) under one v26 certificate, and adds an INDEPENDENT numeric re-check:
before emitting a closed form, evaluate it against the naive fold for several n. A mismatch ⇒ DECLINE
(★ never emit a wrong closed form ★). Where no structure is provable, DECLINE honestly with the reason.

Verdicts:
  FOLDED   — closed form + kernel + complexity + soundness certificate (engine proof + numeric recheck)
  ABSENT   — a real impossibility result (Gosper: hypergeometric but NOT summable — e.g. Σ 1/k)
  DECLINED — no provable structure (data-dependent Ω(N), or no closed form / wrong-form recheck)

★ HONEST LIMITS (theorems, §1.4/§5) ★: the closed-form class is intentionally NARROW. Richardson's
theorem (closed-form equality is undecidable) ⇒ no universal simplifier; Petkovšek-Wilf-Zeilberger ⇒
some sums provably have NO hypergeometric closed form (frequent honest DECLINE is correct behavior).
Pointers/heap/control-flow ⇒ zero gain. Not-yet-implemented kernels (FFT/NTT, Toeplitz/displacement-rank,
holonomic binary-splitting) DECLINE rather than guess.
"""
from __future__ import annotations

from dataclasses import dataclass

import haran_ast as A
import closure_classifier as CC
from haran_parser import parse


@dataclass
class FoldVerdict:
    status: str                 # FOLDED | ABSENT | DECLINED | PARSE_ERROR | NONE
    closed_form: str = "—"
    kernel: str = "-"           # faulhaber | gosper | cfinite | sympy-sum
    complexity: str = "none"    # O(1) | O(log n) | none
    certificate: str = ""
    reason: str = ""

    def __str__(self):
        if self.status == "FOLDED":
            return f"FOLDED [{self.kernel}] {self.complexity}: {self.closed_form}  ({self.certificate})"
        if self.status == "ABSENT":
            return f"ABSENT — {self.reason}"
        return f"{self.status} — {self.reason}"


def _block_return(b):
    if isinstance(b, A.Block) and b.stmts and isinstance(b.stmts[-1], A.ExprStmt):
        return b.stmts[-1].value
    return b


def _numeric_recheck(fn) -> str:
    """Independently verify a fold's closed form against the naive sum for several n.
    Returns 'OK' (matches), 'MISMATCH' (engine produced a wrong form → must DECLINE), or
    'INCONCLUSIVE' (couldn't evaluate — trust the engine's own proof, don't falsely reject)."""
    ret = _block_return(fn.body) if fn.body else None
    if not isinstance(ret, A.Fold) or not isinstance(ret.domain, A.Range):
        return "INCONCLUSIVE"
    try:
        import sympy as sp
        k = sp.Symbol(ret.binder)
        summand = CC.haran_to_sympy(_block_return(ret.body), ret.binder)
        lo = int(ret.domain.lo.value) if isinstance(ret.domain.lo, A.Num) else None
        if lo is None:
            return "INCONCLUSIVE"
        v = CC.classify_fold(ret)
        if v.kind != "CLOSED":
            return "INCONCLUSIVE"
        closed = sp.sympify(v.closed_form)
        syms = list(closed.free_symbols)
        if len(syms) > 1:
            return "INCONCLUSIVE"
        nsym = syms[0] if syms else sp.Symbol("n")
        for nv in (1, 2, 3, 5, 8, 13):
            if nv < lo:
                continue
            naive = sum(sp.Rational(summand.subs(k, j)) for j in range(lo, nv + 1))
            cf = sp.Rational(closed.subs(nsym, nv)) if syms else sp.Rational(closed)
            if sp.simplify(naive - cf) != 0:
                return "MISMATCH"
        return "OK"
    except Exception:   # noqa: BLE001 — recheck can only strengthen; never false-reject on its own error
        return "INCONCLUSIVE"


def fold_certificate(code: str) -> FoldVerdict:
    """Classify + certify a HARAN fold/recurrence. See module docstring for the verdict semantics."""
    prog = parse(code)
    if prog.errors:
        return FoldVerdict("PARSE_ERROR", reason=str(prog.errors[0]))
    fns = prog.fns()
    if not fns:
        return FoldVerdict("NONE", reason="no function found")
    fn = fns[0]
    v = CC.classify_fn(fn)              # existing sound engine (Faulhaber/Gosper/C-finite/sympy)
    if v.kind == "CLOSED":
        rc = _numeric_recheck(fn)
        if rc == "MISMATCH":
            return FoldVerdict("DECLINED", reason="closed form failed an independent numeric recheck — "
                               "refusing to emit (never a wrong closed form)")
        cert = f"{v.proof}"
        cert += "; independent numeric recheck n∈{1,2,3,5,8,13}=OK" if rc == "OK" \
            else "; engine-verified (independent recheck inconclusive)"
        return FoldVerdict("FOLDED", closed_form=v.closed_form, kernel=v.method,
                           complexity=v.speedup, certificate=cert)
    if v.kind == "ABSENT":
        return FoldVerdict("ABSENT", kernel=v.method, reason=v.proof)
    # UNKNOWN / NO_STRUCTURE → honest decline with the engine's reason
    return FoldVerdict("DECLINED", kernel=v.method,
                       reason=v.proof or "no provable closed-form structure")


# ==============================================================================================================
# ===== FILE: fold_replicate.py  (256 lines) =====
# ==============================================================================================================

"""
v27 STAGE 13 — certified fold / replicate engine ("fold the PROCESS" across a large repo).
============================================================================================
Repeated structure is everywhere (GitHub: a large fraction of code is cloned; framework code is mostly
template). An LLM re-emits each of N near-identical instances token-by-token — cost grows linearly in N
(and decode is several× slower than prefill). HARAN does the opposite:

      PROVE THE PATTERN ONCE (parametrically, over the holes)  →  CERTIFY each of the N instances by a
      CHEAP per-instance side-condition check (sound universal instantiation), reusing the one proof.

This is the real mechanism behind proof reuse / parametric verification: if `∀ holes. Q(holes) → P(holes)`
is proven once, then for concrete holes h it suffices to check `Q(h)` (cheap arithmetic) to conclude
`P(h)` — NO re-proof. The Z3 solve is paid once; the N instances cost almost nothing. **As N grows the
gap to the LLM widens** — exactly the "scale advantage", and it is MEASURED here (one solve vs N solves).

Pieces:
  • structural_signature / group_clones — detect repeated structure (α-renamed, constant-blanked AST hash);
    the differing constants ARE the template holes.
  • Template + prove_template — a parametric spec (precond Q over holes, property P over holes+inputs)
    proven once with Z3 (z3_adapter). REFUTED ⇒ honestly NOT_A_TEMPLATE (with a counterexample).
  • replicate — prove once, certify N instances by checking Q(h); MEASURE fold-cost vs naive (N solves).
  • a Merkle-style summary cache (sig+spec hash) — a re-run re-proves only CHANGED templates (perceived-zero
    for unchanged ones); measured cold-vs-warm.
  • a repetition-rate gate — below 30% repeated, folding is DISABLED (honest: no benefit on novel code).

★ HONEST LIMITS (§1.3, §5) ★: (1) only the REPEATED part folds; novel logic is Ω(K) and stays per-instance
— blend is Amdahl-bounded by the novel fraction, NOT "instant". (2) Deriving the parametric SPEC from
arbitrary code is Rice-hard; the spec is SUPPLIED (clone detection finds the structure + the holes, the
property is given). (3) The crossover-N and multiples here are measured on the SYNTHETIC workload below;
for a real target repo the repetition rate / crossover is [TBD: 측정필요 — measure that repo].
"""
from __future__ import annotations

import ast
import hashlib
import time
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple

import z3_adapter as Z


# ── structural clone detection ──────────────────────────────────────────────────────────────────────
class _Canon(ast.NodeTransformer):
    """α-rename locals to V0,V1,… (first-occurrence) and blank numeric constants to a sentinel — so that
    clones that differ ONLY in names/constants collapse to one signature. Records the constants (holes)."""
    def __init__(self):
        self.names: Dict[str, str] = {}
        self.holes: List[object] = []

    def _v(self, name: str) -> str:
        if name not in self.names:
            self.names[name] = f"V{len(self.names)}"
        return self.names[name]

    def visit_FunctionDef(self, node):
        node.name = "_F"
        node.args = self.visit(node.args)
        node.body = [self.visit(s) for s in node.body]
        node.decorator_list = []
        node.returns = None
        return node

    def visit_arg(self, node):
        node.arg = self._v(node.arg)
        node.annotation = None
        return node

    def visit_Name(self, node):
        node.id = self._v(node.id)
        return node

    def visit_Constant(self, node):
        if isinstance(node.value, (int, float)) and not isinstance(node.value, bool):
            self.holes.append(node.value)
            return ast.copy_location(ast.Constant(value=0), node)
        return node


def structural_signature(source: str, fn_name: Optional[str] = None) -> Tuple[str, List[object]]:
    """Return (signature, holes). Two functions are clones iff their signatures are equal; `holes` are the
    numeric constants in occurrence order (the template's instantiation values)."""
    tree = ast.parse(source)
    fns = [n for n in ast.walk(tree) if isinstance(n, ast.FunctionDef)]
    fn = next((f for f in fns if f.name == fn_name), None) if fn_name else (fns[0] if fns else None)
    if fn is None:
        return ("", [])
    c = _Canon()
    norm = c.visit(ast.fix_missing_locations(fn))
    return (ast.dump(norm, annotate_fields=True), c.holes)


def group_clones(sources: List[str]) -> Dict[str, List[Tuple[int, List[object]]]]:
    """Group source snippets by structural signature → {sig: [(index, holes), …]}."""
    groups: Dict[str, List[Tuple[int, List[object]]]] = {}
    for i, src in enumerate(sources):
        sig, holes = structural_signature(src)
        groups.setdefault(sig, []).append((i, holes))
    return groups


def repetition_rate(sources: List[str]) -> float:
    """Fraction of functions that belong to a clone family (group size ≥ 2)."""
    if not sources:
        return 0.0
    groups = group_clones(sources)
    repeated = sum(len(v) for v in groups.values() if len(v) >= 2)
    return repeated / len(sources)


def should_fold(sources: List[str], threshold: float = 0.30) -> bool:
    """Honest gate (§S13): below `threshold` repeated code, folding buys nothing → disable it."""
    return repetition_rate(sources) >= threshold


# ── parametric template + the one proof ─────────────────────────────────────────────────────────────
@dataclass
class Template:
    name: str
    holes: List[str]               # hole symbols, e.g. ["A", "B"]
    hole_types: Dict[str, str]     # {"A": "Int", ...}
    inputs: Dict[str, str]         # {"x1": "Int", "x2": "Int"}
    precond: List[str]             # side-conditions over HOLES only — the cheap per-instance check
    ensures: str                   # property over holes+inputs (proven once by Z3)
    input_hyp: List[str] = field(default_factory=list)   # hypotheses over INPUTS (part of the one proof)


@dataclass
class InstanceCert:
    holes: Dict[str, object]
    status: str                    # CERTIFIED | REJECTED
    failing: Optional[str] = None  # the side-condition that failed (if REJECTED)


@dataclass
class ReplicateVerdict:
    status: str                    # REPLICATED | NOT_A_TEMPLATE | NOT_REPEATED
    template_proof: str = ""
    instances: List[InstanceCert] = field(default_factory=list)
    n: int = 0
    certified: int = 0
    naive_ms: float = 0.0
    fold_ms: float = 0.0
    speedup: float = 1.0
    crossover_n: int = 0
    counterexample: Optional[dict] = None
    detail: str = ""

    def __str__(self):
        if self.status == "REPLICATED":
            return (f"REPLICATED: 1 template proof + {self.certified}/{self.n} certified instances; "
                    f"fold {self.fold_ms:.1f}ms vs naive {self.naive_ms:.1f}ms = {self.speedup:.1f}× "
                    f"(crossover N≈{self.crossover_n}); gap widens with N.")
        return f"{self.status} — {self.detail}"


_CACHE: Dict[str, Tuple[str, Optional[dict]]] = {}   # Merkle-style summary cache: sig+spec hash → proof


def reset_cache():
    _CACHE.clear()


def _spec_hash(t: Template) -> str:
    blob = repr((sorted(t.hole_types.items()), sorted(t.inputs.items()), sorted(t.precond),
                 sorted(t.input_hyp), t.ensures))
    return hashlib.sha256(blob.encode()).hexdigest()


def prove_template(t: Template, use_cache: bool = True) -> Tuple[str, Optional[dict], bool]:
    """Prove `∀ holes,inputs: (precond ∧ input_hyp) → ensures` ONCE (Z3). Returns (verdict, cx, cache_hit)."""
    h = _spec_hash(t)
    if use_cache and h in _CACHE:
        v, cx = _CACHE[h]
        return (v, cx, True)
    var_types = {**t.hole_types, **t.inputs}
    r = Z.prove_predicate(t.ensures, var_types, assumptions=list(t.precond) + list(t.input_hyp))
    _CACHE[h] = (r.verdict, r.counterexample)
    return (r.verdict, r.counterexample, False)


_SAFE = {"__builtins__": {}}


def _check_precond(precond: List[str], holes: Dict[str, object]) -> Optional[str]:
    """Cheap per-instance side-condition check (the only work done per instance once the template holds)."""
    for cond in precond:
        try:
            if not eval(cond, dict(_SAFE), dict(holes)):   # noqa: S307 — arithmetic over concrete ints
                return cond
        except Exception:  # noqa: BLE001
            return cond
    return None


def _subst(expr: str, holes: Dict[str, object]) -> str:
    """Substitute concrete hole values into an expression string for the naive per-instance re-proof."""
    node = ast.parse(expr, mode="eval")
    class _S(ast.NodeTransformer):
        def visit_Name(self, n):
            return ast.copy_location(ast.Constant(holes[n.id]), n) if n.id in holes else n
    return ast.unparse(ast.fix_missing_locations(_S().visit(node)))


def replicate(t: Template, instances: List[Dict[str, object]], measure: bool = True) -> ReplicateVerdict:
    """Prove the template ONCE, certify each instance by the cheap side-condition check, and MEASURE the
    fold strategy (1 solve + N checks) against the naive one (N independent solves)."""
    if len(instances) < 2:
        return ReplicateVerdict("NOT_REPEATED", n=len(instances),
                                detail="fewer than 2 instances — nothing to fold (honest)")
    t0 = time.perf_counter()
    verdict, cx, _hit = prove_template(t, use_cache=False)   # measure the genuine one-time proof cost
    if verdict != "PROVEN":
        return ReplicateVerdict("NOT_A_TEMPLATE", template_proof=verdict, counterexample=cx, n=len(instances),
                                detail=f"the parametric property does not hold ({verdict}) — no replication")
    certs: List[InstanceCert] = []
    for h in instances:
        fail = _check_precond(t.precond, h)
        certs.append(InstanceCert(h, "CERTIFIED" if fail is None else "REJECTED", fail))
    fold_ms = (time.perf_counter() - t0) * 1000
    certified = sum(1 for c in certs if c.status == "CERTIFIED")
    proof = (f"template `{t.name}`: PROVEN ∀{list(t.hole_types)},{list(t.inputs)}: "
             f"({' ∧ '.join(t.precond)}) → {t.ensures}. Each instance certified by checking the precond on "
             f"its concrete holes (sound universal instantiation) — the Z3 solve is paid ONCE.")
    v = ReplicateVerdict("REPLICATED", template_proof=proof, instances=certs, n=len(instances),
                         certified=certified, fold_ms=fold_ms)
    if measure:
        # naive baseline: verify each instance INDEPENDENTLY from scratch (one Z3 solve per instance)
        t1 = time.perf_counter()
        for h in instances:
            ens = _subst(t.ensures, h)
            asm = [_subst(c, h) for c in t.precond] + list(t.input_hyp)
            Z.prove_predicate(ens, dict(t.inputs), assumptions=asm)
        v.naive_ms = (time.perf_counter() - t1) * 1000
        v.speedup = v.naive_ms / fold_ms if fold_ms > 0 else 1.0
        # crossover N: smallest N where (1 solve + N·check) < (N·solve). check≪solve ⇒ N≈1 once proven.
        per_solve = v.naive_ms / len(instances)
        per_check = max((fold_ms - per_solve) / len(instances), 0.0) + 1e-9
        v.crossover_n = max(1, int(per_solve / max(per_solve - per_check, 1e-9)))
    return v


def fold_repo(items: List[Tuple[Template, List[Dict[str, object]]]], reset: bool = True) -> Dict[str, object]:
    """Process many (template, instances) families with the summary cache; re-running re-proves only the
    CHANGED templates. Returns counts + cold/warm wall-clock (perceived-zero re-verify for unchanged)."""
    if reset:
        reset_cache()
    t = time.perf_counter()
    proved = cached = 0
    for tmpl, _inst in items:
        _v, _cx, hit = prove_template(tmpl, use_cache=True)
        cached += int(hit)
        proved += int(not hit)
    return {"templates": len(items), "proved": proved, "cached": cached,
            "ms": (time.perf_counter() - t) * 1000}


