# ===== FILE: frontend_js.py  (113 lines) =====
# ==============================================================================================================

"""
HARAN v17 Part C · C3 — JavaScript / TypeScript frontend.
=========================================================
Token-scan → HIR (esprima's native build failed → AST DEFER) + a PERSISTENT node worker for execution
(node startup is ~80ms; a long-lived line-oriented process amortizes it so thousands of property checks
stay fast). TypeScript is compiled with `tsc` first, then run by the same worker.

Honest: JS is dynamically typed — without type info the array/scalar shape is inferred from usage (weak,
like Python). TypeScript's annotations make the shape explicit → stronger. Async / closures DEFER.
"""
from __future__ import annotations

import atexit
import os
import shutil
import subprocess
import tempfile
from typing import Callable, Optional

import hir
import frontend_native

_NODE = shutil.which("node")
_TSC = shutil.which("tsc")


def available() -> bool:
    return _NODE is not None


def _infer_array(source: str, fn: hir.HFunction) -> bool:
    return ("[" in source and "]" in source) or ".length" in source or ".push" in source \
        or "number[]" in source or bool({"index_load", "index_store", "sort"} & fn.op_kinds())


def js_to_hir(source: str, lang: str = "javascript") -> hir.HModule:
    fn = frontend_native.scan_function(source, lang)
    if fn and _infer_array(source, fn):
        fn.signature["kind"] = "array_return"
    elif fn:
        fn.signature["kind"] = "scalar"
    return hir.HModule(lang, [fn] if fn else [], source)


def ts_to_hir(source: str) -> hir.HModule:
    return js_to_hir(source, "typescript")


def _worker_js(hfn: hir.HFunction, body_js: str) -> str:
    name, scalar = hfn.name, hfn.signature["kind"] == "scalar"
    parse = "Number(line.trim())" if scalar else \
            "line.trim()? line.trim().split(/\\s+/).map(Number): []"
    emit = "String(r)" if scalar else "(Array.isArray(r)? r.join(' '): String(r))"
    return (body_js + "\n"
            "const rl=require('readline').createInterface({input:process.stdin});\n"
            "rl.on('line',(line)=>{try{const x=" + parse + ";const r=" + name + "(x);"
            "process.stdout.write(" + emit + "+'\\n');}catch(e){process.stdout.write('ERR\\n');}});\n")


def _prepare_js(hfn: hir.HFunction) -> str:
    """Return a path to a runnable .js worker (compiling TS with tsc if needed)."""
    d = tempfile.mkdtemp()
    if hfn.lang == "typescript" and _TSC is not None:
        tspath = os.path.join(d, "f.ts")
        open(tspath, "w").write("// @ts-nocheck\n" + hfn.source)
        subprocess.run([_TSC, "--target", "es2019", "--outDir", d, "--noEmitOnError", "false", tspath],
                       capture_output=True, text=True, timeout=60)
        jspath = os.path.join(d, "f.js")
        body = open(jspath).read() if os.path.exists(jspath) else hfn.source
    else:
        body = hfn.source
    worker = os.path.join(d, "w.js")
    open(worker, "w").write(_worker_js(hfn, body))
    return worker


class _JsWorker:
    """Long-lived node process: write one input line, read one output line."""
    def __init__(self, worker_path: str):
        self.p = subprocess.Popen([_NODE, worker_path], stdin=subprocess.PIPE, stdout=subprocess.PIPE,
                                  text=True, bufsize=1)
        atexit.register(self.close)

    def call(self, line: str) -> str:
        self.p.stdin.write(line + "\n")
        self.p.stdin.flush()
        return self.p.stdout.readline().strip()

    def close(self):
        try:
            self.p.stdin.close(); self.p.terminate()
        except Exception:
            pass


def js_callable(hfn: hir.HFunction) -> Callable:
    worker = _JsWorker(_prepare_js(hfn))
    scalar = hfn.signature["kind"] == "scalar"

    def run(x):
        line = " ".join(str(int(v)) for v in (x if isinstance(x, (list, tuple)) else [x]))
        out = worker.call(line)
        if out == "ERR":
            raise RuntimeError("js function threw")
        toks = out.split()
        vals = [int(float(t)) for t in toks] if toks else []
        return (vals[0] if vals else 0) if scalar else vals
    return run


hir.FRONTENDS["javascript"] = js_to_hir if available() else None
hir.FRONTENDS["typescript"] = ts_to_hir if available() else None


# ==============================================================================================================
# ===== FILE: frontend_native.py  (108 lines) =====
# ==============================================================================================================

"""
HARAN v17 Part C · STAGE C2/C3 — shared language-aware token scanner → HIR operations.
=====================================================================================
Full AST parsers (go/parser, syn, tree-sitter) are a refinement; here we extract the HIR operation
list (compare/arith/index_load/index_store/call/return + line numbers) with a language-aware TOKEN
scanner, which is enough for op-kind localization. Execution (the part that actually finds bugs) uses
the REAL native compiler per language (frontend_go/rust/js). Honest: the scanner is heuristic — it may
miss/merge operations on pathological lines; a true AST frontend is DEFER (syn/tree-sitter).
"""
from __future__ import annotations

import re
from typing import List, Optional, Tuple

import hir

_HEADER = {
    "go": re.compile(r"func\s+(\w+)\s*\(([^)]*)\)\s*([^\{]*)\{"),
    "rust": re.compile(r"fn\s+(\w+)\s*\(([^)]*)\)\s*(->\s*[^\{]*)?\{"),
    "javascript": re.compile(r"function\s+(\w+)\s*\(([^)]*)\)\s*\{"),
    "typescript": re.compile(r"function\s+(\w+)\s*\(([^)]*)\)\s*(:[^\{]*)?\{"),
}
_ARR = re.compile(r"\[\s*\]|Vec\s*<|\[\s*i\d+|\&\s*\[|Array|number\[\]|\:\s*\w+\[\]|list")


def _params(ptext: str) -> List[str]:
    out = []
    for part in ptext.split(","):
        part = part.strip()
        if not part:
            continue
        m = re.match(r"(?:mut\s+)?(\w+)", part)
        if m:
            out.append(m.group(1))
    return out


def _brace_body(source: str, open_idx: int) -> Tuple[str, int]:
    depth, i = 0, open_idx
    for i in range(open_idx, len(source)):
        if source[i] == "{":
            depth += 1
        elif source[i] == "}":
            depth -= 1
            if depth == 0:
                return source[open_idx:i + 1], i
    return source[open_idx:], len(source)


_CMP = re.compile(r"(?<![-=<>!])(<=|>=|==|!=|<|>)(?![=>])")
_AUG = re.compile(r"[-+*/%]=")
_ARITH = re.compile(r"(?<![-+*/%])[-+*/%](?![-+*/%=])")
_CALL = re.compile(r"\b(\w+)\s*\(")
_IDX = re.compile(r"\w+\s*\[")
_KW = {"if", "for", "while", "func", "fn", "function", "return", "let", "match", "switch", "range"}


def _scan_ops(body: str, base_line: int) -> List[hir.HOp]:
    ops: List[hir.HOp] = []
    for k, line in enumerate(body.splitlines()):
        ln = base_line + k
        if re.search(r"\.swap\s*\(", line):
            ops.append(hir.HOp("index_store", ln, "swap"))
        if re.search(r"\.sort\b", line) or re.search(r"sorted\s*\(", line):
            ops.append(hir.HOp("sort", ln))
        for _ in _CMP.findall(line):
            ops.append(hir.HOp("compare", ln))
        # index store vs load: an indexed target left of a single '=' is a store
        if _IDX.search(line) and re.search(r"\w+\s*\[[^\]]*\]\s*=(?!=)", line):
            ops.append(hir.HOp("index_store", ln))
        for _ in _IDX.findall(line):
            ops.append(hir.HOp("index_load", ln))
        for _ in _AUG.findall(line):
            ops.append(hir.HOp("aug", ln))
        for _ in _ARITH.findall(line):
            ops.append(hir.HOp("arith", ln))
        for name in _CALL.findall(line):
            if name not in _KW:
                ops.append(hir.HOp("call", ln, name))
        if re.search(r"\breturn\b", line):
            ops.append(hir.HOp("return", ln))
    return ops


def scan_function(source: str, lang: str) -> Optional[hir.HFunction]:
    hdr = _HEADER.get(lang)
    if not hdr:
        return None
    m = hdr.search(source)
    if not m:
        return None
    name, ptext = m.group(1), m.group(2)
    ret = (m.group(3) or "") if m.lastindex and m.lastindex >= 3 else ""
    open_idx = source.index("{", m.end() - 1)
    body, _ = _brace_body(source, open_idx)
    base_line = source[:open_idx].count("\n") + 1
    ops = _scan_ops(body, base_line)
    params = _params(ptext)
    is_arr = bool(_ARR.search(ptext))
    ret_arr = bool(_ARR.search(ret))
    kind = ("array_return" if (is_arr and (ret_arr or lang in ("go", "rust")))
            else ("array_inplace" if is_arr else "scalar"))
    sig = {"kind": kind, "arr": params[0] if params else None,
           "n": params[1] if len(params) > 1 else None, "ret_arr": ret_arr}
    start = source[:m.start()].count("\n") + 1
    end = source[:open_idx + len(body)].count("\n") + 1
    return hir.HFunction(name, params, ops, source, start, end, lang=lang, signature=sig)


