"""
perf-build STAGE 1 — Rust graph core via ctypes (dependency-0: no PyO3/maturin/cffi).
======================================================================================
Loads the std-only Rust cdylib (rust_graph/target/release/libgraph_core.so) and offloads the two hot loops
that cap repo_partition.py at N=4000 (measured 50.3 s @ N=4000, BLOCKED-scale above):
  • the deflated power iteration for the Fiedler vector  (O(iters·E)), and
  • the Kernighan–Lin balanced swap refinement           (O(passes·N²)).

★ The RNG stays in Python (random.Random(seed)) and the initial vector is passed to Rust, so both sides start
  identical — the Rust Fiedler vector is DIFFERENTIAL-TESTED against repo_partition.fiedler_vector (must match
  to FP rounding) and the KL result is integer-exact. No fake speedup. ★
★ If the shared library is absent (rustc unavailable / not built) every entry point returns [BLOCKED] and the
  caller falls back to the pure-Python repo_partition — never a fabricated number. ★

This raises the SCALING CEILING (Clock B / orchestration), not Clock A (LLM latency) or Clock C (emitted code).
"""
from __future__ import annotations

import ctypes
import os
import random
from typing import Dict, List, Tuple

import repo_partition as RP

_SO = os.path.join(os.path.dirname(os.path.abspath(__file__)), "rust_graph", "target", "release", "libgraph_core.so")
_LIB = None
_LOAD_ERR = None


def _lib():
    global _LIB, _LOAD_ERR
    if _LIB is not None or _LOAD_ERR is not None:
        return _LIB
    try:
        lib = ctypes.CDLL(_SO)
        u64 = ctypes.c_uint64
        usize = ctypes.c_size_t
        lib.gc_abi_version.restype = u64
        lib.gc_fiedler.argtypes = [usize, ctypes.POINTER(usize), ctypes.POINTER(ctypes.c_uint32),
                                   ctypes.POINTER(ctypes.c_double), usize, ctypes.POINTER(ctypes.c_double)]
        lib.gc_fiedler.restype = ctypes.c_int
        lib.gc_kl_refine.argtypes = [usize, ctypes.POINTER(usize), ctypes.POINTER(ctypes.c_uint32),
                                     ctypes.POINTER(ctypes.c_uint8), usize]
        lib.gc_kl_refine.restype = ctypes.c_int64
        lib.gc_transitive_dependents.argtypes = [usize, ctypes.POINTER(usize), ctypes.POINTER(ctypes.c_uint32),
                                                 usize, ctypes.POINTER(ctypes.c_uint32)]
        lib.gc_transitive_dependents.restype = ctypes.c_int64
        assert lib.gc_abi_version() == 1
        _LIB = lib
    except Exception as e:  # noqa: BLE001
        _LOAD_ERR = f"[BLOCKED: {type(e).__name__}: {e}]"
    return _LIB


def available() -> bool:
    return _lib() is not None


def load_error() -> str:
    _lib()
    return _LOAD_ERR or ""


def _csr(n: int, adj: Dict[int, List[int]]):
    """Build CSR (offsets[n+1], targets[2E]) preserving repo_partition's neighbor order (so the Laplacian
    summation order matches Python exactly)."""
    off = (ctypes.c_size_t * (n + 1))()
    flat: List[int] = []
    acc = 0
    for i in range(n):
        off[i] = acc
        nb = adj[i]
        flat.extend(nb)
        acc += len(nb)
    off[n] = acc
    tgt = (ctypes.c_uint32 * max(acc, 1))()
    for k, v in enumerate(flat):
        tgt[k] = v
    return off, tgt


def fiedler_vector(n: int, adj: Dict[int, List[int]], iters: int = 300, seed: int = 12345) -> List[float]:
    """Rust Fiedler vector with the SAME init vector Python would use (random.Random(seed))."""
    lib = _lib()
    if lib is None:
        return RP.fiedler_vector(n, adj, iters, seed)
    if n <= 1:
        return [0.0] * n
    rng = random.Random(seed)
    init = (ctypes.c_double * n)(*[rng.uniform(-1.0, 1.0) for _ in range(n)])
    off, tgt = _csr(n, adj)
    out = (ctypes.c_double * n)()
    lib.gc_fiedler(n, off, tgt, init, iters, out)
    return list(out)


def _kl_refine(parts: List[int], n: int, adj: Dict[int, List[int]], passes: int = 6) -> Tuple[List[int], int]:
    lib = _lib()
    off, tgt = _csr(n, adj)
    arr = (ctypes.c_uint8 * n)(*[int(p) for p in parts])
    cut = int(lib.gc_kl_refine(n, off, tgt, arr, passes))
    return list(arr), cut


def _bisect(n: int, adj: Dict[int, List[int]], edges) -> Tuple[List[int], str]:
    """Mirror of repo_partition._bisect, hot loops in Rust."""
    if n <= 1:
        return [0] * n, "trivial"
    fv = fiedler_vector(n, adj)
    order = sorted(range(n), key=lambda i: fv[i])
    parts = [0] * n
    for rank, node in enumerate(order):
        parts[node] = 0 if rank < n // 2 else 1
    method = "spectral-seed+KL(rust)"
    if len(set(parts)) == 1:
        parts = [0 if i < n // 2 else 1 for i in range(n)]
        method = "balanced-seed+KL(rust)"
    base_cut = RP.cut_size(parts, edges)
    refined, ref_cut = _kl_refine(parts, n, adj)
    if ref_cut <= base_cut:
        parts = refined
    return parts, method


def partition(graph: "RP.Graph", k: int = 2) -> RP.Partition:
    """Rust-accelerated drop-in for repo_partition.partition (identical API + result semantics). The N>4000
    ceiling is gone — Rust handles the O(iters·E) power iteration and O(passes·N²) KL. Falls back to pure
    Python when the cdylib is unavailable."""
    if not available():
        return RP.partition(graph, k)
    n, adj, edges = RP._normalize(graph)
    if n == 0:
        return RP.Partition([], 0, 0, "trivial", [], False, "empty graph")
    if k <= 1 or n <= 1:
        return RP.Partition([0] * n, 1, 0, "trivial", [n], False)
    parts, method = _bisect(n, adj, edges)
    next_id = 2
    while next_id < k:
        sizes = [sum(1 for p in parts if p == g) for g in range(next_id)]
        target = max(range(next_id), key=lambda g: sizes[g])
        members = sorted(i for i in range(n) if parts[i] == target)
        if len(members) <= 1:
            break
        remap = {old: new for new, old in enumerate(members)}
        subg = {remap[i]: [remap[j] for j in adj[i] if parts[j] == target] for i in members}
        sp, _m = _bisect(len(members), subg, RP._edges_of(subg))
        for old in members:
            if sp[remap[old]] == 1:
                parts[old] = next_id
        next_id += 1
    sizes = [sum(1 for p in parts if p == g) for g in range(max(parts) + 1)]
    return RP.Partition(parts, max(parts) + 1, RP.cut_size(parts, edges), method, sizes, False,
                        "rust graph core (ceiling removed)")


# ==============================================================================================================
# ===== FILE: groebner.py  (114 lines) =====
# ==============================================================================================================

"""
HARAN #19 (Group A) — GRÖBNER BASIS (Buchberger) for ideal membership, with a re-checkable COFACTOR certificate.
================================================================================================================
Buchberger's algorithm completes a generating set F = {f₁..f_m} to a Gröbner basis G under a monomial order by
repeatedly reducing S-polynomials; ideal membership q ∈ ⟨F⟩ is then decided by reduction-to-zero modulo G. We DRIVE
the Buchberger completion ourselves (S-polynomials, the pair loop, AND a TRANSFORMATION matrix so every basis
element is tracked as g_j = Σ T_{ji} f_i), using sympy only for the underlying polynomial ring arithmetic and as
an independent cross-check (`sympy.groebner`). The CERTIFICATE is what makes a YES re-checkable WITHOUT trusting
the basis search: for q ∈ ⟨F⟩ we emit explicit cofactors H_i with q = Σ H_i f_i, verified by direct polynomial
expansion (a Positivstellensatz-style ideal-membership witness). For a NO we emit the nonzero normal form and
re-verify Buchberger's criterion (every S-pair of G reduces to 0) so the decision is sound, not a library
say-so. HONEST: Gröbner bases are EXPSPACE in the worst case (NEVER O(1)); this runs under the extend budget and
honestly DECLINEs (infeasible-within-budget) past a step cap — decision-procedure-correct, not magic.
"""
from __future__ import annotations

from typing import List, Sequence

import kernel_verdict as KV

_STEP_CAP = 4000                                              # extend-budget guard: bail honestly past this many pairs


def _spoly(f, g, gens, order):
    import sympy as sp
    lmf, lmg = f.LM(order=order).as_expr(), g.LM(order=order).as_expr()
    lcm = sp.lcm(lmf, lmg)
    mf = sp.Poly(lcm / (f.LC(order=order) * lmf), *gens)     # L/lt(f)
    mg = sp.Poly(lcm / (g.LC(order=order) * lmg), *gens)     # L/lt(g)
    return mf, mg, mf * f - mg * g                           # multipliers + the S-polynomial


def ideal_member_grade(gens: Sequence[str], query: str, variables: Sequence[str], order: str = "grevlex") -> KV.Verdict:
    """Decide whether `query` ∈ ⟨`gens`⟩ in ℚ[`variables`] by a self-driven Buchberger completion + reduction.
    YES ⇒ EXACT with a COFACTOR certificate q = Σ H_i f_i (verified by expansion). NO ⇒ EXACT with the nonzero
    normal form, after re-verifying Buchberger's S-pair criterion on the computed basis (sound, not a say-so).
    Cross-checked against sympy.groebner. EXPSPACE worst case ⇒ honest DECLINE past the step cap."""
    import sympy as sp
    try:
        gen_syms = sp.symbols(list(variables))
        if not isinstance(gen_syms, (list, tuple)):
            gen_syms = (gen_syms,)
        F = [sp.Poly(sp.sympify(g), *gen_syms, domain="QQ") for g in gens]
        Q = sp.Poly(sp.sympify(query), *gen_syms, domain="QQ")
    except (sp.SympifyError, sp.PolynomialError, TypeError, ValueError) as e:
        return KV.decline(f"groebner: parse error {e} ⇒ DECLINE", "groebner")
    if any(f.is_zero for f in F):
        F = [f for f in F if not f.is_zero]
    if not F:
        return KV.decline("groebner: empty/zero generating set ⇒ DECLINE", "groebner")

    # ── self-driven Buchberger with transformation tracking: basis[j] = (poly, [cofactors in terms of F]) ──
    m = len(F)
    basis = [(F[i], [sp.Poly(1 if j == i else 0, *gen_syms, domain="QQ") for j in range(m)]) for i in range(m)]
    pairs = [(i, j) for i in range(len(basis)) for j in range(i + 1, len(basis))]
    steps = 0
    while pairs:
        if steps >= _STEP_CAP:
            return KV.decline(f"groebner: exceeded {_STEP_CAP} S-pairs (EXPSPACE — infeasible within budget) ⇒ "
                              f"DECLINE", "groebner")
        steps += 1
        i, j = pairs.pop()
        mf, mg, s = _spoly(basis[i][0], basis[j][0], gen_syms, order)
        if s.is_zero:
            continue
        qr = sp.reduced(s.as_expr(), [b[0].as_expr() for b in basis], *gen_syms, order=order)
        quo = [sp.Poly(c, *gen_syms, domain="QQ") for c in qr[0]]
        r = sp.Poly(qr[1], *gen_syms, domain="QQ")
        if r.is_zero:
            continue
        # r = s − Σ quo[k]·basis[k];  transform of r in terms of F (so the basis stays certified):
        tr = [mf * basis[i][1][t] - mg * basis[j][1][t] for t in range(m)]
        for k in range(len(basis)):
            for t in range(m):
                tr[t] = tr[t] - quo[k] * basis[k][1][t]
        basis.append((r, tr))
        pairs += [(k, len(basis) - 1) for k in range(len(basis) - 1)]

    G = [b[0] for b in basis]
    qr = sp.reduced(Q.as_expr(), [g.as_expr() for g in G], *gen_syms, order=order)
    quo = [sp.Poly(c, *gen_syms, domain="QQ") for c in qr[0]]
    rem = sp.Poly(qr[1], *gen_syms, domain="QQ")
    member = rem.is_zero

    if member:
        # cofactors of Q in terms of F:  H_i = Σ_k quo[k]·T_{ki}
        H = [sum((quo[k] * basis[k][1][i] for k in range(len(basis))), sp.Poly(0, *gen_syms, domain="QQ"))
             for i in range(m)]
        recon = sum((H[i] * F[i] for i in range(m)), sp.Poly(0, *gen_syms, domain="QQ"))
        if not (recon - Q).is_zero:                          # ★ re-check the cofactor witness by expansion ★
            return KV.decline("groebner: cofactor reconstruction ≠ query ⇒ DECLINE (bug guard)", "groebner")
        cofs = [str(h.as_expr()) for h in H]
        cert = KV.Cert(KV.EXACT, "groebner_cofactor_membership", passed=True,
                       check_cost=f"Buchberger {steps} S-pairs + cofactor expansion",
                       detail=f"{query} ∈ ⟨{', '.join(gens)}⟩: {query} = Σ Hᵢ·fᵢ with H={cofs} (verified by "
                              f"polynomial expansion — a re-checkable ideal-membership witness)")
        return KV.exact({"member": True, "cofactors": cofs}, "groebner", f"Buchberger ({order})", cert)

    # NO: re-verify Buchberger's criterion (every S-pair of G reduces to 0) ⇒ G is a genuine Gröbner basis
    for a in range(len(G)):
        for b in range(a + 1, len(G)):
            _, _, s = _spoly(G[a], G[b], gen_syms, order)
            if s.is_zero:
                continue
            sr = sp.reduced(s.as_expr(), [g.as_expr() for g in G], *gen_syms, order=order)[1]
            if not sp.Poly(sr, *gen_syms, domain="QQ").is_zero:
                return KV.decline("groebner: S-pair criterion failed ⇒ basis not Gröbner ⇒ DECLINE (sound-NO guard)",
                                  "groebner")
    cert = KV.Cert(KV.EXACT, "groebner_nonmembership_normalform", passed=True,
                   check_cost=f"Buchberger {steps} S-pairs + S-pair criterion re-check",
                   detail=f"{query} ∉ ⟨{', '.join(gens)}⟩: nonzero normal form {rem.as_expr()} modulo a basis "
                          f"re-verified Gröbner (all S-pairs reduce to 0) ⇒ sound NO")
    return KV.exact({"member": False, "normal_form": str(rem.as_expr())}, "groebner", f"Buchberger ({order})", cert)


# ==============================================================================================================
# ===== FILE: grounding_pipeline.py  (164 lines) =====
# ==============================================================================================================

"""
v28 STAGE 21 — large-prompt GROUNDING pipeline (grounding, NOT understanding — Rice-bounded).
==============================================================================================
A frontier LLM blurs a huge prompt: attention loses the middle (lost-in-the-middle; RULER shows effective
context ≪ nominal). We do NOT claim to "understand" the input (Rice). We GROUND it — structurally — and
report measurable proxies:

  1. structure      — parse to entities + a dependency/call graph (reuse the S20 IR / facts).
  2. hierarchical   — cluster the graph (reuse S14 spectral partition) into a 2-level summary TREE with
       index          EXTRACTIVE (no-LLM) summaries. ★Honest: extractive, not LLM-abstractive — real
                       embeddings + abstractive summaries are the [BLOCKED: key] enhancement.★
  3. multi-hop      — answer reachability / transitive-dependency queries by EXACT graph traversal. By
       retrieval      construction there is no lost-in-the-middle: the answer is complete and grounded.
  4. spec extract   — pull checkable claims (HARAN `ensures`-style) and MACHINE-VERIFY them: GROUNDED
       + verify       (proof) / REFUTED (counterexample) / BEST_EFFORT (natural-language, unverifiable —
                       labeled, never faked).

★ HONEST (§1.2,1.4,§5.2) ★: full semantic understanding is impossible (Rice). The edge is exactly three
things: (a) the VERIFIABLE slice (we prove/refute it), (b) EXACT structural retrieval (Ω(input), no
hallucinated middle), (c) grounding ≠ understanding. Natural-language intent we are NO better than an LLM
at — those claims are BEST_EFFORT. A live LLM head-to-head needs a key/egress ([BLOCKED]); the structural
proxies here are measured.
"""
from __future__ import annotations

from collections import deque
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Set, Tuple

import ai_loop
import repo_partition as RP
try:
    import graph_core as GC          # v38 Rust graph core (cdylib/ctypes) — drop-in, internal Python fallback
except Exception:                     # noqa: BLE001 — never let an import break grounding
    GC = None


def _partition(graph, k):
    """Live partition: prefer the differential-verified Rust core (removes the N=4000 ceiling), else the
    pure-Python repo_partition. graph_core.partition falls back internally too, so this is doubly safe."""
    if GC is not None and GC.available():
        return GC.partition(graph, k=k)
    return RP.partition(graph, k=k)


@dataclass
class Entity:
    name: str
    source: str = ""        # the snippet (HARAN/code) — the verifiable slice
    kind: str = "function"


@dataclass
class GroundingIndex:
    entities: Dict[str, Entity]
    edges: List[Tuple[str, str]]                 # directed dependency/call edges a→b
    adj: Dict[str, List[str]] = field(default_factory=dict)
    clusters: List[List[str]] = field(default_factory=list)
    cluster_summaries: List[str] = field(default_factory=list)
    root_summary: str = ""

    def transitive_deps(self, start: str) -> Set[str]:
        """Exact multi-hop: everything reachable from `start` along dependency edges (BFS — complete)."""
        seen: Set[str] = set()
        q = deque(self.adj.get(start, []))
        while q:
            x = q.popleft()
            if x not in seen:
                seen.add(x)
                q.extend(self.adj.get(x, []))
        return seen

    def reaches(self, src: str, dst: str) -> bool:
        return dst in self.transitive_deps(src)

    def coverage(self) -> float:
        """Fraction of entities that landed in the hierarchical index (graph coverage proxy)."""
        indexed = {e for c in self.clusters for e in c}
        return len(indexed) / len(self.entities) if self.entities else 0.0


def build_index(entities: List[Entity], edges: List[Tuple[str, str]], k: int = 2) -> GroundingIndex:
    ents = {e.name: e for e in entities}
    adj: Dict[str, List[str]] = {e.name: [] for e in entities}
    for a, b in edges:
        adj.setdefault(a, []).append(b)
        adj.setdefault(b, [])
    idx = GroundingIndex(ents, list(edges), adj)
    # cluster via the S14 spectral partitioner (undirected view) → the leaves of the summary tree
    undirected: Dict[str, List[str]] = {n: [] for n in ents}
    for a, b in edges:
        if a in ents and b in ents:
            undirected[a].append(b)
            undirected[b].append(a)
    if len(ents) >= 2:
        part = _partition(undirected, k=min(k, len(ents)))
        nodes_sorted = sorted(undirected)
        clusters: Dict[int, List[str]] = {}
        for node_idx, pid in enumerate(part.parts):
            clusters.setdefault(pid, []).append(nodes_sorted[node_idx])
        idx.clusters = [sorted(v) for v in clusters.values()]
    else:
        idx.clusters = [list(ents)]
    # EXTRACTIVE (no-LLM) summaries: signatures + counts per cluster, then a root summary
    idx.cluster_summaries = [f"cluster[{', '.join(c)}] — {len(c)} entities" for c in idx.clusters]
    idx.root_summary = f"{len(ents)} entities in {len(idx.clusters)} clusters; {len(edges)} dependency edges"
    return idx


# ── spec extraction + machine verification ──────────────────────────────────────────────────────────
@dataclass
class ClaimVerdict:
    claim: str
    status: str             # GROUNDED | REFUTED | BEST_EFFORT
    detail: str = ""
    counterexample: Optional[dict] = None


def _is_haran_spec(text: str) -> bool:
    return text.strip().startswith("fn ") and "ensures" in text


def verify_claim(claim: str) -> ClaimVerdict:
    """A checkable claim (a HARAN function with `ensures`) is GROUNDED (proven) / REFUTED (counterexample);
    anything not formalizable here is BEST_EFFORT (labeled — never a fake GROUNDED)."""
    if _is_haran_spec(claim):
        v = ai_loop.verify_haran(claim)
        if v.ok:
            return ClaimVerdict(claim, "GROUNDED", "verified against its ensures spec")
        return ClaimVerdict(claim, "REFUTED", "spec violated", v.counterexample)
    return ClaimVerdict(claim, "BEST_EFFORT", "natural-language / non-formalizable claim — NOT verified "
                        "(we are no better than an LLM here; labeled, not faked)")


@dataclass
class GroundingResult:
    index: GroundingIndex
    claims: List[ClaimVerdict]
    multihop_accuracy: float = 0.0
    fidelity: float = 0.0           # fraction of formalizable claims actually GROUNDED/REFUTED (not blurred)
    coverage: float = 0.0
    note: str = ""

    @property
    def grounded(self) -> List[ClaimVerdict]:
        return [c for c in self.claims if c.status == "GROUNDED"]


def ground(entities: List[Entity], edges: List[Tuple[str, str]], claims: List[str],
           multihop_queries: Optional[List[Tuple[str, str, bool]]] = None) -> GroundingResult:
    """Build the index, verify the claims, and report measurable grounding proxies. NOT 'understanding'."""
    idx = build_index(entities, edges)
    verdicts = [verify_claim(c) for c in claims]
    formalizable = [v for v in verdicts if v.status in ("GROUNDED", "REFUTED")]
    fidelity = len(formalizable) / len(verdicts) if verdicts else 0.0
    acc = 1.0
    if multihop_queries:
        correct = sum(1 for (s, d, expected) in multihop_queries if idx.reaches(s, d) == expected)
        acc = correct / len(multihop_queries)
    note = ("GROUNDING, not understanding (Rice). Multi-hop retrieval is EXACT graph traversal (no "
            "lost-in-the-middle); claims are proven/refuted or labeled BEST_EFFORT. A live LLM comparison "
            "is [BLOCKED: key/egress].")
    return GroundingResult(idx, verdicts, acc, fidelity, idx.coverage(), note)


# ==============================================================================================================
# ===== FILE: haran_ast.py  (314 lines) =====
# ==============================================================================================================

"""
HARAN AST (STAGE H1) — the structured form of a HARAN program.
==============================================================
Per haran-design.md §1.1 every function carries FOUR parts side by side:
  fn name(args) -> Ret  requires <e>  ensures <e>  decreases <e>  effects <k>  { body }
and §1.3 adds the coinductive shell:  proc name(...) -> ...  produces <e>  effects io { cofix ... }.

The whole point (§0 공리 1, §2.1 단계 1): the SPEC (requires/ensures/decreases/produces) lives
*next to* the IMPL (body), so Mr.Jeffrey READS the intent — it never infers it. So `FnDecl` keeps the
spec clauses and the body as separate, explicit fields. Every node carries a source `Span` so
diagnostics can point at an exact line:col (H1 requirement: "파싱 에러는 정확한 line/col과 함께").
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import List, Optional


@dataclass
class Span:
    line: int
    col: int
    end_line: int = 0
    end_col: int = 0
    def __str__(self):
        return f"{self.line}:{self.col}"


# ============================== Types (§1.2) ==============================
@dataclass
class TypeArg:
    """An argument inside `Name<...>`: a type (List<T>) or a term (Vec<Int, 3>)."""
    kind: str            # "type" | "term"
    value: object        # Ty if type, Expr if term
    span: Span


@dataclass
class TyName:
    name: str
    args: List[TypeArg]
    span: Span


@dataclass
class TyOwn:               # own Buffer  (§1.4 ownership move)
    inner: object
    span: Span


@dataclass
class TyRef:               # &Buffer / &mut Buffer  (§1.4 borrow)
    inner: object
    mutable: bool
    span: Span


@dataclass
class TyRefine:            # { x: T | pred }  (§1.2 refinement / dependent type)
    var: str
    base: object           # Ty
    pred: object           # Expr
    span: Span


@dataclass
class GenericParam:
    """A generic parameter in a `type Name<...>` header: `T` (type) or `n: Nat` (value)."""
    name: str
    kind: Optional[object]   # None => type param; Ty => value param (n: Nat)
    span: Span


# ============================== Expressions ==============================
@dataclass
class Num:
    value: str
    is_float: bool
    span: Span


@dataclass
class Var:
    name: str             # 'result' is just a Var named "result" (special at H2, not here)
    span: Span


@dataclass
class BoolLit:
    value: bool
    span: Span


@dataclass
class Bin:
    op: str               # ∧ ∨ = ≠ < ≤ > ≥ + - * / % ++ ...
    lhs: object
    rhs: object
    span: Span


@dataclass
class Un:
    op: str               # - ¬ !
    operand: object
    span: Span


@dataclass
class Call:
    func: object
    args: List[object]
    span: Span


@dataclass
class Lambda:             # λy. y ≤ p
    params: List[str]
    body: object
    span: Span


@dataclass
class Quant:             # ∀ req. ...   /   ∃ x. ...
    kind: str            # "∀" | "∃"
    vars: List[str]
    body: object
    span: Span


@dataclass
class ListLit:           # []  /  [p]  /  [a, b, c]
    elems: List[object]
    span: Span


@dataclass
class Range:             # 1..n  (fold domain)
    lo: object
    hi: object
    span: Span


@dataclass
class Block:             # { stmt* }  — also usable as an expression (last stmt is the value)
    stmts: List[object]
    span: Span


@dataclass
class Match:             # match scrut { pat => body ... }
    scrut: object
    arms: List[object]   # List[MatchArm]
    span: Span


@dataclass
class Fold:              # fold k in 1..n { body }   (§1.5)
    binder: str
    domain: object
    body: object
    span: Span


@dataclass
class Cofix:             # cofix loop { ... }   (§1.3 coinductive fixpoint)
    name: str
    body: object
    span: Span


