# ---- v17 E2.1: honest automation-boundary probe ----
def auto_attempt(statement: str, preamble: str, auto_tactic: str = "induction l; simpl; auto.") -> bool:
    """Try to close `statement` with a PURE-automation proof. Returns True iff coqc accepts it (no
    helper lemmas). Used to show which theorems automation can/can't reach — honestly."""
    src = preamble + "\n" + statement + f"\nProof. {auto_tactic} Qed.\n"
    return prove_coq(src, "auto_try").proven


# ----------------------------------------------------------------- discharge
_ADMIT_RE = re.compile(r"\b(Admitted|admit|Axiom|Admit)\b")


@dataclass
class CoqResult:
    name: str
    proven: bool          # coqc accepted AND no admits/axioms
    coqc_ok: bool
    has_admit: bool
    mode: str
    unbounded: str
    detail: str


def prove_coq(src: str, name: str = "thm", mode: str = "manual", unbounded: str = "") -> CoqResult:
    if not coq_available():
        return CoqResult(name, False, False, False, mode, unbounded, "BLOCKED: coqc not available")
    has_admit = bool(_ADMIT_RE.search(src))
    d = tempfile.mkdtemp()
    vpath = os.path.join(d, "t.v")
    open(vpath, "w").write(src)
    r = subprocess.run([_COQC, vpath], capture_output=True, text=True, cwd=d, timeout=120)
    coqc_ok = r.returncode == 0
    proven = coqc_ok and not has_admit
    detail = "QED (no admits)" if proven else (r.stderr[:200] if not coqc_ok else "contains admit/axiom")
    return CoqResult(name, proven, coqc_ok, has_admit, mode, unbounded, detail)


def prove_property(name: str) -> CoqResult:
    t = THEOREMS[name]
    return prove_coq(t.preamble + "\n" + t.statement_and_proof, t.name, t.mode, t.unbounded)


# ----------------------------------------------------------------- A3.2 HARAN spec → Coq theorem
def _calls_named(e, fname: str) -> bool:
    if isinstance(e, A.Call) and isinstance(e.func, A.Var) and e.func.name == fname:
        return True
    for f in getattr(e, "__dataclass_fields__", {}):
        v = getattr(e, f)
        if f == "span":
            continue
        if isinstance(v, list):
            if any(_calls_named(x, fname) for x in v if hasattr(x, "__dataclass_fields__")):
                return True
        elif hasattr(v, "__dataclass_fields__") and _calls_named(v, fname):
            return True
    return False


def spec_to_coq(fn: A.FnDecl) -> List[str]:
    """Map a HARAN function's `ensures` to the Coq theorem(s) that discharge it, for recognized
    property shapes. Unrecognized specs → [] (honest DEFER, not a fake)."""
    out = []
    ens = fn.ensures
    if ens is None:
        return out
    if _calls_named(ens, "sorted"):
        out.append("isort_sorted")
    if _calls_named(ens, "permutation"):
        out.append("isort_perm")
    # Faulhaber Σi = n(n+1)/2 : the body is `fold <k> in .. { <k> }` (linear sum of the binder) —
    # exactly what the Coq `faulhaber_all` theorem (2*sumto n = n*(n+1)) discharges.
    body = cc._block_return(fn.body) if fn.body else None
    if isinstance(body, A.Fold):
        summand = cc._block_return(body.body) if isinstance(body.body, A.Block) else body.body
        if isinstance(summand, A.Var) and summand.name == body.binder:
            out.append("faulhaber")
    return out


# ----------------------------------------------------------------- A3.4 summary vs Z3 bounded
@dataclass
class UnboundedSummary:
    proven: List[CoqResult]
    z3_bounded_note: str

    @property
    def count(self):
        return sum(1 for r in self.proven if r.proven)


def prove_all() -> UnboundedSummary:
    results = [prove_property(n) for n in THEOREMS]
    return UnboundedSummary(results,
                            "Z3 baseline (v8): sort proven only for ∀-VALUES at length ≤ 4 (no induction).")


# ==============================================================================================================
# ===== FILE: haran_eval.py  (249 lines) =====
# ==============================================================================================================

"""
STAGE H6 (support) — a small tree-walking evaluator for HARAN's pure fragment.
=============================================================================
Needed so the CORRECTNESS obligation of a *general proposition* (e.g. sort's `sorted(result) ∧
permutation(result, xs)`) can be discharged by BOUNDED FUZZING (§2.1 단계3 third engine) — run the
HARAN implementation on random inputs and check `ensures`. This is honestly TESTED, not proven: a
counterexample is definitive (FAILED), but passing N cases is evidence, not a ∀-proof (Boundary 1).

Supported pure fragment: match (list/cons/num/bool/wildcard patterns), let, fold, λ + application,
list literals, ++, arithmetic/comparison/boolean ops, recursion, and a small builtin catalog
(filter, map, length, sorted, permutation). Anything else → EvalError → the caller reports UNKNOWN.
"""
from __future__ import annotations

import random
from typing import List, Optional

import haran_ast as A


class EvalError(Exception):
    pass


class Closure:
    __slots__ = ("params", "body", "env")
    def __init__(self, params, body, env):
        self.params, self.body, self.env = params, body, dict(env)


class Interp:
    def __init__(self, ftab: dict, max_steps: int = 400_000):
        self.ftab = ftab
        self.steps = 0
        self.max_steps = max_steps

    def _tick(self):
        self.steps += 1
        if self.steps > self.max_steps:
            raise EvalError("step limit exceeded (possible non-termination)")

    def call_fn(self, fn: A.FnDecl, argvals: List[object]):
        self._tick()
        env = {p.name: v for p, v in zip(fn.params, argvals)}
        return self.eval(fn.body, env)

    def apply_closure(self, clo: Closure, *vals):
        env = dict(clo.env)
        for p, v in zip(clo.params, vals):
            env[p] = v
        return self.eval(clo.body, env)

    def eval(self, node, env):
        self._tick()
        if isinstance(node, A.Num):
            return float(node.value) if node.is_float else int(node.value)
        if isinstance(node, A.BoolLit):
            return node.value
        if isinstance(node, A.Var):
            if node.name in env:
                return env[node.name]
            raise EvalError(f"unbound variable '{node.name}'")
        if isinstance(node, A.ListLit):
            return [self.eval(e, env) for e in node.elems]
        if isinstance(node, A.Lambda):
            return Closure(node.params, node.body, env)
        if isinstance(node, A.Un):
            v = self.eval(node.operand, env)
            if node.op == "-":
                return -v
            if node.op in ("¬", "!"):
                return not v
            raise EvalError(f"unary op '{node.op}'")
        if isinstance(node, A.Bin):
            return self._binop(node, env)
        if isinstance(node, A.Call):
            return self._call(node, env)
        if isinstance(node, A.Block):
            return self._block(node, env)
        if isinstance(node, A.Match):
            return self._match(node, env)
        if isinstance(node, A.Fold):
            return self._fold(node, env)
        if isinstance(node, A.Range):
            return ("range", self.eval(node.lo, env), self.eval(node.hi, env))
        raise EvalError(f"cannot evaluate {type(node).__name__}")

    def _binop(self, node, env):
        op = node.op
        if op in ("∧", "&&"):
            return bool(self.eval(node.lhs, env)) and bool(self.eval(node.rhs, env))
        if op in ("∨", "||"):
            return bool(self.eval(node.lhs, env)) or bool(self.eval(node.rhs, env))
        a = self.eval(node.lhs, env)
        b = self.eval(node.rhs, env)
        if op == "+":
            return a + b
        if op == "-":
            return a - b
        if op == "*":
            return a * b
        if op == "/":
            return a // b if isinstance(a, int) and isinstance(b, int) and b != 0 and a % b == 0 else a / b
        if op == "%":
            return a % b
        if op == "**":
            return a ** b
        if op == "++":
            return list(a) + list(b)
        if op in ("=", "=="):
            return a == b
        if op in ("≠", "!="):
            return a != b
        if op == "<":
            return a < b
        if op in ("≤", "<="):
            return a <= b
        if op == ">":
            return a > b
        if op in ("≥", ">="):
            return a >= b
        raise EvalError(f"binary op '{op}'")

    def _call(self, node, env):
        if not isinstance(node.func, A.Var):
            raise EvalError("only named calls supported")
        name = node.func.name
        args = [self.eval(a, env) for a in node.args]
        b = _BUILTINS.get(name)
        if b is not None:
            return b(self, args)
        if name in self.ftab:
            return self.call_fn(self.ftab[name], args)
        raise EvalError(f"unknown function '{name}'")

    def _block(self, node, env):
        env = dict(env)
        val = None
        for st in node.stmts:
            if isinstance(st, A.Let):
                env[st.name] = self.eval(st.value, env)
            elif isinstance(st, A.ExprStmt):
                val = self.eval(st.value, env)
            elif isinstance(st, A.Yield):
                val = self.eval(st.value, env)
            else:
                raise EvalError(f"stmt {type(st).__name__}")
        return val

    def _match(self, node, env):
        scrut = self.eval(node.scrut, env)
        for arm in node.arms:
            bound = {}
            if _match_pat(arm.pattern, scrut, bound):
                e2 = dict(env)
                e2.update(bound)
                return self.eval(arm.body, e2)
        raise EvalError("no matching arm (non-exhaustive at runtime)")

    def _fold(self, node, env):
        dom = self.eval(node.domain, env)
        if not (isinstance(dom, tuple) and dom[0] == "range"):
            raise EvalError("fold domain is not a range")
        _, lo, hi = dom
        acc = 0
        for k in range(int(lo), int(hi) + 1):   # inclusive (matches H4)
            e2 = dict(env)
            e2[node.binder] = k
            acc += self.eval(node.body, e2)
        return acc


def _match_pat(pat, value, bound: dict) -> bool:
    if isinstance(pat, A.PWild):
        return True
    if isinstance(pat, A.PVar):
        bound[pat.name] = value
        return True
    if isinstance(pat, A.PNum):
        return value == int(pat.value)
    if isinstance(pat, A.PBool):
        return value == pat.value
    if isinstance(pat, A.PListEmpty):
        return isinstance(value, list) and len(value) == 0
    if isinstance(pat, A.PCons):
        if isinstance(value, list) and len(value) >= 1:
            return _match_pat(pat.head, value[0], bound) and _match_pat(pat.tail, value[1:], bound)
        return False
    if isinstance(pat, A.PList):
        if isinstance(value, list) and len(value) == len(pat.elems):
            return all(_match_pat(p, v, bound) for p, v in zip(pat.elems, value))
        return False
    raise EvalError(f"pattern {type(pat).__name__}")


# ---- builtin catalog (pure) ----
def _b_filter(it: Interp, args):
    lst, clo = args[0], args[1]
    return [x for x in lst if it.apply_closure(clo, x)]
def _b_map(it: Interp, args):
    lst, clo = args[0], args[1]
    return [it.apply_closure(clo, x) for x in lst]
def _b_length(it, args):
    return len(args[0])
def _b_sorted(it, args):
    l = args[0]
    return all(l[i] <= l[i + 1] for i in range(len(l) - 1))
def _b_permutation(it, args):
    return sorted(args[0]) == sorted(args[1])

_BUILTINS = {"filter": _b_filter, "map": _b_map, "length": _b_length,
             "sorted": _b_sorted, "permutation": _b_permutation}


# ---- input generation + bounded fuzzing ----
def _gen_input(ty, rng: random.Random):
    if isinstance(ty, A.TyName):
        if ty.name in ("List", "Vec", "Seq"):
            return [rng.randint(-9, 9) for _ in range(rng.randint(0, 6))]
        if ty.name in ("Nat",):
            return rng.randint(0, 20)
        if ty.name in ("Int",):
            return rng.randint(-20, 20)
        if ty.name in ("Bool",):
            return rng.choice([True, False])
        if ty.name in ("Float",):
            return rng.uniform(-10, 10)
    raise EvalError(f"cannot generate inputs for type {getattr(ty, 'name', ty)}")


def bounded_fuzz(fn: A.FnDecl, ftab: dict, ensures, n: int = 200, seed: int = 20260616):
    """Run fn on n random inputs; check `ensures`. Returns (status, detail, counterexample).
    status ∈ {PASS, FAIL, UNKNOWN}; deterministic (fixed seed)."""
    rng = random.Random(seed)
    try:
        for _ in range(n):
            args = [_gen_input(p.ty, rng) for p in fn.params]
            it = Interp(ftab)
            result = it.call_fn(fn, args)
            env = {p.name: a for p, a in zip(fn.params, args)}
            env["result"] = result
            ok = it.eval(ensures, env)
            if not bool(ok):
                inputs = {p.name: a for p, a in zip(fn.params, args)}
                return ("FAIL", f"ensures false on a random input", {"inputs": inputs, "result": result})
    except EvalError as e:
        return ("UNKNOWN", f"cannot evaluate ({e})", None)
    return ("PASS", f"no counterexample in {n} random cases (tested, not proven)", None)


# ==============================================================================================================
# ===== FILE: haran_parser.py  (553 lines) =====
# ==============================================================================================================

"""
HARAN parser (STAGE H1) — source → AST, with located diagnostics.
=================================================================
Hand-written lexer + recursive-descent parser for the HARAN surface in haran-design.md
(§1.1 fn 4중 구조, §1.2 refinement/dependent types, §1.3 proc/cofix, §1.4 own/&, §1.5 fold).

Discipline (H1):
  - errors carry an EXACT line:col and parsing does NOT stop at the first one (item-level recovery);
  - NO fake success: a malformed program returns a Program whose `.errors` is non-empty;
  - the grammar is delimiter-driven (keywords / brackets / explicit operators), so newlines are
    insignificant — there is no juxtaposition application, so adjacent statements never merge.

Public API:  parse(src) -> Program     (Program.items, Program.errors, Program.ok)
"""
from __future__ import annotations

from typing import List, Optional

import haran_ast as A
from haran_ast import Span


# ----------------------------------------------------------------------------- lexer
KEYWORDS = {
    "fn", "proc", "type", "data", "requires", "ensures", "decreases", "effects", "produces",
    "match", "let", "fold", "cofix", "yield", "in", "own", "mut", "true", "false",
}
# two-char operators (checked before single-char); '..' before '.', '->' before '-', etc.
OPS2 = ["**", "->", "=>", "++", "..", "==", "!=", ">=", "<=", "&&", "||"]
OPS1 = set("(){}[],:;|&<>=+-*/%.!~")
UNI_OPS = set("∧∨¬≤≥≠≡⊂⊆∈→λ∀∃")


class Token:
    __slots__ = ("kind", "text", "line", "col")
    def __init__(self, kind, text, line, col):
        self.kind = kind      # "num" | "ident" | "kw" | "op" | "eof"
        self.text = text
        self.line = line
        self.col = col
    def __repr__(self):
        return f"<{self.kind}:{self.text!r}@{self.line}:{self.col}>"


def tokenize(src: str):
    toks: List[Token] = []
    i, n = 0, len(src)
    line, col = 1, 1
    def adv(k=1):
        nonlocal i, col
        i += k
        col += k
    while i < n:
        ch = src[i]
        if ch == "\n":
            i += 1; line += 1; col = 1; continue
        if ch in " \t\r":
            adv(); continue
        if ch == "/" and i + 1 < n and src[i + 1] == "/":   # // comment
            while i < n and src[i] != "\n":
                i += 1; col += 1
            continue
        # number
        if ch.isdigit():
            start_col = col
            j = i
            while j < n and src[j].isdigit():
                j += 1
            is_float = False
            if j + 1 < n and src[j] == "." and src[j + 1].isdigit():   # float, NOT range '..'
                is_float = True
                j += 1
                while j < n and src[j].isdigit():
                    j += 1
            text = src[i:j]
            toks.append(Token("num", text, line, start_col))
            col += (j - i); i = j
            continue
        # two-char operators
        two = src[i:i + 2]
        if two in OPS2:
            toks.append(Token("op", two, line, col)); adv(2); continue
        # single-char ascii op / unicode op
        if ch in OPS1 or ch in UNI_OPS:
            toks.append(Token("op", ch, line, col)); adv(); continue
        # identifier / keyword  (note: λ ∀ ∃ are handled above as ops, before isalpha)
        if ch == "_" or ch.isalpha():
            start_col = col
            j = i
            while j < n and (src[j] == "_" or src[j].isalnum()):
                j += 1
            text = src[i:j]
            kind = "kw" if text in KEYWORDS else "ident"
            toks.append(Token(kind, text, line, start_col))
            col += (j - i); i = j
            continue
        # unknown character — emit as an op token so the parser reports it at this line:col
        toks.append(Token("op", ch, line, col)); adv()
    toks.append(Token("eof", "<eof>", line, col))
    return toks


# ----------------------------------------------------------------------------- parser
class _ParseError(Exception):
    pass


CMP_OPS = {"=", "==", "≠", "!=", "<", "≤", "<=", ">", "≥", ">=", "≡"}
AND_OPS = {"∧", "&&"}
OR_OPS = {"∨", "||"}
ADD_OPS = {"+", "-"}
MUL_OPS = {"*", "/", "%"}
UN_OPS = {"-", "¬", "!"}
CLAUSE_KW = {"requires", "ensures", "decreases", "effects", "produces"}


class Parser:
    def __init__(self, tokens: List[Token]):
        self.toks = tokens
        self.i = 0
        self.errors: List[A.Diagnostic] = []

    # --- token cursor ---
    def peek(self, k=0) -> Token:
        j = self.i + k
        return self.toks[j] if j < len(self.toks) else self.toks[-1]
    def at(self, *texts) -> bool:
        t = self.peek()
        return t.kind in ("op", "kw") and t.text in texts
    def at_kw(self, *texts) -> bool:
        t = self.peek()
        return t.kind == "kw" and t.text in texts
    def at_kind(self, kind) -> bool:
        return self.peek().kind == kind
    def eof(self) -> bool:
        return self.peek().kind == "eof"
    def next(self) -> Token:
        t = self.peek()
        if t.kind != "eof":
            self.i += 1
        return t
    def span(self, t: Token) -> Span:
        return Span(t.line, t.col)

    # --- error / recovery ---
    def fail(self, msg: str, tok: Optional[Token] = None):
        tok = tok or self.peek()
        self.errors.append(A.Diagnostic(tok.line, tok.col, msg))
        raise _ParseError(msg)
    def expect(self, text: str, what: str = None) -> Token:
        if self.at(text):
            return self.next()
        self.fail(f"expected '{text}'" + (f" ({what})" if what else "")
                  + f", found '{self.peek().text}'")
    def expect_ident(self, what: str = "identifier") -> Token:
        if self.at_kind("ident"):
            return self.next()
        self.fail(f"expected {what}, found '{self.peek().text}'")
    def recover_to_item(self):
        # skip to the next top-level item start, so one bad item doesn't poison the rest
        while not self.eof() and not self.at_kw("fn", "proc", "type", "data"):
            self.next()

    # ============================= top level =============================
    def parse_program(self) -> A.Program:
        items = []
        while not self.eof():
            if self.at_kw("fn", "proc", "type", "data"):
                try:
                    items.append(self.parse_item())
                except _ParseError:
                    self.recover_to_item()
            else:
                # stray token at top level
                self.errors.append(A.Diagnostic(self.peek().line, self.peek().col,
                                                f"expected 'fn', 'proc', 'type' or 'data', found '{self.peek().text}'"))
                self.recover_to_item()
        return A.Program(items, self.errors)

    def parse_item(self):
        if self.at_kw("type"):
            return self.parse_type_alias()
        if self.at_kw("data"):
            return self.parse_data()
        return self.parse_fn()

    def parse_data(self) -> A.DataDecl:
        # brace form (consistent with this parser's newline-insensitive style): data Name<g> { Ctor(T,..) ... }
        start = self.next()                      # 'data'
        name = self.expect_ident("data type name").text
        generics = self.parse_generic_params() if self.at("<") else []
        self.expect("{", "constructor list")
        ctors = []
        while not self.at("}") and not self.eof():
            t = self.expect_ident("constructor name")
            arg_types = []
            if self.at("("):
                self.next()
                arg_types.append(self.parse_type())
                while self.at(","):
                    self.next()
                    arg_types.append(self.parse_type())
                self.expect(")")
            ctors.append(A.Ctor(t.text, arg_types, self.span(t)))
        self.expect("}", "close data declaration")
        return A.DataDecl(name, generics, ctors, self.span(start))

    # ============================= fn / proc =============================
    def parse_fn(self) -> A.FnDecl:
        start = self.next()                      # 'fn' | 'proc'
        kind = start.text
        name = self.expect_ident("function name").text
        generics = self.parse_generic_params() if self.at("<") else []
        self.expect("(", "parameter list")
        params = self.parse_params()
        self.expect(")")
        ret = None
        if self.at("->", "→"):
            self.next()
            ret = self.parse_type()
        requires = ensures = decreases = produces = None
        effects: List[str] = []
        while self.at_kw(*CLAUSE_KW):
            kw = self.next().text
            if kw == "effects":
                effects = self.parse_effects()
            else:
                e = self.parse_expr()
                if kw == "requires": requires = e
                elif kw == "ensures": ensures = e
                elif kw == "decreases": decreases = e
                elif kw == "produces": produces = e
        body = self.parse_block() if self.at("{") else self._fail_body()
        return A.FnDecl(kind, name, generics, params, ret, requires, ensures,
                        decreases, produces, effects, body, self.span(start))

    def _fail_body(self):
        self.fail(f"expected '{{' (function body), found '{self.peek().text}'")

    def parse_effects(self) -> List[str]:
        names = [self.expect_ident("effect kind (pure|io|state|...)").text]
        while self.at(","):
            self.next()
            names.append(self.expect_ident("effect kind").text)
        return names

    def parse_params(self) -> List[A.Param]:
        params = []
        if self.at(")"):
            return params
        while True:
            t = self.expect_ident("parameter name")
            self.expect(":", "parameter type")
            ty = self.parse_type()
            params.append(A.Param(t.text, ty, self.span(t)))
            if self.at(","):
                self.next(); continue
            break
        return params

    # ============================= types (§1.2) =============================
    def parse_type_alias(self) -> A.TypeAlias:
        start = self.next()                      # 'type'
        name = self.expect_ident("type name").text
        generics = self.parse_generic_params() if self.at("<") else []
        self.expect("=", "type alias body")
        body = self.parse_type()
        return A.TypeAlias(name, generics, body, self.span(start))

    def parse_generic_params(self) -> List[A.GenericParam]:
        self.expect("<")
        ps = []
        while not self.at(">"):
            t = self.expect_ident("generic parameter")
            kind = None
            if self.at(":"):                     # value param: n: Nat
                self.next()
                kind = self.parse_type()
            ps.append(A.GenericParam(t.text, kind, self.span(t)))
            if self.at(","):
                self.next(); continue
            break
        self.expect(">", "close generic parameters")
        return ps

    def parse_type(self):
        t = self.peek()
        if self.at_kw("own"):
            self.next()
            return A.TyOwn(self.parse_type(), self.span(t))
        if self.at("&"):
            self.next()
            mutable = False
            if self.at_kw("mut"):
                self.next(); mutable = True
            return A.TyRef(self.parse_type(), mutable, self.span(t))
        if self.at("{"):
            return self.parse_refinement()
        name = self.expect_ident("type name").text
        args = self.parse_type_args() if self.at("<") else []
        return A.TyName(name, args, self.span(t))

    def parse_refinement(self):
        start = self.expect("{")
        var = self.expect_ident("refinement variable").text
        self.expect(":", "refinement variable type")
        base = self.parse_type()
        self.expect("|", "refinement predicate (use '{ x: T | pred }')")
        pred = self.parse_expr()
        self.expect("}")
        return A.TyRefine(var, base, pred, self.span(start))

    def parse_type_args(self) -> List[A.TypeArg]:
        self.expect("<")
        args = []
        while not self.at(">"):
            t = self.peek()
            if self.at_kind("num"):              # value/term arg (e.g. Vec<Int, 3>, mod<3329>)
                # additive precedence: '<'/'>' delimit the generic — NOT comparisons here
                args.append(A.TypeArg("term", self.parse_add(), self.span(t)))
            else:
                args.append(A.TypeArg("type", self.parse_type(), self.span(t)))
            if self.at(","):
                self.next(); continue
            break
        self.expect(">", "close type arguments")
        return args

    # ============================= blocks / statements =============================
    def parse_block(self) -> A.Block:
        start = self.expect("{")
        stmts = []
        while not self.at("}") and not self.eof():
            if self.at_kw("let"):
                stmts.append(self.parse_let())
            elif self.at_kw("yield"):
                yt = self.next()
                stmts.append(A.Yield(self.parse_expr(), self.span(yt)))
            else:
                e = self.parse_expr()
                stmts.append(A.ExprStmt(e, e.span if hasattr(e, "span") else self.span(start)))
        self.expect("}", "close block")
        return A.Block(stmts, self.span(start))

    def parse_let(self) -> A.Let:
        start = self.next()                      # 'let'
        name = self.expect_ident("binding name").text
        ty = None
        if self.at(":"):
            self.next()
            ty = self.parse_type()
        self.expect("=", "binding value")
        value = self.parse_expr()
        return A.Let(name, ty, value, self.span(start))

    # ============================= expressions =============================
    def parse_expr(self):
        if self.at("λ"):
            return self.parse_lambda()
        if self.at("∀", "∃"):
            return self.parse_quant()
        return self.parse_range()

    def parse_lambda(self):
        start = self.next()                      # λ
        params = [self.expect_ident("lambda parameter").text]
        while self.at(","):
            self.next()
            params.append(self.expect_ident("lambda parameter").text)
        self.expect(".", "lambda body (use 'λx. expr')")
        body = self.parse_expr()
        return A.Lambda(params, body, self.span(start))

    def parse_quant(self):
        start = self.next()                      # ∀ | ∃
        vars_ = [self.expect_ident("quantified variable").text]
        while self.at(","):
            self.next()
            vars_.append(self.expect_ident("quantified variable").text)
        self.expect(".", "quantifier body (use '∀x. expr')")
        body = self.parse_expr()
        return A.Quant(start.text, vars_, body, self.span(start))

    def parse_range(self):
        lo = self.parse_or()
        if self.at(".."):
            t = self.next()
            hi = self.parse_or()
            return A.Range(lo, hi, self.span(t))
        return lo

    def _binary_level(self, sub, ops):
        lhs = sub()
        while self.at(*ops):
            t = self.next()
            rhs = sub()
            lhs = A.Bin(t.text, lhs, rhs, self.span(t))
        return lhs

    def parse_or(self):
        return self._binary_level(self.parse_and, OR_OPS)
    def parse_and(self):
        return self._binary_level(self.parse_cmp, AND_OPS)
    def parse_cmp(self):
        return self._binary_level(self.parse_concat, CMP_OPS)
    def parse_concat(self):
        return self._binary_level(self.parse_add, {"++"})
    def parse_add(self):
        return self._binary_level(self.parse_mul, ADD_OPS)
    def parse_mul(self):
        return self._binary_level(self.parse_unary, MUL_OPS)

    def parse_unary(self):
        if self.at(*UN_OPS):
            t = self.next()
            return A.Un(t.text, self.parse_unary(), self.span(t))
        return self.parse_pow()

    def parse_pow(self):
        base = self.parse_postfix()
        if self.at("**"):                        # right-assoc: postfix ** unary  (grammar A.8)
            t = self.next()
            return A.Bin("**", base, self.parse_unary(), self.span(t))
        return base

    def parse_postfix(self):
        e = self.parse_primary()
        while self.at("("):                      # call f(args) — HARAN has no juxtaposition/index
            t = self.next()
            args = []
            if not self.at(")"):
                args.append(self.parse_expr())
                while self.at(","):
                    self.next()
                    args.append(self.parse_expr())
            self.expect(")")
            e = A.Call(e, args, self.span(t))
        return e

    def parse_primary(self):
        t = self.peek()
        if self.at_kind("num"):
            self.next()
            return A.Num(t.text, "." in t.text, self.span(t))
        if self.at_kw("true", "false"):
            self.next()
            return A.BoolLit(t.text == "true", self.span(t))
        if self.at_kw("match"):
            return self.parse_match()
        if self.at_kw("fold"):
            return self.parse_fold()
        if self.at_kw("cofix"):
            return self.parse_cofix()
        if self.at("("):
            self.next()
            e = self.parse_expr()
            self.expect(")")
            return e
        if self.at("["):
            return self.parse_list_expr()
        if self.at("{"):
            return self.parse_block()
        if self.at_kind("ident"):
            self.next()
            return A.Var(t.text, self.span(t))
        self.fail(f"expected an expression, found '{t.text}'")

    def parse_list_expr(self):
        start = self.expect("[")
        elems = []
        if not self.at("]"):
            elems.append(self.parse_expr())
            while self.at(","):
                self.next()
                elems.append(self.parse_expr())
        self.expect("]", "close list literal")
        return A.ListLit(elems, self.span(start))

    def parse_match(self):
        start = self.next()                      # 'match'
        scrut = self.parse_expr()
        self.expect("{", "match arms")
        arms = []
        while not self.at("}") and not self.eof():
            pt = self.peek()
            pat = self.parse_pattern()
            self.expect("=>", "match arm body")
            body = self.parse_expr()
            arms.append(A.MatchArm(pat, body, self.span(pt)))
        self.expect("}", "close match")
        return A.Match(scrut, arms, self.span(start))

    def parse_fold(self):
        start = self.next()                      # 'fold'
        binder = self.expect_ident("fold binder").text
        self.expect("in", "fold domain")
        domain = self.parse_expr()
        body = self.parse_block()
        return A.Fold(binder, domain, body, self.span(start))

    def parse_cofix(self):
        start = self.next()                      # 'cofix'
        name = self.expect_ident("cofix label").text
        body = self.parse_block()
        return A.Cofix(name, body, self.span(start))

    # ============================= patterns =============================
    def parse_pattern(self):
        t = self.peek()
        if self.at("_"):
            self.next()
            return A.PWild(self.span(t))
        if self.at("["):
            self.next()
            if self.at("]"):
                self.next()
                return A.PListEmpty(self.span(t))
            first = self.parse_pattern()
            if self.at("|"):
                self.next()
                tail = self.parse_pattern()
                self.expect("]", "close cons pattern '[h|t]'")
                return A.PCons(first, tail, self.span(t))
            elems = [first]
            while self.at(","):
                self.next()
                elems.append(self.parse_pattern())
            self.expect("]", "close list pattern")
            return A.PList(elems, self.span(t))
        if self.at_kind("num"):
            self.next()
            return A.PNum(t.text, self.span(t))
        if self.at_kw("true", "false"):
            self.next()
            return A.PBool(t.text == "true", self.span(t))
        if self.at_kind("ident"):
            self.next()
            if self.at("("):                     # constructor pattern Ctor(p, ...)
                self.next()
                args = [self.parse_pattern()]
                while self.at(","):
                    self.next()
                    args.append(self.parse_pattern())
                self.expect(")", "close constructor pattern")
                return A.PCtor(t.text, args, self.span(t))
            return A.PVar(t.text, self.span(t))
        self.fail(f"expected a pattern, found '{t.text}'")


def parse(src: str) -> A.Program:
    """Parse HARAN source into a Program (with located errors). Never raises on user input."""
    return Parser(tokenize(src)).parse_program()


