# ===== FILE: hidden_closed.py  (153 lines) =====
# ==============================================================================================================

"""
perf-build STAGE 4 — hidden closed-form recovery (the HONEST "O(1)" direction).
================================================================================
Some sequences the C-finite classifier labels O(log n) (companion-matrix power) are SECRETLY polynomials:
a linear recurrence whose characteristic roots are all 1 ⇒ the sequence is a polynomial ⇒ an O(1) closed
form (the companion-matrix O(log n) was a "fake O(log n)"). This module RECOVERS those, EXACTLY, via finite
differences + held-out verification.

★ HONEST BOUNDARIES (non-negotiable) ★
  • EXACT O(1) requires a genuine polynomial (finite differences vanish). C-finite with a non-unit root
    (Fibonacci φ) is NOT polynomial ⇒ EXACT value stays O(log n); O(1) is only a FLOAT approximation
    (Binet) ⇒ graded PROBABILISTIC(ε), NEVER EXACT (float ≠ exact integer). [§4.2]
  • If the VALUE has Θ(n) bits (2^n, n!) then writing it is Ω(n) — the Ω(N) axiom — so we do NOT claim O(1)
    evaluation; we report THETA_N_OUTPUT (a closed FORMULA exists, but exact emission is Ω(output bits)).
  • No structure (random / general code) ⇒ DECLINE. Recovery is domain-specific (numeric); general ≈ 0.
★ SOUND GATE ★ a recovered polynomial is fit on a prefix and must predict HELD-OUT samples EXACTLY (exact
  rational arithmetic) before we call it CLOSED. A wrong fit fails the held-out check ⇒ DECLINE.
"""
from __future__ import annotations

from dataclasses import dataclass
from fractions import Fraction
from math import comb
from typing import Callable, List, Optional, Tuple

CLOSED_O1 = "CLOSED_O1"          # genuine polynomial → O(1) field ops, value is polylog bits
OLOGN = "OLOGN"                  # C-finite non-polynomial (e.g. Fibonacci) → EXACT stays O(log n)
THETA_N_OUTPUT = "THETA_N"       # closed formula exists but value has Θ(n) bits ⇒ Ω(n) to emit (Ω(N) axiom)
DECLINE = "DECLINE"


@dataclass
class Recovery:
    status: str
    degree: Optional[int] = None
    coeffs_newton: Optional[List[Fraction]] = None      # Newton forward coefficients Δ^i a(0)
    checked_holdout: int = 0
    detail: str = ""
    grade: str = "EXACT"                                # EXACT for CLOSED_O1; PROBABILISTIC only for approx


def _newton_forward(prefix: List[Fraction]) -> List[Fraction]:
    """Δ^i a(0) for i=0..len-1 (the forward-difference coefficients)."""
    coeffs = []
    row = list(prefix)
    coeffs.append(row[0])
    while len(row) > 1:
        row = [row[i + 1] - row[i] for i in range(len(row) - 1)]
        coeffs.append(row[0])
    return coeffs


def _eval_newton(coeffs: List[Fraction], n: int, deg: int) -> Fraction:
    """a(n) = Σ_{i=0}^{deg} C(n,i)·Δ^i a(0)."""
    return sum(Fraction(comb(n, i)) * coeffs[i] for i in range(deg + 1))


def recover_polynomial(samples: List[Tuple[int, int]], fit: int = None, max_deg: int = 12) -> Optional[Recovery]:
    """`samples` = consecutive (n, a(n)) for n=0,1,2,…  Fit Newton forward differences on a prefix; the degree
    is the highest non-vanishing difference. Accept ONLY if it predicts the HELD-OUT remainder EXACTLY and the
    degree is genuinely bounded (evidence the higher differences vanished, not mere interpolation)."""
    if len(samples) < 4:
        return None
    fit = fit or max(4, (len(samples) * 2) // 3)
    fit = min(fit, len(samples))
    prefix = [Fraction(v) for (_, v) in samples[:fit]]
    coeffs = _newton_forward(prefix)
    # degree = highest index with a nonzero forward difference
    deg = max((i for i, c in enumerate(coeffs) if c != 0), default=0)
    if deg > max_deg or deg >= fit - 1:
        return None                                     # no vanishing higher differences ⇒ not a bounded poly
    holdout = samples[fit:]
    if not holdout:
        return None
    for (n, v) in holdout:                              # ★ sound gate: exact held-out prediction ★
        if _eval_newton(coeffs, n, deg) != Fraction(v):
            return None
    return Recovery(CLOSED_O1, degree=deg, coeffs_newton=coeffs[:deg + 1], checked_holdout=len(holdout),
                    detail=f"degree-{deg} polynomial recovered (Newton forward diffs), held-out-verified on "
                           f"{len(holdout)} points", grade="EXACT")


def classify(seq: Callable[[int], int], m: int = 60, max_deg: int = 12, value_bits_theta_n: bool = False)\
        -> Recovery:
    """Classify a sequence by SAMPLING a(0..m). Polynomial ⇒ CLOSED_O1 (recovered, held-out verified). Else if
    the value grows exponentially (Θ(n) bits) ⇒ THETA_N_OUTPUT. Else ⇒ DECLINE (C-finite non-poly is handled
    by classify_recurrence)."""
    samples = [(n, seq(n)) for n in range(m + 1)]
    rec = recover_polynomial(samples, max_deg=max_deg)
    if rec is not None:
        return rec
    if value_bits_theta_n:
        return Recovery(THETA_N_OUTPUT, detail="closed formula exists but value has Θ(n) bits ⇒ Ω(n) to emit "
                                               "(Ω(N) axiom) — NOT O(1) evaluation")
    return Recovery(DECLINE, detail="no bounded-degree polynomial structure (held-out check failed)")


def classify_recurrence(c: List[int], init: List[int], m: int = 60, max_deg: int = 12) -> Recovery:
    """Given a C-finite recurrence (currently O(log n) via companion), check whether it is SECRETLY a
    polynomial (all characteristic roots = 1) ⇒ recover O(1). Otherwise it stays OLOGN (EXACT O(1) impossible)."""
    import cfinite
    samples = [(n, cfinite.naive_nth(list(c), list(init), n)) for n in range(m + 1)]
    rec = recover_polynomial(samples, max_deg=max_deg)
    if rec is not None:
        rec.detail += " — upgraded from C-finite O(log n) companion to O(1) polynomial"
        return rec
    return Recovery(OLOGN, detail="C-finite with a non-unit characteristic root (e.g. φ): EXACT value stays "
                                  "O(log n) (companion). O(1) is only a float approximation ⇒ PROBABILISTIC.")


def approx_O1_probabilistic(phi: float, psi: float, scale: float, n: int) -> Tuple[float, Recovery]:
    """A float O(1) APPROXIMATION (e.g. Binet a(n) ≈ φ^n/√5) — explicitly PROBABILISTIC/inexact, NEVER EXACT.
    Returns (approx_value, Recovery with grade=PROBABILISTIC and the |error| as ε)."""
    val = (phi ** n) / scale
    return val, Recovery("CLOSED_O1_APPROX", grade="PROBABILISTIC",
                         detail=f"float approximation (Binet-type) — O(1) but INEXACT (round-off); never EXACT")


# ───────────────────────────── §4.3 measurement: recovery rate by category (held-out verified)
def measure_recovery() -> dict:
    """Run the hidden-closed-form kernel over a category-labeled corpus and report the recovered-to-CLOSED_O1
    rate per category (held-out verified). Honest: polynomial-class recovers; Fibonacci/exp/random do not."""
    import cfinite
    corpus = {
        "polynomial-sum": [                                   # secretly O(1) (often mislabeled O(log n))
            lambda n: n * (n + 1) // 2,                       # Σk
            lambda n: n * (n + 1) * (2 * n + 1) // 6,         # Σk²
            lambda n: (n * (n + 1) // 2) ** 2,                # Σk³
            lambda n: n * n,                                  # Σ(2k-1)
            lambda n: 3 * n * n * n - 2 * n + 5,              # arbitrary cubic
        ],
        "cfinite-nonpoly": [                                  # genuinely O(log n) (NOT recoverable to EXACT O(1))
            lambda n: cfinite.naive_nth([1, 1], [0, 1], n),   # Fibonacci
            lambda n: cfinite.naive_nth([1, 1], [2, 1], n),   # Lucas
            lambda n: cfinite.naive_nth([2], [1], n),         # 2^n (also Θ(n) bits)
        ],
        "general-noise": [                                    # no structure ⇒ DECLINE (Ω(N))
            lambda n: (n * 2654435761) % 1000003,
            lambda n: (n * n * 97 + 7 * n + 13) % 9973 + (1 if (n * 31) % 7 == 0 else 0),
        ],
    }
    exponential = {id(corpus["cfinite-nonpoly"][2])}          # 2^n has Θ(n)-bit values
    out = {}
    for cat, seqs in corpus.items():
        recovered = 0
        for s in seqs:
            rec = classify(s, m=40, value_bits_theta_n=(cat == "cfinite-nonpoly"))
            if rec.status == CLOSED_O1 and rec.grade == "EXACT":
                recovered += 1
        out[cat] = {"recovered_O1": recovered, "n": len(seqs),
                    "rate": round(recovered / len(seqs), 3)}
    return out


# ==============================================================================================================
# ===== FILE: hir.py  (202 lines) =====
# ==============================================================================================================

"""
HARAN v16 Part B · STAGE B1 — language detection + frontend → HARAN-IR (HIR).
=============================================================================
Type B accepts arbitrary-language code, lowers it to a common IR (HIR), and runs the property-based /
probabilistic engine on the IR (language-agnostic). Python is the first frontend (ast module is exact
and free); C/Rust/Go are registered EXTENSION POINTS only (DEFER — added later via pycparser etc.).

HIR is deliberately small: per function we keep the parameter list, the source text (so property testing
can `exec` the real code — we test behaviour, not a reimplementation), and a flat list of OPERATIONS
with line numbers (kind ∈ append/pop/slice/compare/arith/index_store/call/...). That operation list is
what STAGE B4 maps violated properties onto, and what B8 slices.

Honest scope: detection is extension+syntax heuristics (optional AI confirm only if an API key exists);
only Python lowers to HIR now — every other language is an explicit registered stub, not a fake.
"""
from __future__ import annotations

import ast
from dataclasses import dataclass, field
from typing import Callable, Dict, List, Optional


# ----------------------------------------------------------------- HIR data model
@dataclass
class HOp:
    kind: str        # append|pop|insert|slice|sort|reverse|compare|arith|aug|index_load|index_store|call|return|swap
    line: int
    detail: str = ""


@dataclass
class HFunction:
    name: str
    params: List[str]
    ops: List[HOp]
    source: str          # exact source of this function (for behavioural property testing & slicing)
    start_line: int
    end_line: int
    lang: str = "python"        # language of `source` (drives runtime.make_callable)
    signature: dict = field(default_factory=dict)   # frontend-supplied calling info (param/return shapes)

    def op_kinds(self) -> set:
        return {o.kind for o in self.ops}


@dataclass
class HModule:
    lang: str
    functions: List[HFunction]
    source: str

    def fn(self, name: str) -> Optional[HFunction]:
        return next((f for f in self.functions if f.name == name), None)


# ----------------------------------------------------------------- B1.1 language detection
_EXT = {".py": "python", ".c": "c", ".h": "c", ".rs": "rust", ".go": "go",
        ".js": "javascript", ".ts": "typescript", ".java": "java", ".cpp": "cpp"}


def detect_language(filename: Optional[str] = None, source: str = "") -> str:
    if filename:
        for ext, lang in _EXT.items():
            if filename.endswith(ext):
                return lang
    s = source
    if "#include" in s or ("int main(" in s and "{" in s):
        return "c"
    if "fn " in s and ("let " in s or "->" in s) and "{" in s:
        return "rust"
    if "package " in s and "func " in s:
        return "go"
    if "function " in s or "const " in s and "=>" in s:
        return "javascript"
    if "def " in s or "import " in s or "lambda" in s:
        # confirm it actually parses as Python
        try:
            ast.parse(s)
            return "python"
        except SyntaxError:
            pass
    try:
        ast.parse(s)
        return "python"
    except SyntaxError:
        return "unknown"


def ai_confirm_language(source: str) -> Optional[str]:
    """Optional AI confirmation. DISABLED under the level-1 key policy (no env keys ever) — returns
    None so the keyword heuristic stands. Any AI augmentation would take an explicit per-call key
    (level-1), never an environment variable."""
    return None


# ----------------------------------------------------------------- B1.2 Python → HIR
_CALL_KIND = {"append": "append", "pop": "pop", "insert": "insert", "extend": "extend",
              "remove": "remove", "sort": "sort", "reverse": "reverse", "sorted": "sort",
              "reversed": "reverse", "min": "compare", "max": "compare", "len": "len"}


class _PyOps(ast.NodeVisitor):
    def __init__(self):
        self.ops: List[HOp] = []

    def _add(self, kind, node, detail=""):
        self.ops.append(HOp(kind, getattr(node, "lineno", 0), detail))

    def visit_Call(self, node):
        kind = "call"
        detail = ""
        f = node.func
        if isinstance(f, ast.Attribute):
            detail = f.attr
            kind = _CALL_KIND.get(f.attr, "call")
        elif isinstance(f, ast.Name):
            detail = f.id
            kind = _CALL_KIND.get(f.id, "call")
        self._add(kind, node, detail)
        self.generic_visit(node)

    def visit_Subscript(self, node):
        ctx = "index_store" if isinstance(node.ctx, ast.Store) else "index_load"
        if isinstance(node.slice, ast.Slice):
            self._add("slice", node)
        else:
            self._add(ctx, node)
        self.generic_visit(node)

    def visit_Compare(self, node):
        self._add("compare", node, detail="".join(type(o).__name__ for o in node.ops))
        self.generic_visit(node)

    def visit_BinOp(self, node):
        self._add("arith", node, detail=type(node.op).__name__)
        self.generic_visit(node)

    def visit_AugAssign(self, node):
        self._add("aug", node, detail=type(node.op).__name__)
        self.generic_visit(node)

    def visit_Return(self, node):
        self._add("return", node)
        self.generic_visit(node)


def python_to_hir(source: str) -> HModule:
    tree = ast.parse(source)
    src_lines = source.splitlines()
    fns: List[HFunction] = []
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            v = _PyOps()
            for stmt in node.body:
                v.visit(stmt)
            params = [a.arg for a in node.args.args]
            start = node.lineno
            end = getattr(node, "end_lineno", start)
            src = "\n".join(src_lines[start - 1:end])
            fns.append(HFunction(node.name, params, v.ops, src, start, end))
    return HModule("python", fns, source)


# ----------------------------------------------------------------- B1.3 extension registry
FRONTENDS: Dict[str, Optional[Callable[[str], HModule]]] = {
    "python": python_to_hir,
    "c": None,           # DEFER — pycparser frontend (extension point exists, engine is shared)
    "rust": None,        # DEFER
    "go": None,          # DEFER
    "javascript": None,  # DEFER
}


@dataclass
class FrontendResult:
    lang: str
    module: Optional[HModule]
    supported: bool
    detail: str


_FRONTEND_MODULES = {"c": "frontend_c", "go": "frontend_go", "rust": "frontend_rust",
                     "javascript": "frontend_js", "typescript": "frontend_js", "java": "frontend_java"}


def to_hir(source: str, filename: Optional[str] = None) -> FrontendResult:
    lang = detect_language(filename, source)
    fe = FRONTENDS.get(lang)
    if fe is None and lang in _FRONTEND_MODULES:        # lazy-load the frontend, which self-registers
        try:
            __import__(_FRONTEND_MODULES[lang])
            fe = FRONTENDS.get(lang)
        except Exception as e:
            return FrontendResult(lang, None, False, f"{lang}: frontend unavailable ({e}) — BLOCKED")
    if fe is None:
        return FrontendResult(lang, None, False,
                              f"{lang}: frontend not implemented (registered extension point; DEFER)")
    try:
        return FrontendResult(lang, fe(source), True, "lowered to HIR")
    except SyntaxError as e:
        return FrontendResult(lang, None, False, f"parse error: {e}")


# ==============================================================================================================
# ===== FILE: ic3_pdr.py  (98 lines) =====
# ==============================================================================================================

"""
v27 STAGE 17b — unbounded safety by k-induction (IC3/PDR family), complementing bounded model checking.
========================================================================================================
S6's model checker is BOUNDED (it explores states up to a depth). This proves safety for ALL reachable
states (infinite horizon) by k-induction over an SMT transition system:

    base step   : no state reachable within k transitions from init violates the property (else UNSAFE+trace)
    induction   : if the property held for k consecutive states, it holds at the (k+1)-th (k-inductive)
    ⇒ both hold : SAFE — the property is an inductive invariant for the whole (infinite) state space.

Predicates are Z3 callables on state dicts (init(s), trans(s,s'), prop(s)) — the same style as S6 — so the
solver is the trusted kernel. UNSAFE returns a concrete counterexample trace; not-k-inductive-within-bound
returns UNKNOWN (honest — needs a stronger invariant), never a false SAFE.

★ HONEST (§1.9, §5) ★: the implemented method is k-INDUCTION (a sound SMT-based unbounded-safety procedure
in the IC3/PDR/SAT-model-checking family). Full IC3/PDR clause-learning + interpolation is the extension
point — NOT claimed built here. SMT may return UNKNOWN on hard nonlinear systems; that is reported, never
hidden.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Callable, Dict, List, Optional

import z3

State = Dict[str, z3.ArithRef]
Pred1 = Callable[[State], z3.BoolRef]
Pred2 = Callable[[State, State], z3.BoolRef]


@dataclass
class SafetyVerdict:
    status: str                  # SAFE | UNSAFE | UNKNOWN
    method: str = "k-induction"
    k: int = 0
    invariant: str = ""
    trace: List[Dict[str, int]] = field(default_factory=list)
    detail: str = ""

    def __str__(self):
        if self.status == "SAFE":
            return f"SAFE (k-induction, k={self.k}): property is an inductive invariant — {self.invariant}"
        if self.status == "UNSAFE":
            return f"UNSAFE: counterexample trace {self.trace}"
        return f"UNKNOWN — {self.detail}"


def _state(varnames: List[str], tag: str) -> State:
    return {v: z3.Int(f"{v}_{tag}") for v in varnames}


def _model_trace(m, states: List[State], varnames: List[str]) -> List[Dict[str, int]]:
    out = []
    for s in states:
        row = {}
        for v in varnames:
            val = m.eval(s[v], model_completion=True)
            row[v] = val.as_long() if hasattr(val, "as_long") else str(val)
        out.append(row)
    return out


def prove_safety(varnames: List[str], init: Pred1, trans: Pred2, prop: Pred1,
                 max_k: int = 8, invariant_str: str = "prop") -> SafetyVerdict:
    """k-induction: increase k until the property is k-inductive (SAFE), a base counterexample appears
    (UNSAFE + trace), or the bound is hit (UNKNOWN — not k-inductive, needs strengthening)."""
    for k in range(1, max_k + 1):
        # ── base: is there a path of length <k from init that violates prop at some step? ──
        base = z3.Solver()
        bs = [_state(varnames, f"b{i}") for i in range(k)]
        base.add(init(bs[0]))
        for j in range(k - 1):
            base.add(trans(bs[j], bs[j + 1]))
        base.add(z3.Or([z3.Not(prop(bs[i])) for i in range(k)]))
        r = base.check()
        if r == z3.sat:
            return SafetyVerdict("UNSAFE", k=k, trace=_model_trace(base.model(), bs, varnames),
                                 detail=f"reachable property violation within {k} steps")
        if r == z3.unknown:
            return SafetyVerdict("UNKNOWN", k=k, detail="SMT returned unknown on the base case")
        # ── induction: assume prop for k consecutive states + transitions, derive prop at the next ──
        step = z3.Solver()
        ss = [_state(varnames, f"s{i}") for i in range(k + 1)]
        for j in range(k):
            step.add(prop(ss[j]))
            step.add(trans(ss[j], ss[j + 1]))
        step.add(z3.Not(prop(ss[k])))
        r2 = step.check()
        if r2 == z3.unsat:
            return SafetyVerdict("SAFE", k=k, invariant=invariant_str,
                                 detail=f"property is {k}-inductive")
        if r2 == z3.unknown:
            return SafetyVerdict("UNKNOWN", k=k, detail="SMT returned unknown on the induction step")
        # else: not yet k-inductive (a CTI exists) — try a larger k
    return SafetyVerdict("UNKNOWN", k=max_k,
                         detail=f"not k-inductive within k≤{max_k} — needs a stronger invariant (honest)")


# ==============================================================================================================
# ===== FILE: incorrectness.py  (151 lines) =====
# ==============================================================================================================

"""
v26 STAGE 3 — incorrectness-logic bug-existence checker (UX, zero false positives by construction).
====================================================================================================
The dual of verification: instead of proving a bug ABSENT (over-approximate, OX), prove a bug PRESENT
(under-approximate, UX — O'Hearn POPL 2020). Here: reachable division/modulo-by-zero. For each `/`/`%`,
ask Z3 whether some input satisfying `requires` AND the path condition to that operation makes the
denominator 0. If SAT, the Z3 model is a concrete WITNESS → BUG_REACHABLE. Because the witness is a real
model of (requires ∧ path ∧ denom=0), there are **zero false positives by construction**.

Verdicts:  BUG_REACHABLE (class + witness) | NO_BUG_FOUND | UNMODELED (e.g. requires not encodable).

★ HONEST LABELS (§1.8) ★:
  • This is UX (under-approximation). `NO_BUG_FOUND` is **NOT** a proof of absence — it means this
    under-approximate search found none (other bug classes, or regions it doesn't analyze, may hide bugs).
  • Path-sensitive & sound: a division guarded by a branch (e.g. `match b {0 => .. _ => a/b}`) is NOT
    reported (its path condition `b≠0` makes `denom=0` unsat). Divisions inside list/ADT-pattern arms or
    fold bodies are NOT analyzed (skipped, never falsely reported) to keep FP=0.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import List, Optional

import haran_ast as A
import z3_adapter as Z
from haran_parser import parse


@dataclass
class BugVerdict:
    status: str                         # BUG_REACHABLE | NO_BUG_FOUND | UNMODELED | PARSE_ERROR | NONE
    bugs: List[dict] = field(default_factory=list)   # [{cls, line, witness}]
    detail: str = ""

    def __str__(self):
        if self.status == "BUG_REACHABLE":
            b = self.bugs[0]
            return f"BUG_REACHABLE ({len(self.bugs)}): {b['cls']} at line {b['line']} — witness {b['witness']} (UX)"
        if self.status == "NO_BUG_FOUND":
            return "NO_BUG_FOUND — under-approximate search found no modeled bug. NOT a proof of absence."
        return f"{self.status} — {self.detail}"


def _var_types(fn):
    vt = {}
    for p in fn.params:
        if isinstance(p.ty, A.TyName) and p.ty.name in ("Float", "Real", "rat"):
            vt[p.name] = "Real"
        elif isinstance(p.ty, A.TyName) and p.ty.name in ("Int", "Nat"):
            vt[p.name] = "Int"
    return vt


def check_reachable_bugs(code: str) -> BugVerdict:
    """Find reachable division/modulo-by-zero with a concrete witness (UX). See module docstring."""
    if not Z.z3_available():
        return BugVerdict("UNMODELED", detail="Z3 unavailable")
    prog = parse(code)
    if prog.errors:
        return BugVerdict("PARSE_ERROR", detail=str(prog.errors[0]))
    fns = prog.fns()
    if not fns:
        return BugVerdict("NONE", detail="no function found")
    fn = fns[0]
    import z3
    vt = _var_types(fn)
    real = any(t == "Real" for t in vt.values())
    zenv = {n: (z3.Real(n) if t == "Real" else z3.Int(n)) for n, t in vt.items()}

    # base assumption = requires (must be encodable, else we cannot soundly witness → UNMODELED)
    base = []
    if fn.requires is not None:
        try:
            base = [Z._to_z3(fn.requires, zenv, real)]
        except Z._Unsupported:
            return BugVerdict("UNMODELED", detail="`requires` not Z3-encodable — cannot soundly witness "
                              "a bug under it (avoiding a false positive)")

    bugs: List[dict] = []

    def query_zero(denom, line, path):
        try:
            dz = Z._to_z3(denom, zenv, real)
        except Z._Unsupported:
            return                       # can't encode this denominator → skip (no false positive)
        s = z3.Solver(); s.set("timeout", 5000)
        for c in base + path:
            s.add(c)
        s.add(dz == 0)
        if s.check() == z3.sat:
            m = s.model()
            witness = {n: str(m.eval(zenv[n], model_completion=True)) for n in vt}
            bugs.append({"cls": "div_by_zero" , "line": line, "witness": witness})

    def scan(n, path, analyzable):
        if n is None:
            return
        if isinstance(n, A.Bin):
            if n.op in ("/", "%") and analyzable:
                query_zero(n.rhs, getattr(getattr(n, "span", None), "line", 0), path)
            scan(n.lhs, path, analyzable); scan(n.rhs, path, analyzable)
        elif isinstance(n, A.Un):
            scan(n.operand, path, analyzable)
        elif isinstance(n, A.Call):
            for a in n.args:
                scan(a, path, analyzable)
        elif isinstance(n, A.Block):
            for st in n.stmts:
                scan(st, path, analyzable)
        elif isinstance(n, (A.ExprStmt, A.Let)):
            scan(n.value, path, analyzable)
        elif isinstance(n, A.Match):
            # encode the scrutinee; build each arm's path guard from PNum/PBool patterns + wildcard
            try:
                scz = Z._to_z3(n.scrut, zenv, real)
                scrut_ok = True
            except Z._Unsupported:
                scrut_ok = False
            prior = []
            import z3
            for arm in n.arms:
                guard, arm_ok = [], scrut_ok and analyzable
                p = arm.pattern
                if isinstance(p, A.PNum) and arm_ok:
                    guard = [scz == int(p.value)]; prior.append(int(p.value))
                elif isinstance(p, A.PBool) and arm_ok:
                    guard = [scz == (1 if p.value else 0)]
                elif isinstance(p, (A.PWild, A.PVar)) and arm_ok:
                    guard = [scz != k for k in prior]            # the catch-all: none of the prior nums
                else:
                    arm_ok = False                                # list/ADT pattern → don't analyze interior
                scan(arm.body, path + guard, arm_ok)
        elif isinstance(n, A.Fold):
            scan(n.body, path, False)                             # binder semantics → not analyzed (sound)
        # other nodes: nothing to scan for div/mod

    scan(fn.body, [], True)
    if bugs:
        return BugVerdict("BUG_REACHABLE", bugs=bugs)
    return BugVerdict("NO_BUG_FOUND")


def bug_feedback(v: BugVerdict) -> str:
    """Witness → concrete fix instruction for the write→verify→fix loop."""
    if v.status != "BUG_REACHABLE" or not v.bugs:
        return ""
    b = v.bugs[0]
    return (f"REACHABLE BUG ({b['cls']}) at line {b['line']} on input {b['witness']}: the denominator "
            f"can be 0. Fix: guard the division (e.g. `requires` the divisor ≠ 0, or branch on it) so the "
            f"divide-by-zero state is unreachable. Return the corrected HARAN function only.")


# ==============================================================================================================
# ===== FILE: incremental_smt.py  (63 lines) =====
# ==============================================================================================================

"""
STAGE 1.2 — incremental SMT (solver reuse) [SPEED · decision-identical].
========================================================================
When a *family* of goals shares the same assumption prefix (a function's `requires`, a fixed set of
domain facts), the default `prove_forall` builds a fresh Z3 solver per goal and re-asserts the whole
prefix every time. Incremental solving asserts the shared prefix **once**, then `push` / assert ¬goal /
`check` / `pop` per goal — the solver keeps the learned clauses about the shared part across goals.

★ decision-identical: incremental returns the SAME verdict as fresh per-goal solving (verified in
  measure_incremental). It is purely a speed lever — never changes an answer.
★ honesty: incremental is NOT always faster (the handoff asks to find the slow cases). measure_incremental
  reports the A/B wall-clock either way; on small/linear prefixes the win can vanish or go negative.
"""
from __future__ import annotations

from typing import Dict, List

import z3_adapter as Z


def _env(var_types: Dict[str, str]):
    import z3
    real = all(t == "Real" for t in var_types.values()) or not var_types
    return {n: (z3.Real(n) if t == "Real" else z3.Int(n)) for n, t in var_types.items()}, real


def prove_batch_incremental(shared_assumptions: List, goals: List, var_types: Dict[str, str]) -> List[str]:
    """One reused solver: assert the shared prefix once; push/¬goal/check/pop per goal."""
    import z3
    env, real = _env(var_types)
    s = z3.Solver()
    s.set("timeout", 5000)
    for a in shared_assumptions:
        s.add(Z._to_z3(a, env, real))
    out = []
    for goal in goals:
        s.push()
        s.add(z3.Not(Z._to_z3(goal, env, real)))
        r = s.check()
        out.append("PROVEN" if r == z3.unsat else ("REFUTED" if r == z3.sat else "UNKNOWN"))
        s.pop()
    return out


def prove_batch_fresh(shared_assumptions: List, goals: List, var_types: Dict[str, str]) -> List[str]:
    """Baseline: a fresh solver per goal (re-asserts the shared prefix every time)."""
    return [Z.prove_forall(goal, var_types, list(shared_assumptions)).verdict for goal in goals]


def measure_incremental(shared_assumptions: List, goals: List, var_types: Dict[str, str]) -> dict:
    """A/B the two strategies; verify they agree (decision-identical) and report wall-clock both ways."""
    import time
    t = time.perf_counter(); inc = prove_batch_incremental(shared_assumptions, goals, var_types)
    inc_s = time.perf_counter() - t
    t = time.perf_counter(); fresh = prove_batch_fresh(shared_assumptions, goals, var_types)
    fresh_s = time.perf_counter() - t
    disagreements = sum(1 for a, b in zip(inc, fresh) if a != b)
    return {"goals": len(goals), "shared_assumptions": len(shared_assumptions),
            "disagreements": disagreements, "incremental_s": round(inc_s, 4),
            "fresh_s": round(fresh_s, 4),
            "speedup": round(fresh_s / inc_s, 2) if inc_s else 0.0,
            "verdicts": inc}


