# ===== FILE: intent.py  (287 lines) =====
# ==============================================================================================================

"""
HARAN v24 Part U — intent classification + clarity + chat + routing.
====================================================================
Turns the engine into a conversational product that knows what you mean:

  • U1  classify_intent(text, key?)  — CODING / CHAT / QUESTION   (keyword-first, Claude only if unsure)
  • U2  assess_clarity(req, key?)    — clear → proceed, vague → expected questions
  • U3  chat_reply(text, key?)       — non-coding → a plain Claude answer (NO verification label)
  • U4  route(text, mode, key?)      — classify → coding pipeline | chat reply | ask

★ SPEED HONESTY ★ — stage 1 is LOCAL keyword matching (no network, sub-ms); only genuinely ambiguous
  text falls through to a Claude call (an internet round-trip = hundreds of ms). We never claim a Claude
  call is "0.5ms". The method/source on every result says exactly which path ran.

★ KEY LEVEL 1 ★ — every Claude call here (classify / clarity / chat) goes through claude_agent, which
  takes the key per-call and drops it (never stored/logged). No key → labeled mock (source='mock-sim').

★ CODING vs CHAT honesty ★ — coding answers are HARAN-verified (carry proof labels elsewhere); chat
  answers are a plain LLM reply and carry NO verification label (we didn't verify them).
"""
from __future__ import annotations

import json
import re
from dataclasses import dataclass, field
from typing import List, Optional

import agentic as AG
import claude_agent as CA

# ── U1: keyword signals (local, no LLM) ─────────────────────────────────────────────────────────
# imperative "make/implement/fix" → almost certainly a coding request
_CODING_VERBS = [
    "만들어", "만들어줘", "구현", "짜줘", "짜봐", "작성", "코딩", "고쳐", "고쳐줘", "리팩토", "최적화",
    "implement", "write a", "write me", "create", "build", "code up", "fix", "refactor", "optimize",
    "generate",
]
_CODING_NOUNS = [
    "함수", "코드", "알고리즘", "정렬", "클래스", "메서드", "버그", "자료구조", "재귀", "반복문", "배열",
    "function", "code", "algorithm", "sort", "class", "method", "bug", "data structure", "recursion",
    "loop", "array", "parser", "regex",
]
_CHAT_KW = [
    "안녕", "하이", "헬로", "반가", "고마", "감사", "잘 가", "잘가", "ㅋㅋ", "ㅎㅎ", "누구야", "누구니",
    "뭐해", "심심", "hi", "hello", "hey", "thanks", "thank you", "bye", "who are you", "what's up",
]
_QUESTION_KW = ["뭐야", "무엇", "뭔지", "어떻게", "왜", "설명", "알려줘", "what is", "what's", "what are",
                "how do", "how does", "how can", "why", "explain", "tell me about", "difference"]

INTENTS = ("CODING", "CHAT", "QUESTION")

# neutral system prompt for the structured (classify/clarity) Claude calls — must NOT be the HARAN-code
# system prompt, or Claude would return code instead of the requested JSON.
_CLASSIFY_SYSTEM = ("You are a precise classifier. Reply with ONLY the requested JSON object — no prose, "
                    "no code, no markdown fences.")


@dataclass
class IntentResult:
    intent: str               # CODING | CHAT | QUESTION
    method: str               # "keyword" (local, sub-ms) | "claude" (live) | "mock-default" (no key)
    confidence: float         # 0..1
    source: str = "local"     # "local" | "claude-live" | "mock-sim"


def _has(text: str, kws) -> bool:
    return any(k in text for k in kws)


def _keyword_intent(text: str) -> Optional[IntentResult]:
    """Stage 1 — local, no network. Returns a confident result or None (→ ambiguous)."""
    t = text.lower().strip()
    has_verb = _has(t, _CODING_VERBS)
    has_noun = _has(t, _CODING_NOUNS)
    has_chat = _has(t, _CHAT_KW)
    is_question = t.endswith("?") or _has(t, _QUESTION_KW)

    # 1) explicit coding command wins (imperative verb) — "정렬 함수 만들어줘"
    if has_verb:
        return IntentResult("CODING", "keyword", 0.95)
    # 2) clear smalltalk (greeting/thanks) with no coding noun — "안녕", "고마워"
    if has_chat and not has_noun:
        return IntentResult("CHAT", "keyword", 0.9)
    # 3) an informational question with no coding command — "정렬이 뭐야?", "HARAN이 뭐야?"
    if is_question and not has_verb:
        return IntentResult("QUESTION", "keyword", 0.85)
    # 4) a coding noun, no question/greeting — "퀵소트 코드", "이진탐색 알고리즘"
    if has_noun:
        return IntentResult("CODING", "keyword", 0.8)
    return None   # ambiguous → stage 2


def _extract_json(text: str) -> dict:
    m = re.search(r"\{.*\}", text, re.S)
    if not m:
        return {}
    try:
        return json.loads(m.group(0))
    except Exception:   # noqa: BLE001
        return {}


# conservative default for the no-key path: "거의 다 코딩" → assume CODING when unsure
_CLASSIFY_MOCK = '{"is_coding": true, "confidence": 0.55}'


def classify_intent(text: str, api_key: Optional[str] = None, *,
                    mock_response: Optional[str] = None,
                    provider: Optional[str] = None, model: Optional[str] = None,
                    base_url: Optional[str] = None) -> IntentResult:
    """U1: CODING / CHAT / QUESTION. Stage 1 = local keywords (sub-ms, no network). Stage 2 (only when
    ambiguous) = a model call (hundreds of ms) or, with no key, a conservative mock default (CODING).
    `provider`/`model`/`base_url` (v26 S0) select the gateway for the stage-2 call."""
    if not (text or "").strip():
        return IntentResult("CHAT", "keyword", 0.5)
    kw = _keyword_intent(text)
    if kw is not None:
        return kw
    # stage 2 — ambiguous: ask the model (real round-trip) or fall back to a conservative mock default
    prompt = ('Classify this user message. Reply ONLY JSON {"is_coding": bool, "confidence": 0..1}. '
              'is_coding=true for requests to write/fix/optimize code; false for smalltalk or questions.\n'
              f"Message: {text}")
    gen = CA.claude_generate(prompt, api_key, system=_CLASSIFY_SYSTEM,
                             mock_response=mock_response or _CLASSIFY_MOCK,
                             provider=provider, model=model, base_url=base_url)
    obj = _extract_json(gen.text)
    is_coding = bool(obj.get("is_coding", True))      # default true (conservative)
    conf = float(obj.get("confidence", 0.55)) if isinstance(obj.get("confidence", 0.55), (int, float)) else 0.55
    method = "claude" if api_key else "mock-default"
    intent = "CODING" if is_coding else "CHAT"
    return IntentResult(intent, method, conf, source=gen.source)


# ── U2: clarity assessment ──────────────────────────────────────────────────────────────────────
# A bare "정렬 함수" is ambiguous (asc/desc? type?) — building it blind would be wrong. A request that
# already states constraints proceeds immediately. Known-ambiguous topics get topic-specific questions
# locally; otherwise (rare) Claude decides. The questions are SUGGESTIONS — the user may answer or ignore.
_CONSTRAINT_KW = ["오름차순", "내림차순", "ascending", "descending", "정수", "integer", "int", "float",
                  "문자열", "string", "리스트", "list", "1부터", "1 to", "0부터", "ensures", "명세",
                  "반환", "returns", "given", "입력은", "input is"]
_TOPIC_ASKS = {
    "sort": ["오름차순/내림차순? (ascending or descending?)", "원소 타입? (int / float / string?)",
             "안정 정렬이 필요한가요? (stable?)"],
    "search": ["입력이 정렬돼 있나요? (sorted input?)", "원소 타입? (type?)",
               "못 찾으면 어떻게? (not-found behavior?)"],
    "parse": ["입력 형식은? (input format?)", "잘못된 입력 처리? (error handling?)"],
}
_TOPIC_KW = {
    "sort": ["정렬", "sort", "소트"],
    "search": ["탐색", "검색", "search", "find"],
    "parse": ["파싱", "파서", "parse", "parser"],
}


@dataclass
class ClarityResult:
    clear: bool                       # True → proceed straight to agentic_code
    asks: List[str] = field(default_factory=list)   # expected questions when vague (suggestions)
    method: str = "keyword"           # "keyword" (local) | "claude" | "mock-default"
    source: str = "local"


def _detect_topic(t: str) -> Optional[str]:
    for topic, kws in _TOPIC_KW.items():
        if _has(t, kws):
            return topic
    return None


_CLARITY_MOCK = '{"clear": true, "asks": []}'


def assess_clarity(request: str, api_key: Optional[str] = None, *,
                   mock_response: Optional[str] = None,
                   provider: Optional[str] = None, model: Optional[str] = None,
                   base_url: Optional[str] = None) -> ClarityResult:
    """U2: is a coding request specific enough to build, or should we ask first? Local first (constraint
    keywords → clear; known-ambiguous topic w/o constraints → topic questions); model only if unsure."""
    t = (request or "").lower()
    if _has(t, _CONSTRAINT_KW):                 # already states constraints → proceed
        return ClarityResult(True, [], "keyword", "local")
    topic = _detect_topic(t)
    if topic:                                    # known-ambiguous topic, no constraints → ask (local)
        return ClarityResult(False, _TOPIC_ASKS[topic], "keyword", "local")
    # undecided locally → model (or conservative mock = proceed)
    prompt = ('Is this coding request specific enough to implement, or are key details missing? Reply '
              'ONLY JSON {"clear": bool, "asks": ["q1","q2"]} (asks = the questions to ask if unclear).\n'
              f"Request: {request}")
    gen = CA.claude_generate(prompt, api_key, system=_CLASSIFY_SYSTEM,
                             mock_response=mock_response or _CLARITY_MOCK,
                             provider=provider, model=model, base_url=base_url)
    obj = _extract_json(gen.text)
    clear = bool(obj.get("clear", True))
    asks = [str(a) for a in obj.get("asks", [])] if isinstance(obj.get("asks", []), list) else []
    return ClarityResult(clear, asks if not clear else [], "claude" if api_key else "mock-default", gen.source)


# ── U3: chat reply (non-coding → a plain answer, NEVER verified) ─────────────────────────────────
# Chat/questions get a normal LLM answer. ★ It carries NO verification label ★ — we did not prove it,
# so we never stamp it "PROVEN/반례". (Coding answers are HARAN-verified; chat answers are not. Honest.)
CHAT_SYSTEM = ("You are MR.JEFFREY, a friendly assistant for a verified-coding product. Answer briefly "
               "and warmly. After smalltalk, gently offer to build & verify some code.")


@dataclass
class ChatReply:
    text: str
    source: str = "mock-sim"          # "claude-live" | "mock-sim"
    kind: str = "chat"
    verified: bool = False            # ALWAYS False — chat is never verified (no proof label)


def _canned_chat(text: str) -> str:
    t = (text or "").lower()
    if _has(t, ["안녕", "하이", "헬로", "반가", "hi", "hello", "hey", "what's up"]):
        return "안녕하세요! 무엇을 만들어 드릴까요? (Hi! What should we build & verify?)"
    if _has(t, ["고마", "감사", "thanks", "thank you"]):
        return "천만에요! 코드가 필요하면 언제든 말씀해 주세요. (Anytime — say the word for code.)"
    if _has(t, ["누구", "who are you", "mr.jeffrey", "mr. jeffrey", "haran", "뭐야", "what is", "뭔지"]):
        return ("저는 MR.JEFFREY예요 — Claude가 코드를 짜면 제가 수학적으로 검증·최적화합니다. "
                "함수나 알고리즘을 요청해 보세요. (I'm MR.JEFFREY: Claude writes code, I verify & "
                "optimize it mathematically. Ask for a function or algorithm.)")
    return ("음 — 코드로 만들어 검증해 드릴까요? 예: '정렬 함수' 같은 걸요. "
            "(Want me to turn that into verified code? e.g. a sort function.)")


def chat_reply(text: str, api_key: Optional[str] = None, history=None, *,
               mock_response: Optional[str] = None,
               provider: Optional[str] = None, model: Optional[str] = None,
               base_url: Optional[str] = None) -> ChatReply:
    """U3: a plain conversational answer for CHAT/QUESTION. With a key → a real model reply (general
    system prompt). No key → a canned SIM reply. NEVER carries a verification label (verified=False)."""
    if api_key:
        gen = CA.claude_generate(text, api_key, system=CHAT_SYSTEM,   # general answer, not HARAN code
                                 provider=provider, model=model, base_url=base_url)
        return ChatReply(gen.text, gen.source)
    return ChatReply(mock_response or _canned_chat(text), "mock-sim")


# ── U4: unified router ──────────────────────────────────────────────────────────────────────────
# input → classify → CODING (clear → agentic_code | vague → ask) | CHAT/QUESTION → chat_reply.
# Whole-program coding asks are out of scope (Rice) → an honest plain reply (NOT a fake verification).
# keep the keyword set in sync with server._SCOPE_RE.
_SCOPE_RE = re.compile(r"백엔드|서버|backend|server|큐|queue|상태\s*머신|state\s*machine|\bapi\b|jwt|"
                       r"결제|payment", re.I)
SCOPE_REPLY = ("이 요청은 큰 프로그램입니다. MR.JEFFREY는 작은~중간 코드를 *명세 대비* 검증·최적화합니다 "
               "(Rice: 무에서 전체 생성 불가). 핵심 로직과 명세(ensures)를 주세요. / This is a large "
               "program — give the core logic + a spec; MR.JEFFREY verifies small~medium code against it.")


def is_scope(text: str) -> bool:
    return bool(_SCOPE_RE.search(text or ""))


@dataclass
class RouteResult:
    kind: str                          # "code" | "chat" | "ask"
    intent: str                        # CODING | CHAT | QUESTION
    request: str
    source: str
    verified: bool = False             # True ONLY for a verified coding result; chat/ask = False
    code_result: object = None         # AgenticResult (kind="code")
    reply: Optional[str] = None        # (kind="chat")
    asks: List[str] = field(default_factory=list)  # (kind="ask")


def route(text: str, mode: str = "normal", api_key: Optional[str] = None, history=None,
          force: bool = False, *, provider: Optional[str] = None, model: Optional[str] = None,
          base_url: Optional[str] = None) -> RouteResult:
    """U4: classify the message and route it. CODING+clear → run the verified pipeline; CODING+vague →
    return expected questions (unless `force` → proceed anyway); CHAT/QUESTION → a plain (unverified)
    reply. The `kind` says which. `provider`/`model`/`base_url` (v26 S0) select the gateway at runtime."""
    it = classify_intent(text, api_key, provider=provider, model=model, base_url=base_url)
    if it.intent == "CODING":
        if is_scope(text):                                   # whole-program ask → honest scope reply
            return RouteResult("chat", "CODING", text, "local", verified=False, reply=SCOPE_REPLY)
        if not force:                                        # U7: 'proceed anyway' skips the clarity gate
            clarity = assess_clarity(text, api_key, provider=provider, model=model, base_url=base_url)
            if not clarity.clear:                            # missing details → ask first (suggestions)
                return RouteResult("ask", "CODING", text, clarity.source, verified=False, asks=clarity.asks)
        res = AG.agentic_code(text, mode, api_key, history=history or [],   # the verified pipeline
                              model=model or CA.DEFAULT_MODEL, provider=provider, base_url=base_url)
        return RouteResult("code", "CODING", text, res.source, verified=res.converged, code_result=res)
    # CHAT / QUESTION → plain answer, never verified
    cr = chat_reply(text, api_key, history, provider=provider, model=model, base_url=base_url)
    return RouteResult("chat", it.intent, text, cr.source, verified=False, reply=cr.text)


# ==============================================================================================================
# ===== FILE: jeff_adapter.py  (115 lines) =====
# ==============================================================================================================

"""
STAGE 3 — JEFF EXACT engine adapter (the strongest verification tier).
======================================================================
Connects Mr. to the **real JEFF** exact engine (Rust `jeff-math`, the coefficient-zero mechanism)
via a thin CLI (`examples/jeff_identity`). sympy is the *parser front-end* (expression → exact
rational coefficients); JEFF performs the exact `is_zero` verdict over `BigRational`.

Fallback chain (each tier labeled, honest):
    JEFF (exact, proof-carrying, univariate poly)  →  sympy (exact CAS, general)  →  DEFER.

Honest scope (Stage 3.4): for a *polynomial identity*, JEFF and sympy give the **same exact**
verdict — JEFF is not "more" there; its distinctions are (a) an independent exact re-check by a
separate engine, and (b) proof-CARRYING (the verdict comes from JEFF's actual coefficient-zero
mechanism, the same one `jeff-verify` re-checks), versus sympy's black-box `simplify`. JEFF's reach
*beyond* sympy (telescoper / fold certificates for structured sums, Stage 26/35 in the Rust engine)
is real but not yet CLI-exposed for arbitrary sums — stated, not implied.
"""
from __future__ import annotations
import os
import subprocess
from dataclasses import dataclass

try:
    import sympy as sp
    from verify_exact import prove_equiv  # sympy tier (the prototype)
    _SYMPY = True
except Exception:  # pragma: no cover
    _SYMPY = False


@dataclass
class ExactResult:
    verdict: str   # "PROVEN" | "REFUTED" | "DEFER"
    backend: str   # "jeff" | "sympy" | "none"
    detail: str = ""
    witness: str = ""

    def __str__(self):
        if self.verdict == "PROVEN":
            return f"PROVEN (all inputs) by {self.backend.upper()} — {self.detail}"
        if self.verdict == "REFUTED":
            return f"REFUTED by {self.backend.upper()} — {self.detail}" + (f" (witness {self.witness})" if self.witness else "")
        return f"DEFER — {self.detail}"


def find_jeff_binary():
    """Locate the prebuilt `jeff_identity` binary in the JEFF Rust workspace, or None."""
    here = os.path.dirname(os.path.abspath(__file__))
    repo = os.path.dirname(here)  # mr_jeffrey/.. = repo root
    for sub in ("target/release/examples/jeff_identity", "target/debug/examples/jeff_identity"):
        p = os.path.join(repo, sub)
        if os.path.isfile(p) and os.access(p, os.X_OK):
            return p
    env = os.environ.get("JEFF_IDENTITY_BIN")
    return env if env and os.path.isfile(env) else None


def _uni_coeffs(expr_str, var):
    """sympy: expression → ascending exact rational coefficient strings ('num/den'), or None if it
    is not a univariate polynomial in `var`."""
    x = sp.symbols(var)
    try:
        e = sp.expand(sp.sympify(expr_str, locals={var: x}))
        p = sp.Poly(e, x)
    except Exception:
        return None
    if len(p.gens) != 1:
        return None
    asc = list(reversed(p.all_coeffs()))  # all_coeffs is highest-degree first
    out = []
    for c in asc:
        r = sp.nsimplify(c)
        fr = sp.Rational(r)
        out.append(f"{fr.p}/{fr.q}")
    return out


def prove_identity(cand_expr: str, ref_expr: str, variables: list) -> ExactResult:
    """Prove `cand ≡ ref` for all inputs, using the JEFF→sympy→DEFER chain."""
    if not _SYMPY:
        return ExactResult("DEFER", "none", "sympy not available")

    # --- Tier 1: JEFF (univariate polynomial identities) ---
    if len(variables) == 1:
        binp = find_jeff_binary()
        cc = _uni_coeffs(cand_expr, variables[0])
        rc = _uni_coeffs(ref_expr, variables[0])
        if binp and cc is not None and rc is not None:
            try:
                out = subprocess.run([binp, ",".join(cc), ",".join(rc)],
                                     capture_output=True, text=True, timeout=30).stdout.strip()
            except Exception as e:
                out = ""
            if out.startswith("PROVEN_EQUAL"):
                return ExactResult("PROVEN", "jeff", f"{cand_expr} ≡ {ref_expr} (coefficient-zero, exact)")
            if out.startswith("REFUTED"):
                w = out[len("REFUTED"):].strip()  # e.g. "degree=1 residual=-1/2"
                return ExactResult("REFUTED", "jeff",
                                   f"{cand_expr} ≢ {ref_expr} (exact disagreement: {w})", witness=w)
            # else fall through to sympy

    # --- Tier 2: sympy (general exact CAS) ---
    v = prove_equiv(cand_expr, ref_expr, variables)
    if v.verdict == "PROVEN_EQUAL":
        return ExactResult("PROVEN", "sympy", v.detail)
    if v.verdict == "PROVEN_UNEQUAL":
        return ExactResult("REFUTED", "sympy", v.detail, witness=v.witness)
    # --- Tier 3: DEFER ---
    return ExactResult("DEFER", "none", v.detail)


def backends_available():
    """Report which exact backends are live (for honest status output)."""
    return {"jeff": find_jeff_binary() is not None, "sympy": _SYMPY}


# ==============================================================================================================
# ===== FILE: kernel_router.py  (84 lines) =====
# ==============================================================================================================

"""
v40 PHASE 1A — the ROUTER / dispatcher (the entrance to every collapse kernel).
================================================================================
A cheap (µs) classification of the input picks the right kernel; if none applies (or all DECLINE), the router
falls back honestly (DECLINE). Each kernel carries a HARAN CONTRACT (requires/ensures + grade) — Constitution
§4 (HARAN-first): the applicability + grade rules live in the contract, the dispatch is thin Python glue, and
the grade is ENFORCED by the Verdict ADT (kernel_verdict). UNVERIFIED kernels are never auto-selected (§4.5).
"""
from __future__ import annotations

import time
from dataclasses import dataclass, field
from typing import Any, Callable, Dict, List, Optional

import kernel_verdict as KV


@dataclass
class Kernel:
    num: int                                  # router reference number (Appendix A)
    name: str
    group: str                                # A..H (Appendix A)
    contract: str                             # HARAN contract: requires … ensures … grade …
    detect: Callable[[Any], bool]             # cheap applicability test (µs)
    run: Callable[..., KV.Verdict]            # returns a graded Verdict
    status: str = "VERIFIED"                  # VERIFIED | UNVERIFIED (excluded from auto-select)


REGISTRY: Dict[str, Kernel] = {}
_LAST_US: float = 0.0


def register(k: Kernel) -> Kernel:
    REGISTRY[k.name] = k
    return k


def registered(verified_only: bool = True) -> List[str]:
    return [n for n, k in REGISTRY.items() if (not verified_only or k.status == "VERIFIED")]


def dispatch(data: Any, **kw) -> KV.Verdict:
    """Classify `data` and run the first applicable VERIFIED kernel whose verdict is non-DECLINE; else DECLINE.
    Records the router decision latency (µs) on the verdict (router_us)."""
    global _LAST_US
    t0 = time.perf_counter()
    tried: List[str] = []
    for k in REGISTRY.values():
        if k.status != "VERIFIED":
            continue
        try:
            applicable = k.detect(data)
        except Exception:  # noqa: BLE001 — a detector must never crash the router
            applicable = False
        if not applicable:
            continue
        tried.append(k.name)
        v = k.run(data, **kw)
        if v.status != KV.DECLINE:
            _LAST_US = (time.perf_counter() - t0) * 1e6
            return v
    _LAST_US = (time.perf_counter() - t0) * 1e6
    return KV.decline(f"no kernel applicable (tried {tried or 'none'}) — fallback to existing path", "router")


def last_decision_us() -> float:
    return _LAST_US


# ── dogfood: the contracts are well-formed HARAN-style (requires/ensures/grade) and grades are declared ──
def verify_contracts() -> dict:
    """Constitution §0.1/§4: every registered kernel must carry a contract that names requires, ensures, and a
    grade ∈ {EXACT, PROBABILISTIC, DECLINE}. A malformed contract is a build failure, not a warning."""
    bad = []
    for n, k in REGISTRY.items():
        c = k.contract
        ok = ("requires" in c and "ensures" in c
              and any(g in c for g in (KV.EXACT, KV.PROBABILISTIC, KV.DECLINE)))
        if not ok:
            bad.append(n)
    return {"n_kernels": len(REGISTRY), "verified": len(registered()),
            "unverified": [n for n, k in REGISTRY.items() if k.status != "VERIFIED"],
            "malformed_contracts": bad, "all_well_formed": not bad}


# ==============================================================================================================
# ===== FILE: kernel_verdict.py  (95 lines) =====
# ==============================================================================================================

"""
v40 PHASE 1B — the GRADE ADT, enforced (Constitution §0.2: grades never mix).
=============================================================================
Generalizes v37's SublinearVerdict.__post_init__ pattern to EVERY collapse kernel. A kernel output is exactly
one of EXACT / PROBABILISTIC(ε,δ) / DECLINE, and the grade is ENFORCED at construction (a runtime exception,
not a label):
  • non-DECLINE  ⇒ a certificate that is passed=True (no rubber stamp);
  • grade == certificate.grade (can't claim EXACT while carrying a PROBABILISTIC cert);
  • PROBABILISTIC ⇒ δ is stated (a number), never None;
  • EXACT ⇒ exact algorithm + exact certificate, OR a proven error interval (machine-ε ball). A SAMPLING count
    can NEVER be EXACT — §0.2: it is bounded by rule-of-three δ=3/n, and if the caller needs a smaller δ than
    the available n affords, the honest answer is DECLINE.
"""
from __future__ import annotations

from dataclasses import dataclass
from typing import Any, Optional

EXACT = "EXACT"
PROBABILISTIC = "PROBABILISTIC"
DECLINE = "DECLINE"
_GRADES = {EXACT, PROBABILISTIC, DECLINE}


@dataclass
class Cert:
    """A machine-rechecked certificate. `passed` must be the result of the actual fast verifier, not a wish."""
    grade: str
    kind: str                       # freivalds | schwartz_zippel | sylvester | exact_replay | interval | …
    passed: bool
    check_cost: str = ""            # the verifier's cost, e.g. "O(r·n)" — must be ≪ the kernel cost
    epsilon: Optional[float] = None
    delta: Optional[float] = None
    bound: Optional[float] = None
    detail: str = ""


@dataclass
class Verdict:
    status: str
    result: Any
    kernel: str
    complexity: str                 # the COMPUTE cost (NOT output-size); §0.1 keeps these separate
    certificate: Optional[Cert] = None
    reason: str = ""
    crossover_n: Optional[int] = None   # measured n at/after which the kernel beats the baseline (NO_UNMEASURED)
    amdahl_p: Optional[float] = None    # measured runtime-dominance fraction (small p ⇒ collapse barely helps)

    def __post_init__(self):
        assert self.status in _GRADES, f"bad grade {self.status!r}"
        if self.status != DECLINE:
            assert self.certificate is not None and self.certificate.passed, \
                f"{self.status} requires a passed certificate (no rubber stamp)"
            assert self.certificate.grade == self.status, \
                f"grade/cert mismatch: {self.status} vs {self.certificate.grade}"
            if self.status == PROBABILISTIC:
                assert self.certificate.delta is not None, "PROBABILISTIC must state δ (a number)"
            if self.status == EXACT:
                # EXACT forbids a probabilistic δ masquerading as exact (an exact interval uses epsilon/bound)
                assert self.certificate.delta is None, \
                    "EXACT cannot carry a probabilistic δ — use PROBABILISTIC, or an exact interval (epsilon)"


# ── constructors ────────────────────────────────────────────────────────────────────────────────────
def decline(reason: str, kernel: str = "-") -> Verdict:
    return Verdict(DECLINE, None, kernel, "-", None, reason)


def exact(result, kernel: str, complexity: str, cert: Cert, **kw) -> Verdict:
    return Verdict(EXACT, result, kernel, complexity, cert, **kw)


def probabilistic(result, kernel: str, complexity: str, cert: Cert, **kw) -> Verdict:
    return Verdict(PROBABILISTIC, result, kernel, complexity, cert, **kw)


# ── §0.2 rule-of-three: a sampling count yields δ=3/n, never EXACT ────────────────────────────────────
def rule_of_three_delta(n_samples: int) -> float:
    """Upper bound on the failure probability after n independent passes that all succeeded (zero failures):
    P(true rate ≥ 3/n) ≤ ~0.05 — the rule of three. This is the SMALLEST honest δ a pure sampling count earns."""
    return 3.0 / max(int(n_samples), 1)


def sampling_verdict(result, kernel: str, complexity: str, n_samples: int, required_delta: float,
                     kind: str = "differential_sampling", detail: str = "") -> Verdict:
    """Grade a SAMPLING-based check honestly: δ = rule-of-three(3/n). If the caller needs a tighter δ than the
    available samples afford, DECLINE (never inflate a sample count into EXACT — §0.2)."""
    delta = rule_of_three_delta(n_samples)
    if delta > required_delta:
        return decline(f"sampling δ={delta:.2e} (3/{n_samples}) exceeds required {required_delta:.2e} — "
                       f"would need ≥{int(3.0 / required_delta)} samples; DECLINE rather than overclaim", kernel)
    return probabilistic(result, kernel, complexity,
                         Cert(PROBABILISTIC, kind, True, f"{n_samples} samples", delta=delta,
                              detail=detail or f"rule-of-three δ=3/{n_samples}"))


