# ===== FILE: prompt_consistency.py  (108 lines) =====
# ==============================================================================================================

"""
v29 STAGE 31 — cross-representation consistency gate (Clover-for-prompts) + entity grounding.
==============================================================================================
Clover's idea applied to PROMPTS: generate the requirement in more than one representation and flag the
DIVERGENCE. Here, deterministically and key-free, we cross-check the prompt's OWN representations —
its stated NL constraints vs its worked EXAMPLES — and we ground its entities against a code/IR symbol
table (reusing S21).

  • consistency: a stated constraint on the result (e.g. "non-negative result") vs an example output
    (e.g. "f(2) returns -4") — if the example SOUNDLY violates the constraint, the prompt is internally
    DIVERGENT → route to S28 (contradiction) / S29 (ambiguity). ★zero false-positives: we flag ONLY a
    proven numeric violation (Clover's 0-FP property), never a heuristic hunch.★
  • grounding: prompt entities → code/IR symbols; a symbol that exists is GROUNDED, one that doesn't is
    flagged (checkable, reuses S21's entity-linking).

★ HONEST (§1.4, §1.5) ★: cross-representation agreement is a CONSISTENCY check, not intent correctness
(Rice) — two reps can agree and both be wrong about intent. Grounding only covers the checkable part
(symbol existence / test compiles). LLM-generated alternative representations (richer than examples) are
[BLOCKED: key/egress]; the example-vs-constraint check and symbol grounding are measured.
"""
from __future__ import annotations

import re
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple

# ── extract result-bounds and worked examples from the prompt's text ────────────────────────────────
# sign phrases, MOST-SPECIFIC FIRST (so "non-negative" wins and "negative" inside it never double-counts)
_PHRASE_BOUND = [
    (r"non[- ]?negative", (">=", 0)), (r"non[- ]?positive", ("<=", 0)),
    (r"\bpositive\b", (">", 0)), (r"\bnegative\b", ("<", 0)),
]
_RESULT_OP = re.compile(r"result\s*(?:must be|should be|is)?\s*"
                        r"(<=|>=|<|>|=|at least|at most)\s*(-?\d+)", re.IGNORECASE)
# example-output markers: a value-producing verb/arrow + a number (NO bare '=', which would catch '>= 100')
_EXAMPLE = re.compile(r"(?:returns?|outputs?|gives?|yields?|->|=>)\s*(-?\d+)", re.IGNORECASE)
_OPMAP = {"<=": "<=", ">=": ">=", "<": "<", ">": ">", "=": "==", "at least": ">=", "at most": "<="}


def result_bounds(text: str) -> List[Tuple[str, int]]:
    out: List[Tuple[str, int]] = []
    low = text.lower()
    for rx, (op, n) in _PHRASE_BOUND:           # first matching sign phrase wins (no double-count)
        if re.search(rx, low):
            out.append((op, n))
            break
    for m in _RESULT_OP.finditer(text):         # explicit "result <op> N" bounds
        out.append((_OPMAP[m.group(1).lower()], int(m.group(2))))
    return out


def example_outputs(text: str) -> List[int]:
    """Worked-example outputs: a value-producing marker followed by a number, anywhere in the prompt."""
    return [int(m.group(1)) for m in _EXAMPLE.finditer(text)]


def _violates(out: int, bound: Tuple[str, int]) -> bool:
    op, n = bound
    return not {"<": out < n, ">": out > n, "<=": out <= n, ">=": out >= n, "==": out == n}[op]


@dataclass
class ConsistencyReport:
    status: str                 # CONSISTENT | DIVERGENT
    divergences: List[str] = field(default_factory=list)
    grounded: List[str] = field(default_factory=list)
    ungrounded: List[str] = field(default_factory=list)
    route: str = ""             # "" | S28 | S29
    detail: str = ""

    def __str__(self):
        if self.status == "CONSISTENT":
            return f"CONSISTENT (grounded {len(self.grounded)}/{len(self.grounded) + len(self.ungrounded)})"
        return f"DIVERGENT → {self.route}: {self.divergences}"


def check_consistency(prompt: str) -> ConsistencyReport:
    """Cross-check the prompt's stated result-constraints against its worked examples. Flag ONLY a sound
    numeric violation (zero false positives); route a divergence to S28 (contradiction) / S29 (ambiguity)."""
    bounds = result_bounds(prompt)
    outs = example_outputs(prompt)
    divergences = [f"example output {o} violates stated constraint result {op} {n}"
                   for o in outs for (op, n) in bounds if _violates(o, (op, n))]
    if divergences:
        return ConsistencyReport("DIVERGENT", divergences, route="S28",
                                 detail="example contradicts a stated constraint (internally inconsistent prompt)")
    return ConsistencyReport("CONSISTENT", detail="stated constraints and worked examples agree (or none to check)")


# ── entity grounding to a code/IR symbol table (reuse S21's linking idea) ───────────────────────────
def ground_entities(prompt: str, symbols: List[str], entities: Optional[List[str]] = None) -> Tuple[List[str], List[str]]:
    """Link referenced entities to existing symbols. Returns (grounded, ungrounded). Checkable: a grounded
    entity names a symbol that EXISTS in the code/IR (reuses the S21 grounding notion)."""
    if entities is None:
        entities = sorted(set(re.findall(r"\b([a-z_][a-z0-9_]*)\s*\(", prompt, re.IGNORECASE)))   # f(...) calls
    symset = set(symbols)
    grounded = [e for e in entities if e in symset]
    ungrounded = [e for e in entities if e not in symset]
    return (grounded, ungrounded)


def gate(prompt: str, symbols: Optional[List[str]] = None) -> ConsistencyReport:
    """The full S31 gate: consistency (zero-FP) + entity grounding. DIVERGENT routes to S28/S29."""
    rep = check_consistency(prompt)
    if symbols is not None:
        rep.grounded, rep.ungrounded = ground_entities(prompt, symbols)
    return rep


# ==============================================================================================================
# ===== FILE: prompt_frontend.py  (100 lines) =====
# ==============================================================================================================

"""
v29 §4 — the prompt-understanding FRONT-END: S26→S31 wired into one fail-safe pipeline.
=========================================================================================
                          prompt
                            │
              [S26] requirement-structure parse  (cached on the prefix)
                            │
      ┌──────── parallel cascade (cheap; runs beside the first token) ────────┐
      │  [S27] missing-info   [S28] danger/contradiction   [S29] ambiguity    │
      │                       [S31] cross-representation consistency           │
      └───────────────────────────────┬───────────────────────────────────────┘
                            │  [policy engine]
   • danger/contradiction/divergence  → FLAG + safe alternative (proceed, never silently comply)
   • genuine high-stakes fork / critical-missing → [S30] VoI: ASK_ONE (rare) else PROCEED
   • minor ambiguity / minor missing  → PROCEED + STATED ASSUMPTIONS  (does NOT ask)
   • all clear                        → PROCEED
                            │
        structured · grounded · clarified requirements → write→verify→fix (v26–v28)

★ This breaks garbage-in-garbage-out: a bad prompt is detected and completed/flagged, never silently
propagated. ★ FAIL-SAFE everywhere: the default is PROCEED with stated assumptions; we ask only on a
VoI-cleared high-stakes fork and we flag danger — never a silent wrong action, never a hard block.
★ ZERO-WRONG-ANSWER (§1.12): the front-end only ADDS structure/assumptions/flags; the original prompt is
preserved and the downstream verifier's correctness is unchanged. ★ Latency: the cascade is deterministic
(regex + a couple of Z3 calls), measured here; the live model first-token is [BLOCKED: key/egress].
"""
from __future__ import annotations

import time
from dataclasses import dataclass, field
from typing import List, Optional

import ambiguity_detector as S29
import clarification_policy as S30
import dangerous_instruction_detector as S28
import missing_info_detector as S27
import prompt_consistency as S31
import requirement_parser as S26


@dataclass
class FrontendDecision:
    action: str                 # PROCEED | ASK_ONE | FLAG
    proceed: bool               # True unless we must get the answer first (ASK_ONE)
    assumptions: List[str] = field(default_factory=list)   # reasonable completions, stated for the user
    flags: List[str] = field(default_factory=list)         # danger/contradiction/divergence + alternatives
    question: Optional[str] = None
    requirements: object = None
    latency_ms: float = 0.0
    detail: str = ""

    def __str__(self):
        if self.action == "ASK_ONE":
            return f"ASK_ONE: {self.question}"
        if self.action == "FLAG":
            return f"FLAG (proceeds with safe reading): {self.flags}"
        return f"PROCEED" + (f" with assumptions {self.assumptions}" if self.assumptions else " (all clear)")


def analyze(prompt: str, symbols: Optional[List[str]] = None, mode: str = "normal",
            monitor: Optional[S30.AskRateMonitor] = None) -> FrontendDecision:
    """Run the full understanding cascade + policy engine. Default PROCEED (+stated assumptions); ASK only a
    VoI-cleared high-stakes fork; FLAG danger/contradiction. Never silent, never hard-block (fail-safe)."""
    t0 = time.perf_counter()
    req = S26.parse_requirements(prompt, mode)
    missing = S27.detect_missing(req)
    danger = S28.detect(prompt)
    ambiguity = S29.detect_ambiguity(prompt)
    consistency = S31.gate(prompt, symbols)
    latency = (time.perf_counter() - t0) * 1000

    assumptions: List[str] = []
    assumptions += missing.assumptions()
    assumptions += ambiguity.assumptions()
    flags: List[str] = []
    if danger.status == "FLAGGED":
        flags += [f"{f.kind}({f.cwe or '-'}): {f.evidence} → {f.alternative}" for f in danger.flags]
    if consistency.status == "DIVERGENT":
        flags += [f"inconsistent prompt: {d}" for d in consistency.divergences]

    # policy engine (priority): danger/divergence FLAG → high-stakes fork S30 → minor PROCEED+assume → clear
    if flags:
        return FrontendDecision("FLAG", True, assumptions, flags, None, req, latency,
                                "flagged a danger/contradiction/divergence + safe alternative; proceeds, "
                                "never silently complies, never hard-blocks")
    high_stakes = (ambiguity.status == "HIGH_STAKES_FORK") or missing.escalate_to_s30
    if high_stakes:
        fork = ambiguity if ambiguity.status == "HIGH_STAKES_FORK" else \
            S29.AmbiguityReport("HIGH_STAKES_FORK", fork="critical missing requirement")
        decision = S30.decide(prompt, fork, req=req, monitor=monitor)
        if decision.status == "ASK_ONE":
            return FrontendDecision("ASK_ONE", False, assumptions, [], decision.question, req, latency,
                                    "genuine high-stakes fork, VoI over threshold → exactly one question")
        return FrontendDecision("PROCEED", True, assumptions, [], None, req, latency,
                                "high-stakes fork but VoI/detailed → reasonable completion (no question)")
    if monitor is not None:
        monitor.record(S30.is_detailed(req), False)
    return FrontendDecision("PROCEED", True, assumptions, [], None, req, latency,
                            "reasonable completion with stated assumptions" if assumptions else "all clear")


# ==============================================================================================================
# ===== FILE: prony.py  (102 lines) =====
# ==============================================================================================================

"""
v37 STAGE 1.1 — Prony / ESPRIT: recover an exponential-sum recurrence from samples (the data-driven inverse of fold).
=====================================================================================================================
A C-finite sequence is a sum of exponentials f(t)=Σ_{j<k} cⱼ·βⱼᵗ; fold CLOSES such a recurrence symbolically,
Prony RECOVERS it from O(k) samples. Hankel matrix → ESPRIT (SVD + shift-pencil) → roots βⱼ → Vandermonde cⱼ.

★ EXACT certificate (§S1.1): the recovered k-term model must reproduce HELD-OUT samples (not used in the fit).
  Noiseless ⇒ residual ≈ machine-ε ⇒ EXACT (the recurrence is determined). For an integer recurrence we ALSO
  cross-check the recovered coefficients with cfinite.py (must agree). Residual above machine-ε, or no
  singular-value gap (rank ≈ N/2) ⇒ DECLINE (honest: not an exponential sum / too noisy for an EXACT claim). ★
Complexity: O(k) samples (+ a one-time O(N) SVD on the small Hankel) vs O(N) to read the whole sequence.
"""
from __future__ import annotations

from dataclasses import dataclass
from typing import List, Optional, Tuple

import numpy as np

import sublinear_layer as SL

_MACH_TOL = 1e-7        # held-out residual below this ⇒ EXACT (machine-ε determined)


def _hankel(s: np.ndarray, rows: int) -> np.ndarray:
    cols = len(s) - rows + 1
    return np.array([s[i:i + cols] for i in range(rows)], dtype=complex)


def _estimate_rank(sv: np.ndarray, rel_gap: float = 1e-6) -> int:
    """Numerical rank = #singular values above rel_gap·σ₀. A sharp drop ⇒ a clean k; no drop ⇒ rank≈N/2."""
    if sv[0] == 0:
        return 0
    return int(np.sum(sv > rel_gap * sv[0]))


def recover(samples, k_max: int = 20, validate: int = 4) -> SL.SublinearVerdict:
    """Recover f(t)=Σ cⱼ βⱼᵗ from `samples` via ESPRIT; EXACT iff the held-out residual is ~machine-ε.
    `validate` samples at the tail are HELD OUT (never used in the fit) — the residual on them is the witness."""
    s = np.asarray(samples, dtype=complex)
    N = len(s)
    if N < 6:
        return SL.decline("too few samples for Prony", "prony")
    fit, held = s[:N - validate], s[N - validate:]
    rows = len(fit) // 2
    H = _hankel(fit, rows)
    U, sv, _ = np.linalg.svd(H, full_matrices=False)
    k = _estimate_rank(sv)
    if k == 0 or k > min(k_max, rows - 1):
        return SL.decline(f"no low-rank exponential structure (estimated rank {k}, no singular-value gap)", "prony")
    if k >= rows - 1 or k >= (N - validate) // 2:
        return SL.decline(f"rank≈N/2 (k={k}) — no compression, looks structureless ⇒ DECLINE", "prony")
    # ESPRIT: eigenvalues of the shift pencil on the top-k signal subspace = the βⱼ
    Uk = U[:, :k]
    phi, *_ = np.linalg.lstsq(Uk[:-1], Uk[1:], rcond=None)
    betas = np.linalg.eigvals(phi)
    # Vandermonde solve for cⱼ over the fit samples
    t = np.arange(len(fit))
    V = betas[None, :] ** t[:, None]
    c, *_ = np.linalg.lstsq(V, fit, rcond=None)

    def model(tt):
        return (c[None, :] * (betas[None, :] ** np.asarray(tt)[:, None])).sum(axis=1)
    # ★ the certificate: residual on HELD-OUT samples (not used in the fit) ★
    pred = model(np.arange(N - validate, N))
    residual = float(np.max(np.abs(pred - held))) if validate > 0 else float(np.max(np.abs(model(t) - fit)))
    rel = residual / (np.max(np.abs(s)) + 1e-30)
    if rel > 1e-3:
        return SL.decline(f"held-out residual {rel:.2e} too large — not an exponential sum ⇒ DECLINE", "prony")
    if rel > _MACH_TOL:
        return SL.decline(f"residual {rel:.2e} above machine-ε — noisy, not EXACT-determined (DECLINE EXACT claim)", "prony")
    cert = SL.Certificate(grade=SL.EXACT, kind="residual", passed=True,
                          check_cost=f"O({validate}) held-out samples + O(N) Hankel SVD",
                          epsilon=None, delta=None, bound=rel,
                          detail=f"k={k} exponentials; held-out residual {rel:.2e} ≈ machine-ε ⇒ recurrence determined")
    return SL.SublinearVerdict(SL.EXACT, {"betas": betas, "coeffs": c, "k": k}, "prony",
                              f"O(k) samples, k={k}, N={N}", cert)


def recover_recurrence(samples) -> Tuple[Optional[List[int]], bool, str]:
    """Recover the INTEGER linear recurrence (Prony polynomial = characteristic polynomial) and cross-check it
    with cfinite.py. Returns (coeffs, cfinite_agrees, detail). The Prony poly's roots are the βⱼ; for a real
    integer C-finite sequence the monic char-poly has integer coefficients ⇒ the recurrence a(n)=Σ cᵢa(n-i)."""
    v = recover(samples, validate=4)
    if v.status == SL.DECLINE:
        return None, False, v.reason
    betas = v.result["betas"]
    # characteristic polynomial from the roots: ∏(z-βⱼ) → coefficients (highest first)
    poly = np.real(np.poly(betas))                       # real for a real recurrence
    # a(n) = c1 a(n-1)+...+ck a(n-k): char poly z^k - c1 z^{k-1} - ... - ck ⇒ cᵢ = -poly[i]
    coeffs = [-int(round(x)) for x in poly[1:]]
    # cross-check with cfinite: does this recurrence reproduce the samples?
    import cfinite
    try:
        ok, _ = cfinite.verify_cfinite(coeffs, [int(round(np.real(x))) for x in np.asarray(samples)[:len(coeffs)]])
    except Exception:  # noqa: BLE001
        ok = False
    return coeffs, ok, f"recovered recurrence coeffs={coeffs}, cfinite-agrees={ok}"


SL.register("exponential_sum", recover)


