# ===== FILE: properties.py  (161 lines) =====
# ==============================================================================================================

"""
HARAN v16 Part B · STAGE B2 — property extraction (metamorphic relations, no full spec).
========================================================================================
We don't need a complete specification — only RELATIONS the intended behaviour should satisfy
(metamorphic / preservation / algebraic / range). They are extracted from the function's shape + HIR
operations (+ optional AI), then TESTED by running the real code (B3). The more independent properties
we extract, the harder the later digit-narrowing (B5) can squeeze — but only if they are genuinely
independent, which B2.3 assesses honestly.

Honest strength boundary (B2 discipline): code with clear relations (math / transforms / data
structures — the fold domain) yields many properties → strong. Arbitrary business logic yields few →
"property-poor, weak" is reported, not hidden.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Callable, List, Optional

import hir


# ----------------------------------------------------------------- compile HIR fn → callable
def compile_callable(hfn: hir.HFunction, glb: Optional[dict] = None):
    """Language-agnostic: Python execs in-process; other languages compile+run via runtime.make_callable
    (the same engine then tests the REAL native output)."""
    if getattr(hfn, "lang", "python") == "python" and glb is not None:
        ns: dict = dict(glb)
        exec(hfn.source, ns)
        return ns[hfn.name]
    import runtime
    return runtime.make_callable(hfn, glb)


# ----------------------------------------------------------------- property model
@dataclass
class Property:
    name: str
    kind: str            # preservation | metamorphic | algebraic | range | sanity
    description: str
    check: Callable      # (fn, input) -> bool   (a metamorphic / preservation test on the REAL fn)
    group: str           # independence group (different groups ≈ independent; B5 multiplies across groups)
    operations: List[str] = field(default_factory=list)   # HIR op kinds this property constrains (→ B4)


def _is_listish(x):
    return isinstance(x, (list, tuple))


# ---- the metamorphic / preservation relations (run the real function) ----
def _determinism(fn, x):
    return fn(_copy(x)) == fn(_copy(x))


def _length_preservation(fn, x):
    y = fn(_copy(x))
    return _is_listish(y) and len(y) == len(x)


def _permutation(fn, x):
    y = fn(_copy(x))
    try:
        return sorted(y) == sorted(x)        # multiset preserved
    except TypeError:
        return False


def _idempotence(fn, x):
    y = fn(_copy(x))
    return fn(_copy(y)) == y


def _ordered_output(fn, x):
    y = fn(_copy(x))
    return _is_listish(y) and all(y[i] <= y[i + 1] for i in range(len(y) - 1))


def _order_invariance(fn, x):
    # sorting is invariant to input order: f(reversed(x)) == f(x)
    y1 = fn(_copy(x))
    y2 = fn(list(reversed(list(x))))
    return y1 == y2


def _nonneg_range(fn, x):
    y = fn(_copy(x))
    return isinstance(y, (int, float)) and y >= 0


def _copy(x):
    return list(x) if isinstance(x, list) else x


# canonical library (name -> Property factory)
def _sort_props() -> List[Property]:
    return [
        Property("determinism", "sanity", "f(x) == f(x)", _determinism, "g_det", ["call", "arith"]),
        Property("length_preservation", "preservation", "len(f(x)) == len(x)", _length_preservation,
                 "g_size", ["append", "pop", "slice", "insert", "extend", "remove"]),
        Property("permutation", "preservation", "multiset(f(x)) == multiset(x)", _permutation,
                 "g_size", ["append", "pop", "index_store", "arith", "insert", "remove"]),
        Property("ordered_output", "metamorphic", "f(x) is sorted", _ordered_output, "g_order",
                 ["compare", "index_store", "swap"]),
        Property("idempotence", "algebraic", "f(f(x)) == f(x)", _idempotence, "g_idem",
                 ["compare", "index_store"]),
        Property("order_invariance", "metamorphic", "f(reverse(x)) == f(x)", _order_invariance, "g_order",
                 ["compare", "index_store"]),
    ]


# ----------------------------------------------------------------- B2.1/B2.2 extraction
def looks_like_sort(hfn: hir.HFunction) -> bool:
    k = hfn.op_kinds()
    return ("sort" in k) or ({"compare", "index_store"} <= k) or ("reverse" in k and "compare" in k)


def returns_listish(hfn: hir.HFunction, sample) -> bool:
    try:
        fn = compile_callable(hfn)
        return _is_listish(fn(_copy(sample)))
    except Exception:
        return False


def extract_properties(hfn: hir.HFunction, sample=None) -> List[Property]:
    """Heuristic extraction from HIR shape/ops. Sort-shaped functions get the full metamorphic suite;
    list→list functions get preservation; everything gets determinism."""
    sample = sample if sample is not None else [3, 1, 2]
    props: List[Property] = []
    if looks_like_sort(hfn):
        props = _sort_props()
    else:
        props = [p for p in _sort_props() if p.name == "determinism"]
        if returns_listish(hfn, sample):
            props += [p for p in _sort_props() if p.name in ("length_preservation",)]
    return props


def ai_extract_properties(hfn: hir.HFunction) -> List[str]:
    """Optional AI augmentation. DISABLED under the level-1 key policy (no env keys ever) — returns []
    so the heuristics stand. Any AI augmentation would take an explicit per-call key (level-1), never
    an environment variable."""
    return []


# ----------------------------------------------------------------- B2.3 independence assessment
@dataclass
class IndependenceReport:
    groups: dict                 # group -> [property names]
    independent_count: int       # number of distinct groups (≈ independent factors for B5)
    note: str


def assess_independence(props: List[Property]) -> IndependenceReport:
    groups: dict = {}
    for p in props:
        groups.setdefault(p.group, []).append(p.name)
    note = ("properties in different groups test different aspects (≈ independent → B5 may multiply); "
            "same-group properties are correlated (e.g. permutation ⇒ length) — NOT independently "
            "multiplied (B6 discounts).")
    return IndependenceReport(groups, len(groups), note)


# ==============================================================================================================
# ===== FILE: property_test.py  (108 lines) =====
# ==============================================================================================================

"""
HARAN v16 Part B · STAGE B3 — property testing (fast: run the code, don't read it).
==================================================================================
Each extracted relation is tested against thousands of inputs by RUNNING the function and inspecting
outputs only — no static analysis, so it is fast (the "뚝딱"). We record every violation (property +
the input that broke it) for the fault-mapping (B4) and minimal-counterexample (B8) stages.

Deterministic: the input generator is seeded, so the same code yields the same violations every run
(the determinism the whole pipeline promises).
"""
from __future__ import annotations

import random
import time
from dataclasses import dataclass, field
from typing import Callable, Dict, List

import properties as PR


# ----------------------------------------------------------------- input generation (seeded)
def gen_int_lists(n: int, seed: int = 0, max_len: int = 8, val: int = 20) -> List[list]:
    rng = random.Random(seed)
    edges = [[], [0], [1], [1, 1], [2, 1], [1, 2], [1, 2, 3], [3, 2, 1], [5, 5, 5], [-1, 0, 1]]
    out = list(edges)
    for _ in range(n):
        L = rng.randint(0, max_len)
        out.append([rng.randint(-val, val) for _ in range(L)])
    return out


def gen_int_scalars(n: int, seed: int = 0, val: int = 50) -> List[int]:
    rng = random.Random(seed)
    edges = [0, 1, 2, 3, 5, 10, -1, -3]
    return edges + [rng.randint(-val, val) for _ in range(n)]


def infer_domain(hfn) -> str:
    """Probe whether the function takes a LIST or a SCALAR, so we don't feed lists to a scalar function
    (which would crash and be miscounted as a violation — a false positive)."""
    import properties as PR
    try:
        fn = PR.compile_callable(hfn)
    except Exception:
        return "list"
    try:
        fn([1, 2, 3])
        return "list"
    except Exception:
        try:
            fn(3)
            return "scalar"
        except Exception:
            return "list"


def gen_inputs(hfn, n: int = 400, seed: int = 0) -> List:
    """Domain-aware input generation: scalars for scalar functions, int-lists for list functions."""
    return gen_int_scalars(n, seed) if infer_domain(hfn) == "scalar" else gen_int_lists(n, seed)


# ----------------------------------------------------------------- testing
@dataclass
class TestReport:
    violations: Dict[str, List[list]]   # property name -> failing inputs
    tested_inputs: int
    properties: int
    elapsed_s: float
    crashes: int = 0

    def violated_properties(self) -> List[str]:
        return [p for p, v in self.violations.items() if v]

    def held_properties(self) -> List[str]:
        return [p for p, v in self.violations.items() if not v]

    @property
    def checks(self):
        return self.tested_inputs * self.properties

    def checks_per_sec(self):
        return self.checks / self.elapsed_s if self.elapsed_s > 0 else float("inf")


def test_properties(fn: Callable, props: List[PR.Property], inputs: List[list]) -> TestReport:
    violations: Dict[str, List[list]] = {p.name: [] for p in props}
    crashes = 0
    t = time.perf_counter()
    for x in inputs:
        for p in props:
            try:
                ok = p.check(fn, x)
            except Exception:
                ok = False           # a crash on a metamorphic check is itself a violation
                crashes += 1
            if not ok:
                violations[p.name].append(x)
    dt = time.perf_counter() - t
    return TestReport(violations, len(inputs), len(props), dt, crashes)


def run(hfn, n_random: int = 2000, seed: int = 0) -> TestReport:
    """Convenience: compile the HIR function, extract its properties, test on edges + n random inputs."""
    fn = PR.compile_callable(hfn)
    props = PR.extract_properties(hfn)
    inputs = gen_int_lists(n_random, seed=seed)
    return test_properties(fn, props, inputs)


# ==============================================================================================================
# ===== FILE: prove_exact.py  (217 lines) =====
# ==============================================================================================================

"""
STAGE X3 — proof-power completion (exact paths proven too).
==========================================================
v1 confessed "sort = tested-not-proven". Here we strengthen exact verification and fill the
obligations that v1 only *generated*:

  correctness tiers (kept distinct, never relabeled):
    PROVEN          exact arithmetic identity, ∀ unbounded (JEFF/sympy).
    PROVEN-BOUNDED  EXHAUSTIVE enumeration over a finite domain (ALL |xs|≤N, values∈[0,V)) — a real
                    proof for that domain, strictly stronger than random fuzz. (sort lands here.)
    TESTED          random bounded fuzz (last resort).
  contract     each call to a `requires`-function: args satisfy the callee's requires (Z3).
  aliasing     `own` values used at most once (use-after-move check).
  adt          a match on a `data` type covers all constructors (or has a wildcard).

Honesty: PROVEN-BOUNDED is NOT a full ∀-proof — a Z3/array-induction proof of unbounded sorting is
out of scope and not claimed. The tier name says exactly what was shown.
"""
from __future__ import annotations

from dataclasses import dataclass
from itertools import product
from typing import List, Optional

import haran_ast as A
import haran_eval
import z3_adapter
from haran_to_obligations import discharge_correctness


@dataclass
class Verdict:
    tier: str               # PROVEN | PROVEN-BOUNDED | TESTED | FAILED | UNKNOWN
    detail: str
    counterexample: Optional[dict] = None
    def proven(self) -> bool:
        return self.tier in ("PROVEN", "PROVEN-BOUNDED")
    def __str__(self):
        cx = f"  cx={self.counterexample}" if self.counterexample else ""
        return f"{self.tier} — {self.detail}{cx}"


def _walk(node):
    import dataclasses
    yield node
    if dataclasses.is_dataclass(node) and not isinstance(node, A.Span):
        for f in dataclasses.fields(node):
            v = getattr(node, f.name)
            if isinstance(v, list):
                for x in v:
                    if dataclasses.is_dataclass(x):
                        yield from _walk(x)
            elif dataclasses.is_dataclass(v):
                yield from _walk(v)


# --------------------------------------------------------- X3.1 correctness (proven where possible)
def _list_params(fn):
    return [p.name for p in fn.params if isinstance(p.ty, A.TyName) and p.ty.name in ("List", "Vec", "Seq")]


def exhaustive_list_check(fn, ftab, ens, max_len=4, vals=4) -> Optional[Verdict]:
    lps = _list_params(fn)
    if len(lps) != 1:
        return None
    pname = lps[0]
    cases = 0
    for L in range(max_len + 1):
        for combo in product(range(vals), repeat=L):
            cases += 1
            xs = list(combo)
            try:
                it = haran_eval.Interp(ftab)
                result = it.call_fn(fn, [xs])
                ok = it.eval(ens, {pname: xs, "result": result})
            except haran_eval.EvalError:
                return None    # cannot evaluate exhaustively → caller falls back to fuzz
            if not bool(ok):
                return Verdict("FAILED", f"ensures false at {pname}={xs}",
                               {"inputs": {pname: xs}, "result": result})
    return Verdict("PROVEN-BOUNDED",
                   f"EXHAUSTIVE: all |{pname}|≤{max_len}, values∈[0,{vals - 1}] ({cases} cases) satisfy ensures")


def prove_correctness(fn, ftab) -> Verdict:
    if fn.ensures is None:
        return Verdict("UNKNOWN", "no ensures")
    # STAGE 1.3 — Clover spec gate (SOUND): a "PROVEN" against a spec that constrains nothing is the
    # core soundness hole. Reject a DEMONSTRABLY-vacuous spec here, before proving. Fires only when Z3
    # *proves* vacuity (unsat); specs Z3 can't model (lists/opaque) pass through unchanged.
    import spec_gate
    g = spec_gate.gate_spec(fn)
    if g.vacuous():
        return Verdict("VACUOUS", f"spec rejected before proof — {g.reason}")
    # 1. exact arithmetic identity → JEFF/sympy ∀
    d = discharge_correctness(fn)
    if d.verdict == "PROVEN":
        return Verdict("PROVEN", f"exact ∀ via {d.backend}: {d.detail}")
    if d.verdict == "REFUTED":
        return Verdict("FAILED", d.detail, d.counterexample)
    # 2. predicate over a single list → exhaustive enumeration (upgrade from random fuzz)
    ex = exhaustive_list_check(fn, ftab, fn.ensures)
    if ex is not None:
        return ex
    # 3. random fuzz (honest last resort)
    status, detail, cx = haran_eval.bounded_fuzz(fn, ftab, fn.ensures)
    if status == "PASS":
        return Verdict("TESTED", f"bounded fuzz: {detail}")
    if status == "FAIL":
        return Verdict("FAILED", "ensures false on a random input", cx)
    return Verdict("UNKNOWN", detail)


# --------------------------------------------------------- X3.2 contract (requires)
def _subst(e, m):
    if isinstance(e, A.Var):
        return m.get(e.name, e)
    if isinstance(e, A.Bin):
        return A.Bin(e.op, _subst(e.lhs, m), _subst(e.rhs, m), e.span)
    if isinstance(e, A.Un):
        return A.Un(e.op, _subst(e.operand, m), e.span)
    if isinstance(e, A.Call):
        return A.Call(e.func, [_subst(a, m) for a in e.args], e.span)
    return e


def _numeric_var_types(fn):
    out = {}
    for p in fn.params:
        if isinstance(p.ty, A.TyName) and p.ty.name in ("Float", "Real", "rat"):
            out[p.name] = "Real"
        elif isinstance(p.ty, A.TyName) and p.ty.name in ("Int", "Nat"):
            out[p.name] = "Int"
    return out


@dataclass
class ContractCheck:
    callee: str
    verdict: str            # PASS | FAIL | UNKNOWN
    counterexample: Optional[dict] = None


def check_contract(fn, ftab) -> List[ContractCheck]:
    out = []
    var_types = _numeric_var_types(fn)
    assumptions = [fn.requires] if fn.requires is not None else []
    for x in _walk(fn.body) if fn.body else []:
        if isinstance(x, A.Call) and isinstance(x.func, A.Var):
            g = ftab.get(x.func.name)
            if g is not None and g.requires is not None and len(x.args) == len(g.params):
                sub = _subst(g.requires, {p.name: a for p, a in zip(g.params, x.args)})
                r = z3_adapter.prove_forall(sub, var_types, assumptions)
                out.append(ContractCheck(g.name, "PASS" if r.verdict == "PROVEN"
                                         else ("FAIL" if r.verdict == "REFUTED" else "UNKNOWN"),
                                         r.counterexample))
    return out


# --------------------------------------------------------- X3.3 aliasing (own/&)
@dataclass
class AliasIssue:
    name: str
    uses: int
    msg: str


def check_aliasing(fn) -> List[AliasIssue]:
    issues = []
    for p in fn.params:
        if isinstance(p.ty, A.TyOwn):
            uses = sum(1 for x in _walk(fn.body) if isinstance(x, A.Var) and x.name == p.name) if fn.body else 0
            if uses > 1:
                issues.append(AliasIssue(p.name, uses, f"own value '{p.name}' used {uses}× (use-after-move)"))
    return issues


# --------------------------------------------------------- X3.4 ADT exhaustiveness
def build_data_index(prog):
    ctors_of = {}
    for it in prog.items:
        if isinstance(it, A.DataDecl):
            ctors_of[it.name] = {c.name for c in it.ctors}
    return ctors_of


def check_adt_exhaustiveness(fn, ctors_of) -> List[tuple]:
    """Returns [(scrut, verdict, missing)]. verdict ∈ PASS|FAIL|UNKNOWN."""
    ptypes = {p.name: (p.ty.name if isinstance(p.ty, A.TyName) else None) for p in fn.params}
    out = []
    for m in (x for x in _walk(fn.body) if isinstance(x, A.Match)) if fn.body else []:
        if not isinstance(m.scrut, A.Var):
            continue
        tname = ptypes.get(m.scrut.name)
        if tname not in ctors_of:
            continue
        if any(isinstance(a.pattern, (A.PWild, A.PVar)) for a in m.arms):
            out.append((m.scrut.name, "PASS", set()))
            continue
        covered = {a.pattern.name for a in m.arms if isinstance(a.pattern, A.PCtor)}
        missing = ctors_of[tname] - covered
        out.append((m.scrut.name, "PASS" if not missing else "FAIL", missing))
    return out


# --------------------------------------------------------- X3.4 proven ratio
def proven_ratio(corpus: dict):
    from haran_parser import parse
    rows = []
    for label, src in corpus.items():
        prog = parse(src)
        fns = [it for it in prog.items if isinstance(it, A.FnDecl) and it.ensures is not None]
        ftab = {f.name: f for f in prog.items if isinstance(f, A.FnDecl)}
        for f in fns:
            rows.append((label, prove_correctness(f, ftab)))
    return rows


