# ===== FILE: provider.py  (190 lines) =====
# ==============================================================================================================

"""
provider.py — non-secret gateway/router configuration (the only module that reads the environment).
====================================================================================================
HARAN's model call can target any of the common API gateways/routers. The user picks one with THREE
environment variables; this module resolves them. It deliberately handles only **non-secret config**
(provider mode, model name, base URL). The API KEY stays a per-call argument everywhere else —
`claude_agent.py` never imports `os` and never reads the key from the environment (LEVEL-1).

  HARAN_PROVIDER  one of:
      anthropic         (default) — official Anthropic API (Anthropic SDK, SDK's own base URL)
      anthropic_compat  — Anthropic SDK with a CUSTOM base_url (AgentRouter and other Anthropic-shaped
                          gateways): set HARAN_BASE_URL=https://agentrouter.org/v1
      openai_compat     — OpenAI-shaped gateways (OpenRouter, TokenMix, most others): OpenAI SDK +
                          /chat/completions; set HARAN_BASE_URL=https://openrouter.ai/api/v1
  HARAN_MODEL     model id for the chosen gateway (e.g. claude-opus-4-8, claude-sonnet-4-5-20250929,
                  anthropic/claude-3.5-sonnet, qwen/qwen3-coder). Default: claude-opus-4-8.
  HARAN_BASE_URL  the gateway base URL. Default: none (anthropic mode uses the SDK default).

  HARAN_KEY       the gateway key (read here ONLY as a server/CLI fallback via resolve_key(); the web
                  UI still passes the key per-request and it is never stored). Masked in all output.

So: set HARAN_PROVIDER + HARAN_MODEL + HARAN_BASE_URL (+ HARAN_KEY) and any router works.
"""
from __future__ import annotations

import os
from dataclasses import dataclass
from typing import Optional

_ANTHROPIC = "anthropic"
_ANTHROPIC_COMPAT = "anthropic_compat"
_OPENAI_COMPAT = "openai_compat"
_OPENAI = "openai"            # PHASE P — native ChatGPT (api.openai.com/v1/chat/completions)
_GEMINI = "gemini"            # PHASE P — native Gemini (generativelanguage.googleapis.com)
_GROQ = "groq"               # PHASE P2 — Groq (OpenAI-compatible; free, no credit card)
VALID_PROVIDERS = (_ANTHROPIC, _ANTHROPIC_COMPAT, _OPENAI_COMPAT, _OPENAI, _GEMINI, _GROQ)

DEFAULT_MODEL = "claude-opus-4-8"

# PHASE P — native-endpoint defaults (filled from each vendor's public docs; editable in the UI, never guessed).
_OPENAI_DEFAULT_BASE = "https://api.openai.com/v1"
_GEMINI_DEFAULT_BASE = "https://generativelanguage.googleapis.com/v1beta"
_GROQ_DEFAULT_BASE = "https://api.groq.com/openai/v1"           # OpenAI-compatible /chat/completions

# Per-provider default model ids (free, no-card tiers for groq/gemini). Editable in the UI; never guessed.
DEFAULT_MODELS = {
    _ANTHROPIC: DEFAULT_MODEL,
    _ANTHROPIC_COMPAT: DEFAULT_MODEL,
    _OPENAI: "gpt-4o",
    _OPENAI_COMPAT: "",                                         # gateway-specific; user fills it in
    _GEMINI: "gemini-3.5-flash",                                # free tier, no card (per directive; editable in UI)
    _GROQ: "llama-3.3-70b-versatile",                           # free, fast, no card
}


def default_model_for(p: Optional[str] = None) -> str:
    """The prefilled default model for a provider (free-tier ids for groq/gemini). Editable in the UI."""
    return DEFAULT_MODELS.get(p or provider_name(), DEFAULT_MODEL)


def provider_name() -> str:
    p = (os.environ.get("HARAN_PROVIDER") or os.environ.get("PROVIDER") or _ANTHROPIC).strip().lower()
    return p if p in VALID_PROVIDERS else _ANTHROPIC


def model() -> str:
    return (os.environ.get("HARAN_MODEL") or DEFAULT_MODEL).strip()


def base_url(p: Optional[str] = None) -> Optional[str]:
    """Resolve the base URL for the chosen provider. HARAN_BASE_URL wins; otherwise a provider-specific
    fallback (ANTHROPIC_BASE_URL / OPENAI_BASE_URL). Plain `anthropic` returns None → the Anthropic SDK
    uses its own default (or its own ANTHROPIC_BASE_URL handling)."""
    p = p or provider_name()
    bu = os.environ.get("HARAN_BASE_URL")
    if bu:
        return bu.strip()
    if p == _OPENAI_COMPAT:
        return (os.environ.get("OPENAI_BASE_URL") or "").strip() or None
    if p == _ANTHROPIC_COMPAT:
        return (os.environ.get("ANTHROPIC_BASE_URL") or "").strip() or None
    if p == _OPENAI:                                              # native ChatGPT
        return (os.environ.get("OPENAI_BASE_URL") or _OPENAI_DEFAULT_BASE).strip()
    if p == _GEMINI:                                              # native Gemini
        return (os.environ.get("GEMINI_BASE_URL") or _GEMINI_DEFAULT_BASE).strip()
    if p == _GROQ:                                                # Groq (OpenAI-compatible)
        return (os.environ.get("GROQ_BASE_URL") or _GROQ_DEFAULT_BASE).strip()
    return None


def transport_kind(p: Optional[str] = None) -> str:
    """Which wire protocol the chosen provider speaks (PHASE P). The proposer selects its HTTP shape from this:
      • anthropic_sdk   — Anthropic Messages API (official or anthropic_compat gateway)
      • openai_chat     — POST {base}/chat/completions (native OpenAI and every openai_compat gateway)
      • gemini_generate — POST {base}/models/{model}:generateContent?key=… (native Gemini)"""
    p = p or provider_name()
    if p in (_ANTHROPIC, _ANTHROPIC_COMPAT):
        return "anthropic_sdk"
    if p == _GEMINI:
        return "gemini_generate"
    return "openai_chat"                                          # openai + openai_compat + groq


def resolve_key_for(p: Optional[str] = None) -> Optional[str]:
    """Provider-specific key fallback for the server/CLI path. HARAN_KEY always wins; otherwise the vendor's
    own var (OPENAI_API_KEY / GEMINI_API_KEY / ANTHROPIC_API_KEY). Returns the key or None — never logged,
    never stored, never phoned home; the web UI passes its own key per request and never touches this."""
    p = p or provider_name()
    if os.environ.get("HARAN_KEY"):
        return os.environ["HARAN_KEY"].strip()
    if p == _OPENAI:
        return (os.environ.get("OPENAI_API_KEY") or "").strip() or None
    if p == _GEMINI:
        return (os.environ.get("GEMINI_API_KEY") or "").strip() or None
    if p == _GROQ:
        return (os.environ.get("GROQ_API_KEY") or "").strip() or None
    if p in (_ANTHROPIC, _ANTHROPIC_COMPAT):
        return (os.environ.get("ANTHROPIC_API_KEY") or "").strip() or None
    return (os.environ.get("OPENAI_API_KEY") or "").strip() or None   # openai_compat gateways


def resolve_key() -> Optional[str]:
    """Server/CLI key fallback ONLY. Returns the env key (HARAN_KEY first) or None. The caller uses it
    for exactly one call and drops it; it is never stored here. The web UI path passes its own key and
    never touches this. (claude_agent never calls this — it only ever receives the key as an argument.)"""
    return (os.environ.get("HARAN_KEY") or os.environ.get("ANTHROPIC_API_KEY")
            or os.environ.get("OPENAI_API_KEY") or None)


def is_openai(p: Optional[str] = None) -> bool:
    return (p or provider_name()) == _OPENAI_COMPAT


def is_openai_native(p: Optional[str] = None) -> bool:
    return (p or provider_name()) == _OPENAI


def is_gemini(p: Optional[str] = None) -> bool:
    return (p or provider_name()) == _GEMINI


def is_groq(p: Optional[str] = None) -> bool:
    return (p or provider_name()) == _GROQ


# v26.2 S8 — gateway presets. Each: (provider, base_url, default_model, verified_source).
# base_urls/models are EDITABLE defaults in the UI; only fill from documentation, never guess.
# GLM/Z.ai verified via web search (Z.ai docs + multiple corroborating sources, June 2026):
#   OpenAI-compatible base_url = https://api.z.ai/api/paas/v4/ , model id e.g. glm-4.6 (glm-4.7 also).
#   NOTE: "GLM-5.2" is NOT a verified model id anywhere — use the exact id from your Z.ai console.
GATEWAY_PRESETS = {
    "Claude (official)": (_ANTHROPIC, None, DEFAULT_MODEL, "anthropic"),
    "ChatGPT (OpenAI)":  (_OPENAI, _OPENAI_DEFAULT_BASE, "gpt-4o", "openai docs (native /chat/completions)"),
    "Gemini (Google)":   (_GEMINI, _GEMINI_DEFAULT_BASE, "gemini-3.5-flash", "google docs (generateContent; free, no card)"),
    "Groq":              (_GROQ, _GROQ_DEFAULT_BASE, "llama-3.3-70b-versatile", "groq docs (OpenAI-compatible; free, no card)"),
    "GLM (Z.ai)":        (_OPENAI_COMPAT, "https://api.z.ai/api/paas/v4/", "glm-4.6", "z.ai docs (web-confirmed)"),
    "OpenRouter":        (_OPENAI_COMPAT, "https://openrouter.ai/api/v1", "", "well-known (editable)"),
    "DeepSeek":          (_OPENAI_COMPAT, "https://api.deepseek.com", "deepseek-chat", "well-known (editable)"),
}

# Free, no-credit-card providers (the default way to test the whole site) + where to get a key.
FREE_NO_CARD = (_GEMINI, _GROQ)
GET_KEY_URL = {
    _GEMINI: "https://aistudio.google.com/apikey",
    _GROQ: "https://console.groq.com/keys",
    _OPENAI: "https://platform.openai.com/api-keys",
    _ANTHROPIC: "https://console.anthropic.com/settings/keys",
}


def is_free_no_card(p: Optional[str] = None) -> bool:
    return (p or provider_name()) in FREE_NO_CARD


def get_key_url(p: Optional[str] = None) -> Optional[str]:
    return GET_KEY_URL.get(p or provider_name())


@dataclass
class Config:
    provider: str
    model: str
    base_url: Optional[str]
    has_env_key: bool          # whether a key is available in env (bool only — never the key itself)


def config() -> Config:
    p = provider_name()
    return Config(provider=p, model=model(), base_url=base_url(p), has_env_key=bool(resolve_key()))


# ==============================================================================================================
# ===== FILE: q_fold.py  (209 lines) =====
# ==============================================================================================================

"""
v32 STAGE B2 — q-Gosper / q-holonomic telescoping fold core [Clock C].
=======================================================================
Target: q-series summation loops (q-geometric / q-rational terms) whose sum SymPy's `summation` leaves
unevaluated. If t(k) telescopes, Σ_{k=lo}^n t(k) collapses to an O(1) closed form in q^n — a Clock C win.

PIPELINE (detect → candidate → SOUND verify → fold | HONEST_DEFER):
  B2.1 detect : the q-ratio ρ(x)=t(k+1)/t(k) must be RATIONAL in x=q^k (the q-hypergeometric test). The term
                t(k) must itself be rational in q^k (linear-in-k exponents only) — a quadratic exponent
                (q^{k²}, theta) is detected and DEFERRED (it is q-hypergeometric but NOT summable).
  B2.2 solve  : seek a telescoper σ(X) (rational in X=q^n) with σ(X)-σ(X/q)=τ(X) via a BOUNDED rational
                ansatz (partial fractions over q-shifts ∏(1-q^j X) + a polynomial part), solved EXACTLY
                over ℚ(q).  Then S(n)=σ(q^n)-σ(q^{lo-1}).
  B2.3 verify : ★ THE SOUND GATE ★ — require S(n)-S(n-1) ≡ t(n) AND S(lo) ≡ t(lo), simplified to EXACTLY 0
                (symbolic). Only a verified telescoper folds. No certificate ⇒ HONEST_DEFER.
  B2.4 measure: run over the defer corpus `q-holonomic` category — hit rate + verification rate (held out).

HONEST LIMITS: the ansatz search is BOUNDED (dispersion bound). A genuinely summable term outside the
ansatz space is DEFERRED honestly (under-coverage, never a wrong fold). theta / q-harmonic have NO closed
form and are correctly DEFERRED (q-hypergeometric-but-not-summable — informative certificate).
Certificate: exact (bit-exact closed form, verified by exact symbolic telescoping). Clock C only.
"""
from __future__ import annotations

from dataclasses import dataclass
from typing import Optional


class _NonRational(Exception):
    pass


@dataclass
class QFoldVerdict:
    status: str                 # FOLDED | DEFER
    q_hypergeometric: Optional[bool] = None   # did the q-ratio test pass?
    closed_form: str = "—"
    cert_type: str = "exact"
    verified: bool = False
    clock: str = "C"
    detail: str = ""

    def __str__(self):
        if self.status == "FOLDED":
            return f"FOLDED [Clock C] S(n)={self.closed_form}  (cert: {self.cert_type}, exact-verified)"
        return f"DEFER — {self.detail}"


def _to_X(expr, q, k, X):
    """Rewrite a term in q^k as a rational function of X=q^k. q^{c1·k+c0} → q^{c0}·X^{c1}. A non-linear
    exponent in k (e.g. q^{k²}) is NOT rational in q^k → raise _NonRational (theta-type, not summable here)."""
    import sympy as sp
    expr = sp.expand_power_exp(sp.powsimp(expr, force=True))

    def is_qpow(e):
        return isinstance(e, sp.Pow) and e.base == q and k in (e.exp.free_symbols if hasattr(e.exp, "free_symbols") else set())

    for p in expr.atoms(sp.Pow):
        if is_qpow(p):
            poly = sp.Poly(p.exp, k)
            if poly.total_degree() > 1:
                raise _NonRational(f"exponent {p.exp} is non-linear in {k}")

    def repl(p):
        poly = sp.Poly(p.exp, k)
        c1 = poly.coeff_monomial(k)
        c0 = poly.coeff_monomial(1)
        return q**c0 * X**c1

    out = expr.replace(is_qpow, repl)
    if k in out.free_symbols:
        raise _NonRational(f"residual {k} after q^k→X")
    return sp.cancel(sp.together(out))


def _is_zero_in_q(expr, q, n) -> bool:
    """Exact zero-test for an expression in q^n (and q^{n±j}): map q^n→Y (linear exponents) and `cancel`
    as a rational function. Robust where sympy.simplify is incomplete on mixed q^n / q^{n±1} terms."""
    import sympy as sp
    Y = sp.Symbol("_Y")
    try:
        r = _to_X(expr, q, n, Y)
        return sp.cancel(sp.together(r)) == 0
    except _NonRational:
        return sp.simplify(expr) == 0
    except Exception:  # noqa: BLE001
        return sp.simplify(expr) == 0


def _q_ratio_rational(t_expr, q, k, X) -> Optional[object]:
    """B2.1 detector: ρ(x)=t(k+1)/t(k) as a function of x=q^k. Returns the rational ρ(X), or None if the
    ratio is not rational in q^k (not q-hypergeometric)."""
    import sympy as sp
    try:
        ratio = sp.simplify(t_expr.subs(k, k + 1) / t_expr)
        rho = _to_X(ratio, q, k, X)
        rho = sp.cancel(rho)
        if rho.is_rational_function(X):
            return rho
    except _NonRational:
        # ratio non-rational in q^k OR the exponent quadratic — but the ratio of a theta IS rational;
        # fall through: the term itself being non-rational is handled by the summation step.
        try:
            ratio = sp.simplify(t_expr.subs(k, k + 1) / t_expr)
            # ratio may still be rational in q^k even if t isn't (theta): test the ratio alone
            rho = _to_X(ratio, q, k, X)
            return rho if sp.cancel(rho).is_rational_function(X) else None
        except Exception:  # noqa: BLE001
            return None
    except Exception:  # noqa: BLE001
        return None
    return None


def _solve_telescoper(tau_X, q, X, *, shifts=range(0, 4), powers=(1, 2), poly_deg=2):
    """B2.2: find rational σ(X) with σ(X)-σ(X/q)=τ(X) by a BOUNDED ansatz (partial fractions over q-shifts
    + a polynomial part), solved EXACTLY over ℚ(q). Returns σ(X) or None (no telescoper in the ansatz)."""
    import sympy as sp
    coeffs = []
    terms = []
    # polynomial part
    for d in range(poly_deg + 1):
        c = sp.Symbol(f"p{d}")
        coeffs.append(c)
        terms.append(c * X**d)
    # partial fractions A_{j,p} / (1 - q^j X)^p
    for j in shifts:
        for p in powers:
            c = sp.Symbol(f"a_{j}_{p}")
            coeffs.append(c)
            terms.append(c / (1 - q**j * X)**p)
    sigma = sum(terms)
    eq = sp.together(sigma - sigma.subs(X, X / q) - tau_X)
    num = sp.numer(sp.cancel(eq))
    polynum = sp.Poly(sp.expand(num), X)
    # each X-coefficient must vanish → linear system in `coeffs` over ℚ(q)
    sysz = polynum.all_coeffs()
    sol = sp.solve(sysz, coeffs, dict=True)
    if not sol:
        return None
    s0 = sol[0]
    sigma_sol = sigma.subs({c: s0.get(c, 0) for c in coeffs})
    # require a NON-trivial solution (not identically zero unless τ is zero)
    if sp.simplify(sigma_sol) == 0 and sp.simplify(tau_X) != 0:
        return None
    return sp.cancel(sp.together(sigma_sol))


def q_fold(qterm: str, lo: int = 1) -> QFoldVerdict:
    """Decide + (soundly) fold a q-series term Σ_{k=lo}^n t(k). `qterm` is a sympy expression string in q,k."""
    import sympy as sp
    q, k, n, X = sp.symbols("q k n X")
    try:
        t_expr = sp.sympify(qterm, locals={"q": q, "k": k})
    except Exception as e:  # noqa: BLE001
        return QFoldVerdict("DEFER", detail=f"q-term not analyzable ({type(e).__name__})")
    # B2.1 — q-hypergeometric detection (ratio rational in q^k)
    rho = _q_ratio_rational(t_expr, q, k, X)
    q_hyp = rho is not None
    # the SUMMATION needs t(k) itself rational in q^k (linear exponents). Quadratic (theta) ⇒ defer.
    try:
        tau_X = _to_X(t_expr, q, k, X)
    except _NonRational as e:
        return QFoldVerdict("DEFER", q_hypergeometric=q_hyp,
                            detail=f"q-hypergeometric={q_hyp} but term is NOT rational in q^k "
                                   f"({e}) — theta-type, no closed form. HONEST_DEFER.")
    # B2.2 — bounded telescoper search
    sigma = _solve_telescoper(tau_X, q, X)
    if sigma is None:
        return QFoldVerdict("DEFER", q_hypergeometric=q_hyp,
                            detail=f"q-hypergeometric={q_hyp} but no telescoper in the bounded ansatz "
                                   f"(q-Gosper-nonsummable here, e.g. q-harmonic) — HONEST_DEFER.")
    # closed form: S(n) = σ(q^n) - σ(q^{lo-1})
    S_n = sp.cancel(sp.together(sigma.subs(X, q**n) - sigma.subs(X, q**(lo - 1))))
    # B2.3 — ★ SOUND GATE ★: S(n)-S(n-1) ≡ t(n) and S(lo) ≡ t(lo), exact rational-function zero-test
    t_n = t_expr.subs(k, n)
    ok_step = _is_zero_in_q(S_n - S_n.subs(n, n - 1) - t_n, q, n)
    base = sp.simplify(S_n.subs(n, lo) - t_expr.subs(k, lo))
    if (not ok_step) or base != 0:
        return QFoldVerdict("DEFER", q_hypergeometric=q_hyp,
                            detail="candidate telescoper FAILED exact verification (S(n)-S(n-1)≠t(n)) — "
                                   "refusing to fold (no false structure).")
    return QFoldVerdict("FOLDED", q_hypergeometric=q_hyp, closed_form=str(S_n), cert_type="exact",
                        verified=True, clock="C",
                        detail="q-telescoping verified exactly: S(n)-S(n-1)≡t(n) ∧ S(lo)≡t(lo); O(n)→O(1)")


# ─────────────────────────────────────────────────────── B2.4 — corpus measurement
def measure_q_corpus(split: Optional[str] = None) -> dict:
    """Run B2 over the defer corpus `q-holonomic` category. Hit rate + verification rate, ZERO false folds
    (theta / q-harmonic must DEFER). Coverage MEASURED, not estimated."""
    import defer_corpus as DC
    cs = [c for c in DC.load() if c.category == "q-holonomic" and (split is None or c.split == split)]
    folded = correct = verified = 0
    rows = []
    for c in cs:
        v = q_fold(c.meta["qterm"])
        is_fold = (v.status == "FOLDED")
        ok = (is_fold == (c.expect == "foldable"))
        folded += int(is_fold)
        verified += int(v.verified)
        correct += int(ok)
        rows.append((c.cid, c.expect, v.status, ok, v.closed_form if is_fold else ""))
    n = len(cs)
    return {"n": n, "folded": folded, "correct": correct, "verified": verified,
            "hit_rate": round(folded / n, 3) if n else 0.0,
            "correctness": round(correct / n, 3) if n else 0.0,
            "rows": rows, "clock": "C"}


# ==============================================================================================================
# ===== FILE: race_detector.py  (145 lines) =====
# ==============================================================================================================

"""
v26 STAGE 4 — data-race & deadlock detector (lockset + lock-order-cycle).
=========================================================================
Operates on an explicit concurrency MODEL (HARAN has no threads): a dict {thread_id: [event, ...]},
each event a tuple (op, target) with op ∈ {"acq","rel","rd","wr"} and target a lock or variable name.

  • Data race (Eraser-style lockset): two CONFLICTING accesses — different threads, same variable, at
    least one a write — whose held-lock sets are DISJOINT (no common lock protects both) → RACE, with
    the concrete racing pair as the witness.
  • Deadlock (lock-order inversion): if any thread acquires L while holding H, add edge H→L; a cycle in
    this graph (e.g. t1: A then B; t2: B then A) → DEADLOCK, with the lock cycle as the witness.

Verdicts:  RACE_FREE | RACE (pair) | DEADLOCK (cycle) | UNMODELED.

★ HONEST LIMITS (labeled) ★:
  • Lockset is the classic data-race PRINCIPLE for LOCK-based synchronization. If threads synchronize by
    other means (fork/join order, signals, atomics), a reported pair may be ordered in reality — i.e. the
    detector can OVER-report (recall-favoring, like RacerD). It is sound for the lock model: RACE_FREE
    means "every conflicting access pair shares a lock" under the provided events.
  • A deadlock cycle is a NECESSARY lock-order-inversion condition (a standard warning), not a proof the
    schedule will deadlock at runtime.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple

Event = Tuple[str, str]


@dataclass
class RaceVerdict:
    status: str                          # RACE_FREE | RACE | DEADLOCK | UNMODELED
    races: List[dict] = field(default_factory=list)      # [{var, a, b}]
    cycles: List[List[str]] = field(default_factory=list)
    detail: str = ""

    def __str__(self):
        if self.status == "DEADLOCK":
            return f"DEADLOCK — lock-order cycle {self.cycles[0]} (lock-order inversion)"
        if self.status == "RACE":
            r = self.races[0]
            return (f"RACE on '{r['var']}': {r['a']} vs {r['b']} (conflicting, disjoint locksets) "
                    f"[+{len(self.races)-1} more]" if len(self.races) > 1 else
                    f"RACE on '{r['var']}': {r['a']} vs {r['b']} (conflicting, disjoint locksets)")
        if self.status == "RACE_FREE":
            return "RACE_FREE (lock model) — every conflicting access pair shares a lock; no lock cycle."
        return f"{self.status} — {self.detail}"


def _accesses(threads: Dict[str, List[Event]]):
    """Yield (tid, idx, op, var, frozenset(locks_held)) for each rd/wr, tracking the per-thread lockset."""
    out = []
    for tid, evs in threads.items():
        held = []
        for idx, (op, tgt) in enumerate(evs):
            if op == "acq":
                held.append(tgt)
            elif op == "rel":
                if tgt in held:
                    held.remove(tgt)
            elif op in ("rd", "wr"):
                out.append((tid, idx, op, tgt, frozenset(held)))
    return out


def _lock_order_edges(threads: Dict[str, List[Event]]):
    """Edges H→L for every 'acquire L while holding H' (lock-order inversion graph)."""
    edges = set()
    for evs in threads.values():
        held = []
        for op, tgt in evs:
            if op == "acq":
                for h in held:
                    edges.add((h, tgt))
                held.append(tgt)
            elif op == "rel" and tgt in held:
                held.remove(tgt)
    return edges


def _find_cycle(edges) -> Optional[List[str]]:
    """Return a cycle in the directed graph `edges` (set of (u,v)), or None."""
    adj: Dict[str, List[str]] = {}
    for u, v in edges:
        adj.setdefault(u, []).append(v)
    WHITE, GREY, BLACK = 0, 1, 2
    color: Dict[str, int] = {}
    stack: List[str] = []

    def dfs(u) -> Optional[List[str]]:
        color[u] = GREY
        stack.append(u)
        for v in adj.get(u, []):
            if color.get(v, WHITE) == GREY:        # back-edge → cycle
                return stack[stack.index(v):] + [v]
            if color.get(v, WHITE) == WHITE:
                c = dfs(v)
                if c:
                    return c
        stack.pop()
        color[u] = BLACK
        return None

    for n in list(adj):
        if color.get(n, WHITE) == WHITE:
            c = dfs(n)
            if c:
                return c
    return None


def detect_races(threads: Dict[str, List[Event]]) -> RaceVerdict:
    """Detect data races (lockset) and deadlocks (lock-order cycle) on an explicit concurrency model."""
    if not threads or len(threads) < 1:
        return RaceVerdict("UNMODELED", detail="no threads in the model")
    cycle = _find_cycle(_lock_order_edges(threads))
    if cycle:
        return RaceVerdict("DEADLOCK", cycles=[cycle])
    accs = _accesses(threads)
    races = []
    for i in range(len(accs)):
        for j in range(i + 1, len(accs)):
            t1, i1, o1, v1, L1 = accs[i]
            t2, i2, o2, v2, L2 = accs[j]
            if t1 != t2 and v1 == v2 and ("wr" in (o1, o2)) and not (L1 & L2):
                races.append({"var": v1,
                              "a": f"{t1}#{i1}:{o1}", "b": f"{t2}#{i2}:{o2}"})
    if races:
        return RaceVerdict("RACE", races=races)
    return RaceVerdict("RACE_FREE")


def race_feedback(v: RaceVerdict) -> str:
    """Witness → concrete fix instruction for the loop."""
    if v.status == "RACE" and v.races:
        r = v.races[0]
        return (f"DATA RACE on '{r['var']}': {r['a']} and {r['b']} conflict with no common lock. "
                f"Fix: guard every access to '{r['var']}' with the SAME lock (or make it immutable / "
                f"thread-local).")
    if v.status == "DEADLOCK" and v.cycles:
        return (f"DEADLOCK risk: lock-order cycle {v.cycles[0]}. Fix: acquire these locks in one global "
                f"order in every thread (lock-ordering discipline).")
    return ""


# ==============================================================================================================
# ===== FILE: randomized_svd.py  (68 lines) =====
# ==============================================================================================================

"""
v37 STAGE 2.1 — randomized SVD + a POSTERIOR residual certificate (PROBABILISTIC, high-probability bound).
===========================================================================================================
A rank-r approximation in ≈O(N²·r) via the HMT range finder (Halko-Martinsson-Tropp "Finding Structure with
Randomness"): Ω random, Y=AΩ, Q=qr(Y), then SVD the small QᵀA. The result is only USED if a POSTERIOR residual
estimate ‖A−QQᵀA‖ (a few Gaussian probes, a high-probability bound) is within tolerance.

★ GRADE = PROBABILISTIC (§1.5): the residual bound holds with prob ≥ 1−δ (δ from the #probes), NOT EXACT.
  No spectral gap (residual stays large) ⇒ DECLINE → fall back to the full O(N³) SVD. ★
"""
from __future__ import annotations

import math

import numpy as np

import sublinear_layer as SL


def randomized_svd(A: np.ndarray, r: int, oversample: int = 8, power_iters: int = 2, seed: int = 0):
    """HMT randomized SVD: returns (U, s, Vt) rank-(r) factors + the orthonormal range Q."""
    rng = np.random.default_rng(seed)
    m, n = A.shape
    Omega = rng.standard_normal((n, r + oversample))
    Y = A @ Omega
    for _ in range(power_iters):                 # power iteration sharpens the range for slow spectral decay
        Y = A @ (A.T @ Y)
    Q, _ = np.linalg.qr(Y)
    B = Q.T @ A
    Ub, s, Vt = np.linalg.svd(B, full_matrices=False)
    U = Q @ Ub
    return U[:, :r], s[:r], Vt[:r, :], Q


def _posterior_residual(A: np.ndarray, Q: np.ndarray, probes: int = 10, seed: int = 1) -> float:
    """HMT posterior error estimate: ‖A−QQᵀA‖ ≤ 10·√(2/π)·maxᵢ‖(A−QQᵀA)ωᵢ‖ with prob ≥ 1−10^-probes."""
    rng = np.random.default_rng(seed)
    n = A.shape[1]
    E = A - Q @ (Q.T @ A)
    worst = 0.0
    for _ in range(probes):
        w = rng.standard_normal(n)
        worst = max(worst, np.linalg.norm(E @ w) / (np.linalg.norm(w) + 1e-30))
    return 10.0 * math.sqrt(2.0 / math.pi) * worst


def approximate(data, r: int = None, tol: float = 1e-3, probes: int = 10) -> SL.SublinearVerdict:
    """`data` = matrix A. Try a rank-r randomized SVD; ACCEPT (PROBABILISTIC) iff the posterior residual is
    within `tol` (relative); else DECLINE (no low-rank structure → full SVD)."""
    A = np.asarray(data, dtype=float)
    m, n = A.shape
    r = r or max(1, min(m, n) // 10)
    U, s, Vt, Q = randomized_svd(A, r)
    resid = _posterior_residual(A, Q, probes=probes)
    rel = resid / (np.linalg.norm(A, 2) + 1e-30)
    delta = 10.0 ** (-probes)                    # the posterior bound's failure probability
    if rel > tol:
        return SL.decline(f"posterior residual {rel:.2e} > tol {tol} — no rank-{r} structure ⇒ DECLINE (full SVD)",
                          "rsvd")
    cert = SL.Certificate(grade=SL.PROBABILISTIC, kind="concentration", passed=True,
                          check_cost=f"O({probes}·N²) posterior probes", epsilon=rel, delta=delta, bound=rel,
                          detail=f"rank-{r} approx; ‖A−QQᵀA‖/‖A‖≈{rel:.2e} ≤ tol with prob ≥ 1−{delta:.0e}")
    return SL.SublinearVerdict(SL.PROBABILISTIC, {"U": U, "s": s, "Vt": Vt, "r": r}, "rsvd",
                              f"O(N²·r), r={r}, N={n}", cert)


SL.register("low_rank", approximate)


