def test_haran_mobius():
    """HARAN #44 (Group C) — the Möbius function μ(n) from the verified factorization (0 if squareful, else
    (−1)^#distinct-primes), EXACT, certified two INDEPENDENT ways: the Dirichlet identity Σ_{d|n} μ(d) = [n=1]
    over the divisors, and a cross-check against a linear-sieve μ (a different algorithm). Closes the Euler-φ
    partial (φ AND μ now present)."""
    import mathmode.number_theory as NT
    import kernel_verdict as KV

    # (a) exhaustive 1..1200 == an independent linear-sieve μ, all EXACT with the Dirichlet certificate
    sieve = NT._mobius_sieve(1200)
    for n in range(1, 1201):
        v = NT.mobius_grade(n)
        assert v.status == KV.EXACT and v.result == sieve[n], (n, v.result, sieve[n])
        assert v.certificate.kind == "mobius_dirichlet"

    # (b) known values incl. squarefree, squareful, and a 4-prime squarefree (μ=+1)
    assert [NT.mobius_grade(n).result for n in (1, 2, 6, 4, 12, 30, 210)] == [1, -1, 1, 0, 0, -1, 1]

    # (c) Mertens partial sum M(100)=Σ_{n≤100} μ(n) via the graded function matches the sieve cumulative
    assert sum(NT.mobius_grade(n).result for n in range(1, 101)) == sum(sieve[1:101])

    # (d) n<1 ⇒ honest DECLINE
    assert NT.mobius_grade(0).status == KV.DECLINE and NT.mobius_grade(-4).status == KV.DECLINE

    print("PASS test_haran_mobius (#44: Möbius μ from factorization, EXACT; 1..1200 == independent linear-sieve μ; "
          "Dirichlet Σ_(d|n)μ(d)=[n=1] cert; μ(1,2,6,4,12,30,210)=1,−1,1,0,0,−1,1; Mertens M(100) matches; "
          "n<1 → DECLINE — closes the Euler-φ partial)")


def test_haran_broth_lookup():
    """HARAN §2 — the cross-algorithm BROTH: common instantiations of SEVERAL of the 50 algorithms pre-proven
    OFFLINE → O(1) hash lookup at runtime. The certificate discipline is the strongest possible: EVERY cached
    entry re-verifies by RE-RUNNING the real algorithm (a corrupted cache is caught, never silently served).
    §0-B honesty: this is precomputed-lookup-fast (O(1) on a HIT), NOT execution-O(1) — a MISS returns None and
    the caller runs the algorithm at its true complexity."""
    import haran_broth as HB
    import dataclasses

    m = HB.measure(probes=50000)
    assert m["entries"] >= 1300 and m["all_hit"], m
    assert set(m["by_algo"]) == {9, 10, 31, 32, 33, 34, 38, 39, 40, 41, 44, 45, 49}, m["by_algo"]  # 13 of 50 (cross-algo)
    assert m["lookup_us"] < 1.0, f"O(1) lookup must be sub-µs (size-independent): {m['lookup_us']}"

    # ★ SOUNDNESS: stored entries reproduce when the REAL algorithm is re-run (the cache cannot lie). Re-verify a
    # per-family sample (≥3 of each of the 8 families) — covers every family while keeping the suite light ★
    idx = HB.index()
    by_fam: dict = {}
    for e in idx.values():
        by_fam.setdefault(e.algo, []).append(e)
    sample = [e for es in by_fam.values() for e in es[:3]]
    assert all(HB.reverify(e) for e in sample), "every broth family must re-verify by re-execution"
    assert set(by_fam) == set(m["by_algo"]), "every counted family must be sampled"

    # spot HITS return the pre-proven exact result instantly (across many algorithm families)
    assert HB.lookup(("cfinite", "fibonacci")).value == "([1, 1], [0, 1])"
    assert HB.lookup(("wigner3j", 1, 1, 2, 0, 0, 0)).value == "sqrt(30)/15"
    assert HB.lookup(("jacobi", 2, 7)).value == "1"                # (2|7) = +1 (7 ≡ 7 mod 8)
    assert HB.lookup(("pell", 2)).value == "(3, 2)"                # 3²−2·2² = 1
    assert HB.lookup(("fib", 100, 1000)).value == "75"            # F(100) mod 1000
    assert HB.lookup(("mobius", 30)).value == "-1"                 # μ(2·3·5) = (−1)³
    assert HB.lookup(("factorize", 12)).value == "{2: 2, 3: 1}"   # 12 = 2²·3
    assert HB.lookup(("cipolla", 2, 7)).value == "4"              # 4² = 16 ≡ 2 (mod 7)
    assert HB.lookup(("power_tower", 2, 3, 4, 1000000007)).value == "993282280"  # 2^(3^4) mod p
    assert HB.lookup(("dlog", 2, 22, 29)).value == "26"          # 2²⁶ ≡ 22 (mod 29)

    # MISS → None (honest: the algorithm would run; broth does NOT fabricate an O(1) answer)
    assert HB.lookup(("faulhaber", 999)) is None and HB.lookup(("cfinite", "nope")) is None
    assert HB.lookup(("mobius", 99999)) is None and HB.lookup(("factorize", 99991)) is None  # beyond the brewed range

    # a TAMPERED entry is REJECTED by the re-execution recheck (trusted only because re-running agrees), across families
    tampered = dataclasses.replace(HB.lookup(("faulhaber", 5)), value="n + 1")
    assert HB.reverify(tampered) is False
    tampered_fac = dataclasses.replace(HB.lookup(("factorize", 12)), value="{2: 1, 3: 1}")
    assert HB.reverify(tampered_fac) is False

    print(f"PASS test_haran_broth_lookup (§2: {m['entries']} pre-proven instantiations across "
          f"{len(m['by_algo'])} of the 50 [#9 Faulhaber/#10 C-finite/#31 modexp/#32 tower/#33 fib/#34 binom/"
          f"#38 factor/#39 Cipolla/#40 dlog/#41 Pell/#44 Möbius/#45 Jacobi/#49 Wigner3j]; O(1) lookup {m['lookup_us']}µs "
          f"all-hit; EVERY family re-verifies by re-running the real algorithm; miss→None; tampered→rejected — "
          f"precomputed-lookup-fast, NOT execution-O(1))")


def test_mode_budget_roles():
    """§1 (CORE) — fast/normal/extend are DISTINCT roles with DISTINCT, ENFORCED wall-clock budgets, not speed
    presets. The headline guarantee: extend is BOUNDED at ~8 min — NOT unlimited; at the deadline it returns the
    BEST CERTIFIED result reached (or an honest partial), never runs past budget, never fakes a result to fill the
    time, never weakens a grade to go faster; and fast NEVER calls the heavy solver. Each claim is a CHECKED
    invariant here, so the role separation cannot silently drift back into 'same thing, slower/faster'."""
    import time
    import mode_budget as MB
    import kernel_verdict as KV
    from pillar3.mode import Mode, ModePolicy
    from pillar3 import verifier as V

    # (a) the three TOTAL budgets are bounded and strictly ordered — extend is ~8 min, NOT unlimited
    bf, bn, be = (MB.budget_for_mode(m) for m in (Mode.FAST, Mode.NORMAL, Mode.EXTEND))
    assert (bf, bn, be) == (1.0, 30.0, 480.0), (bf, bn, be)
    assert bf < bn < be and be == 480.0, "extend BOUNDED ~8min"
    for m in (Mode.FAST, Mode.NORMAL, Mode.EXTEND):
        assert ModePolicy.for_mode(m).latency_budget_s is not None, f"{m} must be time-bounded (never None/overnight)"

    # (b) fast NEVER calls the heavy solver — its verifier tier provably excludes Z3 (a code-path guarantee)
    assert ModePolicy.for_mode(Mode.FAST).verifier_tier == V.VerifierTier.MICRO
    assert V.tier_allows_certificate(V.VerifierTier.MICRO, 1) is False, "fast (MICRO) must never invoke the solver"
    assert V.tier_allows_certificate(V.VerifierTier.FULL_CERT, 1) is True   # extend may

    # (c) WITHIN_BUDGET: work that completes returns its result + real grade
    def quick(budget, partial):
        partial.offer({"v": 42}, KV.EXACT)
        return KV.exact({"v": 42}, "kern", "demo", KV.Cert(KV.EXACT, "k", True))
    r1 = MB.run_under_mode_budget(Mode.NORMAL, quick)
    assert r1.status == "WITHIN_BUDGET" and r1.grade == KV.EXACT and not r1.deferred

    # (d) NEVER hangs past budget + returns the BEST CERTIFIED partial WITHOUT faking/weakening. A task that
    # ignores the cooperative deadline and would sleep 5 s is abandoned by the watchdog at a tiny 0.2 s budget.
    def runaway(budget, partial):
        partial.offer("best-so-far", KV.PROBABILISTIC)     # the strongest certified result it reached
        while not budget.expired():
            pass
        time.sleep(5.0)                                    # would hang the pipeline without enforcement
        return KV.exact("FAKED", "k", "x", KV.Cert(KV.EXACT, "k", True))  # must NEVER surface (faked-to-fill)
    t0 = time.monotonic()
    r2 = MB.run_under_mode_budget(Mode.EXTEND, runaway, budget_s=0.2)
    elapsed = time.monotonic() - t0
    assert elapsed < 1.5, f"must not hang past budget (took {elapsed:.2f}s)"
    assert r2.status == "DEFERRED_PARTIAL" and r2.deferred
    assert r2.grade == KV.PROBABILISTIC and r2.result == "best-so-far", "must return the honest best-so-far partial"
    assert r2.grade != KV.EXACT, "a DEFERRED partial is NEVER relabeled EXACT (grade not weakened/faked to look done)"

    # (e) GRADES DIFFER BY TIER: extend is EXACT-or-DECLINE (PROBABILISTIC rejected); fast/normal accept the
    # honest fast PROBABILISTIC — so the SAME probabilistic fix is acceptable in fast/normal but NOT in extend
    fast_p, ext_p = ModePolicy.for_mode(Mode.FAST), ModePolicy.for_mode(Mode.EXTEND)
    assert ext_p.acceptable_grades == frozenset({KV.EXACT}), "extend ships only EXACT (or DECLINEs)"
    assert fast_p.grade_acceptable(KV.PROBABILISTIC) and not ext_p.grade_acceptable(KV.PROBABILISTIC)

    # (f) the live UI line (§3): 'mode · m:ss / m:ss' + a fraction in [0,1] that advances with elapsed time
    b = MB.TimeBudget(Mode.EXTEND, 480.0, time.monotonic() - 192.0)     # 3:12 into an 8:00 budget
    assert b.display() == "extend · 3:12 / 8:00", b.display()
    assert 0.0 <= b.fraction_used() <= 1.0 and abs(b.fraction_used() - 0.4) < 0.02
    assert b.remaining_s() > 0 and "BOUNDED" in MB.tier_label(Mode.EXTEND) and "8 min" in MB.tier_label(Mode.EXTEND)

    # (g) the REAL engine path runs UNDER the enforced budget and surfaces it — and grades differ by tier on it:
    # the list-as-set fix is a differential/PROBABILISTIC win → SHIPPED in fast, but extend (EXACT-or-DECLINE)
    # DECLINEs it. So the same code yields a shipped win in fast and a proven decline in extend — distinct roles.
    from webapi import engine_bridge as EB
    waste = "def f(xs):\n    out = []\n    for x in xs:\n        if x in out:\n            continue\n        out.append(x)\n    return out\n"
    rf, rn, re_ = (EB.run_optimize(waste, mm) for mm in ("fast", "normal", "extend"))
    for rr, want_b in ((rf, 1.0), (rn, 30.0), (re_, 480.0)):
        bd = rr["budget"]
        assert bd["budget_s"] == want_b and bd["bounded"] is True and bd["status"] == "WITHIN_BUDGET"
        assert bd["elapsed_s"] <= want_b, "the run must respect (stay within) its mode budget"
    assert re_["budget"]["display"] == "extend · 0:00 / 8:00" or re_["budget"]["display"].endswith("/ 8:00")
    assert len(rf["shipped"]) >= 1, "fast ships the honest differential/PROBABILISTIC win"
    assert len(re_["shipped"]) == 0, "extend is EXACT-or-DECLINE — the PROBABILISTIC-only fix is NOT shipped"

    print(f"PASS test_mode_budget_roles (fast/normal/extend = {bf:.0f}s/{bn:.0f}s/{be:.0f}s ENFORCED & ordered; "
          f"extend BOUNDED ~8min NOT unlimited; fast(MICRO) never calls the solver; budget overrun → DEFERRED_PARTIAL "
          f"in {elapsed:.2f}s [no hang], best-so-far grade={r2.grade} kept honest [not faked/weakened to EXACT]; "
          f"grades differ by tier (extend EXACT-or-DECLINE, PROBABILISTIC rejected); live UI line '{b.display()}')")


def test_loop_decision():
    """§2 (ABSORB MATH into CODE) — decision-procedures-as-analysis. DECIDE whether an accumulation loop
    Σ_{k=lo}^n f(k) collapses to a closed form, with a certificate EITHER WAY. Gosper is COMPLETE on
    hypergeometric terms: a closed form ⇒ the O(n) loop becomes O(1) (gated by OUR differential check vs the
    brute-force sum); a Gosper None ⇒ a PROOF no hypergeometric closed form exists ⇒ the loop is irreducible (a
    first-class PROVEN DECLINE — 'this loop has no closed form', the moat). Outside the class ⇒ honest UNDECIDED
    (no false claim). A wrong closed form is NEVER emitted (the differential gate); a wrong 'irreducible' would be
    a correctness bug — sound/conservative."""
    import loop_decision as LD
    import kernel_verdict as KV
    import sympy as sp
    n = sp.Symbol("n")

    # CLOSED_FORM — each emitted closed form is INDEPENDENTLY re-verified vs the brute-force sum (ground truth)
    for src, var, lo in [("k**2", "k", 1), ("k**3", "k", 1), ("k*2**k", "k", 0), ("1/(k*(k+1))", "k", 1), ("7", "k", 1)]:
        d = LD.decide_sum_collapse(src, var, lo)
        assert d.status == LD.CLOSED_FORM and d.verdict.status == KV.EXACT and d.closed_form, d
        assert d.verdict.certificate is not None and d.verdict.certificate.passed
        k = sp.Symbol(var); f = sp.sympify(src, locals={var: k}); cf = sp.sympify(d.closed_form)
        for nv in (lo, lo + 2, lo + 6, lo + 11):
            brute = sum(f.subs(k, j) for j in range(lo, nv + 1))
            assert sp.simplify(cf.subs(n, nv) - brute) == 0, f"{src}: emitted closed form is WRONG at n={nv}"

    # NO_CLOSED_FORM — PROVEN irreducible: the harmonic Σ1/k and Σ1/k! have no hypergeometric closed form
    for src in ("1/k", "1/factorial(k)"):
        d = LD.decide_sum_collapse(src, "k", 1)
        assert d.status == LD.NO_CLOSED_FORM and d.verdict.status == KV.EXACT, d
        assert "no hypergeometric closed form" in d.certificate.lower() and d.verdict.certificate.passed
    assert "Abramov" in LD.decide_sum_collapse("1/k", "k", 1).certificate   # rational cross-check (defense in depth)

    # UNDECIDED — outside the hypergeometric decision class: NO false 'no closed form' claim
    d = LD.decide_sum_collapse("2**k + 3**k", "k", 0)
    assert d.status == LD.UNDECIDED and not d.closed_form and d.verdict.status == KV.DECLINE

    # ★ the differential GATE is real: a deliberately WRONG closed form is REJECTED; the correct one is accepted ★
    k = sp.Symbol("k")
    okw, chkw = LD._differential_ok(sp.sympify("k**2"), sp.sympify("n**3"), k, n, 1)                 # n^3 ≠ Σk^2
    assert chkw >= 3 and okw < chkw, "the gate must reject a wrong closed form (never emitted)"
    okr, chkr = LD._differential_ok(sp.sympify("k**2"), sp.sympify("n*(n+1)*(2*n+1)/6"), k, n, 1)    # correct
    assert chkr >= 3 and okr == chkr, "the gate must accept the correct closed form"

    # ── ABSORBED INTO THE LIVE CODE PATH: the decision runs on real Python SOURCE (structure_recognizer) ──
    import structure_recognizer as SR
    harm = "def f(n):\n    acc = 0\n    for k in range(1, n+1):\n        acc += 1/k\n    return acc"   # harmonic
    sqs  = "def g(n):\n    s = 0\n    for k in range(1, n+1):\n        s += k*k\n    return s"            # Σk²
    prod = "def p(n):\n    r = 1\n    for k in range(1, n+1):\n        r *= k\n    return r"              # product
    dh, dq = SR.decide_loop(harm), SR.decide_loop(sqs)
    assert dh is not None and dh.status == LD.NO_CLOSED_FORM, dh        # the harmonic loop is PROVEN irreducible
    assert dq is not None and dq.status == LD.CLOSED_FORM and dq.verdict.status == KV.EXACT
    qcf = sp.sympify(dq.closed_form)                                    # and the emitted form is correct
    assert sp.simplify(qcf.subs(n, 9) - sum(j * j for j in range(1, 10))) == 0
    assert SR.decide_loop(prod) is None, "a product loop is outside the Σ-decision scope (honest None)"

    print("PASS test_loop_decision (decision-procedures-as-analysis: Σk²/Σk³/Σk·2ᵏ/Σ1/(k(k+1))/Σ7 → CLOSED_FORM O(1), "
          "each re-verified vs brute force; Σ1/k & Σ1/k! → PROVEN NO_CLOSED_FORM [Gosper complete; Abramov confirms "
          "harmonic]; Σ(2ᵏ+3ᵏ) → honest UNDECIDED [out of class]; differential gate rejects a wrong closed form)")


def test_code_stream():
    """§3 (STREAM EVERY STEP) — the live CODE process trace: ordered, human-readable phase records the UI renders
    progressively (mirroring MATH's ROUTE/RECOGNIZE/KERNEL/증명서). The honesty invariant: every record reflects
    the REAL tier+budget, the REAL decision/fold, and the REAL grade+certificate — the displayed grade EQUALS the
    engine's actual grade (re-derived here), never fabricated progress; extend's budget line shows the BOUNDED
    ~8 min, fast's shows ~1 s."""
    import code_stream as CS
    from webapi import engine_bridge as EB
    import structure_recognizer as SR
    import json

    harm = "def f(n):\n    acc = 0\n    for k in range(1, n+1):\n        acc += 1/k\n    return acc"
    waste = "def f(xs):\n    out = []\n    for x in xs:\n        if x in out:\n            continue\n        out.append(x)\n    return out"

    # (a) ordered, complete phase spine: ANALYZE first, RESULT last, RECOGNIZE+CERTIFY+VERIFY present
    th = CS.build_code_trace(harm, "extend")
    phases = [e.phase for e in th]
    assert phases[0] == CS.ANALYZE and phases[-1] == CS.RESULT
    assert {CS.RECOGNIZE, CS.APPLY, CS.CERTIFY, CS.VERIFY} <= set(phases)
    # every record carries the tier and the BOUNDED extend budget line (~8 min) — never 'unlimited'
    assert all(e.tier == "extend" and e.budget.endswith("/ 8:00") for e in th)

    # (b) the §2 decision is surfaced LIVE and the displayed grade/cert EQUAL the real verdict (no fabrication)
    real = SR.decide_loop(harm)
    assert real is not None and real.status == "NO_CLOSED_FORM"
    res_graded = [e for e in th if e.phase == CS.RESULT and e.grade]
    assert res_graded and res_graded[0].grade == real.verdict.status        # displayed grade == engine grade
    assert res_graded[0].certificate == real.certificate                    # displayed cert == engine cert (verbatim)
    assert "닫힌형이 없음" in res_graded[0].message and "PROVEN DECLINE" in res_graded[0].message

    # (c) for a shipped win, the RESULT grade EQUALS run_optimize's ACTUAL shipped grade (displayed == engine)
    tw = CS.build_code_trace(waste, "fast")
    eng = EB.run_optimize(waste, "fast")
    assert eng["shipped"], "fast ships the differential win"
    rw = [e for e in tw if e.phase == CS.RESULT and e.grade]
    assert rw and rw[0].grade == eng["shipped"][0]["grade"].upper(), "displayed grade must equal the engine's grade"
    assert all(e.budget.endswith("/ 0:01") for e in tw)                     # fast budget ~1 s

    # (d) SSE frames are well-formed and JSON-decodable (the frontend's existing live event channel)
    frames = CS.to_sse(th)
    assert frames and all(f.startswith("data: ") and f.endswith("\n\n") for f in frames)
    for f in frames:
        obj = json.loads(f[len("data: "):].strip())
        assert obj["phase"] and obj["message"] and obj["tier"] == "extend"

    # (e) §4 tie-in: a CLOSED_FORM loop streams a LIVE MEASURED speedup step (O(n)→O(1)) with the honest limits
    sqloop = "def g(n):\n    s = 0\n    for k in range(1, n+1):\n        s += k*k\n    return s"
    tq = CS.build_code_trace(sqloop, "normal")
    meas = [e for e in tq if "속도향상 실측" in e.message]
    assert meas, "a closed-form loop must stream a measured O(n)→O(1) speedup step"
    assert "domain-conditional" in meas[0].detail and "Amdahl" in meas[0].detail, "the live speedup must state its limits"
    assert meas[0].grade == "EXACT" and meas[0].certificate, "the measured collapse is EXACT (closed form verified)"
    # and the RESULT honestly reports the proven O(1) collapse (not 'no fix') with the EXACT grade
    rq = [e for e in tq if e.phase == CS.RESULT and e.grade]
    assert rq and rq[0].grade == "EXACT" and "닫힌형" in rq[0].message and "증명된 붕괴" in rq[0].message

    # (f) §4 ceiling-breaker tie-in: a C-finite state-update loop (Fibonacci) streams the O(n)→O(log n) collapse
    fibloop = "def fib(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, a + b\n    return a"
    tf = CS.build_code_trace(fibloop, "normal")
    appf = [e for e in tf if e.phase == CS.APPLY and "점화식" in e.message]
    rcres = [e for e in tf if e.phase == CS.RESULT and "동반형" in e.message]
    assert appf and "O(log n)" in appf[0].message, "a recurrence loop must stream the O(log n) companion collapse"
    assert rcres and rcres[0].grade == "EXACT" and "증명된 붕괴" in rcres[0].message, "RESULT reports the proven collapse"

    # (g) §4 modular tie-in: a MODULAR C-finite loop streams the O(log n) mod-M collapse (the genuine-win case)
    fibm = "M = 10 ** 9 + 7\ndef f(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, (a + b) % M\n    return a"
    tm = CS.build_code_trace(fibm, "normal")
    appm = [e for e in tm if e.phase == CS.APPLY and "모듈러" in e.message]
    rmres = [e for e in tm if e.phase == CS.RESULT and "모듈러" in e.message]
    assert appm and "O(log n)" in appm[0].message, "a modular recurrence loop must stream the O(log n) mod-M collapse"
    assert rmres and rmres[0].grade == "EXACT" and "증명된 붕괴" in rmres[0].message

    # (h) §3 STREAM↔RESULT consistency: a NON-for fold shape (a comprehension of Σk²) streams its O(1) code-shape
    #     collapse (not the O(log n) recurrence) — the live trace agrees with engine_bridge._loop_collapse's RESULT
    compsum = "def f(n):\n return sum(k*k for k in range(1, n+1))"
    tc = CS.build_code_trace(compsum, "normal")
    appc = [e for e in tc if e.phase == CS.APPLY and "코드형태" in e.message]
    rcc = [e for e in tc if e.phase == CS.RESULT and "닫힌형" in e.message]
    assert appc, "a comprehension fold must stream the O(1) code-shape collapse (not the O(log n) companion)"
    assert rcc and rcc[0].grade == "EXACT" and "n*(n + 1)*(2*n + 1)/6" in rcc[0].message, rcc
    live_cf = EB._loop_collapse(compsum)                                   # the engine RESULT the UI also surfaces
    assert live_cf and live_cf["kind"] == "code_shape" and live_cf["closed_form"] in rcc[0].message, "stream == result"

    print("PASS test_code_stream (live CODE process ANALYZE→RECOGNIZE→APPLY→CERTIFY→VERIFY→RESULT, ordered; extend "
          "budget line BOUNDED '· / 8:00'; the §2 PROVEN DECLINE surfaced live; displayed grade == engine grade "
          f"[harmonic {real.verdict.status} decision; list-as-set {eng['shipped'][0]['grade'].upper()}] — no "
          "fabricated progress; SSE frames JSON-valid)")


def test_loop_speedup():
    """§4 (generated-code speed) — turn a DECIDED closed form into a MEASURED, Amdahl-honest, certificate-backed
    whole-program speedup. The accumulation loop IS the function (f=1), so the naive O(n) loop vs the O(1) closed
    form is a whole-program speedup FOR THIS FUNCTION; the ratio is MEASURED at a stated n (it GROWS as O(n), never
    an average), reported only behind a re-verification that the closed form == the loop AT n (a mismatch DECLINEs
    — never a wrong speedup). DOMAIN-CONDITIONAL: closed-form-able loops only. Per C6 the magnitude is perf_obs
    (informational), not a hard gate — the hard gate is soundness + the honest-limit certificate."""
    import loop_decision as LD
    import kernel_verdict as KV
    import sympy as sp

    m = LD.measure_collapse_speedup("k**2", "k", 1, n=30000, trials=5)
    assert m.status == "MEASURED" and m.verdict.status == KV.EXACT and m.verdict.certificate.passed
    # ★ soundness ★: INDEPENDENTLY re-verify the emitted closed form == the brute-force loop (don't trust the timer)
    n = sp.Symbol("n"); cf = sp.sympify(m.closed_form)
    for nv in (1, 7, 30, 30000):
        assert sp.simplify(cf.subs(n, nv) - sum(j * j for j in range(1, nv + 1))) == 0, f"closed form wrong at n={nv}"
    # the collapse is genuinely faster (O(n)→O(1)) and the timings are real; MAGNITUDE is perf_obs (not a gate)
    assert m.naive_s > 0 and m.closed_s > 0 and m.ratio > 1.0
    perf_obs("loop_collapse_k2", ratio=round(m.ratio, 1), naive_ms=round(m.naive_s * 1e3, 2),
             closed_us=round(m.closed_s * 1e6, 2), n=m.n)
    # ★ honesty markers verbatim in the certificate (the §X limits are stated, never an unconditional claim) ★
    c = m.verdict.certificate.detail
    for marker in ("f=1", "Amdahl", "DOMAIN-CONDITIONAL", "GROWS as O(n)", "NOT an average"):
        assert marker in c, f"the certificate must state the honest limit: {marker}"
    # no closed form ⇒ nothing to measure ⇒ honest DECLINE (the harmonic loop is irreducible, never a faked speedup)
    h = LD.measure_collapse_speedup("1/k", "k", 1, n=1000)
    assert h.status == "DECLINE" and h.verdict.status == KV.DECLINE

    print(f"PASS test_loop_speedup (Σk² O(n) loop → O(1) closed form: MEASURED {m.ratio:.0f}× at n={m.n} [naive "
          f"{m.naive_s * 1e3:.2f}ms → {m.closed_s * 1e6:.2f}µs], closed form independently re-verified == the loop; "
          f"cert states f=1 / Amdahl-ceiling / grows-O(n) / domain-conditional / not-an-average; harmonic Σ1/k → "
          f"honest DECLINE [no closed form to collapse — never a faked speedup])")


def test_loop_recurrence():
    """§4 (ceiling-breaker) — an O(n) state-update loop computing a C-finite sequence collapses to an O(log n)
    companion-matrix form, decided soundly by sample → fit → VERIFY. The Berlekamp-style fit is NEVER trusted on
    its own: companion_nth must equal the USER'S ACTUAL loop on HELD-OUT n (beyond the fit window) AND at the
    measured n — a wrong fit is rejected (DECLINE, never a wrong collapse). DOMAIN-CONDITIONAL: C-finite only (a
    factorial / non-integer loop DECLINEs). Per C6 the speedup magnitude is perf_obs; the hard gate is the verified
    equivalence (the O(log n) form ≡ the loop) + the honest-limit certificate."""
    import loop_recurrence as LR
    import cfinite
    import kernel_verdict as KV

    fib = "def fib(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, a + b\n    return a"
    m = LR.decide_recurrence_collapse(fib, n=50000, trials=3)
    assert m.status == "COLLAPSED" and m.verdict.status == KV.EXACT and m.verdict.certificate.passed
    assert m.c == [1, 1] and m.init == [0, 1] and m.order == 2

    # ★ soundness ★: the O(log n) companion form == a FRESH independent Fibonacci at held-out n (not the fitted seq)
    def fib_ref(nn):
        a, b = 0, 1
        for _ in range(nn):
            a, b = b, a + b
        return a
    for nv in (37, 101, 500, 50000):
        assert cfinite.companion_nth(m.c, m.init, nv) == fib_ref(nv), f"companion ≠ Fibonacci at n={nv}"
    perf_obs("recurrence_collapse_fib", ratio=round(m.ratio, 2), measured_win=m.measured_win,
             naive_ms=round(m.naive_s * 1e3, 2), log_ms=round(m.log_s * 1e3, 2), n=m.n, order=m.order)

    # honest-limit markers + the soundness basis stated verbatim in the certificate
    cert = m.verdict.certificate.detail
    for marker in ("DOMAIN-CONDITIONAL", "Amdahl", "f=1", "C-finite", "VERIFIED ≡ the user's loop on held-out"):
        assert marker in cert, f"the certificate must state the honest limit / soundness basis: {marker}"

    # ── DECLINE: a non-C-finite loop (factorial) and a non-integer loop are honestly declined (keep the loop) ──
    fact = "def f(n):\n    p = 1\n    for k in range(1, n + 1):\n        p *= k\n    return p"
    nonint = "def g(n):\n    return n / 2.0"
    assert LR.decide_recurrence_collapse(fact, n=2000).status == "DECLINE", "factorial is not C-finite ⇒ DECLINE"
    assert LR.decide_recurrence_collapse(nonint, n=2000).status == "DECLINE", "non-integer ⇒ DECLINE"
    # a Pell-like recurrence (different coefficients) is also recognized + verified (not just Fibonacci)
    pell = "def p(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, 2 * b + a\n    return a"
    mp = LR.decide_recurrence_collapse(pell, n=3000)
    assert mp.status == "COLLAPSED" and mp.c == [2, 1], mp

    print(f"PASS test_loop_recurrence (Fibonacci O(n) loop → O(log n) companion [c={m.c}, init={m.init}], VERIFIED ≡ "
          f"a FRESH Fibonacci on held-out n; MEASURED {m.ratio:.1f}× at n={m.n} [win={m.measured_win}; perf_obs, not a "
          f"gate]; Pell c=[2,1] recognized; factorial & non-integer → honest DECLINE [not C-finite — keep the loop]; "
          f"cert states f=1 / Amdahl / domain-conditional / held-out-verified)")


def test_loop_collapse_adversarial():
    """§4 (soundness, adversarial) — spec fragility is the dominant failure mode, so ATTACK it: the loop-collapse
    path must emit ZERO wrong collapses even when a fit is VALID ON THE SAMPLE WINDOW but WRONG beyond it. The
    held-out verification (companion ≡ the ACTUAL loop on n PAST the fit window) is the real soundness authority —
    not the fit; and a wrong closed form is never emitted (the differential gate). A wrong 'verified' here would be
    a correctness bug; these are the gates that prevent it."""
    import loop_recurrence as LR
    import loop_decision as LD
    import cfinite
    import sympy as sp

    # ★ headline attack ★: f == Fibonacci on the fit window (n<30) but DIVERGES beyond ⇒ the fit finds c=[1,1] yet
    # held-out at n≥30 disagrees with the loop ⇒ DECLINE (NOT a wrong O(log n) collapse on a window-only fit)
    trap = ("def f(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, a + b\n"
            "    return a + (1 if n >= 30 else 0)")
    r = LR.decide_recurrence_collapse(trap, sample=24, n=4000)
    assert r.status == "DECLINE", "a fit valid only on the sample window MUST be rejected by held-out verification"
    assert "held-out" in r.verdict.reason and "no wrong collapse" in r.verdict.reason

    # no false negatives: a genuinely C-finite loop still COLLAPSES, and the companion ≡ a FRESH run of the loop
    def lucas_like(nn):
        a, b = 2, 3
        for _ in range(nn):
            a, b = b, a + b
        return a
    good = "def g(n):\n    a, b = 2, 3\n    for _ in range(n):\n        a, b = b, a + b\n    return a"
    rg = LR.decide_recurrence_collapse(good, n=3000)
    assert rg.status == "COLLAPSED" and rg.c == [1, 1] and rg.init == [2, 3], rg
    for nv in (41, 130, 777):
        assert cfinite.companion_nth(rg.c, rg.init, nv) == lucas_like(nv), f"companion ≠ the loop at n={nv}"

    # loop_decision: a real closed form is emitted, a non-summable is PROVEN irreducible (never a wrong claim)…
    assert LD.decide_sum_collapse("k**2", "k", 1).status == LD.CLOSED_FORM
    assert LD.decide_sum_collapse("1/k", "k", 1).status == LD.NO_CLOSED_FORM
    # …and the differential gate rejects a deliberately WRONG closed form (n² ≠ Σk = n(n+1)/2), accepts the right one
    k, n = sp.Symbol("k"), sp.Symbol("n")
    okw, chkw = LD._differential_ok(sp.sympify("k"), sp.sympify("n*n"), k, n, 1)
    okr, chkr = LD._differential_ok(sp.sympify("k"), sp.sympify("n*(n+1)/2"), k, n, 1)
    assert chkw >= 3 and okw < chkw, "the gate must reject a wrong closed form"
    assert chkr >= 3 and okr == chkr, "the gate must accept the correct closed form"

    print("PASS test_loop_collapse_adversarial (held-out gate REJECTS a fit valid only on the sample window "
          "[Fibonacci-then-diverge → DECLINE at n=33, no wrong O(log n) collapse]; a genuine C-finite loop still "
          "COLLAPSES & companion ≡ a fresh run [no false negative]; loop_decision emits no wrong closed form and "
          "never falsely claims irreducible — the dominant failure mode, spec fragility, is gated)")


def test_run_optimize_collapse():
    """§2/§4 — the optimize RESULT (not only the live stream) surfaces the PROVEN loop collapse the canonical-fix
    engine does NOT cover: a Σ-loop → O(1) closed form (or PROVEN-irreducible), a C-finite state-update loop →
    O(log n) companion. Each carries its grade + certificate; absent ⇒ collapse=None (honest, never fabricated)."""
    from webapi import engine_bridge as EB

    sq = "def g(n):\n    s = 0\n    for k in range(1, n + 1):\n        s += k * k\n    return s"
    c = EB.run_optimize(sq, "normal")["collapse"]
    assert c and c["kind"] == "sum" and c["status"] == "CLOSED_FORM" and c["grade"] == "EXACT"
    assert "n" in c["closed_form"] and c["complexity"] == "O(n) → O(1)" and c["certificate"]

    harm = "def f(n):\n    s = 0\n    for k in range(1, n + 1):\n        s += 1 / k\n    return s"
    ch = EB.run_optimize(harm, "normal")["collapse"]
    assert ch and ch["status"] == "NO_CLOSED_FORM" and ch["grade"] == "EXACT", ch    # proven irreducible

    fib = "def fib(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, a + b\n    return a"
    cf = EB.run_optimize(fib, "normal")["collapse"]
    assert cf and cf["kind"] == "recurrence" and cf["status"] == "COLLAPSED"
    assert cf["complexity"] == "O(n) → O(log n)" and cf["c"] == [1, 1] and cf["grade"] == "EXACT" and cf["certificate"]

    fibm = "M = 10 ** 9 + 7\ndef f(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, (a + b) % M\n    return a"
    cm = EB.run_optimize(fibm, "normal")["collapse"]                 # the modular case (genuine-win) also surfaces
    assert cm and cm["kind"] == "modular_recurrence" and cm["status"] == "COLLAPSED" and cm["c"] == [1, 1]
    assert "(mod M)" in cm["complexity"] and cm["grade"] == "EXACT" and cm["certificate"]

    # no loop / glue code ⇒ no fabricated collapse (honest None)
    assert EB.run_optimize("def h(c):\n    return c.get('a', 1)", "normal")["collapse"] is None

    print("PASS test_run_optimize_collapse (the optimize RESULT surfaces the PROVEN collapse: Σk² → O(1) closed form, "
          "harmonic → PROVEN irreducible, Fibonacci → O(log n) companion [c=[1,1]], glue → None — each with grade + "
          "certificate, never fabricated; the canonical-fix engine alone misses these)")


