def test_loop_collapse_fork_safe():
    """§4 (regression) — _loop_collapse is DECIDE-ONLY and SYNCHRONOUS: it surfaces the proven collapse (sample →
    fit → held-out verify) WITHOUT timing the user's loop, so it is fast and spawns NO threads. The earlier
    timing-under-a-daemon-watchdog design left a thread alive on a slow loop and could DEADLOCK a later
    multiprocessing.fork; this guards against that (after _loop_collapse the live thread count does not increase)
    while keeping the proof — the held-out-verified decision + certificate. The measured ratio lives in the live
    trace (§3), a single deliberate step, not on every optimize call."""
    from webapi import engine_bridge as EB
    import threading
    import time

    for code in ("def fib(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, a + b\n    return a",
                 "M = 10 ** 9 + 7\ndef f(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, (a + b) % M\n"
                 "    return a"):
        base = threading.active_count()
        t0 = time.monotonic()
        col = EB._loop_collapse(code)
        dt = time.monotonic() - t0
        assert col and col["status"] == "COLLAPSED" and col["c"] == [1, 1] and col["grade"] == "EXACT", col
        assert col["certificate"] and "ratio" not in col, "decide-only ⇒ proof + certificate but no (unmeasured) ratio"
        assert dt < 2.0, f"decide-only collapse must be fast (took {dt:.2f}s)"
        # ★ the regression guard ★: _loop_collapse adds NO threads (so a later multiprocessing.fork can't deadlock)
        assert threading.active_count() <= base, "decide-only _loop_collapse must spawn NO threads (fork-safe)"

    # ★ §3 (live nested wiring): a doubly-nested Σ_iΣ_j loop now collapses O(n²)→O(1) in the LIVE engine path ★
    nested = "def f(n):\n acc=0\n for i in range(1,n+1):\n  for j in range(1,i+1):\n   acc += j\n return acc"
    col = EB._loop_collapse(nested)
    assert col and col["kind"] == "nested_sum" and col["status"] == "CLOSED_FORM" and col["grade"] == "EXACT", col
    assert col["closed_form"] == "n*(n**2 + 3*n + 2)/6" and "→ O(1)" in col["complexity"], col

    # ★ §3 (live shape wiring): the OTHER fold shapes now surface their OPTIMAL O(1) closed form in the live path
    #   (tried BEFORE the recurrence detector, so a polynomial sum is O(1) — not the suboptimal O(log n) companion).
    #   A genuine state-update recurrence (Fibonacci, above) still correctly routes to the O(log n) recurrence. ★
    for shape_src in (
        "def f(n):\n return sum(k*k for k in range(1,n+1))",                                  # comprehension
        "def f(n):\n s=0\n k=1\n while k<=n:\n  s+=k*k\n  k+=1\n return s",                    # counter-while
        "def f(n):\n if n<1:\n  return 0\n return f(n-1)+n*n",                                 # recursion
        "def f(n):\n return reduce(lambda s,k: s+k*k, range(1,n+1), 0)",                       # reduce
    ):
        c = EB._loop_collapse(shape_src)
        assert c and c["kind"] == "code_shape" and c["status"] == "CLOSED_FORM" and c["grade"] == "EXACT", (shape_src, c)
        assert c["closed_form"] == "n*(n + 1)*(2*n + 1)/6", (shape_src, c["closed_form"])
    # a filtered sum surfaces its O(1) closed form too
    cf = EB._loop_collapse("def f(n):\n s=0\n for k in range(n):\n  if k%2==0:\n   s+=k\n return s")
    assert cf and cf["kind"] == "code_shape" and cf["status"] == "CLOSED_FORM" and cf["grade"] == "EXACT", cf

    # ★ NO-HANG regression: a nested loop with an EXPONENTIAL inner bound is RECOGNIZED-but-declined; it must NOT
    #   fall through to the loop-SAMPLING recurrence detector (which would execute range(1, 2**i) and hang). It
    #   returns None FAST. (This assertion completing under the time bound IS the no-hang proof.) ★
    exp_nested = "def f(n):\n acc=0\n for i in range(1,n+1):\n  for j in range(1,2**i):\n   acc += j\n return acc"
    t0 = time.monotonic()
    col_exp = EB._loop_collapse(exp_nested)
    assert col_exp is None, f"exponential-bound nested must DECLINE (honest NONE), got {col_exp}"
    assert time.monotonic() - t0 < 2.0, "must return FAST — never sample/execute an unbounded nested loop (no hang)"

    print("PASS test_loop_collapse_fork_safe (_loop_collapse decide-only + synchronous: Fibonacci/modular → O(log n) "
          "recurrence COLLAPSED c=[1,1] EXACT, fast, NO threads [fork-safe]; LIVE nested → O(1) [nested_sum]; "
          "comprehension/while/recursion/reduce/filtered → their OPTIMAL O(1) closed form [code_shape EXACT, not the "
          "O(log n) companion]; exponential-bound nested DECLINEs FAST [no-hang] — fork-deadlock + unbounded-sampling "
          "regressions gated, and the live engine now collapses EVERY code-shape)")


def test_modular_recurrence_collapse():
    """§4 (ceiling-breaker) — a MODULAR C-finite loop (f(n) mod M — the common Fibonacci/Pell-mod case) collapses
    to an O(log n) companion-matrix-power-MOD-M form. This is the case where O(log n) GENUINELY WINS: the modulus
    keeps ints BOUNDED (no bigint), so it is true O(log n) ring work (~56× measured here). Sound: M is detected
    from the loop's `% M`, the recurrence is fitted from the early (unwrapped) samples, and — the gate —
    companion_nth_mod ≡ the user's ACTUAL loop on HELD-OUT n WHERE IT HAS WRAPPED. A small M (early values wrap →
    no clean fit) or a non-modular loop DECLINEs. Per C6 the magnitude is perf_obs; the hard gate is the verified
    equivalence + the honest-limit certificate."""
    import loop_recurrence as LR
    import cfinite
    import kernel_verdict as KV

    M = 10 ** 9 + 7
    fibm = ("M = 10 ** 9 + 7\ndef f(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, (a + b) % M\n"
            "    return a")
    r = LR.decide_modular_recurrence_collapse(fibm, n=100000, trials=3)
    assert r.status == "COLLAPSED" and r.verdict.status == KV.EXACT and r.c == [1, 1] and r.init == [0, 1], r

    # ★ soundness ★: the O(log n) companion-mod == a FRESH modular Fibonacci on held-out n WHERE IT HAS WRAPPED
    def fib_mod(nn):
        a, b = 0, 1
        for _ in range(nn):
            a, b = b, (a + b) % M
        return a
    for nv in (84, 500, 5000, 100000):
        assert cfinite.companion_nth_mod(r.c, r.init, nv, M) == fib_mod(nv), f"companion-mod ≠ the loop at n={nv}"
    # the collapse genuinely wins (O(log n) bounded vs O(n) bounded) — magnitude via perf_obs (not a hard gate)
    assert r.naive_s > r.log_s and r.measured_win
    perf_obs("modular_recurrence_collapse_fib", ratio=round(r.ratio, 1), win=r.measured_win, n=r.n,
             naive_ms=round(r.naive_s * 1e3, 2), log_us=round(r.log_s * 1e6, 2))
    cert = r.verdict.certificate.detail
    for marker in ("genuinely WINS", "BOUNDED", "DOMAIN-CONDITIONAL", "Amdahl", "held-out"):
        assert marker in cert, f"the certificate must state: {marker}"

    # Pell-mod (different coefficients, INLINE literal modulus) is also recognized + verified
    pellm = "def g(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, (2 * b + a) % 1000000009\n    return a"
    rp = LR.decide_modular_recurrence_collapse(pellm, n=3000)
    assert rp.status == "COLLAPSED" and rp.c == [2, 1], rp
    # a small modulus (early values wrap → no clean fit) and a non-modular loop DECLINE (honest)
    small = "def f(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, (a + b) % 7\n    return a"
    plain = "def f(n):\n    a, b = 0, 1\n    for _ in range(n):\n        a, b = b, a + b\n    return a"
    assert LR.decide_modular_recurrence_collapse(small).status == "DECLINE", "small M (wraps early) ⇒ DECLINE"
    assert LR.decide_modular_recurrence_collapse(plain).status == "DECLINE", "no `% M` ⇒ DECLINE (use exact recognizer)"

    print(f"PASS test_modular_recurrence_collapse (Fib(n) mod 1e9+7: O(n) modular loop → O(log n) companion-mod "
          f"[c=[1,1]], VERIFIED ≡ a fresh modular loop on WRAPPED held-out n; MEASURED {r.ratio:.0f}× at n={r.n} "
          f"[bounded ints ⇒ O(log n) genuinely wins; perf_obs]; Pell-mod c=[2,1]; small-M & non-modular → DECLINE)")


ALL = [v for k, v in sorted(globals().items()) if k.startswith("test_") and callable(v)]


def main():
    import traceback
    passed = failed = 0
    for t in ALL:
        try:
            t()
            passed += 1
        except Exception:  # noqa: BLE001
            failed += 1
            print(f"FAIL {t.__name__}")
            traceback.print_exc()
    print(f"\n==== test_build: {passed} passed, {failed} failed (of {len(ALL)}) ====")
    return failed


if __name__ == "__main__":
    raise SystemExit(main())


