"""
v28 STAGE 20 — error-recovering, comment/string-correct frontend + a common typed IR.
======================================================================================
A regex scanner cannot match NESTED structure (block comments, macros, strings) — so it silently produces
a WRONG HIR (e.g. it ends a comment at the first `*/`, or treats `//` inside a string as a comment). This
frontend fixes that at the lexical level and lowers to the shared HIR, so every downstream verifier (VC
generation, abstract interpretation, taint, separation logic) is written ONCE over the IR.

Two execution paths, same IR:
  • Tree-sitter (if `tree_sitter` + a grammar module is installed) — a real GLR CST with ERROR RECOVERY;
    `node.has_error` subtrees become explicit UNPARSED markers.
  • pure-Python fallback (always available) — a correct char-level state machine for comments / strings /
    nested blocks (the actual soundness fix), then a brace-stack signature scan.

★ HONEST (§1.4, §1.9, §5) ★: (1) an UNPARSED region is lowered to an `assume_unknown` op — the verifier
treats it as UNKNOWN, never a fake PROVEN. (2) Tree-sitter is syntax only (not types); the recovery tree is
heuristic on broken input (labeled). (3) Adding a language is a FRONTEND, not a verifier rewrite — but the
frontend is most of the work (CodeQL: ~95%); language onboarding is NOT free. (4) `tree_sitter` install may
be [BLOCKED]; the pure-Python path then carries the soundness fix unchanged.
"""
from __future__ import annotations

import re
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple

from hir import HFunction, HModule, HOp

# ── optional Tree-sitter detection (never required for correctness) ─────────────────────────────────
def _detect_tree_sitter() -> Tuple[bool, Dict[str, object]]:
    try:
        import tree_sitter  # noqa: F401
    except Exception:  # noqa: BLE001
        return (False, {})
    grammars: Dict[str, object] = {}
    for lang, mod in (("go", "tree_sitter_go"), ("c", "tree_sitter_c"), ("rust", "tree_sitter_rust")):
        try:
            m = __import__(mod)
            grammars[lang] = m.language()
        except Exception:  # noqa: BLE001
            pass
    return (True, grammars)


TREE_SITTER_AVAILABLE, _GRAMMARS = _detect_tree_sitter()


# ── language lexical config ─────────────────────────────────────────────────────────────────────────
@dataclass
class LexCfg:
    line: str = "//"
    block: Tuple[str, str] = ("/*", "*/")
    nested_block: bool = False          # Rust nests block comments; C/Go do not
    strings: str = '"'
    chars: str = "'"


_LEX = {"c": LexCfg(), "go": LexCfg(), "javascript": LexCfg(),
        "rust": LexCfg(nested_block=True), "python": LexCfg(line="#", block=("", ""))}


# ── THE SOUNDNESS CORE: correct comment/string/nested stripping (pure Python) ───────────────────────
def strip_comments(source: str, lang: str = "c") -> Tuple[str, List[Tuple[int, str]]]:
    """Replace comments with spaces (preserving newlines/line numbers), correctly handling NESTED block
    comments and ignoring comment markers inside string/char literals. Returns (clean_source, comments)."""
    cfg = _LEX.get(lang, LexCfg())
    s = source
    out = []
    comments: List[Tuple[int, str]] = []
    i, n, line = 0, len(s), 1
    lb, rb = cfg.block
    while i < n:
        ch = s[i]
        if ch == "\n":
            out.append(ch); line += 1; i += 1; continue
        # string / char literal — copy verbatim (comment markers inside are NOT comments)
        if ch in (cfg.strings, cfg.chars):
            q = ch; out.append(ch); i += 1
            while i < n:
                out.append(s[i])
                if s[i] == "\\" and i + 1 < n:
                    out.append(s[i + 1]); i += 2; continue
                if s[i] == q:
                    i += 1; break
                if s[i] == "\n":
                    line += 1
                i += 1
            continue
        # line comment
        if cfg.line and s.startswith(cfg.line, i):
            j = s.find("\n", i)
            j = n if j < 0 else j
            comments.append((line, s[i:j])); out.append(" " * (j - i)); i = j; continue
        # block comment (with nesting if the language allows)
        if lb and s.startswith(lb, i):
            depth, start, j = 1, i, i + len(lb)
            startline = line
            while j < n and depth > 0:
                if s[j] == "\n":
                    line += 1
                if cfg.nested_block and s.startswith(lb, j):
                    depth += 1; j += len(lb); continue
                if s.startswith(rb, j):
                    depth -= 1; j += len(rb); continue
                j += 1
            seg = s[start:j]
            comments.append((startline, seg))
            out.append("".join(c if c == "\n" else " " for c in seg)); i = j; continue
        out.append(ch); i += 1
    return ("".join(out), comments)


def naive_regex_strip(source: str) -> str:
    """The BROKEN baseline (for contrast): regex comment stripping. Mishandles nesting and string-embedded
    markers — exactly the bug S20 removes."""
    s = re.sub(r"/\*.*?\*/", "", source, flags=re.DOTALL)   # non-greedy → stops at the FIRST */
    s = re.sub(r"//[^\n]*", "", s)                          # strips '//' even inside a string literal
    return s


# ── simple object-like C macro expansion pre-pass ───────────────────────────────────────────────────
_DEFINE = re.compile(r"^\s*#define\s+([A-Za-z_]\w*)\s+(.+?)\s*$", re.MULTILINE)


def expand_macros(source: str) -> Tuple[str, Dict[str, str]]:
    """Expand object-like `#define NAME BODY` (function-like macros are left as-is — honest)."""
    macros = {m.group(1): m.group(2) for m in _DEFINE.finditer(source)}
    body = _DEFINE.sub("", source)
    for name, val in macros.items():
        body = re.sub(rf"\b{name}\b", val, body)
    return (body, macros)


# ── common IR fact schema (verification mapping consumes this, written once) ────────────────────────
IR_FACT_SCHEMA = ("function(name,params)", "op(kind,line)", "comment(line)", "unparsed(line,reason)")


def to_facts(mod: HModule) -> List[Tuple]:
    facts: List[Tuple] = []
    for fn in mod.functions:
        facts.append(("function", fn.name, tuple(fn.params)))
        for op in fn.ops:
            facts.append(("op" if op.kind != "assume_unknown" else "unparsed", op.kind, op.line))
    return facts


# ── lowering to HIR (Tree-sitter path if available, else the pure-Python fallback) ──────────────────
_SIG = re.compile(r"\bfunc\s+(?:\([^)]*\)\s*)?([A-Za-z_]\w*)\s*\(([^)]*)\)"      # Go
                  r"|\b([A-Za-z_][\w*\s]*?)\s+([A-Za-z_]\w*)\s*\(([^)]*)\)\s*\{")  # C-like


def _params(arglist: str) -> List[str]:
    out = []
    for part in arglist.split(","):
        toks = part.replace("*", " ").split()
        if toks:
            out.append(toks[-1] if len(toks) > 1 else toks[0])   # last token ≈ the parameter name
    return [p for p in out if p.isidentifier()]


def _fallback_to_hir(source: str, lang: str) -> HModule:
    clean, comments = strip_comments(source, lang)
    if lang in ("c", "cpp"):
        clean, _macros = expand_macros(clean)
    fns: List[HFunction] = []
    for m in _SIG.finditer(clean):
        if m.group(1):                              # Go: func NAME(args)
            name, args = m.group(1), m.group(2)
        else:                                       # C-like: ret NAME(args) {
            name, args = m.group(4), m.group(5)
        line = clean[:m.start()].count("\n") + 1
        ops = [HOp("call", line, name)]
        fns.append(HFunction(name, _params(args or ""), ops, m.group(0), line, line, lang=lang))
    # mark a region with unbalanced braces as UNPARSED → unknown (honest, no fake confidence)
    if clean.count("{") != clean.count("}"):
        fns.append(HFunction("<unparsed>", [], [HOp("assume_unknown", 0,
                    "unbalanced-braces region — verifier must treat as unknown (honest-defer)")],
                    "", 0, 0, lang=lang))
    return HModule(lang, fns, source)


def _tree_sitter_to_hir(source: str, lang: str) -> Optional[HModule]:
    if not TREE_SITTER_AVAILABLE or lang not in _GRAMMARS:
        return None
    try:
        from tree_sitter import Language, Parser
        parser = Parser(Language(_GRAMMARS[lang]))
        tree = parser.parse(source.encode())
    except Exception:  # noqa: BLE001
        return None
    fns: List[HFunction] = []
    src = source.encode()

    def text(n):
        return src[n.start_byte:n.end_byte].decode("utf-8", "replace")

    def walk(n):
        if n.type in ("function_declaration", "method_declaration", "function_definition"):
            ident = next((c for c in n.children if c.type in ("identifier", "field_identifier")), None)
            params = []
            pl = next((c for c in n.children if c.type in ("parameter_list", "parameters")), None)
            if pl is not None:
                for pc in pl.children:
                    pid = next((g for g in pc.children if g.type == "identifier"), None)
                    if pid is not None:
                        params.append(text(pid))
            name = text(ident) if ident is not None else "<anon>"
            line = n.start_point[0] + 1
            kind = "assume_unknown" if n.has_error else "call"
            fns.append(HFunction(name, params, [HOp(kind, line, name)], text(n), line,
                                 n.end_point[0] + 1, lang=lang))
        for c in n.children:
            walk(c)

    walk(tree.root_node)
    if tree.root_node.has_error:        # the parse hit a syntax error somewhere → mark an UNPARSED region
        fns.append(HFunction("<unparsed>", [], [HOp("assume_unknown", tree.root_node.start_point[0] + 1,
                   "tree-sitter error-recovery region — verifier must treat as unknown (honest-defer)")],
                   "", 0, 0, lang=lang))
    return HModule(lang, fns, source)


def to_hir(source: str, lang: str = "go") -> Tuple[HModule, str]:
    """Lower `source` to the common HIR. Returns (module, path) where path ∈ {"tree-sitter","fallback"}."""
    ts = _tree_sitter_to_hir(source, lang)
    if ts is not None:
        return (ts, "tree-sitter")
    return (_fallback_to_hir(source, lang), "fallback")


# ==============================================================================================================
# ===== FILE: typed_decoding.py  (138 lines) =====
# ==============================================================================================================

"""
v27 STAGE 16 (lever 1) — type-constrained decoding: prune ill-typed tokens AS THEY ARE GENERATED.
==================================================================================================
A grammar/type automaton masks the next-token set so that only choices keeping a WELL-TYPED parse alive
are allowed. The model still chooses *among* the legal tokens (we never override its ranking) — we only
remove tokens that would guarantee a compile/type error. Net effect (measured below): the well-typed rate
of generated programs goes to 100% by construction, vs a fraction for unconstrained sampling.

Demonstrated on a small typed expression language with an Int target:
  operands  = int literals / Int vars / '('         (a Bool var is PRUNED here — wrong type for an Int slot)
  operators = '+' '*' / ')' (if open) / END          ('<' and '&' are PRUNED — they would yield Bool ≠ Int)
The mask is a left-to-right OPERAND/OPERATOR state machine + paren depth; every accepted string parses and
type-checks to Int. We MEASURE the well-typed rate of constrained vs unconstrained generation on the same
mock token-proposer (no LLM/key needed — the LLM only supplies a ranking we filter).

★ HONEST (§1.9, §5.9) ★: this is a heuristic *accuracy lever*, not a guarantee — it removes TYPE errors,
NOT logic errors. The correctness guarantee remains the write→verify→fix verifier. A live-LLM accuracy
delta needs a key/egress ([BLOCKED] here); the measurable, key-free claim is the well-typed-rate lift.
"""
from __future__ import annotations

import ast
import random
from dataclasses import dataclass
from typing import Dict, List, Optional, Set

INT_VARS = {"x", "y"}
BOOL_VARS = {"b"}
INT_LITS = {"1", "2"}
ARITH = {"+", "*"}          # Int × Int → Int
CMP = {"<"}                 # Int × Int → Bool   (illegal in an Int slot)
BOOLOP = {"&"}              # Bool × Bool → Bool (illegal in an Int slot)
LP, RP, END = "(", ")", "<END>"
VOCAB: List[str] = sorted(INT_VARS | BOOL_VARS | INT_LITS | ARITH | CMP | BOOLOP | {LP, RP})


# ── the type checker (uses Python's parser for the grammar/balance, a type walk for typing) ─────────
def welltyped_int(tokens: List[str]) -> bool:
    """True iff `tokens` parse as a balanced expression AND type-check to Int."""
    if not tokens:
        return False
    expr = " ".join("and" if t == "&" else t for t in tokens)
    try:
        tree = ast.parse(expr, mode="eval").body
    except SyntaxError:
        return False

    def typ(n) -> Optional[str]:
        if isinstance(n, ast.Constant):
            return "Int" if isinstance(n.value, int) and not isinstance(n.value, bool) else None
        if isinstance(n, ast.Name):
            return "Int" if n.id in INT_VARS else ("Bool" if n.id in BOOL_VARS else None)
        if isinstance(n, ast.BinOp) and type(n.op).__name__ in ("Add", "Mult"):
            return "Int" if typ(n.left) == "Int" and typ(n.right) == "Int" else None
        if isinstance(n, ast.Compare) and len(n.ops) == 1 and isinstance(n.ops[0], ast.Lt):
            return "Bool" if typ(n.left) == "Int" and typ(n.comparators[0]) == "Int" else None
        if isinstance(n, ast.BoolOp) and isinstance(n.op, ast.And):
            return "Bool" if all(typ(v) == "Bool" for v in n.values) else None
        return None
    return typ(tree) == "Int"


# ── the type-constrained next-token mask (left-to-right state machine) ───────────────────────────────
@dataclass
class _State:
    mode: str = "OPERAND"   # OPERAND (need an Int operand) | OPERATOR (need an op / close / end)
    depth: int = 0


def _step(st: _State, tok: str) -> Optional[_State]:
    if st.mode == "OPERAND":
        if tok in INT_VARS or tok in INT_LITS:
            return _State("OPERATOR", st.depth)
        if tok == LP:
            return _State("OPERAND", st.depth + 1)
        return None
    # OPERATOR
    if tok in ARITH:
        return _State("OPERAND", st.depth)
    if tok == RP and st.depth > 0:
        return _State("OPERATOR", st.depth - 1)
    if tok == END and st.depth == 0:
        return _State("OPERATOR", st.depth)
    return None


def valid_next_tokens(prefix: List[str]) -> Set[str]:
    """The type-valid next tokens after `prefix` for an Int-typed expression (ill-typed ones are pruned)."""
    st = _State()
    for t in prefix:
        nxt = _step(st, t)
        if nxt is None:
            return set()            # prefix already dead — nothing valid
        st = nxt
    return {t for t in VOCAB + [END] if _step(st, t) is not None}


# ── generation: constrained (mask) vs unconstrained (raw), and the measured well-typed rate ─────────
def constrained_generate(rng: random.Random, max_len: int = 12) -> List[str]:
    """Sample only from the type-valid mask, then FORCE-COMPLETE (supply a pending operand, close open
    parens) so the result is well-typed Int BY CONSTRUCTION."""
    out: List[str] = []
    st = _State()
    while len(out) < max_len:
        if st.mode == "OPERATOR" and st.depth == 0 and out and rng.random() < 0.35:
            return out                                   # legal stopping point (Int, balanced)
        choices = sorted(valid_next_tokens(out) - {END})
        if not choices:
            break
        tok = rng.choice(choices)
        out.append(tok)
        st = _step(st, tok)
    if st.mode == "OPERAND":                              # pending operand → supply one
        out.append(rng.choice(sorted(INT_VARS | INT_LITS)))
        st = _State("OPERATOR", st.depth)
    while st.depth > 0:                                  # close any open parens
        out.append(RP)
        st = _State("OPERATOR", st.depth - 1)
    return out


def unconstrained_generate(rng: random.Random, max_len: int = 12) -> List[str]:
    n = rng.randint(1, max_len)
    return [rng.choice(VOCAB) for _ in range(n)]


def measure_welltyped_rate(n: int = 2000, seed: int = 7) -> Dict[str, float]:
    """Measure the well-typed (compile-success) rate of constrained vs unconstrained generation."""
    rng = random.Random(seed)
    con = sum(1 for _ in range(n) if welltyped_int(constrained_generate(rng)))
    rng = random.Random(seed)
    unc = sum(1 for _ in range(n) if welltyped_int(unconstrained_generate(rng)))
    con_rate, unc_rate = con / n, unc / n
    err_before, err_after = 1 - unc_rate, 1 - con_rate
    reduction = (err_before - err_after) / err_before if err_before > 0 else 0.0
    return {"constrained_welltyped": con_rate, "unconstrained_welltyped": unc_rate,
            "compile_error_reduction": reduction, "n": n}


# ==============================================================================================================
# ===== FILE: verify_exact.py  (109 lines) =====
# ==============================================================================================================

"""
JEFF-style EXACT verification layer
====================================
The bounded verifier (verify_core) is honest but limited: it says
"VERIFIED (bounded)" — strong evidence, not proof. A hidden bug at an untested
input survives.

This layer does what JEFF does: for NUMERIC / ALGEBRAIC code, prove equivalence
for ALL inputs by exact symbolic identity — so the verdict is PROVEN, not "no
counterexample found." This is the differentiator: other AI-test tools can only
fuzz; this returns a real proof for the math-shaped part of the code.

(In production this calls the real JEFF verifier — exact polynomial-identity /
fold certificate. Here we use exact symbolic algebra (sympy, exact rationals) to
demonstrate the SAME idea: closed-form equivalence, proven, no floating point.)
"""

import sympy as sp
from dataclasses import dataclass


@dataclass
class ExactVerdict:
    verdict: str        # PROVEN_EQUAL | PROVEN_UNEQUAL | NOT_APPLICABLE
    detail: str = ""
    witness: str = ""   # for unequal: an input where they differ

    def __str__(self):
        if self.verdict == "PROVEN_EQUAL":
            return f"PROVEN EQUAL (all inputs) -- {self.detail}"
        if self.verdict == "PROVEN_UNEQUAL":
            return f"PROVEN UNEQUAL -- differ at {self.witness}; {self.detail}"
        return f"NOT APPLICABLE (not a closed-form numeric claim) -- {self.detail}"


def prove_equiv(expr_candidate: str, expr_reference: str, variables: list):
    """
    Prove that candidate(x...) == reference(x...) for ALL real x, exactly.
    expr_* are math expressions in the given variable names, e.g.
        prove_equiv("n*(n+1)/2", "Sum(k,(k,1,n))", ["n"])  -> requires closed forms
        prove_equiv("(x+1)**2", "x**2+2*x+1", ["x"])       -> PROVEN_EQUAL
    Returns ExactVerdict.
    """
    syms = sp.symbols(variables, real=True)
    env = dict(zip(variables, syms if isinstance(syms, (list, tuple)) else [syms]))
    try:
        c = sp.sympify(expr_candidate, locals=env)
        r = sp.sympify(expr_reference, locals=env)
    except Exception as e:
        return ExactVerdict("NOT_APPLICABLE", detail=f"could not parse: {e}")

    diff = sp.simplify(c - r)
    if diff == 0:
        return ExactVerdict("PROVEN_EQUAL", detail=f"{expr_candidate}  ≡  {expr_reference}")

    # try harder: expand / factor
    diff2 = sp.simplify(sp.expand(c) - sp.expand(r))
    if diff2 == 0:
        return ExactVerdict("PROVEN_EQUAL", detail=f"{expr_candidate}  ≡  {expr_reference} (after expansion)")

    # they differ — find a witness input exactly
    witness = None
    free = list(diff.free_symbols)
    for trial in range(0, 6):
        subs = {s: trial for s in free}
        try:
            val = diff.subs(subs)
            if val != 0:
                witness = ", ".join(f"{s}={trial}" for s in free) + f" → diff={val}"
                break
        except Exception:
            pass
    return ExactVerdict("PROVEN_UNEQUAL", detail=f"residual = {diff}",
                        witness=witness or "(symbolic residual nonzero)")


def prove_closed_form_sum(closed_form: str, summand: str, index: str,
                          lo: str, hi: str, variables: list):
    """
    JEFF's signature move: prove that a loop computing a sum equals a CLOSED FORM,
    for all n — exactly. e.g. prove sum_{k=1}^{n} k  ==  n*(n+1)/2.
        prove_closed_form_sum("n*(n+1)/2", "k", "k", "1", "n", ["n","k"])
    """
    syms = {v: sp.symbols(v, integer=True, positive=True) for v in variables}
    k = syms[index]
    n_sym = syms.get("n")
    try:
        summand_e = sp.sympify(summand, locals=syms)
        lo_e = sp.sympify(lo, locals=syms)
        hi_e = sp.sympify(hi, locals=syms)
        closed_e = sp.sympify(closed_form, locals=syms)
    except Exception as e:
        return ExactVerdict("NOT_APPLICABLE", detail=f"parse error: {e}")

    actual = sp.summation(summand_e, (k, lo_e, hi_e))
    diff = sp.simplify(actual - closed_e)
    if diff == 0:
        return ExactVerdict("PROVEN_EQUAL",
            detail=f"Σ_{{{index}={lo}}}^{{{hi}}} {summand} ≡ {closed_form}  (proven for all {hi})")
    # witness
    witness = None
    if n_sym is not None:
        for t in range(1, 6):
            if sp.simplify(diff.subs(n_sym, t)) != 0:
                witness = f"n={t}"
                break
    return ExactVerdict("PROVEN_UNEQUAL", detail=f"residual = {diff}",
                        witness=witness or "(nonzero residual)")


# ==============================================================================================================
# ===== FILE: z3_adapter.py  (248 lines) =====
# ==============================================================================================================

"""
STAGE X1 — proof-engine core: Z3 relational backend (foundation for error proofs).
=================================================================================
v1/v2 could prove polynomial identities (JEFF coeff-zero) and decide closure (Gosper/Galois), and
TEST general props (bounded fuzz). What was missing — and what "unstructured conquest" (X2) needs —
is proving INEQUALITIES like |approx − exact| ≤ ε for ALL inputs. This wires Z3 for that.

Extended fallback chain (X1.2):
    jeff (polynomial identity, exact)  →  sympy (exact identity)  →  Z3 (relational / inequality / FOL)
    →  bounded fuzz (last resort, TESTED not PROVEN)

★ Honesty: a Z3 `unsat` of the negation is a real ∀-proof (PROVEN). `sat` → REFUTED with a concrete
counterexample (the model). `unknown`/timeout → UNKNOWN (never upgraded to PROVEN). Boundary 1 holds:
everything proven is *명세 대비*.
"""
from __future__ import annotations

from dataclasses import dataclass
from fractions import Fraction
from typing import Dict, List, Optional

import haran_ast as A

try:
    import z3
    _Z3 = True
except Exception:   # noqa: BLE001
    _Z3 = False


def z3_available() -> bool:
    return _Z3


@dataclass
class ProofResult:
    verdict: str            # PROVEN | REFUTED | UNKNOWN | UNAVAILABLE
    backend: str            # z3 | none
    detail: str
    counterexample: Optional[dict] = None

    def __str__(self):
        cx = f"  cx={self.counterexample}" if self.counterexample else ""
        return f"{self.verdict} via {self.backend} — {self.detail}{cx}"


class _Unsupported(Exception):
    pass


def _to_z3(e, env: Dict[str, object], real=True):
    """HARAN bool/arith expr → a Z3 term. `env` maps free names to typed Z3 consts."""
    if isinstance(e, A.Num):
        if e.is_float or real:
            f = Fraction(e.value)
            return z3.RealVal(f"{f.numerator}/{f.denominator}")
        return z3.IntVal(int(e.value))
    if isinstance(e, A.BoolLit):
        return z3.BoolVal(e.value)
    if isinstance(e, A.Var):
        if e.name not in env:
            raise _Unsupported(f"free variable '{e.name}'")
        return env[e.name]
    if isinstance(e, A.Un):
        if e.op == "-":
            return -_to_z3(e.operand, env, real)
        if e.op in ("¬", "!"):
            return z3.Not(_to_z3(e.operand, env, real))
        raise _Unsupported(f"unary '{e.op}'")
    if isinstance(e, A.Call) and isinstance(e.func, A.Var) and e.func.name == "abs" and len(e.args) == 1:
        a = _to_z3(e.args[0], env, real)
        return z3.If(a >= 0, a, -a)
    if isinstance(e, A.Call) and isinstance(e.func, A.Var) and e.func.name in ("min", "max") and len(e.args) == 2:
        a, b = _to_z3(e.args[0], env, real), _to_z3(e.args[1], env, real)
        return z3.If(a <= b, a, b) if e.func.name == "min" else z3.If(a >= b, a, b)
    if isinstance(e, A.Call):
        raise _Unsupported(f"opaque call '{getattr(e.func, 'name', '?')}' (Z3 cannot model it)")
    if isinstance(e, A.Quant):
        zvars = [z3.Real(v) if real else z3.Int(v) for v in e.vars]
        inner_env = dict(env)
        inner_env.update({v: zv for v, zv in zip(e.vars, zvars)})
        body = _to_z3(e.body, inner_env, real)
        return z3.ForAll(zvars, body) if e.kind == "∀" else z3.Exists(zvars, body)
    if isinstance(e, A.Bin):
        l = _to_z3(e.lhs, env, real)
        r = _to_z3(e.rhs, env, real)
        op = e.op
        if op == "+": return l + r
        if op == "-": return l - r
        if op == "*": return l * r
        if op == "/": return l / r
        if op == "%": return l % r
        if op == "**":
            if isinstance(e.rhs, A.Num) and not e.rhs.is_float:
                out = z3.RealVal(1) if real else z3.IntVal(1)
                for _ in range(int(e.rhs.value)):
                    out = out * l
                return out
            raise _Unsupported("non-constant exponent")
        if op in ("=", "=="): return l == r
        if op in ("≠", "!="): return l != r
        if op == "<": return l < r
        if op in ("≤", "<="): return l <= r
        if op == ">": return l > r
        if op in ("≥", ">="): return l >= r
        if op in ("∧", "&&"): return z3.And(l, r)
        if op in ("∨", "||"): return z3.Or(l, r)
        raise _Unsupported(f"operator '{op}'")
    raise _Unsupported(type(e).__name__)


def prove_forall(goal, var_types: Dict[str, str], assumptions: List = ()) -> ProofResult:
    """Prove ∀ (free vars). goal holds under assumptions, by checking unsat of the negation in Z3."""
    if not _Z3:
        return ProofResult("UNAVAILABLE", "none", "Z3 not installed")
    real = all(t == "Real" for t in var_types.values()) or not var_types
    env = {n: (z3.Real(n) if t == "Real" else z3.Int(n)) for n, t in var_types.items()}
    try:
        s = z3.Solver()
        s.set("timeout", 5000)
        for a in assumptions:
            s.add(_to_z3(a, env, real))
        s.add(z3.Not(_to_z3(goal, env, real)))
    except _Unsupported as e:
        return ProofResult("UNKNOWN", "z3", f"could not encode for Z3: {e}")
    r = s.check()
    if r == z3.unsat:
        return ProofResult("PROVEN", "z3", "∀-proof: negation is unsatisfiable")
    if r == z3.sat:
        m = s.model()
        cx = {}
        for n in var_types:
            v = m.eval(env[n], model_completion=True)
            cx[n] = str(v)
        return ProofResult("REFUTED", "z3", "negation satisfiable — counterexample found", cx)
    return ProofResult("UNKNOWN", "z3", f"Z3 returned {r}")


# --------------------------------------------------------- STAGE 3.3: counterexample diversification
def _violation_tag(goal, env, model, real) -> str:
    """For an (in)equality goal lhs⊙rhs, tag HOW this model violates it: 'lhs<rhs' / 'lhs>rhs' /
    'boundary' (equal) / '—'. Helps a fixer see the SHAPE of the failure, not just one point."""
    if not isinstance(goal, A.Bin) or goal.op not in ("=", "==", "≠", "!=", "<", "≤", "<=", ">", "≥", ">="):
        return "—"
    try:
        import sympy  # noqa: F401
        lv = model.eval(_to_z3(goal.lhs, env, real), model_completion=True)
        rv = model.eval(_to_z3(goal.rhs, env, real), model_completion=True)
        d = z3.simplify(lv - rv)
        if d.as_long() < 0 if d.is_int() else (float(d.as_fraction()) < 0):
            return "lhs<rhs"
        return "lhs>rhs" if (d.as_long() if d.is_int() else float(d.as_fraction())) > 0 else "boundary"
    except Exception:  # noqa: BLE001
        return "—"


def find_counterexamples(goal, var_types: Dict[str, str], assumptions: List = (), k: int = 4):
    """Find up to k DISTINCT counterexamples to ∀goal — each a real Z3 model of ¬goal under the
    assumptions (SOUND: every returned point genuinely violates goal). Block-and-resolve forces
    distinct points; each is tagged with the violation shape. Returns (verdict, [cx,...]) where
    verdict ∈ PROVEN (no CX — negation unsat) | REFUTED (≥1 CX) | UNKNOWN | UNAVAILABLE."""
    if not _Z3:
        return ("UNAVAILABLE", [])
    real = all(t == "Real" for t in var_types.values()) or not var_types
    env = {n: (z3.Real(n) if t == "Real" else z3.Int(n)) for n, t in var_types.items()}
    try:
        s = z3.Solver()
        s.set("timeout", 5000)
        for a in assumptions:
            s.add(_to_z3(a, env, real))
        s.add(z3.Not(_to_z3(goal, env, real)))
    except _Unsupported:
        return ("UNKNOWN", [])
    r = s.check()
    if r == z3.unsat:
        return ("PROVEN", [])
    if r != z3.sat:
        return ("UNKNOWN", [])
    cxs = []
    while len(cxs) < k:
        m = s.model()
        vals = {n: m.eval(env[n], model_completion=True) for n in var_types}
        cxs.append({"point": {n: str(v) for n, v in vals.items()},
                    "violation": _violation_tag(goal, env, m, real)})
        # block this exact point so the next model must differ in ≥1 variable (genuine diversity)
        s.add(z3.Or(*[env[n] != vals[n] for n in var_types]))
        if s.check() != z3.sat:
            break
    return ("REFUTED", cxs)


# --------------------------------------------------------- convenience: parse a predicate string
def parse_predicate(expr_str: str, params: Dict[str, str]):
    """Parse a HARAN boolean expression (the ensures) given param types. Returns the ensures AST."""
    from haran_parser import parse
    decls = ", ".join(f"{n}: {t}" for n, t in params.items())
    src = f"fn _p({decls}) -> Bool\n  ensures {expr_str}\n  effects pure\n{{ true }}\n"
    prog = parse(src)
    if prog.errors:
        raise ValueError("; ".join(str(e) for e in prog.errors))
    return prog.get("_p").ensures


def prove_predicate(expr_str: str, params: Dict[str, str], assumptions: List[str] = ()) -> ProofResult:
    """Parse + prove a HARAN inequality/FOL predicate over the given typed params."""
    goal = parse_predicate(expr_str, params)
    asm = [parse_predicate(a, params) for a in assumptions]
    # Z3 type tag: HARAN 'Float'→Real, 'Int'/'Nat'→Int (default Real for proving over ℝ)
    var_types = {n: ("Real" if t in ("Float", "Real", "rat") else "Int") for n, t in params.items()}
    return prove_forall(goal, var_types, asm)


# --------------------------------------------------------- the extended fallback chain (X1.2)
FALLBACK_CHAIN = ["jeff", "sympy", "z3", "fuzz"]
_SAFE_FNS = {"abs", "min", "max"}
_INEQ = {"<", "≤", "<=", ">", "≥", ">="}


def choose_backend(ensures) -> str:
    """Route a spec to the first capable backend: jeff (poly identity) → sympy → z3 (inequality/FOL)
    → fuzz (opaque predicates). Demonstrates the extended chain."""
    import dataclasses
    from spec_fragment import is_exact_arith

    def walk(n):
        yield n
        if dataclasses.is_dataclass(n) and not isinstance(n, A.Span):
            for f in dataclasses.fields(n):
                v = getattr(n, f.name)
                if isinstance(v, list):
                    for x in v:
                        if dataclasses.is_dataclass(x):
                            yield from walk(x)
                elif dataclasses.is_dataclass(v):
                    yield from walk(v)

    if is_exact_arith(ensures):
        return "jeff"
    opaque = [x.func.name for x in walk(ensures)
              if isinstance(x, A.Call) and isinstance(x.func, A.Var) and x.func.name not in _SAFE_FNS]
    if opaque:
        return "fuzz"                       # references predicates Z3 can't model → bounded fuzz
    has_ineq = any(isinstance(x, A.Bin) and x.op in _INEQ for x in walk(ensures))
    has_quant = any(isinstance(x, A.Quant) for x in walk(ensures))
    if has_ineq or has_quant:
        return "z3"                          # inequality / first-order over arithmetic → Z3
    return "fuzz"


