"""
UNIFIED ARSENAL §3 · P8 — Lagrangian / Hamiltonian mechanics + Noether + Lie point symmetry (EXACT where algebraic).
====================================================================================================================
The variational and symmetry structure of mechanics, with re-substitution certificates:
  • EULER–LAGRANGE: d/dt(∂L/∂q̇) − ∂L/∂q = 0. Fixture: harmonic L=½q̇²−½ω²q² ⇒ q̈+ω²q=0.
  • NOETHER (energy): for L with no explicit t, the Hamiltonian H = q̇·∂L/∂q̇ − L is CONSERVED — certified by
    dH/dt ≡ 0 ON-SHELL (substitute the EL equation q̈ = …). For a cyclic coordinate (∂L/∂q=0), the momentum
    p = ∂L/∂q̇ is conserved (dp/dt ≡ 0 mod EL).
  • POISSON brackets {f,g} = ∂_q f ∂_p g − ∂_p f ∂_q g; the canonical {q,p}=1; {f,H} = df/dt.
  • LIE POINT SYMMETRY of a first-order ODE y′=f(x,y): a generator X=ξ∂_x+η∂_y is a symmetry iff the first
    prolongation kills y′−f on-shell: η_x + (η_y−ξ_x)f − ξ_y f² − ξ f_x − η f_y ≡ 0. A DECISION for a GIVEN
    generator (the certificate is that residual → 0); a NON-symmetry has nonzero residual.
Honest scope (§X): EXACT where the algebra closes; INTEGRATING the determining PDE system (finding all symmetries)
is not guaranteed and is flagged — we VERIFY a given generator, we don't claim to find every one.
"""
from __future__ import annotations

import sympy as sp

import kernel_verdict as KV


def euler_lagrange(L: sp.Expr, q: sp.Function, t: sp.Symbol) -> KV.Verdict:
    """The Euler–Lagrange equation of L(q,q̇,t). EXACT (the equation is exact by the variational derivative)."""
    from sympy.calculus.euler import euler_equations
    eqs = euler_equations(L, q(t), t)
    if not eqs:
        return KV.decline("euler_lagrange: no equation produced ⇒ DECLINE", "lagrangian")
    cert = KV.Cert(KV.EXACT, "euler_lagrange", passed=True, check_cost="d/dt(∂L/∂q̇) − ∂L/∂q",
                   detail=f"EL: {sp.sstr(eqs[0])}")
    return KV.exact(eqs[0], "lagrangian.euler_lagrange", "EXACT (variational derivative)", cert)


def energy_conservation(L: sp.Expr, q: sp.Function, t: sp.Symbol) -> KV.Verdict:
    """Noether (time-translation): H = q̇·∂L/∂q̇ − L is conserved — CERTIFIED by dH/dt ≡ 0 on-shell (EL substituted)."""
    qd, qdd = q(t).diff(t), q(t).diff(t, 2)
    # EXPLICIT t-dependence test: freeze q, q̇ as independent dummies, then see if t still appears
    Q, V = sp.symbols("Q V")
    if t in L.subs(qd, V).subs(q(t), Q).free_symbols:
        return KV.decline("energy_conservation: L depends EXPLICITLY on t ⇒ energy not conserved ⇒ DECLINE", "lagrangian")
    H = qd * sp.diff(L, qd) - L
    # EL solved for q̈
    from sympy.calculus.euler import euler_equations
    el = euler_equations(L, q(t), t)[0]
    sol = sp.solve(el, qdd)
    if not sol:
        return KV.decline("energy_conservation: could not solve EL for q̈ ⇒ DECLINE", "lagrangian")
    dHdt = sp.simplify(sp.diff(H, t).subs(qdd, sol[0]))
    if dHdt != 0:
        return KV.decline(f"energy_conservation: dH/dt = {dHdt} ≠ 0 on-shell ⇒ DECLINE", "lagrangian")
    cert = KV.Cert(KV.EXACT, "noether_energy", passed=True, check_cost="dH/dt ≡ 0 mod EL",
                   detail=f"H = q̇·∂L/∂q̇ − L conserved (dH/dt ≡ 0 after substituting q̈={sp.sstr(sol[0])})")
    return KV.exact(sp.simplify(H), "lagrangian.energy_conservation", "EXACT (Noether: energy)", cert)


def poisson_bracket(f: sp.Expr, g: sp.Expr, q: sp.Symbol, p: sp.Symbol) -> sp.Expr:
    return sp.simplify(sp.diff(f, q) * sp.diff(g, p) - sp.diff(f, p) * sp.diff(g, q))


def canonical_poisson() -> KV.Verdict:
    """{q,p}=1, {q,q}=0, {p,p}=0 — the canonical structure, exact."""
    q, p = sp.symbols("q p")
    if poisson_bracket(q, p, q, p) != 1 or poisson_bracket(q, q, q, p) != 0 or poisson_bracket(p, p, q, p) != 0:
        return KV.decline("canonical_poisson: bracket structure wrong ⇒ DECLINE", "lagrangian")
    cert = KV.Cert(KV.EXACT, "canonical_poisson", passed=True, check_cost="∂_q f ∂_p g − ∂_p f ∂_q g",
                   detail="{q,p}=1, {q,q}=0, {p,p}=0 (canonical symplectic structure)")
    return KV.exact("{q,p}=1", "lagrangian.canonical_poisson", "EXACT (Poisson structure)", cert)


def lie_point_symmetry(f: sp.Expr, xi: sp.Expr, eta: sp.Expr, x: sp.Symbol, y: sp.Symbol) -> KV.Verdict:
    """DECIDE whether X = ξ∂_x + η∂_y is a Lie point symmetry of the first-order ODE y′ = f(x,y), via the
    first-prolongation invariance residual η_x + (η_y−ξ_x)f − ξ_y f² − ξ f_x − η f_y. EXACT (symmetry or not)."""
    f, xi, eta = sp.sympify(f), sp.sympify(xi), sp.sympify(eta)
    residual = sp.simplify(
        sp.diff(eta, x) + (sp.diff(eta, y) - sp.diff(xi, x)) * f - sp.diff(xi, y) * f ** 2
        - xi * sp.diff(f, x) - eta * sp.diff(f, y))
    is_sym = residual == 0
    cert = KV.Cert(KV.EXACT, "lie_prolongation", passed=True, check_cost="1st-prolongation residual",
                   detail=f"X=({sp.sstr(xi)})∂_x+({sp.sstr(eta)})∂_y on y′={sp.sstr(f)}: residual={sp.sstr(residual)} "
                          f"⇒ {'SYMMETRY' if is_sym else 'NOT a symmetry'}")
    return KV.exact(is_sym, "lagrangian.lie_point_symmetry", "DECISION (Lie point symmetry of a 1st-order ODE)", cert)


def solve(problem: dict) -> KV.Verdict:
    """ops: 'euler_lagrange'/'energy' (L string in q(t),q'(t)); 'poisson' (canonical); 'lie' (f,xi,eta)."""
    op = problem.get("op")
    t = sp.Symbol("t")
    q = sp.Function("q")
    if op in ("euler_lagrange", "energy"):
        L = sp.sympify(problem["L"], locals={"q": q, "t": t})
        return euler_lagrange(L, q, t) if op == "euler_lagrange" else energy_conservation(L, q, t)
    if op == "poisson":
        return canonical_poisson()
    if op == "lie":
        x, y = sp.Symbol("x"), sp.Symbol("y")
        return lie_point_symmetry(sp.sympify(problem["f"], locals={"x": x, "y": y}),
                                  problem["xi"], problem["eta"], x, y)
    return KV.decline(f"lagrangian: unknown op {op!r} ⇒ DECLINE", "lagrangian")


# ==============================================================================================================
# ===== FILE: mathmode/linear_algebra.py  (194 lines) =====
# ==============================================================================================================

"""
MATH-Ascent §3 (arsenal) — LINEAR ALGEBRA: exact rational solve / inverse / determinant, self-certified.
========================================================================================================
Exact arithmetic over ℚ (fractions.Fraction — never a float), so the answers are EXACT and carry a
SELF-CERTIFYING check: solving Ax=b is O(n³) but the residual  A·x − b = 0  is checkable in O(n²) and proves the
solution with no trust in the solver; the inverse is proven by  A·A⁻¹ = I  exactly. The determinant (fraction-
free Bareiss, O(n³)) is certified by a SECOND independent exact method — cofactor/Laplace expansion (our own)
for small n, sympy's exact det as the cross-check for larger n. Singular systems ⇒ honest DECLINE (no unique
solution / no inverse — never a fabricated answer). This is the §2 fold ethos: compute exactly, then prove the
result against a cheap independent check; offload the grind from the LLM (it must never invert a 6×6 by hand).
"""
from __future__ import annotations

from fractions import Fraction
from typing import List, Optional, Sequence

import kernel_verdict as KV

Mat = List[List[Fraction]]


# ── exact matrix helpers (Fraction, never float) ─────────────────────────────────────────────────────────
def _F(M: Sequence[Sequence]) -> Mat:
    return [[Fraction(x) for x in row] for row in M]


def _matmul(A: Mat, B: Mat) -> Mat:
    n, m, p = len(A), len(B), len(B[0])
    return [[sum((A[i][k] * B[k][j] for k in range(m)), Fraction(0)) for j in range(p)] for i in range(n)]


def _matvec(A: Mat, x: Sequence[Fraction]) -> List[Fraction]:
    return [sum((A[i][k] * x[k] for k in range(len(x))), Fraction(0)) for i in range(len(A))]


def _ident(n: int) -> Mat:
    return [[Fraction(1) if i == j else Fraction(0) for j in range(n)] for i in range(n)]


def _is_square(A) -> bool:
    return len(A) > 0 and all(len(r) == len(A) for r in A)


# ── exact Gaussian elimination on the augmented matrix (solve & inverse share it) ────────────────────────
def _rref_solve(A: Mat, rhs: Mat) -> Optional[Mat]:
    """Solve A·X = rhs exactly (rhs has one or more columns). Returns X, or None if A is singular."""
    n = len(A)
    aug = [A[i][:] + rhs[i][:] for i in range(n)]
    w = len(rhs[0])
    for col in range(n):
        piv = next((r for r in range(col, n) if aug[r][col] != 0), None)
        if piv is None:
            return None                                   # singular — no unique solution
        aug[col], aug[piv] = aug[piv], aug[col]
        pv = aug[col][col]
        aug[col] = [v / pv for v in aug[col]]
        for r in range(n):
            if r != col and aug[r][col] != 0:
                f = aug[r][col]
                aug[r] = [a - f * b for a, b in zip(aug[r], aug[col])]
    return [row[n:n + w] for row in aug]


def solve_grade(A, b) -> KV.Verdict:
    """Solve A·x = b exactly. Certificate: the residual A·x − b = 0 (exact). Singular A ⇒ DECLINE."""
    if not _is_square(A) or len(b) != len(A):
        return KV.decline("solve: A must be square and match b ⇒ DECLINE", "linear_algebra.solve")
    Af = _F(A)
    X = _rref_solve(Af, [[Fraction(v)] for v in b])
    if X is None:
        return KV.decline("solve: A is singular ⇒ no unique solution ⇒ DECLINE", "linear_algebra.solve")
    x = [row[0] for row in X]
    if _matvec(Af, x) != [Fraction(v) for v in b]:        # ★ self-certifying residual ★
        return KV.decline("solve: residual A·x ≠ b ⇒ DECLINE", "linear_algebra.solve")
    cert = KV.Cert(KV.EXACT, "exact_residual", passed=True, check_cost="O(n²) residual",
                   detail="A·x = b verified exactly over ℚ (residual = 0)")
    return KV.exact(x, "linear_algebra.solve", "O(n³) exact elimination", cert)


def inverse_grade(A) -> KV.Verdict:
    """Exact inverse A⁻¹. Certificate: A·A⁻¹ = I (exact). Singular A ⇒ DECLINE."""
    if not _is_square(A):
        return KV.decline("inverse: A must be square ⇒ DECLINE", "linear_algebra.inverse")
    n = len(A)
    Af = _F(A)
    inv = _rref_solve(Af, _ident(n))
    if inv is None:
        return KV.decline("inverse: A is singular ⇒ not invertible ⇒ DECLINE", "linear_algebra.inverse")
    if _matmul(Af, inv) != _ident(n):                     # ★ self-certifying A·A⁻¹ = I ★
        return KV.decline("inverse: A·A⁻¹ ≠ I ⇒ DECLINE", "linear_algebra.inverse")
    cert = KV.Cert(KV.EXACT, "inverse_identity", passed=True, check_cost="O(n³) one product",
                   detail="A·A⁻¹ = I verified exactly over ℚ")
    return KV.exact(inv, "linear_algebra.inverse", "O(n³) exact elimination", cert)


# ── determinant: fraction-free Bareiss, certified by a second independent exact method ───────────────────
def _bareiss_det(M: Mat) -> Fraction:
    """Fraction-free Bareiss determinant (exact). O(n³), no growing denominators on integer input."""
    n = len(M)
    A = [row[:] for row in M]
    sign = 1
    prev = Fraction(1)
    for k in range(n - 1):
        if A[k][k] == 0:
            sw = next((r for r in range(k + 1, n) if A[r][k] != 0), None)
            if sw is None:
                return Fraction(0)
            A[k], A[sw] = A[sw], A[k]
            sign = -sign
        for i in range(k + 1, n):
            for j in range(k + 1, n):
                A[i][j] = (A[i][j] * A[k][k] - A[i][k] * A[k][j]) / prev
        prev = A[k][k]
    return sign * A[n - 1][n - 1]


def _cofactor_det(M: Mat) -> Fraction:
    """Independent Laplace/cofactor expansion (exact) — the cross-check for small n."""
    n = len(M)
    if n == 1:
        return M[0][0]
    if n == 2:
        return M[0][0] * M[1][1] - M[0][1] * M[1][0]
    total = Fraction(0)
    for j in range(n):
        if M[0][j] == 0:
            continue
        minor = [[M[i][c] for c in range(n) if c != j] for i in range(1, n)]
        total += ((-1) ** j) * M[0][j] * _cofactor_det(minor)
    return total


def det_grade(A) -> KV.Verdict:
    """Exact determinant via Bareiss, certified by an independent exact method (cofactor for small n, sympy
    exact det otherwise). The two exact computations must agree."""
    if not _is_square(A):
        return KV.decline("det: A must be square ⇒ DECLINE", "linear_algebra.det")
    Af = _F(A)
    d = _bareiss_det(Af)
    n = len(Af)
    if n <= 7:
        d2 = _cofactor_det(Af)
        method = "cofactor expansion (our own)"
    else:
        import sympy as sp
        d2 = Fraction(sp.Matrix(A).det())
        method = "sympy exact det"
    if d != d2:                                            # two independent EXACT methods must agree
        return KV.decline(f"det: Bareiss {d} ≠ {method} {d2} ⇒ DECLINE", "linear_algebra.det")
    cert = KV.Cert(KV.EXACT, "det_cross_method", passed=True, check_cost=f"second exact method ({method})",
                   detail=f"det = {d}; fraction-free Bareiss ≡ {method} (exact agreement)")
    return KV.exact(d, "linear_algebra.det", "O(n³) fraction-free", cert)


# ── exact eigenpairs, self-certified by A·v = λ·v ───────────────────────────────────────────────────────
def eigen_grade(A) -> KV.Verdict:
    """Exact eigenvalues/eigenvectors. Certificate: A·v − λ·v = 0 for every returned pair (verified symbolically).
    Eigenvalues with no closed form (an unsolvable characteristic polynomial, degree ≥ 5) ⇒ honest DECLINE."""
    import sympy as sp
    if not _is_square(A):
        return KV.decline("eigen: A must be square ⇒ DECLINE", "linear_algebra.eigen")
    M = sp.Matrix([[sp.nsimplify(x) for x in row] for row in A])
    try:
        eigs = M.eigenvects()
    except Exception as e:                                    # noqa: BLE001
        return KV.decline(f"eigen: eigen-decomposition failed ({type(e).__name__}) ⇒ DECLINE", "linear_algebra.eigen")
    pairs = []
    for val, mult, vecs in eigs:
        if val.has(sp.CRootOf) or val.has(sp.RootOf):        # no explicit closed form ⇒ honest DECLINE
            return KV.decline("eigen: eigenvalues only as implicit RootOf (degree ≥5) ⇒ DECLINE",
                              "linear_algebra.eigen")
        for v in vecs:
            if sp.simplify(M * v - val * v) != sp.zeros(M.rows, 1):   # ★ A·v = λ·v, exact ★
                return KV.decline(f"eigen: A·v ≠ λ·v for λ={sp.sstr(val)} ⇒ DECLINE", "linear_algebra.eigen")
            pairs.append((val, list(v)))
    cert = KV.Cert(KV.EXACT, "eigenpair_verified", passed=True, check_cost=f"{len(pairs)} exact A·v−λ·v checks",
                   detail=f"{len(pairs)} eigenpair(s); each satisfies A·v = λ·v exactly (eigenvalues: "
                          f"{', '.join(sp.sstr(val) for val, _ in pairs)})")
    return KV.exact(pairs, "linear_algebra.eigen", "exact eigenpairs (sympy + verified)", cert)


def solve(problem: dict) -> KV.Verdict:
    """problem = {"op": "solve"|"inverse"|"det"|"eigen", ...}. Unknown op ⇒ honest DECLINE."""
    op = problem.get("op")
    if op == "solve":
        return solve_grade(problem["A"], problem["b"])
    if op == "inverse":
        return inverse_grade(problem["A"])
    if op == "det":
        return det_grade(problem["A"])
    if op == "eigen":
        return eigen_grade(problem["A"])
    return KV.decline(f"linear_algebra: unknown op {op!r} ⇒ DECLINE", "linear_algebra")


# ==============================================================================================================
# ===== FILE: mathmode/logic.py  (146 lines) =====
# ==============================================================================================================

"""
MATH-Ascent §B4 (arsenal) — LOGIC / VERIFICATION: propositional tautology / SAT / equivalence, decided by Z3.
=============================================================================================================
Boolean reasoning with machine-checked certificates (Z3 is the sanctioned prover):
  • TAUTOLOGY φ — valid iff ¬φ is UNSAT (a Z3 proof). If ¬φ is SAT, that satisfying assignment is a concrete
    COUNTEREXAMPLE (EXACT "not a tautology", witness exhibited). For a small variable count we ALSO cross-check
    exhaustively over the truth table (an independent, bounded-domain proof).
  • SATISFIABILITY φ — SAT ⇒ a model, which we VERIFY independently by substituting it back into the formula
    (it must evaluate to True); UNSAT ⇒ a Z3 proof of unsatisfiability.
  • EQUIVALENCE f ≡ g — the tautology of (f ↔ g); a difference is shown by a witness assignment.
The grade is EXACT either way (the decision is exact); we never report "valid" without the UNSAT proof, nor
"satisfiable" without a verified model. sympy parses the formula (&, |, ~, >>, Eq via Implies/Equivalent); the
decision + the certificate are Z3's (and, for small n, an exhaustive truth-table cross-check).
"""
from __future__ import annotations

import itertools

import sympy as sp
from sympy.logic.boolalg import BooleanFunction, BooleanTrue, BooleanFalse

import kernel_verdict as KV

_EXHAUSTIVE_BOUND = 18           # ≤ 2^18 truth-table rows for the independent cross-check


def _parse(formula):
    return sp.sympify(formula) if isinstance(formula, str) else formula


def _to_z3(expr, env, z3):
    if expr is sp.true or isinstance(expr, BooleanTrue):
        return z3.BoolVal(True)
    if expr is sp.false or isinstance(expr, BooleanFalse):
        return z3.BoolVal(False)
    if expr.is_Symbol:
        return env.setdefault(expr.name, z3.Bool(expr.name))
    if isinstance(expr, sp.Not):
        return z3.Not(_to_z3(expr.args[0], env, z3))
    if isinstance(expr, sp.And):
        return z3.And(*[_to_z3(a, env, z3) for a in expr.args])
    if isinstance(expr, sp.Or):
        return z3.Or(*[_to_z3(a, env, z3) for a in expr.args])
    if isinstance(expr, sp.Implies):
        return z3.Implies(_to_z3(expr.args[0], env, z3), _to_z3(expr.args[1], env, z3))
    if isinstance(expr, sp.Equivalent):
        a = [_to_z3(x, env, z3) for x in expr.args]
        return z3.And(*[a[0] == ai for ai in a[1:]]) if len(a) > 1 else z3.BoolVal(True)
    raise ValueError(f"unsupported boolean node: {sp.srepr(expr)}")


def _exhaustive_taut(expr) -> bool:
    """Independent bounded-domain check: φ is True on EVERY assignment (only for small variable counts)."""
    syms = sorted(expr.free_symbols, key=str)
    if len(syms) > _EXHAUSTIVE_BOUND:
        return True                                          # skip (Z3 already decided); bound honestly stated
    for bits in itertools.product([False, True], repeat=len(syms)):
        if expr.subs(dict(zip(syms, bits))) != sp.true:
            return False
    return True


def tautology_grade(formula) -> KV.Verdict:
    """φ valid? EXACT: ¬φ UNSAT ⇒ tautology (Z3 proof + small-n exhaustive cross-check); else a witness."""
    import z3
    expr = _parse(formula)
    env = {}
    try:
        z3f = _to_z3(expr, env, z3)
    except Exception as e:                                   # noqa: BLE001
        return KV.decline(f"tautology: cannot translate ({e}) ⇒ DECLINE", "logic.tautology")
    s = z3.Solver()
    s.add(z3.Not(z3f))
    r = s.check()
    if r == z3.unsat:
        if not _exhaustive_taut(expr):
            return KV.decline("tautology: Z3 UNSAT but exhaustive cross-check disagrees ⇒ DECLINE (sound)",
                              "logic.tautology")
        cert = KV.Cert(KV.EXACT, "z3_unsat_negation", passed=True, check_cost="Z3 UNSAT(¬φ) + small-n truth table",
                       detail=f"¬φ is UNSAT ⇒ φ is a TAUTOLOGY (valid); {len(expr.free_symbols)} vars")
        return KV.exact(True, "logic.tautology", "exact (Z3)", cert)
    if r == z3.sat:
        m = s.model()
        witness = {str(d): bool(m[d]) for d in m.decls()}
        cert = KV.Cert(KV.EXACT, "z3_counterexample", passed=True, check_cost="one satisfying assignment of ¬φ",
                       detail=f"φ is NOT a tautology — counterexample {witness} falsifies it")
        return KV.exact({"tautology": False, "counterexample": witness}, "logic.tautology", "exact (Z3)", cert)
    return KV.decline("tautology: Z3 returned unknown ⇒ DECLINE", "logic.tautology")


def satisfiable_grade(formula) -> KV.Verdict:
    """φ SAT? EXACT: a model (VERIFIED by substitution) or a Z3 UNSAT proof."""
    import z3
    expr = _parse(formula)
    env = {}
    try:
        z3f = _to_z3(expr, env, z3)
    except Exception as e:                                   # noqa: BLE001
        return KV.decline(f"satisfiable: cannot translate ({e}) ⇒ DECLINE", "logic.sat")
    s = z3.Solver()
    s.add(z3f)
    r = s.check()
    if r == z3.sat:
        m = s.model()
        model = {d.name(): bool(m[d]) for d in m.decls()}
        syms = {sym.name: sym for sym in expr.free_symbols}
        assign = {syms[k]: sp.true if v else sp.false for k, v in model.items() if k in syms}
        for sym in expr.free_symbols:                        # unconstrained vars: default False
            assign.setdefault(sym, sp.false)
        if expr.subs(assign) != sp.true:                     # ★ verify the model independently ★
            return KV.decline("satisfiable: Z3 model failed independent substitution ⇒ DECLINE (sound)", "logic.sat")
        cert = KV.Cert(KV.EXACT, "verified_model", passed=True, check_cost="substitute the model into φ",
                       detail=f"SATISFIABLE — model {model} makes φ True (verified)")
        return KV.exact({"satisfiable": True, "model": model}, "logic.sat", "exact (Z3 + verified model)", cert)
    if r == z3.unsat:
        cert = KV.Cert(KV.EXACT, "z3_unsat", passed=True, check_cost="Z3 UNSAT",
                       detail="UNSATISFIABLE — no assignment satisfies φ (Z3 proof)")
        return KV.exact({"satisfiable": False}, "logic.sat", "exact (Z3)", cert)
    return KV.decline("satisfiable: Z3 returned unknown ⇒ DECLINE", "logic.sat")


def equivalent_grade(f, g) -> KV.Verdict:
    """f ≡ g? The tautology of (f ↔ g); a difference is shown by a witness assignment."""
    expr = sp.Equivalent(_parse(f), _parse(g))
    v = tautology_grade(expr)
    if v.status == KV.EXACT and v.result is True:
        cert = KV.Cert(KV.EXACT, "equivalence_tautology", passed=True, check_cost="Z3 UNSAT(¬(f↔g))",
                       detail="f ↔ g is a tautology ⇒ f and g are logically EQUIVALENT")
        return KV.exact({"equivalent": True}, "logic.equiv", "exact (Z3)", cert)
    if v.status == KV.EXACT:                                 # not a tautology ⇒ has a distinguishing witness
        return KV.exact({"equivalent": False, "counterexample": v.result["counterexample"]}, "logic.equiv",
                        "exact (Z3)", KV.Cert(KV.EXACT, "z3_counterexample", True, "distinguishing assignment",
                                              detail=f"f and g DIFFER at {v.result['counterexample']}"))
    return v


def solve(problem: dict) -> KV.Verdict:
    op = problem.get("op")
    if op == "tautology":
        return tautology_grade(problem["formula"])
    if op == "satisfiable":
        return satisfiable_grade(problem["formula"])
    if op == "equivalent":
        return equivalent_grade(problem["f"], problem["g"])
    return KV.decline(f"logic: unknown op {op!r} ⇒ DECLINE", "logic")


