# ===== FILE: mathmode/ore.py  (323 lines) =====
# ==============================================================================================================

"""
UNIFIED ARSENAL §1 · G1 — Ore-algebra / skew-polynomial core  (the non-commutative keystone).
==============================================================================================
The single substrate under differential operators, recurrence (shift) operators, and q-shift operators. An Ore
operator is Σ_i c_i(x) ∂^i over a base field 𝔽 = ℚ(x), with the ONE commutation rule

        ∂ · c  =  σ(c) · ∂  +  δ(c)            (σ an automorphism of 𝔽, δ a σ-derivation)

specialising to:
  • differential  D :  σ = id,            δ = d/dx           D(f) = f′
  • shift         S :  σ(c)=c(x+1),        δ = 0             S(a)(n) = a(n+1)
  • q-shift       Q :  σ(c)=c(q·x),        δ = 0             Q(f)(x) = f(q x)

Why this is the keystone: holonomic closure (G2), creative telescoping (G3), and the QM operator identities (P5)
are ALL ideal/normal-form computations in this one algebra. Build it once, with a real certificate.

WHAT IS CERTIFIED (constitution: our own machine-check, not a library's word):
  • EQUALITY is a DECISION PROCEDURE — two operators are equal iff their canonical normal forms (coeffs cancelled
    over ℚ(x), trailing zeros stripped) are identical. `[D,x]=1`, `[S,n]=S` decided, not asserted.
  • the non-commutative PRODUCT is checked OPERATIONALLY and independently: (A·B) applied to a battery of test
    functions equals A(B(·)) — operator composition. A wrong product fails this and is rejected.
  • right DIVISION / GCRD carry a COFACTOR certificate: A = Q·B + R is re-expanded and must reduce to 0 in normal
    form; a GCRD must right-divide both inputs with remainder 0.
No Lean/Coq — sympy does base-field arithmetic; the normal form + operational replay are OUR proof.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Dict, List, Optional

import sympy as sp

import kernel_verdict as KV


# ── the algebra: a base variable x and a (σ, δ) pair ────────────────────────────────────────────────────────
class OreAlgebra:
    """ℚ(x)[∂; σ, δ] for kind ∈ {'D','S','Q'}. `var` is the base symbol (x or n); `q` only for 'Q'."""

    def __init__(self, var: sp.Symbol, kind: str = "D", q: Optional[sp.Symbol] = None):
        assert kind in ("D", "S", "Q"), f"kind must be D/S/Q, got {kind}"
        self.x = var
        self.kind = kind
        self.q = q if q is not None else sp.Symbol("q")

    def sigma(self, c: sp.Expr) -> sp.Expr:
        c = sp.sympify(c)
        if self.kind == "D":
            return c
        if self.kind == "S":
            return c.subs(self.x, self.x + 1)
        return c.subs(self.x, self.q * self.x)          # Q

    def sigma_pow(self, c: sp.Expr, k: int) -> sp.Expr:
        for _ in range(k):
            c = self.sigma(c)
        return c

    def delta(self, c: sp.Expr) -> sp.Expr:
        if self.kind == "D":
            return sp.diff(sp.sympify(c), self.x)
        return sp.Integer(0)                            # S, Q have δ = 0

    # ∂^i · c  →  dict {m: coeff}, by repeated application of the single Ore rule (works for any σ,δ)
    def _theta_pow_times_scalar(self, i: int, c: sp.Expr) -> Dict[int, sp.Expr]:
        cur: Dict[int, sp.Expr] = {0: sp.sympify(c)}
        for _ in range(i):
            nxt: Dict[int, sp.Expr] = {}
            for m, cm in cur.items():
                nxt[m + 1] = nxt.get(m + 1, sp.Integer(0)) + self.sigma(cm)
                d = self.delta(cm)
                if d != 0:
                    nxt[m] = nxt.get(m, sp.Integer(0)) + d
            cur = nxt
        return cur

    # constructors
    def _S(self, e) -> sp.Expr:
        """sympify binding the base-variable NAME to THIS algebra's symbol (so 'n' maps to the integer symbol,
        not a fresh look-alike — a silent symbol mismatch would make σ's subs a no-op)."""
        if isinstance(e, str):
            return sp.sympify(e, locals={str(self.x): self.x})
        return sp.sympify(e)

    def op(self, coeffs) -> "OrePoly":
        """coeffs: dict {i: expr} or list [c0, c1, …] (c_i is the coeff of ∂^i)."""
        if isinstance(coeffs, dict):
            d = {int(i): self._S(c) for i, c in coeffs.items()}
        else:
            d = {i: self._S(c) for i, c in enumerate(coeffs)}
        return OrePoly(self, d)

    def one(self) -> "OrePoly":
        return self.op({0: 1})

    def theta(self) -> "OrePoly":
        return self.op({1: 1})


@dataclass
class OrePoly:
    alg: OreAlgebra
    coeffs: Dict[int, sp.Expr] = field(default_factory=dict)

    def __post_init__(self):
        self._normalize()

    def _normalize(self):
        out: Dict[int, sp.Expr] = {}
        for i, c in self.coeffs.items():
            cc = sp.cancel(sp.together(sp.sympify(c)))
            if cc != 0:
                out[int(i)] = cc
        self.coeffs = out

    # degree in ∂ (the order of the operator); -1 (or -∞) for the zero operator
    def degree(self) -> int:
        return max(self.coeffs) if self.coeffs else -1

    def lead(self) -> sp.Expr:
        d = self.degree()
        return self.coeffs[d] if d >= 0 else sp.Integer(0)

    def is_zero(self) -> bool:
        return not self.coeffs

    # ── ring ops ──
    def add(self, other: "OrePoly") -> "OrePoly":
        out = dict(self.coeffs)
        for i, c in other.coeffs.items():
            out[i] = out.get(i, sp.Integer(0)) + c
        return OrePoly(self.alg, out)

    def sub(self, other: "OrePoly") -> "OrePoly":
        out = dict(self.coeffs)
        for i, c in other.coeffs.items():
            out[i] = out.get(i, sp.Integer(0)) - c
        return OrePoly(self.alg, out)

    def mul(self, other: "OrePoly") -> "OrePoly":
        """non-commutative product (A·B) via the Ore rule: A·B = Σ_{i,j} a_i (∂^i·b_j) ∂^j."""
        res: Dict[int, sp.Expr] = {}
        for i, ai in self.coeffs.items():
            for j, bj in other.coeffs.items():
                for m, cm in self.alg._theta_pow_times_scalar(i, bj).items():
                    res[m + j] = res.get(m + j, sp.Integer(0)) + ai * cm
        return OrePoly(self.alg, res)

    def scale(self, c: sp.Expr) -> "OrePoly":          # left scalar multiply (c·A)
        c = sp.sympify(c)
        return OrePoly(self.alg, {i: c * ai for i, ai in self.coeffs.items()})

    def monic(self) -> "OrePoly":
        """divide through by the leading coefficient (leading ∂-power coeff → 1) over ℚ(x)."""
        d = self.degree()
        if d < 0:
            return self
        lead = self.coeffs[d]
        return OrePoly(self.alg, {i: sp.cancel(c / lead) for i, c in self.coeffs.items()})

    def reduction_vector(self) -> List[sp.Expr]:
        """for a MONIC order-r operator θ^r + Σ_{i<r} a_i θ^i, return (−a_0,…,−a_{r-1}): θ^r ≡ Σ(−a_i)θ^i."""
        m = self.monic()
        r = m.degree()
        return [-m.coeffs.get(i, sp.Integer(0)) for i in range(r)]

    # ── DECISION: equality via canonical normal form ──
    def equals(self, other: "OrePoly") -> bool:
        diff = self.sub(other)
        return diff.is_zero()

    # ── apply the operator to a concrete function/sequence (the operational certificate) ──
    def apply(self, f: sp.Expr) -> sp.Expr:
        x = self.alg.x
        acc = sp.Integer(0)
        if self.alg.kind == "D":
            for i, ai in self.coeffs.items():
                acc += ai * sp.diff(f, x, i)
        elif self.alg.kind == "S":
            for i, ai in self.coeffs.items():
                acc += ai * f.subs(x, x + i)
        else:  # Q
            for i, ai in self.coeffs.items():
                acc += ai * f.subs(x, self.alg.q ** i * x)
        return sp.expand(acc)

    def __str__(self) -> str:
        if self.is_zero():
            return "0"
        d = "D" if self.alg.kind == "D" else ("S" if self.alg.kind == "S" else "Q")
        return " + ".join(f"({sp.sstr(self.coeffs[i])})·{d}^{i}" for i in sorted(self.coeffs))


# ── right division / GCRD over ℚ(x) (field coeffs ⇒ leading coeff invertible) ───────────────────────────────
def right_divmod(A: OrePoly, B: OrePoly):
    """A = Q·B + R with deg_∂ R < deg_∂ B. Field coefficients. Returns (Q, R)."""
    alg = A.alg
    assert not B.is_zero(), "right_divmod by zero operator"
    R = dict(A.coeffs)
    Q: Dict[int, sp.Expr] = {}
    db, lb = B.degree(), B.lead()
    while R and max(R) >= db:
        dr = max(R)
        shift = dr - db
        c = sp.cancel(R[dr] / alg.sigma_pow(lb, shift))   # kill the leading ∂^dr term
        T = OrePoly(alg, {shift: c}).mul(B)
        for m, cm in T.coeffs.items():
            R[m] = sp.cancel(sp.together(R.get(m, sp.Integer(0)) - cm))
            if R[m] == 0:
                del R[m]
        Q[shift] = Q.get(shift, sp.Integer(0)) + c
    return OrePoly(alg, Q), OrePoly(alg, R)


def gcrd(A: OrePoly, B: OrePoly) -> OrePoly:
    """Greatest Common Right Divisor via the right-Euclidean remainder sequence (monic-normalised)."""
    A, B = (A, B) if A.degree() >= B.degree() else (B, A)
    while not B.is_zero():
        _, R = right_divmod(A, B)
        A, B = B, R
    if not A.is_zero():                                   # make monic in ∂ (divide by leading coeff)
        A = A.scale(sp.cancel(1 / A.lead()))
    return A


# ── battery of test functions for the operational certificate (per kind) ───────────────────────────────────
def _test_functions(alg: OreAlgebra) -> List[sp.Expr]:
    x = alg.x
    if alg.kind == "D":
        return [x ** 3 - 2 * x, sp.exp(x), sp.sin(x), x * sp.exp(x), 1 / (x + 3)]
    if alg.kind == "S":
        return [x ** 2 + 1, sp.Integer(2) ** x, sp.factorial(x), x * sp.Integer(3) ** x]
    return [x ** 2 + 1, x ** 3, sp.Rational(1, 1) * x]    # Q


def product_equals_composition(A: OrePoly, B: OrePoly) -> bool:
    """OPERATIONAL certificate: (A·B)(f) ≡ A(B(f)) on every test function (operator composition).
    Independent of how `mul` is implemented — a wrong product is caught here."""
    alg = A.alg
    AB = A.mul(B)
    for f in _test_functions(alg):
        try:
            lhs = AB.apply(f)
            rhs = A.apply(B.apply(f))
            if sp.simplify(lhs - rhs) != 0:
                return False
        except Exception:  # noqa: BLE001 — a transcendental that won't simplify is skipped, not a pass
            continue
    return True


# ════════════════════════════════════════════ graded public API ════════════════════════════════════════════
_KINDVAR = {"D": sp.Symbol("x"), "S": sp.Symbol("n", integer=True), "Q": sp.Symbol("x")}


def _alg(kind: str) -> OreAlgebra:
    return OreAlgebra(_KINDVAR[kind], kind)


def decide_equality(A: OrePoly, B: OrePoly, what: str = "operators") -> KV.Verdict:
    """DECISION: are two Ore operators equal? EXACT either way — normal-form canonical ⇒ equality is decidable."""
    eq = A.equals(B)
    cert = KV.Cert(KV.EXACT, "ore_normal_form", passed=True, check_cost="O(deg) coeff cancel over ℚ(x)",
                   detail=f"canonical normal forms {'match' if eq else 'differ'} ⇒ {what} {'≡' if eq else '≢'}")
    return KV.exact(eq, "ore.decide_equality", "decision procedure (canonical normal form)", cert)


def commutator(kind: str, scalar: str = None):
    """The bracket [∂, c] = ∂·c − c·∂ in the chosen algebra — the seed of the QM operator identities (P5).
    Returns (alg, OrePoly). For D: [D,x]=1; for S: [S,n]=S."""
    alg = _alg(kind)
    c = alg._S(scalar) if scalar else alg.x
    theta = alg.theta()
    cop = alg.op({0: c})
    return alg, theta.mul(cop).sub(cop.mul(theta))


def grade_product(A: OrePoly, B: OrePoly) -> KV.Verdict:
    """Compute A·B and CERTIFY it operationally ((A·B)(f) ≡ A(B(f))). EXACT with the composition certificate,
    or DECLINE if the operational replay disagrees (a wrong product is a correctness bug, never shipped)."""
    prod = A.mul(B)
    if not product_equals_composition(A, B):
        return KV.decline("ore.product: (A·B)(f) ≠ A(B(f)) on the test battery ⇒ DECLINE", "ore.product")
    cert = KV.Cert(KV.EXACT, "ore_product_composition", passed=True,
                   check_cost="apply to test-function battery",
                   detail=f"(A·B)(f) ≡ A(B(f)) verified; A·B = {prod}")
    return KV.exact(prod, "ore.product", "non-commutative product + operational proof", cert)


def grade_gcrd(A: OrePoly, B: OrePoly) -> KV.Verdict:
    """GCRD with a COFACTOR certificate: G must right-divide both A and B with remainder 0."""
    if A.is_zero() and B.is_zero():
        return KV.decline("ore.gcrd: gcrd(0,0) undefined ⇒ DECLINE", "ore.gcrd")
    G = gcrd(A, B)
    _, rA = right_divmod(A, G)
    _, rB = right_divmod(B, G)
    if not (rA.is_zero() and rB.is_zero()):
        return KV.decline("ore.gcrd: candidate does not right-divide both inputs ⇒ DECLINE", "ore.gcrd")
    cert = KV.Cert(KV.EXACT, "ore_gcrd_cofactor", passed=True, check_cost="two right-divisions, remainders=0",
                   detail=f"G right-divides A and B (both remainders 0); G = {G}")
    return KV.exact(G, "ore.gcrd", "right-Euclidean GCRD + cofactor proof", cert)


def solve(problem: dict) -> KV.Verdict:
    """problem = {"op": ...}. ops: 'equal' (A,B operators as coeff dicts + kind), 'commutator' (kind, scalar),
    'product' (kind, A, B), 'gcrd' (kind, A, B). Unknown ⇒ honest DECLINE."""
    op = problem.get("op")
    kind = problem.get("kind", "D")
    alg = _alg(kind)
    if op == "commutator":
        _, br = commutator(kind, problem.get("scalar"))
        expect = alg.op(problem["expect"]) if "expect" in problem else None
        if expect is not None:
            return decide_equality(br, expect, f"[∂,{problem.get('scalar', alg.x)}]")
        return grade_product(alg.theta(), alg.op({0: problem.get("scalar", alg.x)}))
    if op == "equal":
        return decide_equality(alg.op(problem["A"]), alg.op(problem["B"]))
    if op == "product":
        return grade_product(alg.op(problem["A"]), alg.op(problem["B"]))
    if op == "gcrd":
        return grade_gcrd(alg.op(problem["A"]), alg.op(problem["B"]))
    return KV.decline(f"ore: unknown op {op!r} ⇒ DECLINE", "ore")


# ==============================================================================================================
# ===== FILE: mathmode/parse.py  (239 lines) =====
# ==============================================================================================================

"""
PHASE 1 — robust MATH input parser: the notations people actually type → the internal problem dict.
====================================================================================================
Forgiving of `^` vs `**`, unicode math (Σ ∏ ∫ √ π ² ³ −), LaTeX (\sum_{k=1}^{N}, \frac, \cdot), whitespace, casing.
Recognizes: a^b mod m / pow(a,b,m) / towers a^(b^c) mod m; fibonacci/lucas/catalan(n) [mod m]; Lucas–Lehmer /
isprime(2^p−1); collatz(n); Σ/sum(f,k,lo,hi) (Faulhaber for k^p, else summand fold); n! / factorial; C(n,k) /
binomial; gcd/lcm/isprime/factor/eulerphi; ∫/integrate; d/dx/diff; det/eigenvalues/inverse of [[..]]; solve(...).

Returns a problem dict for the solver, or {"_parse_error": "<precise hint>"} so MATH gives a SPECIFIC
parse-failure message (not a blunt "no structure"). SYMBOLIC parsing needs NO key. NL (prose) is handled
upstream by the optional LLM pipeline (echoed, UNVERIFIED); this module is pure, deterministic, key-free.
"""
from __future__ import annotations

import json
import re
from typing import Optional

import sympy as sp

_SUPERSCRIPT = str.maketrans({"²": "**2", "³": "**3", "⁴": "**4", "⁵": "**5", "⁶": "**6", "⁰": "**0", "¹": "**1"})


def _norm(s: str) -> str:
    """Normalize unicode/LaTeX/`^` to a plain ASCII-ish math string."""
    s = s.strip()
    s = (s.replace("−", "-").replace("×", "*").replace("·", "*").replace("π", "pi")
         .replace("∞", "oo").replace("√", "sqrt"))
    s = s.translate(_SUPERSCRIPT)
    # LaTeX
    s = s.replace(r"\left", "").replace(r"\right", "").replace(r"\,", " ").replace(r"\cdot", "*").replace(r"\times", "*")
    s = re.sub(r"\\frac\s*\{([^{}]*)\}\s*\{([^{}]*)\}", r"((\1)/(\2))", s)
    s = re.sub(r"\\sqrt\s*\{([^{}]*)\}", r"sqrt(\1)", s)
    s = s.replace(r"\sum", "Σ").replace(r"\prod", "∏").replace(r"\int", "∫")
    s = s.replace("^", "**")
    return s


def _to_int(expr: str) -> Optional[int]:
    """Safely evaluate an integer arithmetic expression (digits, ** * + - ( ), e-notation like 1e9, 10**12)."""
    try:
        e = sp.sympify(expr.replace("**", "^").replace("^", "**"), rational=True)
        if e.free_symbols:
            return None
        v = sp.nsimplify(e)
        return int(v) if v == int(v) else None
    except Exception:  # noqa: BLE001
        return None


def _modulus(tail: str) -> Optional[int]:
    """Extract a modulus from a trailing 'mod m' / '% m'."""
    m = re.search(r"(?:mod|%)\s*(.+)$", tail, re.IGNORECASE)
    return _to_int(m.group(1)) if m else None


def parse(text) -> dict:
    if isinstance(text, dict):
        return text
    raw = (text or "").strip()
    if not raw:
        return {"_parse_error": "empty input"}
    if raw[0] == "{":
        try:
            return json.loads(raw)
        except Exception:  # noqa: BLE001
            return {"_parse_error": "looks like JSON but did not parse"}
    s = _norm(raw)
    low = s.lower()

    # ── pow(a,b,m) / a**b mod m / towers a**(b**c) mod m ──
    mp = re.fullmatch(r"\s*pow\s*\(\s*(-?\d+)\s*,\s*(.+?)\s*,\s*(.+?)\s*\)\s*", s, re.IGNORECASE)
    if mp:
        a, b, m = int(mp[1]), _to_int(mp[2]), _to_int(mp[3])
        if b is not None and m is not None:
            return {"kernel": "modexp", "a": a, "b": b, "m": m}
    mexp = re.fullmatch(r"\s*(-?\d+)\s*\*\*\s*\(?\s*(.+?)\s*\)?\s*(?:mod|%)\s*(.+?)\s*", s, re.IGNORECASE)
    if mexp and "**" in _norm(mexp[2]) or (mexp and _to_int(mexp[2]) is not None):
        a, b, m = int(mexp[1]), _to_int(mexp[2]), _to_int(mexp[3])
        if b is not None and m is not None:
            return {"kernel": "modexp", "a": a, "b": b, "m": m}

    # ── Lucas–Lehmer / Mersenne primality isprime(2^p−1) ──
    mll = re.fullmatch(r"\s*(?:lucas[\s_-]*lehmer|ll)\s*\(?\s*(.+?)\s*\)?\s*", low)
    if mll and _to_int(mll[1]) is not None:
        return {"kernel": "lucas_lehmer", "p": _to_int(mll[1])}
    mmers = re.fullmatch(r"\s*is_?prime\s*\(\s*2\s*\*\*\s*(.+?)\s*-\s*1\s*\)\s*", low)
    if mmers and _to_int(mmers[1]) is not None:
        return {"kernel": "lucas_lehmer", "p": _to_int(mmers[1])}

    # ── collatz ──
    mc = re.fullmatch(r"\s*collatz(?:\s+(?:steps|stopping\s*time)\s*(?:of)?)?\s*\(?\s*(\d+)\s*\)?\s*", low)
    if mc:
        return {"kernel": "collatz", "n": int(mc[1])}

    # ── fibonacci / lucas / catalan (n) [mod m] ──
    mfib = re.fullmatch(r"\s*(?:fib(?:onacci)?|f)\s*\(?\s*(.+?)\s*\)?\s*((?:mod|%)\s*.+)?\s*", s, re.IGNORECASE)
    if mfib and re.match(r"^(?:fib|fibonacci|f)\b", low):
        n = _to_int(mfib[1])
        if n is not None:
            return {"kernel": "fib", "n": n, "m": _modulus(mfib[2] or "")}
    mluc = re.fullmatch(r"\s*(?:lucas|l)\s*\(\s*(.+?)\s*\)\s*((?:mod|%)\s*.+)?\s*", s, re.IGNORECASE)
    if mluc and re.match(r"^(?:lucas|l)\s*\(", low):
        n = _to_int(mluc[1])
        if n is not None:
            return {"kernel": "lucas", "n": n, "m": _modulus(mluc[2] or "")}
    mcat = re.fullmatch(r"\s*catalan\s*\(?\s*(\d+)\s*\)?\s*((?:mod|%)\s*.+)?\s*", low)
    if mcat:
        return {"kernel": "catalan", "n": int(mcat[1]), "m": _modulus(mcat[2] or "")}

    # ── summation: sum(f,k,lo,hi) / Σ_{k=lo}^{hi} f / sum f from lo to hi ──
    summ = _parse_sum(s)
    if summ is not None:
        return summ

    # ── factorial n! ──
    mfac = re.fullmatch(r"\s*(?:factorial\s*\(\s*(\d+)\s*\)|(\d+)\s*!)\s*", low)
    if mfac:
        return {"kernel": "factorial", "n": int(mfac[1] or mfac[2])}

    # ── binomial C(n,k) / binomial(n,k) / nCk ──
    mbin = re.fullmatch(r"\s*(?:c|binomial|choose)\s*\(\s*(\d+)\s*,\s*(\d+)\s*\)\s*", low)
    if mbin:
        return {"domain": "combinatorics", "op": "binomial", "n": int(mbin[1]), "r": int(mbin[2])}

    # ── gcd / lcm ──
    mg = re.fullmatch(r"\s*(gcd|lcm)\s*\(\s*(-?\d+)\s*,\s*(-?\d+)\s*\)\s*", low)
    if mg:
        if mg[1] == "gcd":
            return {"domain": "number_theory", "op": "egcd", "a": int(mg[2]), "b": int(mg[3])}
        return {"kernel": "lcm", "a": int(mg[2]), "b": int(mg[3])}

    # ── matrices: det/eigenvalues/inverse of [[...]] ──
    mmat = re.fullmatch(r"\s*(det|determinant|eigenvalues?|eig|inverse|inv)\s*\(?\s*(\[\[.+\]\])\s*\)?\s*", s, re.IGNORECASE)
    if mmat:
        mat = _parse_matrix(mmat[2])
        if mat is not None:
            opmap = {"det": "det", "determinant": "det", "eigenvalue": "eigen", "eigenvalues": "eigen",
                     "eig": "eigen", "inverse": "inverse", "inv": "inverse"}
            return {"domain": "linear_algebra", "op": opmap[mmat[1].lower()], "A": mat}

    # ── delegate to the strict free-text router (isprime/factor/integrate/solve/nonneg/φ/ζ/Γ/…) ──
    nat = _free_text(s)
    if nat:
        return nat

    # ── bare summand mentioning k (indefinite sum) ──
    if "k" in low and re.fullmatch(r"[0-9k\s+\-*/().!]+|.*k\*\*\d+.*", s.replace("factorial", "")):
        return {"sum": s}

    return {"_parse_error": "couldn't parse — try e.g.  sum(k^2,k,1,100) · 2^50 mod 97 · fibonacci(100) mod 1e9+7 · "
                            "isprime(2^31-1) · collatz(27) · C(10,3) · det([[1,2],[3,4]]) · factor x^2-1 · integrate x^2"}


def _parse_sum(s: str) -> Optional[dict]:
    # sum(f, k, lo, hi)
    m = re.fullmatch(r"\s*(?:sum|Σ|∑)\s*\(\s*(.+?)\s*,\s*([a-zA-Z])\s*,\s*(.+?)\s*,\s*(.+?)\s*\)\s*", s, re.IGNORECASE)
    if not m:
        # Σ_{k=lo}^{hi} f   or  \sum_{k=lo}^{hi} f
        m2 = re.fullmatch(r"\s*(?:Σ|∑)\s*_\{?\s*([a-zA-Z])\s*=\s*(.+?)\s*\}?\s*\*\*\s*\{?\s*(.+?)\s*\}?\s+(.+?)\s*", s)
        if m2:
            m = type("M", (), {"__getitem__": lambda self, i: [None, m2[4], m2[1], m2[2], m2[3]][i]})()
        else:
            # sum f from lo to hi   (var defaults to k)
            m3 = re.fullmatch(r"\s*(?:sum|Σ|∑)\s+(.+?)\s+from\s+(.+?)\s+to\s+(.+?)\s*", s, re.IGNORECASE)
            if m3:
                var = "k" if "k" in m3[1] else (next((c for c in m3[1] if c.isalpha()), "k"))
                m = type("M", (), {"__getitem__": lambda self, i: [None, m3[1], var, m3[2], m3[3]][i]})()
            else:
                # bare "sum <expr>" / "Σ <expr>" (no bounds) ⇒ indefinite summand fold
                m4 = re.fullmatch(r"\s*(?:sum|Σ|∑)\s+(.+)", s, re.IGNORECASE)
                if m4 and not re.search(r"\bfrom\b", m4[1], re.IGNORECASE):
                    f = m4[1].strip()
                    var = "k" if "k" in f else next((c for c in f if c.isalpha()), "k")
                    return {"sum": f.replace(var, "k") if var != "k" else f}
                return None
    f, var, lo, hi = m[1].strip(), m[2].strip(), m[3].strip(), m[4].strip()
    lo_i, hi_i = _to_int(lo), _to_int(hi)
    # Faulhaber: summand is var^p (pure power)
    mp = re.fullmatch(rf"\s*{re.escape(var)}\s*\*\*\s*(\d+)\s*", f) or (re.fullmatch(rf"\s*{re.escape(var)}\s*", f) and None)
    if re.fullmatch(rf"\s*{re.escape(var)}\s*", f):
        p = 1
        mp = True
    elif mp:
        p = int(mp[1])
    else:
        mp = None
    if mp and lo_i is not None and hi_i is not None:
        return {"kernel": "faulhaber", "p": p, "N": hi_i, "lo": lo_i}
    # general definite/indefinite summand → fold/Gosper path (rename var to k for the engine)
    fk = f.replace(var, "k") if var != "k" else f
    return {"sum": fk, **({"_lo": lo_i, "_hi": hi_i} if (lo_i is not None and hi_i is not None) else {})}


def _parse_matrix(s: str):
    try:
        rows = json.loads(s)
        if isinstance(rows, list) and all(isinstance(r, list) for r in rows):
            return rows
    except Exception:  # noqa: BLE001
        pass
    return None


def _free_text(s: str) -> dict:
    t = s.strip().rstrip("?.").strip()
    low = t.lower()
    pats = (
        (r"(?:is\s+)?(\d+)\s+(?:a\s+)?prime", lambda m: {"domain": "number_theory", "op": "is_prime", "n": int(m[1])}),
        (r"is_?prime\s*\(?\s*(\d+)\s*\)?", lambda m: {"domain": "number_theory", "op": "is_prime", "n": int(m[1])}),
        (r"factori[sz]e?\s+(\d+)", lambda m: {"domain": "number_theory", "op": "factorize", "n": int(m[1])}),
        (r"factor\s*\(?\s*(\d+)\s*\)?", lambda m: {"domain": "number_theory", "op": "factorize", "n": int(m[1])}),
        (r"(?:euler\s*)?(?:phi|totient|φ)\s*\(?\s*(\d+)\s*\)?", lambda m: {"domain": "number_theory", "op": "euler_phi", "n": int(m[1])}),
        (r"pell\s*\(?\s*(\d+)\s*\)?", lambda m: {"domain": "number_theory", "op": "pell", "N": int(m[1])}),
        (r"(?:zeta|ζ)\s*\(?\s*(\d+)\s*\)?", lambda m: {"domain": "special_functions", "op": "zeta_even", "s": int(m[1])}),
        (r"gamma\s*\(?\s*(\d+)\s*/\s*2\s*\)?", lambda m: {"domain": "special_functions", "op": "gamma", "two_z": int(m[1])}),
        (r"gamma\s*\(?\s*(\d+)\s*\)?", lambda m: {"domain": "special_functions", "op": "gamma", "two_z": 2 * int(m[1])}),
    )
    for pat, build in pats:
        mm = re.fullmatch(pat, low)
        if mm:
            return build(mm)
    mf = re.fullmatch(r"factor\s+(.+)", t, re.IGNORECASE)
    if mf and not re.fullmatch(r"\d+", mf.group(1).strip()):
        return {"domain": "algebra", "op": "factor", "poly": mf.group(1).strip()}
    msv = re.fullmatch(r"(?:solve|roots?(?:\s+of)?)\s+(.+?)(?:\s*=\s*0)?", t, re.IGNORECASE)
    if msv and "x" in msv.group(1):
        return {"domain": "algebra", "op": "solve_poly", "poly": msv.group(1).strip()}
    mi = re.fullmatch(r"(?:integrate|∫)\s+(.+?)(?:\s*d\s*x)?", t, re.IGNORECASE)
    if mi and "x" in mi.group(1):
        return {"domain": "calculus", "op": "integrate", "f": mi.group(1).strip()}
    md = re.fullmatch(r"(?:d/dx|diff(?:erentiate)?|derivative\s+of)\s+(.+?)(?:\s*d?x?)?", t, re.IGNORECASE)
    if md and "x" in md.group(1):
        return {"domain": "calculus", "op": "differentiate", "f": md.group(1).strip()}
    mnn = re.fullmatch(r"(.+?)\s*(?:>=|≥)\s*0", t)
    if mnn and "x" in mnn.group(1):
        return {"domain": "inequalities", "op": "nonneg", "poly": mnn.group(1).strip()}
    return {}


