# ===== FILE: pillar3/bv_validate.py  (137 lines) =====
# ==============================================================================================================

"""
Pillar 3 · ROUND 3 #67 — translation validation under REAL machine semantics (bitvector / overflow-aware).
============================================================================================================
A peephole rewrite that is correct over idealized integers ℤ can be WRONG on a real machine because of
fixed-width wraparound:  (x+1) > x  is a theorem over ℤ but FALSE at INT_MAX;  (x*2)/2 == x  fails on signed
overflow. An optimizer that trusts the ℤ-identity miscompiles. This validator proves equivalence over Z3
BITVECTORS (the machine's actual two's-complement semantics), so a transform is accepted EXACT only if it is
sound under overflow — and an overflow-unsafe rewrite is REFUTED with a concrete counterexample ⇒ DECLINE
(keep the original; a wrong 'safe' is a correctness bug). This is the Clock-B VERIFICATION half (machine-
faithful refinement), not a speedup claim: EXACT here means "proven equivalent on the real machine".
"""
from __future__ import annotations

from dataclasses import dataclass
from typing import Callable, Optional, Tuple

import z3

import kernel_verdict as KV


@dataclass
class BVResult:
    verdict: KV.Verdict
    proved: bool
    counterexample: Optional[dict]


def bv_equiv(orig: Callable, opt: Callable, bits: int = 32, nvars: int = 2) -> Tuple[str, Optional[dict]]:
    """Z3 over BITVECTORS: is orig(v…) == opt(v…) for EVERY machine-integer assignment? PROVEN (unsat of ≠) /
    REFUTED (a wraparound counterexample) / UNKNOWN. orig/opt take z3 BitVec args and return a z3 BitVec expr."""
    xs = [z3.BitVec(f"v{i}", bits) for i in range(nvars)]
    s = z3.Solver()
    s.add(orig(*xs) != opt(*xs))
    r = s.check()
    if r == z3.unsat:
        return "PROVEN", None
    if r == z3.sat:
        m = s.model()
        return "REFUTED", {str(v): (m[v].as_long() if m[v] is not None else None) for v in xs}
    return "UNKNOWN", None


def bv_equiv_inhouse(build: Callable, bits: int = 8) -> Tuple[str, Optional[dict]]:
    """ZERO-DEPENDENCY counterpart of bv_equiv: decide ∀(bits-bit vars). lhs == rhs with the in-house bit-blasting
    SMT (no Z3). `build(bb)` returns (lhs_BV, rhs_BV) over a `bitblast_smt.BitBlaster`. Same contract as bv_equiv —
    PROVEN (UNSAT of ≠) / REFUTED (a checked counterexample) — but EXACT only WITHIN `bits` (the bound is stated by
    the certificate) and only for this solver's QF-BV theory. Used to discharge in-scope obligations with no
    external solver, and to cross-check Z3 where both apply. NOT Z3 parity (no arrays/reals/unbounded ints; signed
    compare, general multiply, right-shift, ite-mux, UNSIGNED+SIGNED division, AND variable-amount shift ARE in-house)."""
    import os
    import sys
    sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))  # repo root → bitblast_smt
    import bitblast_smt as BB
    r = BB.prove_bv_identity(build, bits)
    if r.status == "VALID":
        return "PROVEN", None
    if r.status == "INVALID":
        return "REFUTED", r.model
    return "UNKNOWN", None


def cross_check_inhouse_vs_z3() -> dict:
    """Demonstrate the in-house solver is a FAITHFUL zero-dependency replacement for Z3 on its decidable subset:
    prove every sound peephole BOTH ways at the SAME small width and assert agreement. The unsafe peepholes are
    NOT cross-checked here — they are UNSOUND, and the cross-check asserts PROVEN≡PROVEN so only SOUND peepholes
    participate. (The in-house solver can now DECIDE all three — the conditional ones via ite-mux, mul2_div2_id via
    sdiv — but a refutable UNSOUND peephole is still not a SOUND one, so they stay out of this agreement check.)"""
    import os
    import sys
    sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    import bitblast_smt as BB
    z3_by_name = {name: (o, p) for name, o, p in sound_peepholes()}
    rows = []
    for name, build, width in BB.inhouse_sound_peepholes():
        inhouse, _ = bv_equiv_inhouse(build, width)
        orig, opt = z3_by_name[name]
        z3v, _ = bv_equiv(orig, opt, bits=width, nvars=2)          # Z3 at the SAME width for a fair comparison
        rows.append({"name": name, "width": width, "inhouse": inhouse, "z3": z3v, "agree": inhouse == z3v == "PROVEN"})
    return {"rows": rows, "all_agree": all(r["agree"] for r in rows),
            "covered": [r["name"] for r in rows],
            "out_of_scope_for_inhouse": [n for n, *_ in unsafe_peepholes()]}  # honest: these stay on Z3


def bv_grade(name: str, orig: Callable, opt: Callable, *, bits: int = 32, nvars: int = 2) -> BVResult:
    """EXACT iff the rewrite is PROVEN equivalent under machine (bitvector) semantics; REFUTED/UNKNOWN ⇒ DECLINE
    (keep the original — never an unsound 'safe'). A Clock-B verification verdict (machine-faithful refinement)."""
    verdict, cex = bv_equiv(orig, opt, bits, nvars)
    if verdict == "PROVEN":
        cert = KV.Cert(KV.EXACT, "bitvector_refinement", passed=True, check_cost=f"Z3 ∀ bv{bits}",
                       detail=f"{name}: opt ≡ orig proven over {bits}-bit two's-complement (overflow-faithful)")
        return BVResult(KV.exact(opt, f"bv:{name}", f"Clock-B refinement (bv{bits})", cert), True, None)
    if verdict == "REFUTED":
        return BVResult(KV.decline(f"{name}: overflow-unsafe — opt ≠ orig at {cex} ⇒ DECLINE (keep original)",
                                   f"bv:{name}"), False, cex)
    return BVResult(KV.decline(f"{name}: Z3 UNKNOWN ⇒ conservatively DECLINE", f"bv:{name}"), False, None)


def _i1(b):
    return (z3.BitVecVal(1, b), z3.BitVecVal(0, b))


# ── SOUND peepholes — equivalent under machine wraparound (each EXACT) ──────────────────────────────────
def sound_peepholes(bits: int = 32):
    return [
        ("mul2_to_shl1", lambda x, y: x * 2, lambda x, y: x << 1),
        ("mul8_to_shl3", lambda x, y: x * 8, lambda x, y: x << 3),
        ("xor_via_or_minus_and", lambda x, y: (x | y) - (x & y), lambda x, y: x ^ y),
        ("add_sub_cancel", lambda x, y: (x + y) - y, lambda x, y: x),        # wraps identically ⇒ sound
        ("clear_low_bit", lambda x, y: x & (x - 1), lambda x, y: x & ~(-x & x)),
    ]


# ── UNSAFE over machine ints — true over ℤ, FALSE under overflow (each must be REFUTED ⇒ DECLINE) ───────
def unsafe_peepholes(bits: int = 32):
    one, zero = z3.BitVecVal(1, bits), z3.BitVecVal(0, bits)
    return [
        # (x+1) > x : a ℤ-theorem, false at INT_MAX (signed gt)
        ("succ_gt_self", lambda x, y: z3.If(x + 1 > x, one, zero), lambda x, y: one),
        # (x*2)/2 == x : signed, fails on overflow
        ("mul2_div2_id", lambda x, y: (x * 2) / 2, lambda x, y: x),
        # x+y >= x  (assuming y>=0 is NOT encoded) : false on overflow
        ("add_monotone", lambda x, y: z3.If(x + y >= x, one, zero), lambda x, y: one),
    ]


def idealized_vs_machine_contrast() -> dict:
    """The headline: (x+1) > x is PROVABLE over idealized ℤ but REFUTED over bitvectors. An optimizer that
    trusts the ℤ-identity miscompiles; the machine-faithful validator catches it. Returns both verdicts."""
    xi = z3.Int("x")
    si = z3.Solver()
    si.add(z3.Not(xi + 1 > xi))                              # ℤ: ∀x x+1>x ⇒ negation unsat ⇒ "provable"
    idealized = "PROVEN" if si.check() == z3.unsat else "REFUTED"
    machine, cex = bv_equiv(lambda x, y: z3.If(x + 1 > x, z3.BitVecVal(1, 32), z3.BitVecVal(0, 32)),
                            lambda x, y: z3.BitVecVal(1, 32))
    return {"claim": "(x+1) > x", "idealized_Z": idealized, "machine_bv32": machine, "machine_counterexample": cex}


# ==============================================================================================================
# ===== FILE: pillar3/canonical.py  (198 lines) =====
# ==============================================================================================================

"""
Pillar 3 · PHASE M — the canonical multi-waste program (the mode-distinctness fixture).
========================================================================================
A single program with several stacked, independent wastes, modelled as a pipeline of stages over a shared
`data` dict. Each stage has a slow and a fast implementation; a fix activates the fast one. Running the SAME
program through fast / normal / extend produces observably, measurably different behaviour — that is the proof
that the three modes are real contracts, not presets.

Stages (waste → detector → tier → max provable grade):
  • S1 list-as-set (dedup via membership-in-list)      → list_as_set          (fast)    PROBABILISTIC
  • S2 N+1 (per-item fetch with overhead)              → n_plus_1             (fast)    EXACT (by construction)
  • S3 accidental-O(n²) (list built by concatenation)  → accidental_quadratic (normal)  PROBABILISTIC
  • S4 algorithmic (naive O(n²) poly eval → Horner)    → algorithm_recognition(extend)  EXACT (Z3-proven)
  • S5 SIMD-offloadable numeric (sin·cos+√ → numpy)    → gpu_simd_offload     (extend)  PROBABILISTIC

DETERMINISTIC COST MODEL (so the spine test is robust under full-suite load): each stage's *runtime* is a
controlled busy-loop sized to an exact target fraction of the program; the fast impl shrinks that loop by
`_STAGE_SPEEDUP` (the modelled fix). The stage ALSO performs its real characteristic operation on a small
input and writes the real output, so differential testing is meaningful (a wrong fix is caught) and the S4
Z3 proof is a real equivalence proof. Fractions, marginals and cross-mode monotonicity are therefore
deterministic — they do not depend on incidental timing — while ratio ≤ ceiling still holds by construction
(the engine's floor pipeline passes active stages through, charging them nothing).
"""
from __future__ import annotations

import math
from typing import Dict, List

import numpy as np

from pillar3 import equiv as EQ
from pillar3.engine import Candidate


# ── bare functions for the Z3 proof (S4) — run on symbolic inputs, independent of the pipeline wrappers ──
def naive_poly(coeffs, x):                       # O(n²): recompute xⁱ by repeated multiply
    s = 0
    for i in range(len(coeffs)):
        term = coeffs[i]
        for _ in range(i):
            term = term * x
        s = s + term
    return s


def horner(coeffs, x):                           # O(n)
    r = 0
    for c in reversed(coeffs):
        r = r * x + c
    return r


def prove_poly_equiv():
    return EQ.prove_equiv(naive_poly, horner, EQ.sym_poly_inputs, (3, 5))


# ── the deterministic cost model ───────────────────────────────────────────────────────────────────────
_BASE = 600_000                                  # total busy-loop iterations across the program (tunes wall time)
_STAGE_SPEEDUP = 20                              # each fast stage shrinks its busy-loop ~20× (ratios near ceiling
                                                 # ⇒ large, noise-proof diminishing-returns marginals)
_FRAC = {"S1": 0.22, "S2": 0.14, "S3": 0.13, "S4": 0.45, "S5": 0.02}   # exact target fractions
_RESIDUAL_FRAC = 0.04                            # the un-optimisable remainder ⇒ finite Amdahl ceiling


def _busy(work: float) -> int:
    s = 0
    for _ in range(int(work)):
        s += 1
    return s


# small real-op inputs (kept tiny so the busy-loop dominates timing; the real op is for differential/Z3 only)
_DEG, _NPTS, _NDUP, _NID, _NPARTS, _NARR = 14, 16, 60, 120, 80, 200
_DB = {i: i * i for i in range(_NID + 16)}
_FETCH_OVERHEAD = 8


def make_input() -> Dict:
    return {
        "dups": list(range(_NDUP)) * 2,
        "ids": list(range(_NID)),
        "parts": list(range(_NPARTS)),
        "coeffs": [((i * 7) % 11) - 5 for i in range(_DEG)],
        "xs": [((i * 3) % 7) - 3 for i in range(_NPTS)],
        "arr": [float(i % 100) - 50.0 for i in range(_NARR)],
    }


def residual(data: Dict) -> Dict:
    out = dict(data); out["_r"] = _busy(_RESIDUAL_FRAC * _BASE); return out


# ── S1 list-as-set (real dedup + modelled cost) ───────────────────────────────────────────────────────
def s1_slow(data: Dict) -> Dict:
    _busy(_FRAC["S1"] * _BASE)
    out_list: List = []
    for x in data["dups"]:
        if x not in out_list:                    # real O(n²) membership-in-list (small input, for differential)
            out_list.append(x)
    out = dict(data); out["dedup"] = out_list; return out


def s1_fast(data: Dict) -> Dict:
    _busy(_FRAC["S1"] * _BASE / _STAGE_SPEEDUP)
    out = dict(data); out["dedup"] = list(dict.fromkeys(data["dups"])); return out


# ── S2 N+1 ──────────────────────────────────────────────────────────────────────────────────────────
def _get_one(i: int) -> int:
    s = 0
    for _ in range(_FETCH_OVERHEAD):
        s += _DB[i]
    return _DB[i]


def s2_slow(data: Dict) -> Dict:
    _busy(_FRAC["S2"] * _BASE)
    out = dict(data); out["mapped"] = [_get_one(i) for i in data["ids"]]; return out


def s2_fast(data: Dict) -> Dict:
    _busy(_FRAC["S2"] * _BASE / _STAGE_SPEEDUP)
    out = dict(data); out["mapped"] = [_DB[i] for i in data["ids"]]; return out


# ── S3 accidental quadratic ───────────────────────────────────────────────────────────────────────────
def s3_slow(data: Dict) -> Dict:
    _busy(_FRAC["S3"] * _BASE)
    acc: List = []
    for p in data["parts"]:
        acc = acc + [p]                          # real O(n²) self-concat (small input)
    out = dict(data); out["built"] = acc; return out


def s3_fast(data: Dict) -> Dict:
    _busy(_FRAC["S3"] * _BASE / _STAGE_SPEEDUP)
    out = dict(data); out["built"] = list(data["parts"]); return out


# ── S4 algorithm recognition (poly eval → Horner; real, Z3-provable) ──────────────────────────────────
def s4_slow(data: Dict) -> Dict:
    _busy(_FRAC["S4"] * _BASE)
    co = data["coeffs"]; out = dict(data); out["poly"] = [naive_poly(co, x) for x in data["xs"]]; return out


def s4_fast(data: Dict) -> Dict:
    _busy(_FRAC["S4"] * _BASE / _STAGE_SPEEDUP)
    co = data["coeffs"]; out = dict(data); out["poly"] = [horner(co, x) for x in data["xs"]]; return out


# ── S5 SIMD-offloadable numeric kernel ────────────────────────────────────────────────────────────────
def s5_slow(data: Dict) -> Dict:
    _busy(_FRAC["S5"] * _BASE)
    out = dict(data); out["trig"] = [math.sin(x) * math.cos(x) + math.sqrt(abs(x)) for x in data["arr"]]; return out


def s5_fast(data: Dict) -> Dict:
    _busy(_FRAC["S5"] * _BASE / _STAGE_SPEEDUP)
    a = np.asarray(data["arr"], dtype=float)
    out = dict(data); out["trig"] = (np.sin(a) * np.cos(a) + np.sqrt(np.abs(a))).tolist(); return out


def data_eq(a, b) -> bool:
    """Float-tolerant dict equality (the SIMD stage reorders FP); int/list compared elementwise, floats ±1e-9."""
    if isinstance(a, dict) and isinstance(b, dict):
        return a.keys() == b.keys() and all(data_eq(a[k], b[k]) for k in a)
    if isinstance(a, list) and isinstance(b, list):
        return len(a) == len(b) and all(data_eq(x, y) for x, y in zip(a, b))
    if isinstance(a, float) or isinstance(b, float):
        return abs(a - b) < 1e-9
    return a == b


def build_candidates() -> List[Candidate]:
    """The five stacked wastes as Candidates. Fractions are the DETERMINISTIC target fractions (the busy-loop
    cost model realises them), so the mode-distinctness behaviour is stable under load. Grades: S1/S3/S5 →
    PROBABILISTIC, S2 → EXACT (by construction), S4 → EXACT (Z3)."""
    return [
        Candidate("S1_list_as_set", "list_as_set", "list_as_set", s1_slow, s1_fast,
                  _FRAC["S1"], eq=data_eq),
        Candidate("S2_n_plus_1", "n_plus_1", "n_plus_1", s2_slow, s2_fast,
                  _FRAC["S2"], exact_justification="coalesced_identical_lookups", eq=data_eq),
        Candidate("S3_accidental_quadratic", "accidental_quadratic", "accidental_quadratic", s3_slow, s3_fast,
                  _FRAC["S3"], eq=data_eq),
        Candidate("S4_algorithm_recognition", "algo_replace", "algorithm_recognition", s4_slow, s4_fast,
                  _FRAC["S4"], prove_fn=prove_poly_equiv, region_size=5, eq=data_eq),
        Candidate("S5_simd_offload", "simd_offload", "gpu_simd_offload", s5_slow, s5_fast,
                  _FRAC["S5"], eq=data_eq),
    ]


def sweep_fn(size: int) -> None:
    """A super-linear workload for the extend complexity sweep (the dedup hotspot at varying n)."""
    out: List = []
    for x in list(range(size)):
        if x not in out:
            out.append(x)


