# ===== FILE: pillar3/complexity.py  (106 lines) =====
# ==============================================================================================================

"""
Pillar 3 · Stage 0 — empirical computational complexity fitter (the flagship detector).
========================================================================================
The Goldsmith–Aiken–Wilkerson (ESEC-FSE 2007) trend-prof method: run a target across input sizes spanning
orders of magnitude, fit time (or op-count) to a power law y = a·n^b by least squares on log-log, and report
the empirical exponent b with R². An exponent meaningfully above the expected one flags an accidental
super-linearity ("empirically O(n^1.97), R²=0.99 → likely accidentally quadratic"). Pure numpy.
"""
from __future__ import annotations

import statistics
import time
from dataclasses import dataclass
from typing import Callable, List

import numpy as np


@dataclass
class ComplexityFit:
    exponent: float             # fitted b in y = a·n^b
    coeff: float                # fitted a
    r2: float                   # goodness of fit on log-log
    sizes: List[int]
    times: List[float]
    klass: str                  # human label: "O(1)" "O(log n)" "O(n)" "O(n log n)" "O(n^b)" …
    superlinear: bool           # b meaningfully > 1 (after log-correction heuristic)

    def __str__(self):
        return (f"empirically {self.klass} (b={self.exponent:.2f}, R²={self.r2:.3f}) over "
                f"n∈[{self.sizes[0]},{self.sizes[-1]}]" + ("  ⚠ super-linear" if self.superlinear else ""))


def fit_power_law(sizes: List[int], times: List[float]) -> "tuple[float, float, float]":
    """log(t) = log(a) + b·log(n) least squares. Returns (b, a, R²)."""
    x = np.log(np.asarray(sizes, dtype=float))
    y = np.log(np.asarray(times, dtype=float))
    A = np.vstack([x, np.ones_like(x)]).T
    (b, loga), *_ = np.linalg.lstsq(A, y, rcond=None)
    yhat = A @ np.array([b, loga])
    ss_res = float(np.sum((y - yhat) ** 2))
    ss_tot = float(np.sum((y - np.mean(y)) ** 2))
    r2 = 1.0 - ss_res / ss_tot if ss_tot > 0 else 1.0
    return float(b), float(np.exp(loga)), r2


def _classify(b: float, sizes: List[int], times: List[float]) -> "tuple[str, bool]":
    """Map the exponent to a class. n·log n looks like n^~1.1 on a power-law fit, so we test an n·log n model
    too and prefer it when it fits better than a pure power law near b≈1."""
    if b < 0.3:
        return "O(1)", False
    if b < 0.85:
        # could be O(log n): fit t = a·log n
        x = np.log(np.asarray(sizes, dtype=float))
        y = np.asarray(times, dtype=float)
        if np.corrcoef(x, y)[0, 1] > 0.97:
            return "O(log n)", False
        return f"O(n^{b:.2f})", False
    if b <= 1.2:
        # distinguish O(n) from O(n log n) by which model fits the raw data better (R² of a least-squares fit)
        n = np.asarray(sizes, dtype=float)
        t = np.asarray(times, dtype=float)

        def r2_model(basis):
            A = np.vstack([basis, np.ones_like(basis)]).T
            coef, *_ = np.linalg.lstsq(A, t, rcond=None)
            yhat = A @ coef
            ss_res = float(np.sum((t - yhat) ** 2))
            ss_tot = float(np.sum((t - t.mean()) ** 2))
            return 1.0 - ss_res / ss_tot if ss_tot > 0 else 1.0
        if r2_model(n * np.log(n)) > r2_model(n) + 1e-6:
            return "O(n log n)", False
        return "O(n)", False
    if b < 1.6:
        return f"O(n^{b:.2f})", True
    if b < 2.4:
        return "O(n²)", True
    if b < 3.4:
        return "O(n³)", True
    return f"O(n^{b:.2f})", True


def measure_complexity(fn: Callable[[int], None], sizes: List[int], *, samples: int = 3, warmup: int = 1) -> ComplexityFit:
    """Time `fn(n)` at each size (median of `samples`), fit the power law, classify, flag super-linearity."""
    times = []
    for n in sizes:
        for _ in range(warmup):
            fn(n)
        rs = []
        for _ in range(samples):
            t = time.perf_counter()
            fn(n)
            rs.append(time.perf_counter() - t)
        times.append(statistics.median(rs))
    b, a, r2 = fit_power_law(sizes, times)
    klass, superlinear = _classify(b, sizes, times)
    return ComplexityFit(b, a, r2, list(sizes), times, klass, superlinear)


def fit_counts(sizes: List[int], counts: List[int]) -> ComplexityFit:
    """Same fit but on op-COUNTS (deterministic, noise-free) instead of wall-clock — preferred when a counter
    is available (trend-prof fits basic-block run counts, not time)."""
    b, a, r2 = fit_power_law(sizes, [float(c) for c in counts])
    klass, superlinear = _classify(b, sizes, [float(c) for c in counts])
    return ComplexityFit(b, a, r2, list(sizes), [float(c) for c in counts], klass, superlinear)


# ==============================================================================================================
# ===== FILE: pillar3/complexity_cert.py  (111 lines) =====
# ==============================================================================================================

"""
Pillar 3 · ROUND 3 #72 — complexity certificate (prove the asymptotic CLASS actually improved, not just speed).
================================================================================================================
A speedup on one input size can be a mere constant factor. An ASYMPTOTIC win is different: the advantage grows
with n. This certificate measures the naive and fast region at several sizes, fits the empirical growth exponent
(log-log slope of time vs n), and certifies the fast version is in a STRICTLY LOWER complexity class
(fast_exponent < naive_exponent by a margin). It is an EMPIRICAL certificate ⇒ PROBABILISTIC (measured growth,
reported with the fitted exponents and R²) — never EXACT. Honesty: a pair in the SAME class (both ~O(n)) yields
≈equal exponents ⇒ NOT an asymptotic improvement ⇒ DECLINE (we never claim an asymptotic jump that isn't there).
This is the verification behind every "O(n²)→O(n log n)" claim: the class change is MEASURED, not asserted.
"""
from __future__ import annotations

import math
import time
from dataclasses import dataclass
from typing import Callable, List, Tuple

import kernel_verdict as KV


@dataclass
class ComplexityCert:
    verdict: "KV.Verdict"
    naive_exp: float
    fast_exp: float
    naive_r2: float
    fast_r2: float
    sizes: Tuple[int, ...]


def _fit_loglog(sizes: List[int], times: List[float]) -> Tuple[float, float]:
    """Least-squares slope of log(time) vs log(n) = the empirical power-law exponent; also returns R²."""
    xs = [math.log(s) for s in sizes]
    ys = [math.log(max(t, 1e-9)) for t in times]
    n = len(xs)
    mx, my = sum(xs) / n, sum(ys) / n
    sxx = sum((x - mx) ** 2 for x in xs)
    sxy = sum((x - mx) * (y - my) for x, y in zip(xs, ys))
    slope = sxy / sxx if sxx else 0.0
    intercept = my - slope * mx
    ss_res = sum((y - (slope * x + intercept)) ** 2 for x, y in zip(xs, ys))
    ss_tot = sum((y - my) ** 2 for y in ys)
    r2 = 1.0 - ss_res / ss_tot if ss_tot else 1.0
    return slope, r2


def _time_at(fn: Callable, make_input_n: Callable[[int], tuple], n: int, repeats: int) -> float:
    best = math.inf
    for _ in range(repeats):
        args = make_input_n(n)
        t = time.perf_counter()
        fn(*args)
        best = min(best, time.perf_counter() - t)            # best-of-k (robust to scheduling jitter)
    return best


def certify_complexity(naive: Callable, fast: Callable, make_input_n: Callable[[int], tuple],
                       sizes: Tuple[int, ...], *, margin: float = 0.4, repeats: int = 5) -> ComplexityCert:
    """Measure naive & fast at each size, fit the growth exponents, and certify fast is a STRICTLY LOWER class
    (naive_exp − fast_exp ≥ margin) with good fits. Else DECLINE (no asymptotic improvement — only constant factor)."""
    nt = [_time_at(naive, make_input_n, s, repeats) for s in sizes]
    ft = [_time_at(fast, make_input_n, s, repeats) for s in sizes]
    ne, nr2 = _fit_loglog(list(sizes), nt)
    fe, fr2 = _fit_loglog(list(sizes), ft)
    detail = f"naive ~O(n^{ne:.2f}) (R²={nr2:.2f}) vs fast ~O(n^{fe:.2f}) (R²={fr2:.2f}) over n∈{sizes}"
    if (ne - fe) < margin or nr2 < 0.9:
        v = KV.decline(f"no asymptotic-class improvement: {detail} (Δexp {ne - fe:.2f} < {margin}) ⇒ DECLINE", "complexity")
        return ComplexityCert(v, ne, fe, nr2, fr2, sizes)
    cert = KV.Cert(KV.PROBABILISTIC, "empirical_complexity", passed=True, check_cost=f"{len(sizes)} sizes ×{repeats}",
                   delta=round(1.0 - fr2, 4) + 1e-6, detail=detail + f"; Δexp={ne - fe:.2f} ⇒ strictly lower class")
    v = KV.probabilistic(fast, "complexity", detail, cert)
    return ComplexityCert(v, ne, fe, nr2, fr2, sizes)


# ── demo regions: a genuine asymptotic jump (O(n²)→O(n)) vs a mere constant-factor pair (both O(n)) ────────
def prefix_naive(a):
    out = []
    for i in range(len(a)):
        s = 0
        for j in range(i + 1):                               # O(n²) total
            s += a[j]
        out.append(s)
    return out


def prefix_fast(a):
    out = []
    s = 0
    for x in a:                                              # O(n) single pass
        s += x
        out.append(s)
    return out


def linear_slow(a):
    s = 0
    for x in a:                                              # O(n) with a big constant (3 ops/elem)
        s += (x * 3 + 1) - 1
    return s


def linear_fast(a):
    return sum(a)                                            # O(n) with a small constant — SAME class as linear_slow


def make_list_n(n: int):
    import random as _rnd
    rng = _rnd.Random(n * 2654435761 & 0xFFFFFFFF)
    return ([rng.randrange(-100, 100) for _ in range(n)],)


