# ===== FILE: pillar3/inputgen.py  (120 lines) =====
# ==============================================================================================================

"""
Pillar 3 · PHASE I — stronger input generation (shrink δ, catch what a tiny random sample misses).
==================================================================================================
PROBABILISTIC(ε,δ) is only as trustworthy as the inputs behind it. A 3-sample random check gives δ=3/3=1.0 —
nearly meaningless. This module builds a much stronger evidence set: boundary/edge enumeration (empty, singleton,
zeros, ±extremes, duplicates, sorted/reversed), property-based random over many sizes, and Z3-guided inputs that
drive a branch predicate down BOTH paths (a concolic-lite step). δ is reported from the real sample size (rule of
three, 3/n) — it shrinks as n grows. The slow-correct original is the gold oracle; the first divergence is the
witness. This never invents a win — it only makes a wrong fix more likely to be caught (Rule 6).
"""
from __future__ import annotations

import random
from dataclasses import dataclass
from typing import Any, Callable, List, Optional, Tuple

import z3

from pillar3 import verifier as _V


# ── building blocks ─────────────────────────────────────────────────────────────────────────────────────
def boundary_ints() -> List[int]:
    return [0, 1, -1, 2, -2, 3, 255, 256, -256, 1023, 1024, 10 ** 6, -(10 ** 6)]


def edge_lists() -> List[List[int]]:
    """The shapes a random mid-size sample almost never produces but bugs love."""
    return [[], [0], [1], [-1], [0, 0], [1, 1, 1], [2, 1], [1, 2], list(range(6)), list(range(6))[::-1],
            [5] * 6, [0, 0, 1, 1, 2, 2], [-3, -3, 4, 4]]


def float_edges() -> List[float]:
    """Floating-point boundary values bugs love: zeros (incl. −0.0), tiny/huge, subnormal-ish, and the
    non-finite specials. (NaN/inf are returned so a transform that mishandles them is exercised.)"""
    return [0.0, -0.0, 1.0, -1.0, 0.5, -0.5, 1e-12, -1e-12, 1e12, -1e12,
            float("inf"), float("-inf"), float("nan")]


def random_floats(rng: random.Random, k: int = 16, scale: float = 1000.0) -> List[float]:
    return [(rng.random() - 0.5) * scale for _ in range(k)]


def float_list_evidence(rng: Optional[random.Random] = None) -> "Evidence":
    """Evidence set for float-list kernels: edge-bearing lists (incl. specials) + random over several sizes."""
    rng = rng or random.Random(0)
    fe = float_edges()
    inputs: List[Any] = [[], [0.0], [-0.0], [float("nan")], [float("inf"), 1.0], list(fe)]
    for s in (1, 2, 5, 16, 50):
        inputs.append(random_floats(rng, s))
    n = len(inputs)
    return Evidence(inputs, 3.0 / n if n else 1.0, n)


def random_lists(rng: random.Random, sizes=(0, 1, 2, 3, 8, 25, 64), lo: int = -50, hi: int = 50) -> List[List[int]]:
    out: List[List[int]] = []
    for s in sizes:
        for _ in range(3):
            out.append([rng.randrange(lo, hi) for _ in range(s)])
    return out


def z3_guided_branch(pred_builder: Callable[[Any], Any]) -> List[int]:
    """Concolic-lite: given a predicate over a symbolic int, solve for one input that SATISFIES it and one that
    NEGATES it, so both branches are covered. Returns the concrete ints Z3 found (skips a side if unsat)."""
    found: List[int] = []
    x = z3.Int("x")
    for want in (pred_builder(x), z3.Not(pred_builder(x))):
        s = z3.Solver()
        s.add(want)
        _V.note_z3_check()
        if s.check() == z3.sat:
            found.append(s.model()[x].as_long())
    return found


# ── the generated evidence set + δ ──────────────────────────────────────────────────────────────────────
@dataclass
class Evidence:
    inputs: List[Any]
    delta: float            # rule of three: 3/n
    n: int


def list_evidence(rng: Optional[random.Random] = None) -> Evidence:
    rng = rng or random.Random(0)
    inputs = edge_lists() + random_lists(rng)
    n = len(inputs)
    return Evidence(inputs, 3.0 / n if n else 1.0, n)


def int_evidence(rng: Optional[random.Random] = None, pred_builder: Optional[Callable] = None) -> Evidence:
    rng = rng or random.Random(0)
    vals = boundary_ints() + [rng.randrange(-1000, 1000) for _ in range(20)]
    if pred_builder is not None:
        vals += z3_guided_branch(pred_builder)              # ensure both branches of a predicate are hit
    n = len(vals)
    return Evidence([(v,) if not isinstance(v, tuple) else v for v in vals], 3.0 / n if n else 1.0, n)


def first_divergence(original: Callable, candidate: Callable, inputs: List[Any],
                     eq: Optional[Callable] = None) -> Optional[Any]:
    """The slow-correct `original` is the gold oracle. Returns the first input where candidate disagrees (or
    raises where the original didn't), else None. `inputs` may be raw args or 1-arg values."""
    from pillar3.metamorphic import _eq as _deep_eq
    eqf = eq or _deep_eq
    for x in inputs:
        args = x if isinstance(x, tuple) else (x,)
        try:
            want = original(*args)
        except Exception:
            continue                                        # original itself errors here — not a fair witness
        try:
            got = candidate(*args)
        except Exception as e:  # noqa: BLE001
            return f"{args!r} → candidate raised {type(e).__name__}: {e}"
        if not eqf(got, want):
            return f"{args!r} → original={want!r} candidate={got!r}"
    return None


# ==============================================================================================================
# ===== FILE: pillar3/interproc.py  (116 lines) =====
# ==============================================================================================================

"""
Pillar 3 · ROUND 3 #74 — interprocedural summaries (purity across the call graph) → EXACT memoization.
======================================================================================================
#68 proves purity for a SINGLE function and conservatively rejects ANY call to a non-builtin helper. That is
too weak for real code, which is split across functions. This computes a purity SUMMARY over the call graph by
a monotone fixpoint: a function is pure iff its body is pure GIVEN that its callees are already proven pure.
Start from the leaves, propagate upward until no change. A top-level function reachable to only-pure callees is
then provably pure ⇒ memoizable EXACT — even though it calls helpers. If any reachable callee is impure (I/O,
mutation, nondeterminism), the summary leaves the caller IMPURE ⇒ DECLINE (sound: a wrong "pure" is a bug).
"""
from __future__ import annotations

from typing import Callable, Dict, Optional, Tuple

import kernel_verdict as KV
from pillar3 import lifting as LF
from pillar3 import purity as PU


def purity_summary(functions: Dict[str, Callable]) -> Dict[str, Tuple[bool, str]]:
    """Monotone fixpoint: repeatedly mark a function pure if is_pure holds GIVEN the currently-proven-pure set.
    Returns {name: (pure, reason)}. Sound: a function only becomes pure once all the callees it relies on are."""
    pure_names: set = set()
    reasons: Dict[str, str] = {}
    changed = True
    while changed:
        changed = False
        for name, fn in functions.items():
            if name in pure_names:
                continue
            ok, why = PU.is_pure(fn, known_pure=pure_names)
            reasons[name] = why
            if ok:
                pure_names.add(name)
                changed = True
    return {name: (name in pure_names, reasons.get(name, "impure")) for name in functions}


def memoize_grade_ip(fn: Callable, fn_name: str, functions: Dict[str, Callable], make_input: Callable[[], tuple], *,
                     n: int, samples: int = 5, residual_iters: int = 0, floor: float = 1.20
                     ) -> Tuple[KV.Verdict, Optional[object]]:
    """Prove `fn_name` pure INTERPROCEDURALLY (whole reachable callee set pure), then memoize ⇒ EXACT. If the
    summary leaves it impure ⇒ DECLINE (some reachable callee has an effect)."""
    summary = purity_summary(functions)
    pure, why = summary.get(fn_name, (False, "not in call graph"))
    if not pure:
        return KV.decline(f"interprocedural purity NOT proven for {fn_name} ({why}) ⇒ DECLINE memoization", "memoize_ip"), None

    def naive(workload):
        return [fn(x) for x in workload]

    def memoized(workload):
        cache = {}
        out = []
        for x in workload:
            if x not in cache:
                cache[x] = fn(x)
            out.append(cache[x])
        return out

    wl = make_input()[0]
    if naive(wl) != memoized(wl):
        return KV.decline("memoized ≠ naive (purity summary was wrong) ⇒ DECLINE", "memoize_ip"), None
    rep = LF.measure_lift(lambda w: naive(w), lambda w: memoized(w), make_input, residual_iters, n=n, samples=samples)
    if not rep.beats(floor):
        v = KV.decline(f"interprocedurally pure but no whole-program win (×{rep.whole_program_ratio:.2f}) ⇒ DECLINE", "memoize_ip")
        v.report = rep
        return v, rep
    cert = KV.Cert(KV.EXACT, "interprocedural_purity_memoization", passed=True, check_cost="call-graph purity fixpoint",
                   detail=f"{fn_name} pure across its call graph ({why}); memoization behavior-preserving ⇒ EXACT")
    v = KV.exact(memoized, "memoize_ip", str(rep), cert)
    v.report = rep
    return v, rep


# ── a PURE call graph (top-level calls helpers, all pure) and an IMPURE one (a reachable helper does I/O) ───
def _h_square(x):
    return x * x


def _h_poly(x):
    return _h_square(x) - 3 * x + 7                          # calls _h_square (pure)


def compute_pure(x):
    s = 0
    for i in range(250):
        s += _h_poly(x + i) % 1000                          # calls _h_poly → _h_square (whole graph pure)
    return s


PURE_GRAPH = {"_h_square": _h_square, "_h_poly": _h_poly, "compute_pure": compute_pure}


def _h_io(x):
    print(x)                                                # I/O ⇒ impure
    return x * x


def compute_impure(x):
    return sum(_h_io(x + i) for i in range(8))              # reaches an impure helper


IMPURE_GRAPH = {"_h_io": _h_io, "compute_impure": compute_impure}


_WL_CACHE: dict = {}


def make_workload(unique: int = 60, reps: int = 5000):
    if (unique, reps) not in _WL_CACHE:
        import random as _rnd
        rng = _rnd.Random(45)
        _WL_CACHE[(unique, reps)] = ([rng.randrange(unique) for _ in range(reps)],)
    return _WL_CACHE[(unique, reps)]


