# ===== FILE: pillar3/lifting.py  (442 lines) =====
# ==============================================================================================================

"""
Pillar 3 · PHASE L — verified lifting (the biggest speed lever: lift a hot region to a spec, re-synthesize).
============================================================================================================
Tenspiler-spirit (ECOOP 2024), Z3-backed, NO Lean/Coq/Isabelle. For a restricted hot region (pure arithmetic
over integer arrays, affine indexing — no pointers/objects) we:

  (1) PROPOSE A SPEC      — a mathematical statement of what the region computes (sum / running aggregate /…).
  (2) lifted ≡ original   — Z3 proves the spec equals the original over the input domain (bounded translation
                            validation, Alive2-spirit: symbolic inputs, prove every output entry equal ∀ inputs).
  (3) re-synthesize + prove— synthesize the optimal implementation FROM the spec and Z3-prove it ≡ the spec.

EXACT only if BOTH proofs pass; a subtly-wrong lift is caught by Z3 (counterexample) ⇒ DECLINE. Then the win is
MEASURED whole-program with a coherent Amdahl fraction (ratio ≤ ceiling by construction — Rule 1/2). The grade
comes from the real ADT (Rule 3). This generalises beyond the fixed detectors: it lifts hotspots no detector
names (e.g. a hand-rolled O(n²) running-sum → an O(n) scan), proven, not pattern-matched.
"""
from __future__ import annotations

from dataclasses import dataclass
from typing import Any, Callable, List, Optional, Tuple

import z3

import kernel_verdict as KV
from pillar3 import equiv as EQ
from pillar3 import measure as M
from pillar3 import record as RC
from pillar3 import verifier as _V


# ── the two-step proof (lift correctness + synthesis correctness) ──────────────────────────────────────
def prove_lift(original: Callable, spec: Callable, optimized: Callable,
               sym_factory: Callable[[int], tuple], sizes: Tuple[int, ...]) -> "Tuple[bool, bool, Optional[str]]":
    """Returns (lifted_ok, synth_ok, counterexample). lifted_ok = Z3 proved spec ≡ original; synth_ok = Z3 proved
    optimized ≡ spec. Both true ⇒ original ≡ optimized by transitivity, with the spec as the audited middle."""
    lifted_ok, cex1 = EQ.prove_equiv(original, spec, sym_factory, sizes)
    if not lifted_ok:
        return False, False, f"lift step (spec≡original) failed: {cex1}"
    synth_ok, cex2 = EQ.prove_equiv(spec, optimized, sym_factory, sizes)
    return True, synth_ok, (None if synth_ok else f"synthesis step (optimized≡spec) failed: {cex2}")


# ── coherent whole-program measurement (ratio ≤ ceiling BY CONSTRUCTION; the floor pipeline trick) ──────
def _busy(iters: int) -> int:
    x = 0
    for _ in range(iters):
        x = (x * 1103515245 + 12345) & 0x7FFFFFFF
    return x


def measure_lift(region_orig: Callable, region_opt: Callable, make_input: Callable[[], Any],
                 residual_iters: int, *, n: int, samples: int = 7) -> M.SpeedupReport:
    """Embed the region in a whole program (residual busy-work + region) and measure base/floor/candidate in ONE
    session. floor = residual + region PASSED THROUGH (the infinitely-fast limit) ≤ candidate, so the measured
    ratio = T_base/T_cand ≤ T_base/T_floor = ceiling. f = 1 − T_floor/T_base (the real, measured hotspot share)."""
    noop = lambda *_a: None                                   # the region replaced by the unreachable 0-cost limit

    def whole(region):
        def run(_a):
            args = make_input()                               # make_input returns the full ARGS TUPLE
            _busy(residual_iters)
            return region(*args)
        return run

    args = lambda: (None,)
    t_base = M.time_best(whole(region_orig), args, samples)
    t_floor = M.time_best(whole(noop), args, samples)
    t_cand = M.time_best(whole(region_opt), args, samples)
    t_floor = min(t_floor, t_cand)                            # floor cannot beat the real optimized candidate
    # f = 1 − T_floor/T_base ⇒ ceiling = 1/(1−f) = T_base/T_floor ≥ T_base/T_cand = ratio (floor ≤ cand). The cap
    # only avoids an exactly-infinite ceiling; it must stay ABOVE the measured ratio for big asymptotic wins
    # (e.g. O(2^n)→O(n)), so it is 1−1e-12, NOT 0.999 (which would wrongly cap the ceiling below the ratio).
    f = max(0.0, min(1.0 - 1e-12, 1.0 - t_floor / max(t_base, 1e-12)))
    ratio = t_base / max(t_cand, 1e-12)
    return M.SpeedupReport(whole_program_ratio=ratio, hotspot_fraction=f, n=n, samples=samples,
                           warmup_discarded=1, orig_median_s=t_base, cand_median_s=t_cand)


@dataclass
class Lift:
    """A liftable hot region: the naive code, the proposed spec, the re-synthesized optimal, the symbolic factory
    (for Z3), a runtime input maker, and the residual size that sets the (measured) hotspot fraction."""
    name: str
    waste_type: str
    original: Callable
    spec: Callable
    optimized: Callable
    sym_factory: Callable[[int], tuple]
    make_input: Callable[[], Any]
    residual_iters: int
    eq: Optional[Callable[[Any, Any], bool]] = None
    sizes: Tuple[int, ...] = (3, 5, 8)
    floor: float = 1.05
    n: int = 0


def lift_and_grade(L: "Lift", *, samples: int = 7) -> KV.Verdict:
    """Differential FIRST (Rule 4); then the two-step Z3 lift proof; then a measured whole-program win; then the
    ADT grade (EXACT iff both proofs pass AND a win ≥ floor; PROBABILISTIC if only differential; DECLINE if Z3
    refutes or there is no win). The proposer here is *lifting*; the verifier still arbitrates (Rule 5)."""
    # differential oracle from the trusted-slow original on real inputs (make_input returns the args tuple)
    oracle = RC.record_oracle(L.original, [L.make_input() for _ in range(6)])
    diff = RC.differential_test(L.optimized, oracle, L.eq)
    if not diff.passed:
        return KV.decline(f"differential FAILED ({diff.mismatches}/{diff.n}) ⇒ DECLINE (a wrong lift, even if "
                          f"faster)", L.waste_type)

    lifted_ok, synth_ok, cex = prove_lift(L.original, L.spec, L.optimized, L.sym_factory, L.sizes)
    if cex and "counterexample" in str(cex):                  # Z3 actively refuted — the moat
        return KV.decline(f"Z3 REFUTED the lift ({cex}) ⇒ DECLINE", L.waste_type)
    proven = lifted_ok and synth_ok

    rep = measure_lift(L.original, L.optimized, L.make_input, L.residual_iters, n=L.n or 0, samples=samples)
    if not rep.beats(L.floor):
        v = KV.decline(f"no whole-program win ≥ {L.floor:.2f}× (measured {rep.whole_program_ratio:.2f}×) ⇒ DECLINE",
                       L.waste_type)
        v.report = rep
        return v

    if proven:
        cert = KV.Cert(KV.EXACT, "z3_two_step_lift", passed=True, check_cost="Z3 bounded (lift + synth)",
                       detail="Z3 proved spec≡original AND optimized≡spec on symbolic inputs (Tenspiler-spirit)")
        v = KV.exact(L.optimized, L.waste_type, str(rep), cert)
    else:
        cert = KV.Cert(KV.PROBABILISTIC, "differential", passed=True, check_cost=f"{diff.n} cases",
                       delta=diff.rule_of_three_delta,
                       detail=f"lift proof inconclusive ({cex}); differential PASS on {diff.n} ⇒ PROBABILISTIC")
        v = KV.probabilistic(L.optimized, L.waste_type, str(rep), cert)
    v.report = rep
    return v


# ── concrete liftable regions (real arithmetic; the same fn runs symbolically for Z3 and numerically to time) ─
def _sym_int_list(n: int) -> tuple:
    return ([z3.Int(f"a{i}") for i in range(n)],)


def _sym_int_list_and_c(n: int) -> tuple:
    return ([z3.Int(f"a{i}") for i in range(n)], z3.Int("c"))


# 1) FLAGSHIP — hand-rolled O(n²) running sum  →  O(n) single-pass scan. No fixed detector recognises this.
def rs_original(a):
    out = []
    for i in range(len(a)):
        s = 0
        for j in range(i + 1):
            s = s + a[j]
        out.append(s)
    return out


def rs_spec(a):
    return [sum(a[: i + 1]) for i in range(len(a))]          # the mathematical spec: prefix sums


def rs_optimized(a):
    out = []
    s = 0
    for x in a:
        s = s + x
        out.append(s)
    return out


def rs_wrong(a):                                             # subtly wrong: drops the current element (off-by-one)
    out = []
    s = 0
    for x in a:
        out.append(s)                                        # appends BEFORE adding ⇒ shifted prefix
        s = s + x
    return out


# 2) distributive lift —  sum(c*x for x in a)  →  c*sum(a)  (fewer multiplies; proven by Z3)
def fc_original(a, c):
    s = 0
    for x in a:
        s = s + c * x
    return s


def fc_spec(a, c):
    return sum(c * x for x in a)


def fc_optimized(a, c):
    return c * sum(a)


# 3) telescoping sum —  Σ (a[i+1]−a[i])  →  a[-1] − a[0]   (O(n) → O(1); pure arithmetic, Z3-provable)
def ts_original(a):
    s = 0
    for i in range(len(a) - 1):
        s = s + (a[i + 1] - a[i])
    return s


def ts_spec(a):
    return sum(a[i + 1] - a[i] for i in range(len(a) - 1))


def ts_optimized(a):
    return a[len(a) - 1] - a[0]


def ts_wrong(a):                                            # wrong: forgets it telescopes, drops a sign
    return a[len(a) - 1] + a[0]


# 4) weighted running sum —  [Σ_{j≤i} w·a[j]]  →  single-pass scan with running accumulator  (O(n²) → O(n))
def wrs_original(a, w):
    out = []
    for i in range(len(a)):
        s = 0
        for j in range(i + 1):
            s = s + w * a[j]
        out.append(s)
    return out


def wrs_spec(a, w):
    return [sum(w * a[j] for j in range(i + 1)) for i in range(len(a))]


def wrs_optimized(a, w):
    out = []
    s = 0
    for x in a:
        s = s + w * x
        out.append(s)
    return out


# 5) range-sum queries —  re-sum a[l:r] per query (O(K·n))  →  prefix array, pref[r]−pref[l] per query (O(n+K))
def rq_original(a, q):
    out = []
    for (l, r) in q:
        s = 0
        for j in range(l, r):
            s = s + a[j]
        out.append(s)
    return out


def rq_spec(a, q):
    return [sum(a[l:r]) for (l, r) in q]


def rq_optimized(a, q):
    pref = [0] * (len(a) + 1)
    for i in range(len(a)):
        pref[i + 1] = pref[i] + a[i]
    return [pref[r] - pref[l] for (l, r) in q]


def rq_wrong(a, q):                                          # off-by-one: pref[l-1] (wraps for l=0) ⇒ wrong
    pref = [0] * (len(a) + 1)
    for i in range(len(a)):
        pref[i + 1] = pref[i] + a[i]
    return [pref[r] - pref[l - 1] for (l, r) in q]


_RQ_PROOF_Q = [(0, 2), (1, 3), (0, 3), (2, 3)]


def _sym_int_list_and_q(n):
    return ([z3.Int(f"a{i}") for i in range(n)], _RQ_PROOF_Q)


def _make_rq_input(size: int = 500, k: int = 300):
    import random
    rng = random.Random(23)
    a = [rng.randrange(-1000, 1000) for _ in range(size)]
    q = []
    for _ in range(k):
        l = rng.randrange(0, size - 1)
        r = rng.randrange(l + 1, size)
        q.append((l, r))
    return (a, q)


# 7) multi-loop FUSION — two passes over the same array → one fused pass (same results, half the iteration)
def lfz_unfused(a):
    s = 0
    for x in a:
        s = s + x
    t = 0
    for x in a:
        t = t + x * 2
    return (s, t)


def lfz_spec(a):
    s = 0
    for x in a:
        s = s + x
    t = 0
    for x in a:
        t = t + x * 2
    return (s, t)


def lfz_fused(a):
    s = 0
    t = 0
    for x in a:
        s = s + x
        t = t + x * 2
    return (s, t)


def lfz_wrong(a):                                            # fused but t accumulates x, not x*2 ⇒ wrong
    s = 0
    t = 0
    for x in a:
        s = s + x
        t = t + x
    return (s, t)


_LFZ_CACHE: dict = {}


def _make_lfz_input(size: int = 5000):
    # cached: the timed region is the two-pass kernel, not input-gen (fair fixed workload; read-only)
    if size not in _LFZ_CACHE:
        import random
        rng = random.Random(43)
        _LFZ_CACHE[size] = [rng.randrange(-1000, 1000) for _ in range(size)]
    return (_LFZ_CACHE[size],)


# 6) range UPDATES via a difference array —  add d to a[l:r] per update (O(K·n))  →  diff array (O(n+K))
def da_original(a, ups):
    b = list(a)
    for (l, r, d) in ups:
        for j in range(l, r):
            b[j] = b[j] + d
    return b


def da_spec(a, ups):
    b = list(a)
    for (l, r, d) in ups:
        for j in range(l, r):
            b[j] = b[j] + d
    return b


def da_optimized(a, ups):
    n = len(a)
    diff = [0] * (n + 1)
    for (l, r, d) in ups:
        diff[l] = diff[l] + d
        diff[r] = diff[r] - d
    b = list(a)
    run = 0
    for i in range(n):
        run = run + diff[i]
        b[i] = b[i] + run
    return b


def da_wrong(a, ups):                                        # diff[r]+=d (forgot the minus) ⇒ wrong
    n = len(a)
    diff = [0] * (n + 1)
    for (l, r, d) in ups:
        diff[l] = diff[l] + d
        diff[r] = diff[r] + d
    b = list(a)
    run = 0
    for i in range(n):
        run = run + diff[i]
        b[i] = b[i] + run
    return b


_DA_PROOF_UPS = [(0, 2, 5), (1, 3, -3), (0, 3, 2)]


def _sym_int_list_and_ups(n):
    return ([z3.Int(f"a{i}") for i in range(n)], _DA_PROOF_UPS)


def _make_da_input(size: int = 500, k: int = 300):
    import random
    rng = random.Random(29)
    a = [rng.randrange(-1000, 1000) for _ in range(size)]
    ups = []
    for _ in range(k):
        l = rng.randrange(0, size - 1)
        r = rng.randrange(l + 1, size)
        ups.append((l, r, rng.randrange(-50, 50)))
    return (a, ups)


def _make_ts_input(size: int = 6000):
    import random
    rng = random.Random(13)
    return ([rng.randrange(-1000, 1000) for _ in range(size)],)


def _make_wrs_input(size: int = 220):
    import random
    rng = random.Random(17)
    return ([rng.randrange(-1000, 1000) for _ in range(size)], 3)


def _make_rs_input(size: int = 220):
    import random
    rng = random.Random(7)
    return ([rng.randrange(-1000, 1000) for _ in range(size)],)          # args tuple: (a,)


def _make_fc_input(size: int = 4000):
    import random
    rng = random.Random(11)
    return ([rng.randrange(-1000, 1000) for _ in range(size)], 7)        # args tuple: (a, c)


def catalog() -> List[Lift]:
    """The liftable regions this phase ships. rs_* is the flagship (O(n²)→O(n), no detector covers it)."""
    return [
        Lift("running_sum_lift", "verified_lift", rs_original, rs_spec, rs_optimized,
             _sym_int_list, lambda: _make_rs_input(220), residual_iters=900, sizes=(3, 5, 8), n=220),
        Lift("factor_constant_lift", "verified_lift", fc_original, fc_spec, fc_optimized,
             _sym_int_list_and_c, lambda: _make_fc_input(4000), residual_iters=300, sizes=(3, 5, 8), n=4000),
        Lift("telescoping_sum_lift", "verified_lift", ts_original, ts_spec, ts_optimized,
             _sym_int_list, lambda: _make_ts_input(6000), residual_iters=200, sizes=(3, 5, 8), n=6000),
        Lift("weighted_running_sum_lift", "verified_lift", wrs_original, wrs_spec, wrs_optimized,
             _sym_int_list_and_c, lambda: _make_wrs_input(220), residual_iters=900, sizes=(3, 5, 8), n=220),
        Lift("range_sum_query_lift", "verified_lift", rq_original, rq_spec, rq_optimized,
             _sym_int_list_and_q, lambda: _make_rq_input(500, 300), residual_iters=200,
             sizes=(3, 5, 8), n=500),
        Lift("difference_array_lift", "verified_lift", da_original, da_spec, da_optimized,
             _sym_int_list_and_ups, lambda: _make_da_input(500, 300), residual_iters=200,
             sizes=(3, 5, 8), n=500),
        Lift("loop_fusion_lift", "verified_lift", lfz_unfused, lfz_spec, lfz_fused,
             _sym_int_list, lambda: _make_lfz_input(5000), residual_iters=80, sizes=(3, 5, 8), n=5000),
    ]


# ==============================================================================================================
# ===== FILE: pillar3/loop.py  (128 lines) =====
# ==============================================================================================================

"""
Pillar 3 · Stage 2 — the iterative compounding loop + diminishing-returns controller (normal mode).
====================================================================================================
profile → apply the best VERIFIED fix → REPROFILE (the next hotspot is now dominant) → repeat. The cumulative
whole-program speedup is MEASURED FRESH each round (Rule 1) — never the product of component multipliers
(the Whatnot honesty check: 3×·20×·6.7× ≠ 5.8×). A DECLINE at any step is skipped, not chained (Rule 4).
Stops at diminishing returns (next marginal whole-program gain < floor).

Program model (concrete, testable): a pipeline of stages, each with a slow and a fast implementation. The
program runs the stages in sequence; a fix = activating a stage's fast impl. The all-slow pipeline is the
neutral baseline and the trusted oracle.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any, Callable, Dict, List, Optional, Set, Tuple

import kernel_verdict as KV
from pillar3 import measure as M
from pillar3 import record as RC


@dataclass
class Stage:
    name: str
    slow: Callable[[Any], Any]
    fast: Callable[[Any], Any]
    fraction: float = 0.0           # profiled share of baseline runtime (Amdahl input for this stage)


@dataclass
class Round:
    applied: str
    cumulative_ratio: float         # FRESH whole-program measurement (all active fixes) vs baseline
    marginal_gain: float            # cumulative_this / cumulative_prev − 1
    hotspot_fraction: float
    amdahl_ceiling: float
    grade: str


@dataclass
class CompoundingReport:
    rounds: List[Round] = field(default_factory=list)
    final_cumulative_ratio: float = 1.0
    stop_reason: str = ""
    declined: List[str] = field(default_factory=list)
    product_of_locals: float = 1.0  # for the honesty check: this is NOT the whole-program number

    def best_single_round_ratio(self) -> float:
        return max((r.cumulative_ratio for r in self.rounds[:1]), default=1.0)


def _pipeline(stages: List[Stage], active: Set[str]) -> Callable[[Any], Any]:
    def run(data):
        out = data
        for s in stages:
            out = (s.fast if s.name in active else s.slow)(out)
        return out
    return run


def compound_optimize(stages: List[Stage], make_input: Callable[[], Any], *, n: int,
                      min_marginal_gain: float = 0.03, samples: int = 5,
                      eq: Callable[[Any, Any], bool] = None) -> CompoundingReport:
    """Walk down the flame graph: each round measure (fresh) the whole-program ratio of every candidate fix vs
    the all-slow baseline, verify it against the baseline oracle, apply the best, repeat until the marginal
    whole-program gain drops below `min_marginal_gain`. Cumulative is always a fresh end-to-end measurement."""
    baseline = _pipeline(stages, set())
    oracle = RC.record_oracle(baseline, [(make_input(),) for _ in range(4)])
    active: Set[str] = set()
    rep = CompoundingReport()
    prev_cumulative = 1.0
    make_args = lambda: (make_input(),)
    while len(active) < len(stages):
        best: Optional[Tuple[Stage, M.SpeedupReport]] = None
        for s in stages:
            if s.name in active:
                continue
            cand = _pipeline(stages, active | {s.name})
            diff = RC.differential_test(cand, oracle, eq)
            if not diff.passed:                                  # Rule 4: skip, do not chain a divergent fix
                if s.name not in rep.declined:
                    rep.declined.append(s.name)
                continue
            sr = M.measure_whole_program(baseline, cand, make_args, n=n,
                                         hotspot_fraction=min(0.999, sum(st.fraction for st in stages
                                                                         if st.name in (active | {s.name}))),
                                         samples=samples, timer=M.time_best)   # best-of-k: stable under load
            if best is None or sr.whole_program_ratio > best[1].whole_program_ratio:
                best = (s, sr)
        if best is None:
            rep.stop_reason = "no remaining verified candidate improves the program"
            break
        stage, sr = best
        marginal = sr.whole_program_ratio / prev_cumulative - 1.0
        if marginal < min_marginal_gain and rep.rounds:
            rep.stop_reason = (f"diminishing returns: next marginal whole-program gain {marginal:.1%} "
                               f"< {min_marginal_gain:.0%}")
            break
        active.add(stage.name)
        rep.rounds.append(Round(stage.name, sr.whole_program_ratio, marginal, sr.hotspot_fraction,
                                sr.amdahl_ceiling, KV.PROBABILISTIC))
        prev_cumulative = sr.whole_program_ratio
    rep.final_cumulative_ratio = prev_cumulative
    if not rep.stop_reason:
        rep.stop_reason = "all stages applied"
    # honesty bookkeeping (the Whatnot fallacy): the PRODUCT of each fix's LOCAL multiplier — measured on the
    # stage ALONE (its own slow/fast ratio), NOT in the pipeline. This is the naive "multiply the component
    # speedups" number that does NOT equal the whole-program result. We surface it precisely to refute it.
    prod = 1.0
    sample_in = make_input()
    for s in stages:
        if s.name in active:
            local = M.time_best(s.slow, lambda: (sample_in,), samples=5) / \
                max(M.time_best(s.fast, lambda: (sample_in,), samples=5), 1e-12)
            prod *= local
    rep.product_of_locals = prod
    return rep


def fresh_end_to_end_ratio(stages: List[Stage], make_input: Callable[[], Any], n: int, samples: int = 5) -> float:
    """An INDEPENDENT fresh measurement of all-fast vs all-slow — used to prove the loop's cumulative number is
    a real end-to-end measurement, not a component product (the Whatnot check)."""
    baseline = _pipeline(stages, set())
    allfast = _pipeline(stages, {s.name for s in stages})
    return M.measure_whole_program(baseline, allfast, lambda: (make_input(),), n=n,
                                   hotspot_fraction=0.99, samples=samples, timer=M.time_best).whole_program_ratio


# ==============================================================================================================
# ===== FILE: pillar3/matmul.py  (104 lines) =====
# ==============================================================================================================

"""
Pillar 3 · ROUND 1 #15 — naive O(n³) matmul → blocked/BLAS matmul (EXACT integers under an overflow bound).
============================================================================================================
A hand-rolled triple-loop integer matrix multiply is O(n³) in the interpreter. A blocked/BLAS multiply (numpy
int64 — cache-tiled, vectorized) computes the SAME integer product far faster. Integer matmul is exact UNLESS
a 64-bit accumulator overflows, so — exactly like the NTT convolution — we keep the EXACT grade ONLY under a
PROVEN bound:  |C_ij| ≤ k·max|A|·max|B| < 2^63  ⇒ every entry's int64 value IS the true integer. Bound exceeded
⇒ DECLINE the int64 fast path (Python-bigint or multi-word is the honest extension) — never a wrapped answer.
Certificate = the overflow-bound proof + a full-matrix spot-check vs the naive. A wrong product (transposed /
wrong axis) ⇒ spot-check disagrees ⇒ DECLINE (the moat). UNVERIFIED [no numpy] if the toolchain is absent.
"""
from __future__ import annotations

import random as _rnd
from typing import Callable, List, Optional, Tuple

import kernel_verdict as KV
from pillar3 import lifting as LF

try:
    import numpy as _np
    _NP = True
except Exception:                                            # numpy absent ⇒ UNVERIFIED
    _NP = False

_I64_HALF = 2 ** 63


def matmul_naive(A: List[List[int]], B: List[List[int]]) -> List[List[int]]:
    """Ground-truth O(n³) integer matmul (exact Python ints)."""
    n, k, m = len(A), len(B), len(B[0]) if B else 0
    return [[sum(A[i][t] * B[t][j] for t in range(k)) for j in range(m)] for i in range(n)]


def matmul_numpy(A: List[List[int]], B: List[List[int]]) -> List[List[int]]:
    """Blocked/BLAS integer matmul via numpy int64 (the SAME product, cache-tiled + vectorized)."""
    return (_np.asarray(A, dtype=_np.int64) @ _np.asarray(B, dtype=_np.int64)).tolist()


def matmul_wrong(A: List[List[int]], B: List[List[int]]) -> List[List[int]]:
    """BROKEN: multiplies A by Bᵀ (wrong axis) ⇒ a different product ⇒ spot-check disagrees ⇒ DECLINE."""
    return (_np.asarray(A, dtype=_np.int64) @ _np.asarray(B, dtype=_np.int64).T).tolist()


def _bound(A, B) -> int:
    k = len(B)
    mA = max((abs(x) for row in A for x in row), default=0)
    mB = max((abs(x) for row in B for x in row), default=0)
    return k * mA * mB


def matmul_grade(make_input: Callable[[], tuple], fast_fn: Callable = None, *, n: int, samples: int = 5,
                 residual_iters: int = 0, floor: float = 1.20) -> Tuple[KV.Verdict, Optional[object]]:
    """EXACT iff numpy present AND a PROVEN no-overflow bound holds AND the fast product equals the naive AND a
    whole-program win is measured; bound exceeded / disagreement ⇒ DECLINE; no numpy ⇒ UNVERIFIED (excluded)."""
    if not _NP:
        return KV.decline("matmul UNVERIFIED [no numpy in sandbox] — transform built, excluded", "matmul"), None
    fast_fn = fast_fn or matmul_numpy
    A, B = make_input()
    if _bound(A, B) >= _I64_HALF:                            # the proven exactness condition fails
        return KV.decline("matmul magnitude bound ≥ 2^63 — int64 could overflow; EXACT not certifiable "
                          "(bigint/multi-word is the extension) ⇒ DECLINE fast path", "matmul"), None
    en = matmul_naive(A, B)
    ef = fast_fn(A, B)
    spot_ok = (en == ef)                                     # full-matrix equality on this input
    rep = LF.measure_lift(lambda a, b: matmul_naive(a, b), lambda a, b: fast_fn(a, b),
                          make_input, residual_iters, n=n, samples=samples)
    if not spot_ok:
        v = KV.decline("matmul fast product disagrees with the naive (wrong axis / impossible under the bound) "
                       "⇒ DECLINE", "matmul")
        v.report = rep
        return v, rep
    if not rep.beats(floor):
        v = KV.decline(f"matmul blocked but no whole-program win (×{rep.whole_program_ratio:.2f}) ⇒ DECLINE", "matmul")
        v.report = rep
        return v, rep
    cert = KV.Cert(KV.EXACT, "int64_bound+spotcheck", passed=True, check_cost="O(n²) spot-check",
                   detail=f"blocked/BLAS int64 matmul; proven |C_ij|<2^63 ⇒ exact integers; full-matrix check vs naive")
    v = KV.exact(ef, "matmul", str(rep), cert)
    v.report = rep
    return v, rep


_MM_CACHE: dict = {}


def make_matmul_input(n: int = 160, mag: int = 1000) -> Tuple[List[List[int]], List[List[int]]]:
    """Two n×n integer matrices with |value| ≤ mag, chosen so the proven int64 bound holds (EXACT path)."""
    key = (n, mag)
    if key not in _MM_CACHE:
        rng = _rnd.Random(87)
        A = [[rng.randrange(-mag, mag + 1) for _ in range(n)] for _ in range(n)]
        B = [[rng.randrange(-mag, mag + 1) for _ in range(n)] for _ in range(n)]
        _MM_CACHE[key] = (A, B)
    return _MM_CACHE[key]


def make_matmul_input_overflow(n: int = 64, mag: int = 10 ** 9) -> Tuple[List[List[int]], List[List[int]]]:
    """Huge magnitudes ⇒ the int64 bound is exceeded ⇒ the honest DECLINE path (never a wrapped answer)."""
    rng = _rnd.Random(88)
    A = [[rng.randrange(-mag, mag + 1) for _ in range(n)] for _ in range(n)]
    B = [[rng.randrange(-mag, mag + 1) for _ in range(n)] for _ in range(n)]
    return (A, B)


# ==============================================================================================================
# ===== FILE: pillar3/measure.py  (94 lines) =====
# ==============================================================================================================

"""
Pillar 3 · Stage 0 — neutral-baseline WHOLE-PROGRAM measurement harness (the single source of truth).
======================================================================================================
Every speedup number in Pillar 3 comes from here. A SpeedupReport REFUSES to exist without `n` and
`hotspot_fraction` (Rule 1/2) — so no number can be reported without its operating point and its Amdahl
ceiling. The ratio is a measured, warmup-aware, median wall-clock ratio of the WHOLE program (Clock C).
Kernel speedup is never reported here; only whole-program.
"""
from __future__ import annotations

import statistics
import time
from dataclasses import dataclass
from typing import Callable, Optional


@dataclass
class SpeedupReport:
    whole_program_ratio: float          # measured orig_median / cand_median (Clock C, whole program)
    hotspot_fraction: float             # fraction of original runtime in the region being fixed (Amdahl input)
    n: int                              # the operating-point workload size (a ratio is meaningless without it)
    samples: int
    warmup_discarded: int
    orig_median_s: float
    cand_median_s: float
    amdahl_ceiling: float = 0.0         # 1/(1-hotspot_fraction); the system states its own ceiling (Rule 2)

    def __post_init__(self):
        if self.n is None or self.hotspot_fraction is None:
            raise ValueError("SpeedupReport refuses to exist without n AND hotspot_fraction (Rule 1/2)")
        if not (0.0 <= self.hotspot_fraction <= 1.0):
            raise ValueError(f"hotspot_fraction must be in [0,1], got {self.hotspot_fraction}")
        self.amdahl_ceiling = (1.0 / (1.0 - self.hotspot_fraction)) if self.hotspot_fraction < 1.0 else float("inf")

    def beats(self, floor: float) -> bool:
        return self.whole_program_ratio >= floor

    def __str__(self):
        return (f"{self.whole_program_ratio:.2f}× whole-program @n={self.n} "
                f"(hotspot {self.hotspot_fraction:.0%}, Amdahl ceiling {self.amdahl_ceiling:.1f}×; "
                f"orig {self.orig_median_s*1e3:.2f}ms → cand {self.cand_median_s*1e3:.2f}ms, "
                f"median of {self.samples}, {self.warmup_discarded} warmup discarded)")


def time_median(fn: Callable, make_args: Callable[[], tuple], samples: int = 7, warmup: int = 1) -> float:
    """Median wall-clock of fn over `samples` runs after discarding `warmup` (fresh args each run so mutation
    or caching inside the candidate cannot leak across runs)."""
    for _ in range(warmup):
        fn(*make_args())
    ts = []
    for _ in range(samples):
        args = make_args()
        t = time.perf_counter()
        fn(*args)
        ts.append(time.perf_counter() - t)
    return statistics.median(ts)


def time_best(fn: Callable, make_args: Callable[[], tuple], samples: int = 7, warmup: int = 1) -> float:
    """Best-of-k (minimum) wall-clock — the least-contended run. For CPU-bound deterministic work the minimum is
    the most stable estimator of the true cost (it filters ALL upward OS/GC contention, which the median does
    not when a spike is sustained across several samples). Fresh args each run."""
    for _ in range(warmup):
        fn(*make_args())
    best = float("inf")
    for _ in range(samples):
        args = make_args()
        t = time.perf_counter()
        fn(*args)
        best = min(best, time.perf_counter() - t)
    return best


def measure_whole_program(original: Callable, candidate: Callable, make_args: Callable[[], tuple], *,
                          n: int, hotspot_fraction: float, samples: int = 7, warmup: int = 1,
                          timer: Callable = None) -> SpeedupReport:
    """The neutral-baseline whole-program ratio: timer(original) / timer(candidate) on the SAME workload, at the
    original's normal optimization level. `timer` defaults to the median; pass `time_best` for CPU-bound work
    where the minimum (least-contended run) is the more stable estimator. `hotspot_fraction` comes from the
    profiler (the Amdahl input). Refuses to produce a number without n and hotspot_fraction."""
    if n is None or hotspot_fraction is None:
        raise ValueError("measure_whole_program requires n AND hotspot_fraction (Rule 1/2)")
    timer = timer or time_median
    orig = timer(original, make_args, samples, warmup)
    cand = timer(candidate, make_args, samples, warmup)
    ratio = orig / cand if cand > 0 else float("inf")
    return SpeedupReport(whole_program_ratio=ratio, hotspot_fraction=hotspot_fraction, n=n,
                         samples=samples, warmup_discarded=warmup, orig_median_s=orig, cand_median_s=cand)


def amdahl_ceiling(hotspot_fraction: float) -> float:
    """max_possible_speedup = 1/(1-f). The system states its own ceiling BEFORE attempting a fix (Rule 2)."""
    return (1.0 / (1.0 - hotspot_fraction)) if hotspot_fraction < 1.0 else float("inf")


# ==============================================================================================================
# ===== FILE: pillar3/metamorphic.py  (130 lines) =====
# ==============================================================================================================

"""
Pillar 3 · PHASE M — metamorphic relations + cross-checking (zero human audit, catches what differential misses).
=================================================================================================================
Differential testing only checks "same output as the slow original on the inputs we happened to record." A wrong
fix can slip through if the recorded inputs don't exercise the bug. Two automated nets close that gap:

  • METAMORPHIC RELATIONS — properties the transform must preserve regardless of input (a sort is permutation-
    invariant, idempotent, output-sorted, multiset-preserving; a sum is order-invariant up to FP tolerance; a
    memoized pure function equals the unmemoized one). A violation ⇒ DECLINE, even if differential passed.
  • CROSS-CHECKING — compute the result two independent ways; disagreement ⇒ DECLINE.

The whole gate is automated (no human in the loop). It only ever turns a borderline pass into a DECLINE — it
never manufactures a win (Constitution Rule 6: honest UNVERIFIED/DECLINE over a fake pass).
"""
from __future__ import annotations

import math
import random
from dataclasses import dataclass
from typing import Any, Callable, List, Optional, Tuple


@dataclass
class MRResult:
    name: str
    held: bool
    witness: Optional[str] = None


def _eq(a: Any, b: Any, tol: float = 1e-9) -> bool:
    if isinstance(a, float) or isinstance(b, float):
        return abs(float(a) - float(b)) <= tol * (1 + abs(float(b)))
    if isinstance(a, (list, tuple)) and isinstance(b, (list, tuple)):
        return len(a) == len(b) and all(_eq(x, y, tol) for x, y in zip(a, b))
    return a == b


def _is_sorted(xs) -> bool:
    return all(xs[i] <= xs[i + 1] for i in range(len(xs) - 1))


# ── relation builders (each takes the candidate fn + one sample input, returns held? ) ─────────────────
def rel_idempotent(name: str = "idempotent") -> Tuple[str, Callable]:
    return name, lambda f, x: _eq(f(list(f(x))), f(x))


def rel_permutation_invariant(rng: random.Random) -> Tuple[str, Callable]:
    def holds(f, x):
        y = list(x)
        rng.shuffle(y)
        return _eq(f(y), f(x))
    return "permutation_invariant", holds


def rel_output_sorted() -> Tuple[str, Callable]:
    return "output_sorted", lambda f, x: _is_sorted(f(x))


def rel_multiset_preserved() -> Tuple[str, Callable]:
    return "multiset_preserved", lambda f, x: sorted(f(x)) == sorted(x)


def rel_sum_order_invariant(rng: random.Random, tol: float = 1e-9) -> Tuple[str, Callable]:
    def holds(f, x):
        y = list(x)
        rng.shuffle(y)
        return _eq(f(x), f(y), tol)
    return "sum_order_invariant", holds


def rel_equals_reference(ref: Callable, name: str = "equals_reference") -> Tuple[str, Callable]:
    return name, lambda f, x: _eq(f(x), ref(x))


# ── the gate ───────────────────────────────────────────────────────────────────────────────────────────
def check_relations(candidate: Callable, relations: List[Tuple[str, Callable]],
                    gen: Callable[[], Any], k: int = 12) -> List[MRResult]:
    """Run each relation over k generated inputs; the first failing input is the witness."""
    out: List[MRResult] = []
    for name, holds in relations:
        bad = None
        for _ in range(k):
            x = gen()
            try:
                if not holds(candidate, x):
                    bad = x
                    break
            except Exception as e:  # noqa: BLE001 — a relation that errors is a violation, not a pass
                bad = f"raised {type(e).__name__}: {e}"
                break
        out.append(MRResult(name, bad is None, None if bad is None else f"violated on {bad!r}"))
    return out


def cross_check(fn_a: Callable, fn_b: Callable, gen: Callable[[], Any], k: int = 12,
                eq: Optional[Callable] = None) -> Tuple[bool, Optional[str]]:
    """Two independent implementations must agree on every generated input; first disagreement is the witness."""
    eqf = eq or _eq
    for _ in range(k):
        x = gen()
        if not eqf(fn_a(x), fn_b(x)):
            return False, f"cross-check disagreement on {x!r}"
    return True, None


def metamorphic_gate(candidate: Callable, relations: List[Tuple[str, Callable]], gen: Callable[[], Any],
                     *, cross: Optional[Callable] = None, k: int = 12) -> Tuple[bool, str]:
    """Returns (ok, detail). ok=False ⇒ the caller DECLINEs (the fix violated an invariant or a cross-check).
    This gate can only DOWNGRADE a borderline pass to DECLINE; it never produces a win."""
    results = check_relations(candidate, relations, gen, k)
    violated = [r for r in results if not r.held]
    if violated:
        v = violated[0]
        return False, f"metamorphic relation '{v.name}' {v.witness} ⇒ DECLINE"
    if cross is not None:
        ok, w = cross_check(candidate, cross, gen, k)
        if not ok:
            return False, f"{w} ⇒ DECLINE"
    held = ", ".join(r.name for r in results)
    return True, f"all {len(results)} metamorphic relations held ({held}){' + cross-check agreed' if cross else ''}"


# ── reference relation packs for common transform families ─────────────────────────────────────────────
def sort_relations(rng: random.Random) -> List[Tuple[str, Callable]]:
    return [rel_output_sorted(), rel_idempotent(), rel_permutation_invariant(rng), rel_multiset_preserved()]


def sum_relations(rng: random.Random, tol: float = 1e-9) -> List[Tuple[str, Callable]]:
    return [rel_sum_order_invariant(rng, tol)]


