# ===== FILE: pillar3/transforms.py  (80 lines) =====
# ==============================================================================================================

"""
Pillar 3 · Stage 3 — cross-cutting GLOBAL transforms (the flat-profile killer; extend mode).
=============================================================================================
When no single hotspot dominates ("death by a thousand cuts"), local fixes fail — a global transform that
multiplies across EVERY frame is the only lever. Each transform is differential-verified and whole-program
measured (Rules 1/4). Honest UNVERIFIED tagging where a dependency is absent in the sandbox (Rule 6).

  • async/batch all independent I/O  — sequential blocking I/O → concurrent (ThreadPool, stdlib). VERIFIED.
  • pervasive serialization swap     — json → a faster serializer everywhere, round-trip-value-equivalent.
        orjson/msgpack are ABSENT here ⇒ the production target is tagged UNVERIFIED; we DEMONSTRATE the swap
        with stdlib `marshal` (measurable) and verify round-trip value identity.
  • interpreter → compiled hot region — a hot pure-numeric op compiled via llvmlite (backend_llvm), applied
        across every frame. Differential-verified; tagged UNVERIFIED if llvmlite is unavailable.
"""
from __future__ import annotations

import concurrent.futures as _cf
import json
import marshal
from typing import Any, Callable, List

import kernel_verdict as KV


# ── async / batch all independent I/O ─────────────────────────────────────────────────────────────────
def make_concurrent(io_fn: Callable[[Any], Any], max_workers: int = 16) -> Callable[[List[Any]], List[Any]]:
    """Turn a sequential map over independent blocking I/O into a concurrent one (order-preserving)."""
    def run(items: List[Any]) -> List[Any]:
        with _cf.ThreadPoolExecutor(max_workers=max_workers) as ex:
            return list(ex.map(io_fn, items))
    return run


def sequential(io_fn: Callable[[Any], Any]) -> Callable[[List[Any]], List[Any]]:
    return lambda items: [io_fn(x) for x in items]


# ── pervasive serialization swap (json → marshal here; orjson is the UNVERIFIED production target) ─────
def json_roundtrip(obj: Any) -> Any:
    return json.loads(json.dumps(obj))


def marshal_roundtrip(obj: Any) -> Any:
    return marshal.loads(marshal.dumps(obj))


def serialization_swap_grade(workload: List[Any]) -> "tuple[KV.Verdict, dict]":
    """Verify round-trip VALUE equivalence (json vs marshal) and report which is faster. Output bytes differ
    (different formats) — equivalence is on the deserialized value, which is what callers depend on."""
    import time
    equiv = all(marshal_roundtrip(x) == json_roundtrip(x) == x for x in workload)
    if not equiv:
        return KV.decline("marshal/json round-trip values differ on this workload", "serialize_swap"), {}
    def med(fn):
        ts = []
        for _ in range(7):
            t = time.perf_counter()
            for x in workload:
                fn(x)
            ts.append(time.perf_counter() - t)
        return min(ts)
    tj, tm = med(json_roundtrip), med(marshal_roundtrip)
    info = {"json_s": tj, "marshal_s": tm, "ratio": tj / tm if tm else 0.0,
            "orjson": "UNVERIFIED (ABSENT in sandbox; production target)"}
    cert = KV.Cert(KV.EXACT, "roundtrip_value_equiv", passed=True, check_cost=f"O(n)={len(workload)}",
                   detail="json↔marshal round-trip yields identical deserialized values (bytes differ by format)")
    return KV.exact(marshal_roundtrip, "serialize_swap", f"{info['ratio']:.2f}× per-op (stdlib marshal)", cert), info


# ── interpreter → compiled hot numeric region (llvmlite via backend_llvm) ──────────────────────────────
def compile_numeric_poly(expr: str):
    """Compile an integer polynomial P(n) to native i64 (llvmlite). Returns (callable_or_None, status)."""
    import backend_llvm as BE
    if not BE.llvm_available():
        return None, "UNVERIFIED [BLOCKED: llvmlite absent]"
    nf = BE.compile_closed_form(expr, "n")
    if nf.status != "OK":
        return None, f"UNVERIFIED (not lowerable: {nf.detail})"
    return nf.cfn, "EXACT (native i64; translation-validatable)"


# ==============================================================================================================
# ===== FILE: pillar3/verifier.py  (72 lines) =====
# ==============================================================================================================

"""
Pillar 3 · PHASE M — the verifier-tier ladder + the Z3 invocation counter (Constitution Rules 4 & 5).
=====================================================================================================
The verifier is the *arbiter* — never the proposer (Rule 5). This module encodes the three-rung ladder a
`ModePolicy` selects from, and the single instrument that makes mode separation *checkable*: a global counter
of actual Z3 solver invocations. `fast` must run at tier MICRO and **never invoke Z3** — the counter proves it
(`z3_check_count() == 0` after a fast run). `equiv.prove_equiv` reports every `solver.check()` here, so the
count reflects real SMT work no matter which path reached it.

  • MICRO       — differential test on recorded I/O + probabilistic checks (Freivalds / Schwartz–Zippel
                  spirit). µs-class. NEVER invokes Z3. Never blocks. (fast)
  • CHEAP_CERT  — MICRO + small-region Z3 (bounded translation validation on a *small* region only). (normal)
  • FULL_CERT   — full Z3/SMT translation-validation on every algorithm swap, exhaustive where tractable.
                  EXACT-or-DECLINE lives here. (extend)
"""
from __future__ import annotations

import enum
from typing import Callable, Optional, Tuple


class VerifierTier(enum.IntEnum):
    """Ordered rungs (IntEnum so `policy.verifier_tier >= CHEAP_CERT` is meaningful)."""
    MICRO = 1        # differential + probabilistic, µs-class, NO Z3
    CHEAP_CERT = 2   # + small-region Z3
    FULL_CERT = 3    # full Z3/SMT translation validation


# ── the Z3 invocation counter — the instrument that makes mode separation checkable ───────────────────
_Z3_CHECKS = 0


def note_z3_check() -> None:
    """Called by equiv.prove_equiv on every solver.check(). The honest record of real SMT work."""
    global _Z3_CHECKS
    _Z3_CHECKS += 1


def reset_z3_checks() -> None:
    global _Z3_CHECKS
    _Z3_CHECKS = 0


def z3_check_count() -> int:
    return _Z3_CHECKS


# region size below which CHEAP_CERT will still attempt a (small) Z3 proof
CHEAP_REGION_LIMIT = 6


def tier_allows_certificate(tier: VerifierTier, region_size: int = 1) -> bool:
    """FULL_CERT always; CHEAP_CERT only for a small region; MICRO never (fast never blocks on Z3)."""
    if tier >= VerifierTier.FULL_CERT:
        return True
    if tier == VerifierTier.CHEAP_CERT:
        return region_size <= CHEAP_REGION_LIMIT
    return False


def attempt_certificate(tier: VerifierTier, prove_fn: Optional[Callable[[], "Tuple[bool, Optional[str]]"]],
                        *, region_size: int = 1) -> "Tuple[bool, bool, Optional[str]]":
    """The ONLY gate through which the engine reaches Z3. Returns (attempted, proven, counterexample_or_reason).
    If the tier forbids a certificate (MICRO, or CHEAP_CERT on a too-large region), Z3 is NOT invoked — the
    counter stays put — and we report (attempted=False) so the caller falls back to a differential grade."""
    if prove_fn is None:
        return (False, False, "no proof available")
    if not tier_allows_certificate(tier, region_size):
        return (False, False, f"tier {tier.name} below certificate (region={region_size}) — differential only")
    proven, cex = prove_fn()                       # prove_fn (equiv.prove_equiv) increments the Z3 counter
    return (True, bool(proven), cex)


